    exp,
    log,
    tanh,
    sigmoid,
    iota,
    minimum,
    maximum,
    reverse,
    less,
    more,
    grade_up,
    grade_down,
    not,
    concat,
    count,
    take,
    floor,
    drop,
    sort,
    equal,
    reshape,
    stringify,
    cast,
    contains,
    split,
    join,
    unique,
    find,
    eval_string,
    grad,
    valuegrad,
    prng,
};

