    contains_calls: usize = 0,
    split_calls: usize = 0,
    join_calls: usize = 0,
    contains_opcode_ns: u64 = 0,
    split_opcode_ns: u64 = 0,
    join_opcode_ns: u64 = 0,
    contains_helper_ns: u64 = 0,
    split_helper_ns: u64 = 0,
