pub const DenseRegionKind = enum(u8) {
    numeric_dyad,
    compare_mask,
    reduce,
    scan,
    matmul,
    transpose,
    dense_autodiff,
};

pub const DenseExecBackend = enum(u8) {
    host,
    mlx,
};

fn rawPtr(raw: u64) usize {
    return @as(usize, @intCast(raw));
}

fn stringPerfNow() i128 {
    if (comptime enable_string_instrumentation) {
        return std.time.nanoTimestamp();
    }
    return 0;
}

pub const DensePlanReason = enum(u8) {
    no_mlx_support,
    already_mlx_resident,
    unmaterialized_range_host,
    packed_mask_host,
    host_fast_kernel,
    small_problem,
    large_problem,
    compare_host_default,
    matmul_requires_mlx,
};

const dense_region_kind_count = std.meta.fields(DenseRegionKind).len;
const dense_exec_backend_count = std.meta.fields(DenseExecBackend).len;

const DenseBackendOverride = enum(u8) {
    auto,
    host,
    mlx,
};

const prng_seed_lcg_mul: u64 = 6364136223846793005;
const prng_seed_lcg_inc: u64 = 1442695040888963407;
const prng_jump: [4]u64 = .{
    0x180ec6d33cfd0aba,
    0xd5a61266f0c9392c,
    0xa9582618e03fc9aa,
    0x39abdc4529b1661c,
};

const Prng = struct {
    const lane_count = 4;
    const Vec = @Vector(lane_count, u64);
    const Shift = @Vector(lane_count, u6);
    const use_vec4_kernel = zig_builtin.cpu.arch == .aarch64;

    state: [4][lane_count]u64,
    buffer: [lane_count]u64 = [_]u64{0} ** lane_count,
    buffer_index: usize = 0,

    pub fn initEntropy() Prng {
        var public_state: [4]u64 = undefined;
        while (true) {
            if (comptime zig_builtin.target.cpu.arch == .wasm32) {
                for (&public_state, 0..) |*item, idx| item.* = 0x9e3779b97f4a7c15 *% @as(u64, idx + 1);
            } else {
                for (&public_state) |*item| item.* = std.crypto.random.int(u64);
            }
            if (!allZero(public_state)) break;
        }
        var prng: Prng = undefined;
        prng.setPublicStateUnchecked(public_state);
        return prng;
    }

    fn allZero(words: [4]u64) bool {
        return words[0] == 0 and words[1] == 0 and words[2] == 0 and words[3] == 0;
    }

    fn publicState(self: *const Prng) [4]u64 {
        return .{
            self.state[0][0],
            self.state[1][0],
            self.state[2][0],
            self.state[3][0],
        };
    }

    fn seedFromInt(self: *Prng, seed: i64) void {
        var value: u64 = if (seed == 0)
            if (comptime zig_builtin.target.cpu.arch == .wasm32)
                0x6a09e667f3bcc909
            else
                @bitCast(std.time.microTimestamp())
        else
            @bitCast(seed);
        var public_state: [4]u64 = undefined;
        for (&public_state) |*item| {
            value = value *% prng_seed_lcg_mul +% prng_seed_lcg_inc;
            item.* = value;
        }
        self.setPublicStateUnchecked(public_state);
    }

    fn setPublicState(self: *Prng, words: [4]u64) KError!void {
        if (allZero(words)) return error.Type;
        self.setPublicStateUnchecked(words);
    }

    fn setPublicStateUnchecked(self: *Prng, words: [4]u64) void {
        self.state = undefined;
        inline for (0..4) |word_idx| self.state[word_idx][0] = words[word_idx];
        var jumped = words;
        var lane: usize = 1;
        while (lane < lane_count) : (lane += 1) {
            jumpState(&jumped);
            inline for (0..4) |word_idx| self.state[word_idx][lane] = jumped[word_idx];
        }
        self.buffer_index = 0;
    }

    fn random(self: *Prng) std.Random {
        return std.Random.init(self, fill);
    }

    fn nextWord(self: *Prng) u64 {
        if (self.buffer_index < lane_count) self.refill();
        self.buffer_index -= 1;
        return self.buffer[self.buffer_index];
    }

    fn nextFloat01(self: *Prng) f64 {
        const bits = (@as(u64, 1023) << 52) | (self.nextWord() & ((@as(u64, 1) << 52) - 1));
        const value: f64 = @bitCast(bits);
        return value - 1.0;
    }

    fn fill(self: *Prng, buf: []u8) void {
        var i: usize = 0;
        while (i + 8 <= buf.len) : (i += 8) {
            var chunk: [8]u8 = undefined;
            std.mem.writeInt(u64, &chunk, self.nextWord(), .little);
            @memcpy(buf[i .. i + 8], &chunk);
        }
        if (i != buf.len) {
            var word = self.nextWord();
            while (i < buf.len) : (i += 1) {
                buf[i] = @truncate(word);
                word >>= 8;
            }
        }
    }

    fn refill(self: *Prng) void {
        if (comptime use_vec4_kernel) {
            self.refillVec4();
        } else {
            self.refillScalar();
        }
        self.buffer_index = lane_count;
    }

    fn copyFreshWords(self: *Prng, out: []u64) void {
        var written: usize = 0;
        while (written < out.len) {
            self.refill();
            const chunk = @min(out.len - written, lane_count);
            @memcpy(out[written .. written + chunk], self.buffer[0..chunk]);
            written += chunk;
        }
    }

    fn refillScalar(self: *Prng) void {
        var out: [lane_count]u64 = undefined;
        var lane: usize = 0;
        while (lane < lane_count) : (lane += 1) {
            const result = nextStateWord(.{
                self.state[0][lane],
                self.state[1][lane],
                self.state[2][lane],
                self.state[3][lane],
            });
            self.state[0][lane] = result.state[0];
            self.state[1][lane] = result.state[1];
            self.state[2][lane] = result.state[2];
            self.state[3][lane] = result.state[3];
            out[lane] = result.word;
        }
        self.buffer = out;
    }

    fn refillVec4(self: *Prng) void {
        var s0: Vec = @bitCast(self.state[0]);
        var s1: Vec = @bitCast(self.state[1]);
        var s2: Vec = @bitCast(self.state[2]);
        var s3: Vec = @bitCast(self.state[3]);

        const out = rotlLeft(s0 +% s3, 23, 41) +% s0;
        const t = s1 << @as(Shift, @splat(17));

        s2 ^= s0;
        s3 ^= s1;
        s1 ^= s2;
        s0 ^= s3;
        s2 ^= t;
        s3 = rotlLeft(s3, 45, 19);

        self.state[0] = @bitCast(s0);
        self.state[1] = @bitCast(s1);
        self.state[2] = @bitCast(s2);
        self.state[3] = @bitCast(s3);
        self.buffer = @bitCast(out);
    }

    fn rotlLeft(values: Vec, comptime left_bits: u6, comptime right_bits: u6) Vec {
        const left: Shift = @splat(left_bits);
        const right: Shift = @splat(right_bits);
        return (values << left) | (values >> right);
    }

    fn nextStateWord(state: [4]u64) struct { word: u64, state: [4]u64 } {
        var next = state;
        const word = std.math.rotl(u64, next[0] +% next[3], 23) +% next[0];
        const t = next[1] << 17;
        next[2] ^= next[0];
        next[3] ^= next[1];
        next[1] ^= next[2];
        next[0] ^= next[3];
        next[2] ^= t;
        next[3] = std.math.rotl(u64, next[3], 45);
        return .{ .word = word, .state = next };
    }

    fn jumpState(state: *[4]u64) void {
        var acc = [_]u64{0} ** 4;
        for (prng_jump) |jump_word| {
            var bitset = jump_word;
            var bit: usize = 0;
            while (bit < 64) : (bit += 1) {
                if ((bitset & 1) != 0) {
                    inline for (0..4) |idx| acc[idx] ^= state[idx];
                }
                const result = nextStateWord(state.*);
                state.* = result.state;
                bitset >>= 1;
            }
        }
        state.* = acc;
    }
};

fn denseRegionKindLabel(kind: DenseRegionKind) []const u8 {
    return switch (kind) {
        .numeric_dyad => "numeric_dyad",
        .compare_mask => "compare_mask",
        .reduce => "reduce",
        .scan => "scan",
        .matmul => "matmul",
        .transpose => "transpose",
        .dense_autodiff => "dense_autodiff",
    };
}

fn denseExecBackendLabel(backend: DenseExecBackend) []const u8 {
    return switch (backend) {
        .host => "host",
        .mlx => "mlx",
    };
}

fn densePlanReasonLabel(reason: DensePlanReason) []const u8 {
    return switch (reason) {
        .no_mlx_support => "no_mlx_support",
        .already_mlx_resident => "already_mlx_resident",
        .unmaterialized_range_host => "unmaterialized_range_host",
        .packed_mask_host => "packed_mask_host",
        .host_fast_kernel => "host_fast_kernel",
        .small_problem => "small_problem",
        .large_problem => "large_problem",
        .compare_host_default => "compare_host_default",
        .matmul_requires_mlx => "matmul_requires_mlx",
    };
}

pub const ValueTag = enum(u8) {
    int,
    float,
    bool,
    builtin,
    closure,
    array,
};

pub const DebugArraySubkind = Value.ArraySubkind;

pub const Value = struct {
    raw: u64,

    const tag_bits = 3;
    const tag_mask: u64 = (1 << tag_bits) - 1;
    const array_kind_bits = 3;
    const array_kind_shift = tag_bits;
    const array_kind_mask: u64 = ((1 << array_kind_bits) - 1) << array_kind_shift;
    const array_payload_mask: u64 = tag_mask | array_kind_mask;
    const int_tag: u64 = 0b001;
    const bool_tag: u64 = 0b010;
    const builtin_tag: u64 = 0b011;
    const closure_tag: u64 = 0b100;
    const boxed_float_tag: u64 = 0b101;
    const boxed_int_tag: u64 = 0b110;
    const array_tag: u64 = 0b111;

    const ArraySubkind = enum(u3) {
        numeric_array,
        host_array,
        host_string,
        host_symbol,
        host_string_list,
        host_string_view,
        mlx_array,
    };

    pub fn int(value: i64) KError!Value {
        if (!fitsInlineInt(value)) return error.Unsupported;
        return .{
            .raw = (@as(u64, @bitCast(value)) << tag_bits) | int_tag,
        };
    }

    pub fn fromBool(value: bool) Value {
        return .{
            .raw = (@as(u64, @intFromBool(value)) << tag_bits) | bool_tag,
        };
    }

    pub fn builtin(id: BuiltinId) Value {
        return .{
            .raw = (@as(u64, @intFromEnum(id)) << tag_bits) | builtin_tag,
        };
    }

    pub fn closure(ptr: *const Closure) Value {
        const raw = @intFromPtr(ptr);
        std.debug.assert((raw & tag_mask) == 0);
        return .{ .raw = raw | closure_tag };
    }

    pub fn array(ptr: anytype) Value {
        const raw = @intFromPtr(ptr);
        std.debug.assert((raw & array_payload_mask) == 0);
        const subkind = arraySubkindFromPtr(ptr);
        return .{ .raw = raw | (@as(u64, @intFromEnum(subkind)) << array_kind_shift) | array_tag };
    }

    fn boxedFloat(ptr: *const BoxedFloat) Value {
        const raw = @intFromPtr(ptr);
        std.debug.assert((raw & tag_mask) == 0);
        return .{ .raw = raw | boxed_float_tag };
    }

    fn boxedInt(ptr: *const BoxedInt) Value {
        const raw = @intFromPtr(ptr);
        std.debug.assert((raw & tag_mask) == 0);
        return .{ .raw = raw | boxed_int_tag };
    }

    pub fn tag(self: Value) ValueTag {
        return switch (self.raw & tag_mask) {
            int_tag => .int,
            bool_tag => .bool,
            builtin_tag => .builtin,
            closure_tag => .closure,
            boxed_float_tag => .float,
            boxed_int_tag => .int,
            array_tag => .array,
            else => unreachable,
        };
    }

    pub fn asInt(self: Value) i64 {
        return switch (self.raw & tag_mask) {
            int_tag => @as(i64, @bitCast(self.raw)) >> tag_bits,
            boxed_int_tag => self.asBoxedInt().value,
            else => unreachable,
        };
    }

    pub fn asFloat(self: Value) f64 {
        std.debug.assert(self.tag() == .float);
        return self.asBoxedFloat().value;
    }

    pub fn asBool(self: Value) bool {
        std.debug.assert((self.raw & tag_mask) == bool_tag);
        return ((self.raw >> tag_bits) & 1) != 0;
    }

    pub fn asBuiltin(self: Value) BuiltinId {
        std.debug.assert((self.raw & tag_mask) == builtin_tag);
        return @enumFromInt(self.raw >> tag_bits);
    }

    pub fn asClosure(self: Value) *const Closure {
        std.debug.assert(self.tag() == .closure);
        const ptr: *const Closure = @ptrFromInt(rawPtr(self.raw & ~tag_mask));
        return ptr;
    }

    pub fn arrayKind(self: Value) HeapKind {
        std.debug.assert(self.tag() == .array);
        return switch (self.arraySubkind()) {
            .numeric_array => .numeric_array,
            .host_array => .host_array,
            .host_string => .host_string,
            .host_symbol => .host_symbol,
            .host_string_list => .host_string_list,
            .host_string_view => .host_string_view,
            .mlx_array => .mlx_array,
        };
    }

    pub fn activeArrayKind(self: Value) HeapKind {
        std.debug.assert(self.tag() == .array);
        return switch (self.arraySubkind()) {
            .numeric_array => self.asNumericArray().activeKind(),
            .host_array => .host_array,
            .host_string => .host_string,
            .host_symbol => .host_symbol,
            .host_string_list => .host_string_list,
            .host_string_view => .host_string_view,
            .mlx_array => .mlx_array,
        };
    }

    pub fn arrayOwner(self: Value) HeapOwner {
        std.debug.assert(self.tag() == .array);
        return switch (self.arraySubkind()) {
            .numeric_array => self.asNumericArray().header.owner,
            .host_array => self.asHostArray().header.owner,
            .host_string => self.asHostString().header.owner,
            .host_symbol => self.asHostSymbol().header.owner,
            .host_string_list => self.asHostStringList().header.owner,
            .host_string_view => self.asHostStringView().header.owner,
            .mlx_array => self.asMlxArray().header.owner,
        };
    }

    pub fn asNumericArray(self: Value) *const NumericArray {
        std.debug.assert(self.arraySubkind() == .numeric_array);
        const ptr: *const NumericArray = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostArray(self: Value) *const HostArray {
        return switch (self.arraySubkind()) {
            .numeric_array => self.asNumericArray().host orelse unreachable,
            .host_array => @ptrFromInt(rawPtr(self.arrayPtrRaw())),
            else => unreachable,
        };
    }

    pub fn asMlxArray(self: Value) *const MlxArray {
        return switch (self.arraySubkind()) {
            .numeric_array => self.asNumericArray().mlx orelse unreachable,
            .mlx_array => @ptrFromInt(rawPtr(self.arrayPtrRaw())),
            else => unreachable,
        };
    }

    pub fn asHostString(self: Value) *const HostText {
        std.debug.assert(self.arrayKind() == .host_string);
        const ptr: *const HostText = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostSymbol(self: Value) *const HostText {
        std.debug.assert(self.arrayKind() == .host_symbol);
        const ptr: *const HostText = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostStringList(self: Value) *const HostStringList {
        std.debug.assert(self.arrayKind() == .host_string_list);
        const ptr: *const HostStringList = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostStringView(self: Value) *const HostStringView {
        std.debug.assert(self.arrayKind() == .host_string_view);
        const ptr: *const HostStringView = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    fn asBoxedFloat(self: Value) *const BoxedFloat {
        std.debug.assert((self.raw & tag_mask) == boxed_float_tag);
        const ptr: *const BoxedFloat = @ptrFromInt(rawPtr(self.raw & ~tag_mask));
        return ptr;
    }

    fn asBoxedInt(self: Value) *const BoxedInt {
        std.debug.assert((self.raw & tag_mask) == boxed_int_tag);
        const ptr: *const BoxedInt = @ptrFromInt(rawPtr(self.raw & ~tag_mask));
        return ptr;
    }

    fn arraySubkind(self: Value) ArraySubkind {
        std.debug.assert(self.tag() == .array);
        return @enumFromInt((self.raw & array_kind_mask) >> array_kind_shift);
    }

    fn arrayPtrRaw(self: Value) u64 {
        std.debug.assert(self.tag() == .array);
        return self.raw & ~array_payload_mask;
    }

    fn fitsInlineInt(value: i64) bool {
        const min_inline = -(@as(i64, 1) << 60);
        const max_inline = (@as(i64, 1) << 60) - 1;
        return value >= min_inline and value <= max_inline;
    }
};

fn arraySubkindFromPtr(ptr: anytype) Value.ArraySubkind {
    const Child = std.meta.Child(@TypeOf(ptr));
    if (Child == NumericArray) return .numeric_array;
    if (Child == HostArray) return .host_array;
    if (Child == MlxArray) return .mlx_array;
    if (Child == HostText) {
        return switch (ptr.header.kind) {
            .host_string => .host_string,
            .host_symbol => .host_symbol,
            else => unreachable,
        };
    }
    if (Child == HostStringList) return .host_string_list;
    if (Child == HostStringView) return .host_string_view;
    @compileError("unsupported array pointer type");
}

pub const Closure = struct {
    header: HeapHeader align(8),
    code: *const Code,
    captures: []const Value,
};

const HeapOwner = enum(u8) {
    managed,
    frozen,
    scratch,
};

const HeapKind = enum(u8) {
    boxed_float,
    boxed_int,
    closure,
    numeric_array,
    host_array,
    host_string,
    host_symbol,
    host_string_list,
    host_string_view,
    mlx_array,
};

const HeapHeader = struct {
    kind: HeapKind,
    owner: HeapOwner,
    ref_count: u32 = 0,

    fn init(kind: HeapKind, owner: HeapOwner) HeapHeader {
        return .{
            .kind = kind,
            .owner = owner,
            .ref_count = if (owner == .managed) 1 else 0,
        };
    }
};

const BoxedFloat = struct {
    header: HeapHeader align(8),
    value: f64,
};

const BoxedInt = struct {
    header: HeapHeader align(8),
    value: i64,
};

comptime {
    if (@alignOf(Closure) < 8) @compileError("Closure must remain at least 8-byte aligned for tagged Value pointers.");
    if (@alignOf(BoxedFloat) < 8) @compileError("BoxedFloat must remain at least 8-byte aligned for tagged Value pointers.");
    if (@alignOf(BoxedInt) < 8) @compileError("BoxedInt must remain at least 8-byte aligned for tagged Value pointers.");
}

const HostText = struct {
    header: HeapHeader align(64),
    len: usize,

    pub fn slice(self: *const HostText) []const u8 {
        return hostTextBytes(self);
    }
};

const HostTextSpan = struct {
    start: usize,
    len: usize,
};

const HostStringPiece = union(enum) {
    owned: *HostText,
    view: HostTextSpan,
};

const HostStringListStorage = union(enum) {
    eager: []const HostStringPiece,
    split_scalar: struct {
        sep: u8,
    },
};

const HostStringList = struct {
    header: HeapHeader align(64),
    len: usize,
    bytes_len: usize,
    base: ?*HostText,
    storage: HostStringListStorage,
};

const HostStringView = struct {
    header: HeapHeader align(64),
    base: *HostText,
    span: HostTextSpan,
};

const managed_host_text_intern_limit = 32;

fn hostTextAllocLen(byte_len: usize) usize {
    return @sizeOf(HostText) + byte_len;
}

fn hostTextAllocSlice(allocator: std.mem.Allocator, byte_len: usize) ![]align(@alignOf(HostText)) u8 {
    return try allocator.alignedAlloc(u8, .of(HostText), hostTextAllocLen(byte_len));
}

fn hostTextFromAlloc(buf: []align(@alignOf(HostText)) u8) *HostText {
    std.debug.assert(buf.len >= @sizeOf(HostText));
    return @ptrCast(buf.ptr);
}

fn hostTextBytesFromAlloc(buf: []align(@alignOf(HostText)) u8, byte_len: usize) []u8 {
    return buf[@sizeOf(HostText) .. @sizeOf(HostText) + byte_len];
}

fn hostTextBytes(text: *const HostText) []const u8 {
    const raw: [*]align(@alignOf(HostText)) const u8 = @ptrCast(text);
    return raw[@sizeOf(HostText) .. @sizeOf(HostText) + text.len];
}

fn freeHostTextAlloc(allocator: std.mem.Allocator, text: *HostText) void {
    const raw: [*]align(@alignOf(HostText)) u8 = @ptrCast(text);
    allocator.free(raw[0..hostTextAllocLen(text.len)]);
}

fn hostTextSpanBytes(base: *const HostText, span: HostTextSpan) []const u8 {
    return hostTextBytes(base)[span.start .. span.start + span.len];
}

fn hostStringListItemsOffset() usize {
    return std.mem.alignForward(usize, @sizeOf(HostStringList), @alignOf(HostStringPiece));
}

fn hostStringListAllocLen(item_len: usize) usize {
    return hostStringListItemsOffset() + item_len * @sizeOf(HostStringPiece);
}

fn hostStringListAllocSlice(allocator: std.mem.Allocator, item_len: usize) ![]align(@alignOf(HostStringList)) u8 {
    return try allocator.alignedAlloc(u8, .of(HostStringList), hostStringListAllocLen(item_len));
}

fn hostStringListFromAlloc(buf: []align(@alignOf(HostStringList)) u8) *HostStringList {
    std.debug.assert(buf.len >= @sizeOf(HostStringList));
    return @ptrCast(buf.ptr);
}

fn hostStringListItemsFromAlloc(buf: []align(@alignOf(HostStringList)) u8, item_len: usize) []HostStringPiece {
    const start = hostStringListItemsOffset();
    const bytes = buf[start .. start + item_len * @sizeOf(HostStringPiece)];
    const ptr: [*]HostStringPiece = @ptrCast(@alignCast(bytes.ptr));
    return ptr[0..item_len];
}

fn freeHostStringListAlloc(allocator: std.mem.Allocator, list: *HostStringList) void {
    const raw: [*]align(@alignOf(HostStringList)) u8 = @ptrCast(list);
    allocator.free(raw[0..hostStringListAllocLen(list.len)]);
}

fn hostStringPieceBytes(base: ?*const HostText, piece: HostStringPiece) []const u8 {
    return switch (piece) {
        .owned => |text| hostTextBytes(text),
        .view => |view| hostTextSpanBytes(base orelse unreachable, view),
    };
}

fn hostStringViewBytes(view: *const HostStringView) []const u8 {
    return hostTextSpanBytes(view.base, view.span);
}

const HostStringSource = struct {
    base: *HostText,
    span: HostTextSpan,

    fn bytes(self: HostStringSource) []const u8 {
        return hostTextSpanBytes(self.base, self.span);
    }
};

fn stringSourceInfo(value: Value) ?HostStringSource {
    if (value.tag() != .array) return null;
    return switch (value.arrayKind()) {
        .host_string => {
            const text = value.asHostString();
            return .{
                .base = @constCast(text),
                .span = .{ .start = 0, .len = text.len },
            };
        },
        .host_string_view => {
            const view = value.asHostStringView();
            return .{
                .base = view.base,
                .span = view.span,
            };
        },
        else => null,
    };
}

fn hostStringListIsContiguousBaseViews(list: *const HostStringList) bool {
    const base = list.base orelse return false;
    return switch (list.storage) {
        .eager => |items| blk: {
            var offset: usize = 0;
            for (items) |item| switch (item) {
                .view => |view| {
                    if (view.start != offset) break :blk false;
                    offset += view.len;
                },
                .owned => break :blk false,
            };
            break :blk offset == list.bytes_len and offset == base.len;
        },
        .split_scalar => false,
    };
}

fn countScalarSplits(src: []const u8, sep: u8) usize {
    var parts: usize = 1;
    var start: usize = 0;
    while (std.mem.indexOfScalarPos(u8, src, start, sep)) |idx| {
        parts += 1;
        start = idx + 1;
    }
    return parts;
}

comptime {
    if (@alignOf(HostText) < 8) @compileError("HostText must remain at least 8-byte aligned for tagged Value pointers.");
}

const HostArrayElem = enum(u8) {
    int,
    float,
};

const HostIntStorageKind = enum(u8) {
    bit,
    int8,
    int16,
    int32,
    int64,
};

const HostArrayStorageKind = enum(u8) {
    bit,
    int8,
    int16,
    int32,
    int64,
    float64,
    boxed,
};

const HostArrayStorage = union(HostArrayStorageKind) {
    bit: []u64,
    int8: []i8,
    int16: []i16,
    int32: []i32,
    int64: []i64,
    float64: []f64,
    boxed: []Value,
};

const host_array_flag_normalized: u8 = 1 << 0;
const host_array_flag_asc: u8 = 1 << 1;
const host_array_flag_dsc: u8 = 1 << 2;

const HostArray = struct {
    header: HeapHeader align(64),
    logical_handle: ?*NumericArray = null,
    logical_len: usize,
    flags: u8 = 0,
    int_range_known: bool = false,
    int_range_min: i64 = 0,
    int_range_max: i64 = 0,
    storage: HostArrayStorage,

    fn len(self: *const HostArray) usize {
        return self.logical_len;
    }
};

const host_bit_word_bits = @bitSizeOf(u64);

fn hostArrayNumericMode(array: *const HostArray) ?HostArrayElem {
    return switch (array.storage) {
        .bit, .int8, .int16, .int32, .int64 => .int,
        .float64 => .float,
        .boxed => null,
    };
}

pub fn debugHostArrayFlags(value: Value) u8 {
    std.debug.assert(value.tag() == .array and value.activeArrayKind() == .host_array);
    return value.asHostArray().flags;
}

pub fn debugHostArrayAddress(value: Value) usize {
    std.debug.assert(value.tag() == .array and value.activeArrayKind() == .host_array);
    return @intFromPtr(value.asHostArray());
}

pub fn debugArraySubkind(value: Value) ?DebugArraySubkind {
    if (value.tag() != .array) return null;
    return value.arraySubkind();
}

pub const DebugHostArrayFlagNormalized = host_array_flag_normalized;
pub const DebugHostArrayFlagAsc = host_array_flag_asc;
pub const DebugHostArrayFlagDsc = host_array_flag_dsc;

fn hostIntStorageRank(kind: HostIntStorageKind) u8 {
    return switch (kind) {
        .bit => 0,
        .int8 => 1,
        .int16 => 2,
        .int32 => 3,
        .int64 => 4,
    };
}

fn maxHostIntStorageKind(left: HostIntStorageKind, right: HostIntStorageKind) HostIntStorageKind {
    return if (hostIntStorageRank(left) >= hostIntStorageRank(right)) left else right;
}

fn widenHostIntStorageKind(kind: HostIntStorageKind) HostIntStorageKind {
    return switch (kind) {
        .bit => .int8,
        .int8 => .int16,
        .int16 => .int32,
        .int32 => .int64,
        .int64 => .int64,
    };
}

fn hostIntStorageKindForValue(value: i64) HostIntStorageKind {
    if (std.math.cast(i8, value) != null) return .int8;
    if (std.math.cast(i16, value) != null) return .int16;
    if (std.math.cast(i32, value) != null) return .int32;
    return .int64;
}

fn hostIntStorageKindForRange(min_value: i64, max_value: i64) HostIntStorageKind {
    if (std.math.cast(i8, min_value) != null and std.math.cast(i8, max_value) != null) return .int8;
    if (std.math.cast(i16, min_value) != null and std.math.cast(i16, max_value) != null) return .int16;
    if (std.math.cast(i32, min_value) != null and std.math.cast(i32, max_value) != null) return .int32;
    return .int64;
}

fn hostIntStorageKindForSlice(items: []const i64) HostIntStorageKind {
    if (items.len == 0) return .bit;
    var min_value = items[0];
    var max_value = items[0];
    for (items[1..]) |item| {
        min_value = @min(min_value, item);
        max_value = @max(max_value, item);
    }
    return hostIntStorageKindForRange(min_value, max_value);
}

const HostIntRange = struct {
    min: i64,
    max: i64,
};

const HostIntAnalysis = struct {
    range: HostIntRange,
    kind: HostIntStorageKind,
    flags: u8,
};

const HostAddScanIntAnalysis = struct {
    range: HostIntRange,
    kind: HostIntStorageKind,
    flags: u8,
};

fn hostArraySetFlags(array: *HostArray, flags: u8) void {
    array.flags = flags;
}

fn hostArraySetCachedIntRange(array: *HostArray, range: HostIntRange) void {
    array.int_range_known = true;
    array.int_range_min = range.min;
    array.int_range_max = range.max;
}

fn hostArrayClearCachedIntRange(array: *HostArray) void {
    array.int_range_known = false;
    array.int_range_min = 0;
    array.int_range_max = 0;
}

fn hostArrayCachedIntRange(array: *const HostArray) ?HostIntRange {
    if (!array.int_range_known) return null;
    return .{
        .min = array.int_range_min,
        .max = array.int_range_max,
    };
}

fn hostArrayHasFlag(array: *const HostArray, flag: u8) bool {
    return (array.flags & flag) != 0;
}

fn hostArrayReusePriority(array: *const HostArray) u8 {
    return switch (array.header.owner) {
        .scratch => 2,
        .managed => 1,
        .frozen => 0,
    };
}

fn orderFlagsFromMonotonic(asc: bool, dsc: bool) u8 {
    return (if (asc) host_array_flag_asc else 0) | (if (dsc) host_array_flag_dsc else 0);
}

fn monotonicFlags(flags: u8) u8 {
    return flags & (host_array_flag_asc | host_array_flag_dsc);
}

fn invertMonotonicFlags(flags: u8) u8 {
    const mono = monotonicFlags(flags);
    return (if ((mono & host_array_flag_asc) != 0) host_array_flag_dsc else 0) |
        (if ((mono & host_array_flag_dsc) != 0) host_array_flag_asc else 0);
}

fn isRenderableMatrix(items: []const Value) bool {
    if (items.len == 0) return false;
    var row_len: ?usize = null;
    for (items) |item| {
        if (item.tag() != .array) return false;
        if (valueNumericMode(item) == null) return false;
        if (valueNonVectorNumericShape(item) != null) return false;
        const len = numericVectorLen(item) orelse return false;
        if (row_len) |expected| {
            if (len != expected) return false;
        } else {
            row_len = len;
        }
    }
    return true;
}

fn numericArraySetVectorShape(handle: *NumericArray, len: usize) void {
    handle.rank = 1;
    handle.shape[0] = @intCast(len);
    for (1..numeric_array_max_rank) |idx| handle.shape[idx] = 0;
}

fn numericArraySetRangeIota(handle: *NumericArray, len: usize) void {
    handle.structural = .range_iota;
    handle.range_iota = .{ .start = 0, .step = 1 };
    numericArraySetVectorShape(handle, len);
}

fn numericArraySetMatrixShape(handle: *NumericArray, rows: usize, cols: usize) void {
    handle.rank = 2;
    handle.shape[0] = @intCast(rows);
    handle.shape[1] = @intCast(cols);
    for (2..numeric_array_max_rank) |idx| handle.shape[idx] = 0;
}

fn numericArraySetShapeFromMlx(handle: *NumericArray, array: mlx.Array) void {
    const rank = @min(array.ndim(), numeric_array_max_rank);
    handle.rank = @intCast(rank);
    for (0..rank) |idx| handle.shape[idx] = @intCast(array.shape()[idx]);
    for (rank..numeric_array_max_rank) |idx| handle.shape[idx] = 0;
}

const NumericShapeSnapshot = struct {
    rank: u8 = 0,
    shape: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank,

    fn shapeSlice(self: *const NumericShapeSnapshot) []const i32 {
        return self.shape[0..self.rank];
    }
};

const NumericMatrixShape = struct {
    rows: usize,
    cols: usize,
};

const NumericMatrixView = struct {
    value: Value,
    handle: *const NumericArray,
    shape: NumericMatrixShape,
    mode: HostArrayElem,
};

fn numericShapeSnapshotFromHandle(handle: *const NumericArray) NumericShapeSnapshot {
    return .{
        .rank = handle.rank,
        .shape = handle.shape,
    };
}

fn numericArrayIsRangeIota(handle: *const NumericArray) bool {
    return handle.structural == .range_iota;
}

fn numericArrayIsFlatSlice(handle: *const NumericArray) bool {
    return handle.structural == .flat_slice and handle.flat_slice != null;
}

fn numericArrayIsFlatConcat(handle: *const NumericArray) bool {
    return handle.structural == .flat_concat and handle.flat_concat != null;
}

fn numericArrayIsFlatSegments(handle: *const NumericArray) bool {
    return handle.structural == .flat_segments and handle.flat_segments != null;
}

fn numericArrayIsFirstAxisSlice(handle: *const NumericArray) bool {
    return handle.structural == .first_axis_slice and handle.first_axis_slice != null;
}

fn numericArrayIsFirstAxisIndex(handle: *const NumericArray) bool {
    return handle.structural == .first_axis_index and handle.first_axis_index != null;
}

fn numericArrayIsFirstAxisConcat(handle: *const NumericArray) bool {
    return handle.structural == .first_axis_concat and handle.first_axis_concat != null;
}

fn numericArrayIsReshapeView(handle: *const NumericArray) bool {
    return handle.structural == .reshape_view and handle.reshape_view != null;
}

fn numericArrayIsTransposeView(handle: *const NumericArray) bool {
    return handle.structural == .transpose_view and handle.transpose_view != null;
}

fn numericArrayIsVectorRangeIota(handle: *const NumericArray) bool {
    return numericArrayIsRangeIota(handle) and handle.rank == 1;
}

fn numericArrayFlatSliceSource(handle: *const NumericArray) ?Value {
    const slice = handle.flat_slice orelse return null;
    return if (numericArrayIsFlatSlice(handle)) slice.source else null;
}

fn numericArrayFlatSliceStart(handle: *const NumericArray) ?usize {
    const slice = handle.flat_slice orelse return null;
    return if (numericArrayIsFlatSlice(handle)) slice.start else null;
}

fn numericArrayFlatConcatLeft(handle: *const NumericArray) ?Value {
    const concat = handle.flat_concat orelse return null;
    return if (numericArrayIsFlatConcat(handle)) concat.left else null;
}

fn numericArrayFlatConcatRight(handle: *const NumericArray) ?Value {
    const concat = handle.flat_concat orelse return null;
    return if (numericArrayIsFlatConcat(handle)) concat.right else null;
}

fn numericArrayFlatSegmentsValues(handle: *const NumericArray) ?[]const Value {
    const segments = handle.flat_segments orelse return null;
    return if (numericArrayIsFlatSegments(handle)) segments.values else null;
}

fn numericArrayFirstAxisSliceSource(handle: *const NumericArray) ?Value {
    const slice = handle.first_axis_slice orelse return null;
    return if (numericArrayIsFirstAxisSlice(handle)) slice.source else null;
}

fn numericArrayFirstAxisSliceRowStart(handle: *const NumericArray) ?usize {
    const slice = handle.first_axis_slice orelse return null;
    return if (numericArrayIsFirstAxisSlice(handle)) slice.start else null;
}

fn numericArrayFirstAxisSliceRowStep(handle: *const NumericArray) ?i32 {
    const slice = handle.first_axis_slice orelse return null;
    return if (numericArrayIsFirstAxisSlice(handle)) slice.step else null;
}

fn numericArrayFirstAxisIndexSource(handle: *const NumericArray) ?Value {
    const index = handle.first_axis_index orelse return null;
    return if (numericArrayIsFirstAxisIndex(handle)) index.source else null;
}

fn numericArrayFirstAxisIndexRows(handle: *const NumericArray) ?Value {
    const index = handle.first_axis_index orelse return null;
    return if (numericArrayIsFirstAxisIndex(handle)) index.row_indices else null;
}

fn numericArrayFirstAxisConcatLeft(handle: *const NumericArray) ?Value {
    const concat = handle.first_axis_concat orelse return null;
    return if (numericArrayIsFirstAxisConcat(handle)) concat.left else null;
}

fn numericArrayFirstAxisConcatRight(handle: *const NumericArray) ?Value {
    const concat = handle.first_axis_concat orelse return null;
    return if (numericArrayIsFirstAxisConcat(handle)) concat.right else null;
}

fn numericArrayReshapeSource(handle: *const NumericArray) ?Value {
    const reshape = handle.reshape_view orelse return null;
    return if (numericArrayIsReshapeView(handle)) reshape.source else null;
}

fn numericArrayTransposeSource(handle: *const NumericArray) ?Value {
    const transpose = handle.transpose_view orelse return null;
    return if (numericArrayIsTransposeView(handle)) transpose.source else null;
}

fn numericArrayElementCount(handle: *const NumericArray) usize {
    if (handle.rank == 0) return 0;
    var total: usize = 1;
    for (handle.shapeSlice()) |dim| total *= @as(usize, @intCast(dim));
    return total;
}

fn numericArrayRangeLen(handle: *const NumericArray) usize {
    std.debug.assert(numericArrayIsRangeIota(handle));
    return numericArrayElementCount(handle);
}

fn numericArrayRangeIotaValueAt(handle: *const NumericArray, idx: usize) KError!i64 {
    std.debug.assert(numericArrayIsRangeIota(handle));
    if (idx >= numericArrayRangeLen(handle)) return error.Type;
    const idx_i64 = std.math.cast(i64, idx) orelse return error.Unsupported;
    const scaled = std.math.mul(i64, handle.range_iota.step, idx_i64) catch return error.Unsupported;
    return std.math.add(i64, handle.range_iota.start, scaled) catch return error.Unsupported;
}

fn numericArrayRangeIotaBounds(handle: *const NumericArray) HostIntRange {
    std.debug.assert(numericArrayIsRangeIota(handle));
    const len = numericArrayRangeLen(handle);
    if (len == 0) return .{ .min = handle.range_iota.start, .max = handle.range_iota.start };
    const first = handle.range_iota.start;
    const last = numericArrayRangeIotaValueAt(handle, len - 1) catch unreachable;
    return .{
        .min = @min(first, last),
        .max = @max(first, last),
    };
}

fn numericShapeSnapshotMatrix(rows: usize, cols: usize) NumericShapeSnapshot {
    var snapshot = NumericShapeSnapshot{};
    snapshot.rank = 2;
    snapshot.shape[0] = @intCast(rows);
    snapshot.shape[1] = @intCast(cols);
    return snapshot;
}

fn numericShapeTailSnapshot(handle: *const NumericArray) ?NumericShapeSnapshot {
    if (handle.rank <= 1) return null;
    var snapshot = NumericShapeSnapshot{};
    snapshot.rank = handle.rank - 1;
    for (0..snapshot.rank) |idx| snapshot.shape[idx] = handle.shape[idx + 1];
    for (snapshot.rank..numeric_array_max_rank) |idx| snapshot.shape[idx] = 0;
    return snapshot;
}

fn numericShapeFirstAxisSliceSnapshot(handle: *const NumericArray, first_axis_len: usize) ?NumericShapeSnapshot {
    if (handle.rank <= 1) return null;
    var snapshot = numericShapeSnapshotFromHandle(handle);
    snapshot.shape[0] = @intCast(first_axis_len);
    return snapshot;
}

fn numericShapeInnerBlockLen(handle: *const NumericArray) usize {
    if (handle.rank <= 1) return 1;
    var total: usize = 1;
    for (handle.shape[1..handle.rank]) |dim| total *= @as(usize, @intCast(dim));
    return total;
}

const ContiguousIndexSlice = struct {
    start: usize,
    len: usize,
};

const ArithmeticIndexSlice = struct {
    start: usize,
    len: usize,
    step: i32 = 1,
};

const NumericStructuralView = struct {
    handle: *const NumericArray,

    fn init(value: Value) ?NumericStructuralView {
        const handle = valueNumericHandle(value) orelse return null;
        return .{ .handle = handle };
    }
};

fn numericArrayCopyShape(dst: *NumericArray, src: *const NumericArray) void {
    dst.rank = src.rank;
    dst.shape = src.shape;
}

fn numericArrayShapeEqual(left: *const NumericArray, right: *const NumericArray) bool {
    if (left.rank != right.rank) return false;
    return std.mem.eql(i32, left.shapeSlice(), right.shapeSlice());
}

fn valueNumericHandle(value: Value) ?*const NumericArray {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .numeric_array => value.asNumericArray(),
        .host_array => if (value.asHostArray().logical_handle) |handle| handle else null,
        .mlx_array => if (value.asMlxArray().logical_handle) |handle| handle else null,
        else => null,
    };
}

fn logicalHandleForNumericPayloadValue(value: Value) ?*NumericArray {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .host_array => blk: {
            const array = @constCast(value.asHostArray());
            if (hostArrayNumericMode(array) == null) break :blk null;
            break :blk array.logical_handle;
        },
        .mlx_array => @constCast(value.asMlxArray()).logical_handle,
        else => null,
    };
}

fn mutableNumericHandle(value: Value) ?*NumericArray {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .numeric_array => @constCast(value.asNumericArray()),
        .host_array, .mlx_array => logicalHandleForNumericPayloadValue(value),
        else => null,
    };
}

fn numericHandleRequired(value: Value) KError!*NumericArray {
    return mutableNumericHandle(value) orelse error.Type;
}

fn hostArrayIfPresent(value: Value) ?*const HostArray {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .host_array => value.asHostArray(),
        .numeric_array => value.asNumericArray().host,
        .mlx_array => if (valueNumericHandle(value)) |handle| handle.host else null,
        else => null,
    };
}

fn mlxArrayIfPresent(value: Value) ?*const MlxArray {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .mlx_array => value.asMlxArray(),
        .numeric_array => value.asNumericArray().mlx,
        .host_array => if (value.asHostArray().logical_handle) |handle| handle.mlx else null,
        else => null,
    };
}

fn ensureNumericHostAttachmentForDenseView(self: *Session, value: Value) KError!?*const HostArray {
    const handle = valueNumericHandle(value) orelse return null;
    if (handle.host) |array| return array;
    if (numericValueSupportsStructuralFlatItemsWithoutHost(value)) return null;
    return try tryEnsureHostRealizationForHandle(self, @constCast(handle));
}

fn tryCollapseHostFlatSlice(self: *Session, source: Value, start: usize, len: usize) KError!?HostCollapsedFlatSlice {
    const handle = valueNumericHandle(source) orelse return null;

    if (numericArrayIsFlatSlice(handle)) {
        const base_source = numericArrayFlatSliceSource(handle) orelse return error.Type;
        const base_start = numericArrayFlatSliceStart(handle) orelse return error.Type;
        if (try tryCollapseHostFlatSlice(self, base_source, base_start + start, len)) |collapsed| return collapsed;
        return .{ .flat_slice = .{
            .source_value = base_source,
            .source_host = try ensureNumericHostAttachmentForDenseView(self, base_source),
            .start = base_start + start,
            .len = len,
        } };
    }

    if (numericArrayIsReshapeView(handle)) {
        const base_source = numericArrayReshapeSource(handle) orelse return error.Type;
        if (try tryCollapseHostFlatSlice(self, base_source, start, len)) |collapsed| return collapsed;
        return .{ .flat_slice = .{
            .source_value = base_source,
            .source_host = try ensureNumericHostAttachmentForDenseView(self, base_source),
            .start = start,
            .len = len,
        } };
    }

    if (handle.rank != 2) return null;
    const row_width = numericShapeInnerBlockLen(handle);
    if (row_width == 0 or len != row_width or start % row_width != 0) return null;
    const row_pos = start / row_width;

    if (numericArrayIsFirstAxisSlice(handle)) {
        const slice = handle.first_axis_slice orelse return error.Type;
        const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row_pos)) * @as(i64, slice.step);
        if (source_row_i64 < 0) return error.Type;
        const base_source = slice.source;
        if (try tryCollapseHostFlatSlice(self, base_source, @as(usize, @intCast(source_row_i64)) * row_width, len)) |collapsed| return collapsed;
        return .{ .flat_slice = .{
            .source_value = base_source,
            .source_host = try ensureNumericHostAttachmentForDenseView(self, base_source),
            .start = @as(usize, @intCast(source_row_i64)) * row_width,
            .len = len,
        } };
    }

    if (numericArrayIsFirstAxisIndex(handle)) {
        const index = handle.first_axis_index orelse return error.Type;
        const source_row_i64 = try numericIntAt(index.row_indices, row_pos);
        if (source_row_i64 < 0) return error.Type;
        const base_source = index.source;
        if (try tryCollapseHostFlatSlice(self, base_source, @as(usize, @intCast(source_row_i64)) * row_width, len)) |collapsed| return collapsed;
        return .{ .flat_slice = .{
            .source_value = base_source,
            .source_host = try ensureNumericHostAttachmentForDenseView(self, base_source),
            .start = @as(usize, @intCast(source_row_i64)) * row_width,
            .len = len,
        } };
    }

    if (numericArrayIsTransposeView(handle)) {
        const transpose = handle.transpose_view orelse return error.Type;
        const base_source = transpose.source;
        const base_shape = valueNumericMatrixShape(base_source) orelse return error.Type;
        return .{ .flat_stride = .{
            .source_value = base_source,
            .source_host = try ensureNumericHostAttachmentForDenseView(self, base_source),
            .start = row_pos,
            .len = base_shape.rows,
            .step = base_shape.cols,
        } };
    }

    return null;
}

pub fn debugNumericStructuralTag(value: Value) ?DebugNumericStructuralTag {
    const handle = valueNumericHandle(value) orelse return null;
    return handle.structural;
}

fn debugMlxArrayForValue(value: Value) ?mlx.Array {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .mlx_array => value.asMlxArray().array,
        .host_array => if (value.asHostArray().logical_handle) |handle|
            if (handle.mlx) |mlx_array| mlx_array.array else null
        else
            null,
        .numeric_array => blk: {
            const handle = value.asNumericArray();
            if (handle.mlx) |mlx_array| break :blk mlx_array.array;
            if (numericArrayFlatSliceSource(handle)) |source| break :blk debugMlxArrayForValue(source);
            if (numericArrayFlatConcatLeft(handle)) |left| {
                if (debugMlxArrayForValue(left)) |array| break :blk array;
                const right = numericArrayFlatConcatRight(handle) orelse break :blk null;
                break :blk debugMlxArrayForValue(right);
            }
            if (numericArrayFlatSegmentsValues(handle)) |segments| {
                for (segments) |segment| {
                    if (debugMlxArrayForValue(segment)) |array| break :blk array;
                }
            }
            if (numericArrayFirstAxisSliceSource(handle)) |source| break :blk debugMlxArrayForValue(source);
            if (numericArrayFirstAxisIndexSource(handle)) |source| break :blk debugMlxArrayForValue(source);
            if (numericArrayFirstAxisConcatLeft(handle)) |left| {
                if (debugMlxArrayForValue(left)) |array| break :blk array;
                const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk null;
                break :blk debugMlxArrayForValue(right);
            }
            if (numericArrayReshapeSource(handle)) |source| break :blk debugMlxArrayForValue(source);
            if (numericArrayTransposeSource(handle)) |source| break :blk debugMlxArrayForValue(source);
            break :blk null;
        },
        else => null,
    };
}

pub fn debugMlxDtypeName(value: Value) ?[]const u8 {
    const array = debugMlxArrayForValue(value) orelse return null;
    return switch (array.dtype()) {
        c.MLX_BOOL => "bool",
        c.MLX_INT32 => "int32",
        c.MLX_INT64 => "int64",
        c.MLX_UINT32 => "uint32",
        c.MLX_FLOAT32 => "float32",
        c.MLX_FLOAT64 => "float64",
        else => null,
    };
}

fn shapedNumericHandle(value: Value) ?*const NumericArray {
    const handle = valueNumericHandle(value) orelse return null;
    return if (handle.rank > 1) handle else null;
}

fn isUnmaterializedRangeIotaValue(value: Value) bool {
    const handle = valueNumericHandle(value) orelse return false;
    return numericArrayIsRangeIota(handle) and handle.host == null and handle.mlx == null;
}

fn valueRangeIotaHandle(value: Value) ?*const NumericArray {
    const handle = valueNumericHandle(value) orelse return null;
    return if (numericArrayIsRangeIota(handle)) handle else null;
}

fn numericHandleSupportsStructuralFlatItemsWithoutHost(handle: *const NumericArray) bool {
    if (handle.host != null) return true;
    if (numericArrayIsRangeIota(handle)) return true;
    if (numericArrayIsFlatSlice(handle)) {
        const source = numericArrayFlatSliceSource(handle) orelse return false;
        return numericValueSupportsStructuralFlatItemsWithoutHost(source);
    }
    if (numericArrayIsFlatConcat(handle)) {
        const left = numericArrayFlatConcatLeft(handle) orelse return false;
        const right = numericArrayFlatConcatRight(handle) orelse return false;
        return numericValueSupportsStructuralFlatItemsWithoutHost(left) and
            numericValueSupportsStructuralFlatItemsWithoutHost(right);
    }
    if (numericArrayIsFlatSegments(handle)) {
        const segments = numericArrayFlatSegmentsValues(handle) orelse return false;
        for (segments) |segment| {
            if (!numericValueSupportsStructuralFlatItemsWithoutHost(segment)) return false;
        }
        return true;
    }
    if (numericArrayIsFirstAxisSlice(handle)) {
        const source = numericArrayFirstAxisSliceSource(handle) orelse return false;
        return numericValueSupportsStructuralFlatItemsWithoutHost(source);
    }
    if (numericArrayIsFirstAxisIndex(handle)) {
        const source = numericArrayFirstAxisIndexSource(handle) orelse return false;
        const row_indices = numericArrayFirstAxisIndexRows(handle) orelse return false;
        return numericValueSupportsStructuralFlatItemsWithoutHost(source) and
            numericValueSupportsStructuralFlatItemsWithoutHost(row_indices);
    }
    if (numericArrayIsFirstAxisConcat(handle)) {
        const left = numericArrayFirstAxisConcatLeft(handle) orelse return false;
        const right = numericArrayFirstAxisConcatRight(handle) orelse return false;
        return numericValueSupportsStructuralFlatItemsWithoutHost(left) and
            numericValueSupportsStructuralFlatItemsWithoutHost(right);
    }
    if (numericArrayIsReshapeView(handle)) {
        const source = numericArrayReshapeSource(handle) orelse return false;
        return numericValueSupportsStructuralFlatItemsWithoutHost(source);
    }
    if (numericArrayIsTransposeView(handle)) {
        const source = numericArrayTransposeSource(handle) orelse return false;
        return numericValueSupportsStructuralFlatItemsWithoutHost(source);
    }
    return false;
}

fn numericValueSupportsStructuralFlatItemsWithoutHost(value: Value) bool {
    return switch (value.tag()) {
        .int, .bool, .float => true,
        .array => switch (value.arraySubkind()) {
            .host_array => hostArrayNumericMode(value.asHostArray()) != null,
            .mlx_array => if (value.asMlxArray().logical_handle) |handle|
                numericHandleSupportsStructuralFlatItemsWithoutHost(handle)
            else
                false,
            .numeric_array => numericHandleSupportsStructuralFlatItemsWithoutHost(value.asNumericArray()),
            else => false,
        },
        else => false,
    };
}

fn valueVectorRangeIotaHandle(value: Value) ?*const NumericArray {
    const handle = valueNumericHandle(value) orelse return null;
    return if (numericArrayIsVectorRangeIota(handle)) handle else null;
}

fn valueNonVectorNumericShape(value: Value) ?NumericShapeSnapshot {
    const handle = shapedNumericHandle(value) orelse return null;
    return numericShapeSnapshotFromHandle(handle);
}

fn numericShapeSnapshotEqual(left: NumericShapeSnapshot, right: NumericShapeSnapshot) bool {
    if (left.rank != right.rank) return false;
    return std.mem.eql(i32, left.shape[0..left.rank], right.shape[0..right.rank]);
}

fn numericShapeSnapshotElementCount(snapshot: NumericShapeSnapshot) KError!usize {
    if (snapshot.rank == 0) return 0;
    var total: usize = 1;
    for (snapshot.shape[0..snapshot.rank]) |dim| {
        total = std.math.mul(usize, total, @as(usize, @intCast(dim))) catch return error.Unsupported;
    }
    return total;
}

fn stackedNumericBuilderShape(outer_len: usize, item_shape: NumericShapeSnapshot) KError!NumericShapeSnapshot {
    if (item_shape.rank == 0 or item_shape.rank + 1 > numeric_array_max_rank) return error.Unsupported;
    var snapshot = NumericShapeSnapshot{};
    snapshot.rank = item_shape.rank + 1;
    snapshot.shape[0] = @intCast(outer_len);
    for (0..item_shape.rank) |idx| snapshot.shape[idx + 1] = item_shape.shape[idx];
    return snapshot;
}

fn valueNumericBuilderShape(value: Value) ?NumericShapeSnapshot {
    if (value.tag() != .array) return null;
    if (valueNumericMode(value) == null) return null;
    if (valueNonVectorNumericShape(value)) |shape| return shape;
    const len = numericFlatLen(value) orelse return null;
    var snapshot = NumericShapeSnapshot{};
    snapshot.rank = 1;
    snapshot.shape[0] = @intCast(len);
    return snapshot;
}

fn createManagedStackedNumericArray(self: *Session, values: []const Value, mode: HostArrayElem, item_shape: NumericShapeSnapshot) KError!Value {
    const item_len = try numericShapeSnapshotElementCount(item_shape);
    const total_len = std.math.mul(usize, values.len, item_len) catch return error.Unsupported;
    const shape = try stackedNumericBuilderShape(values.len, item_shape);

    return switch (mode) {
        .int => blk: {
            const data = try self.allocator.alloc(i64, total_len);
            defer self.allocator.free(data);
            var out_idx: usize = 0;
            for (values) |value| {
                for (0..item_len) |idx| {
                    data[out_idx] = try numericIntAt(value, idx);
                    out_idx += 1;
                }
            }
            const stacked = try self.createManagedHostIntArray(data);
            break :blk try applyNonVectorNumericShapeToValue(self, stacked, shape);
        },
        .float => blk: {
            const data = try self.allocator.alloc(f64, total_len);
            defer self.allocator.free(data);
            var out_idx: usize = 0;
            for (values) |value| {
                for (0..item_len) |idx| {
                    data[out_idx] = try numericFloatAt(value, idx);
                    out_idx += 1;
                }
            }
            const stacked = try self.createManagedHostFloatArray(data);
            break :blk try applyNonVectorNumericShapeToValue(self, stacked, shape);
        },
    };
}

fn numericStructuralScalarIndexValue(self: *Session, view: NumericStructuralView, raw_index: i64) KError!?Value {
    const handle = view.handle;
    if (numericArrayIsFlatSlice(handle)) {
        const source = numericArrayFlatSliceSource(handle) orelse return error.Type;
        const len = numericVectorLen(Value.array(@constCast(handle))) orelse return error.Type;
        const idx = try normalizeIndex(raw_index, len);
        return switch (valueNumericMode(source) orelse return error.Type) {
            .int => try self.intValue(try numericIntAt(source, (numericArrayFlatSliceStart(handle) orelse return error.Type) + idx)),
            .float => try self.floatValue(try numericFloatAt(source, (numericArrayFlatSliceStart(handle) orelse return error.Type) + idx)),
        };
    }
    if (numericArrayIsFlatConcat(handle)) {
        const left = numericArrayFlatConcatLeft(handle) orelse return error.Type;
        const right = numericArrayFlatConcatRight(handle) orelse return error.Type;
        const left_len = numericVectorLen(left) orelse return error.Type;
        const total_len = left_len + (numericVectorLen(right) orelse return error.Type);
        const idx = try normalizeIndex(raw_index, total_len);
        if (idx < left_len) {
            return switch (valueNumericMode(left) orelse return error.Type) {
                .int => try self.intValue(try numericIntAt(left, idx)),
                .float => try self.floatValue(try numericFloatAt(left, idx)),
            };
        }
        const right_idx = idx - left_len;
        return switch (valueNumericMode(right) orelse return error.Type) {
            .int => try self.intValue(try numericIntAt(right, right_idx)),
            .float => try self.floatValue(try numericFloatAt(right, right_idx)),
        };
    }
    if (numericArrayIsFlatSegments(handle)) {
        const len = numericVectorLen(Value.array(@constCast(handle))) orelse return error.Type;
        const idx = try normalizeIndex(raw_index, len);
        return switch (valueNumericMode(Value.array(@constCast(handle))) orelse return error.Type) {
            .int => try self.intValue(try numericIntAt(Value.array(@constCast(handle)), idx)),
            .float => try self.floatValue(try numericFloatAt(Value.array(@constCast(handle)), idx)),
        };
    }
    if (numericArrayIsFirstAxisConcat(handle)) {
        const rows: usize = @intCast(handle.shape[0]);
        const cols: usize = @intCast(handle.shape[1]);
        const idx = try normalizeIndex(raw_index, rows);
        var segments = std.ArrayList(FirstAxisMatrixSegment).empty;
        defer segments.deinit(self.allocator);
        try collectFirstAxisMatrixSegments(self.allocator, Value.array(@constCast(handle)), cols, &segments);
        var row_base: usize = 0;
        for (segments.items) |segment| {
            if (idx < row_base + segment.rows) {
                return try numericValueFirstAxisSegmentRowValue(self, segment.value, idx - row_base);
            }
            row_base += segment.rows;
        }
        return error.Type;
    }
    if (numericArrayIsFirstAxisSlice(handle)) {
        const source = numericArrayFirstAxisSliceSource(handle) orelse return error.Type;
        const base_start = numericArrayFirstAxisSliceRowStart(handle) orelse return error.Type;
        const row_step = numericArrayFirstAxisSliceRowStep(handle) orelse return error.Type;
        const rows: usize = @intCast(handle.shape[0]);
        const idx = try normalizeIndex(raw_index, rows);
        const row_idx_i64 = @as(i64, @intCast(base_start)) + @as(i64, @intCast(idx)) * @as(i64, row_step);
        if (row_idx_i64 < 0) return error.Type;
        return try numericValueScalarIndexValue(self, source, @intCast(row_idx_i64));
    }
    if (numericArrayIsFirstAxisIndex(handle)) {
        const source = numericArrayFirstAxisIndexSource(handle) orelse return error.Type;
        const row_indices = numericArrayFirstAxisIndexRows(handle) orelse return error.Type;
        const rows: usize = @intCast(handle.shape[0]);
        const idx = try normalizeIndex(raw_index, rows);
        const source_row_i64 = try numericIntAt(row_indices, idx);
        if (source_row_i64 < 0) return error.Type;
        return try numericValueScalarIndexValue(self, source, @intCast(source_row_i64));
    }
    if (!numericArrayIsRangeIota(handle)) return null;
    if (handle.rank > 1) {
        const outer_len: usize = @intCast(handle.shape[0]);
        const block_len = numericShapeInnerBlockLen(handle);
        const outer_idx = try normalizeIndex(raw_index, outer_len);
        const start_idx = outer_idx * block_len;
        const start = try numericArrayRangeIotaValueAt(handle, start_idx);
        return try newRangeIotaValueWithShape(
            self,
            .managed,
            block_len,
            start,
            handle.range_iota.step,
            numericShapeTailSnapshot(handle),
        );
    }
    const idx = try normalizeIndex(raw_index, numericArrayRangeLen(handle));
    return try self.intValue(try numericArrayRangeIotaValueAt(handle, idx));
}

fn numericStructuralArithmeticSliceValue(self: *Session, view: NumericStructuralView, slice: ArithmeticIndexSlice) KError!?Value {
    const handle = view.handle;
    if (numericArrayIsFlatSlice(handle) and handle.rank == 1 and slice.step == 1) {
        return try newFlatSliceValue(
            self,
            numericArrayFlatSliceSource(handle) orelse return error.Type,
            (numericArrayFlatSliceStart(handle) orelse return error.Type) + slice.start,
            slice.len,
        );
    }
    if (numericArrayIsFlatConcat(handle) and handle.rank == 1 and slice.step == 1) {
        return try newFlatSliceValue(self, Value.array(@constCast(handle)), slice.start, slice.len);
    }
    if (numericArrayIsFlatSegments(handle) and handle.rank == 1 and slice.step == 1) {
        return try newFlatSliceValue(self, Value.array(@constCast(handle)), slice.start, slice.len);
    }
    if (numericArrayIsFirstAxisConcat(handle) and slice.step == 1) {
        const cols: usize = @intCast(handle.shape[1]);
        var segments = std.ArrayList(FirstAxisMatrixSegment).empty;
        defer segments.deinit(self.allocator);
        try collectFirstAxisMatrixSegments(self.allocator, Value.array(@constCast(handle)), cols, &segments);

        var selected = std.ArrayList(FirstAxisMatrixSegment).empty;
        defer selected.deinit(self.allocator);
        try selected.ensureTotalCapacity(self.allocator, segments.items.len);

        var want_start = slice.start;
        var want_len = slice.len;
        var row_base: usize = 0;
        for (segments.items) |segment| {
            if (want_len == 0) break;
            const seg_start = row_base;
            const seg_end = row_base + segment.rows;
            if (want_start >= seg_end or want_start + want_len <= seg_start) {
                row_base = seg_end;
                continue;
            }
            const local_start = if (want_start > seg_start) want_start - seg_start else 0;
            const available = segment.rows - local_start;
            const take_rows = @min(available, want_len);
            const piece = try numericValueFirstAxisSegmentSliceValue(self, segment.value, local_start, take_rows, cols);
            try selected.append(self.allocator, .{ .value = piece, .rows = take_rows, .owned = true });
            want_start += take_rows;
            want_len -= take_rows;
            row_base = seg_end;
        }
        if (selected.items.len == 0) return error.Type;
        return try buildFirstAxisMatrixComposition(self, selected.items, cols);
    }
    if (numericArrayIsFirstAxisSlice(handle)) {
        const source = numericArrayFirstAxisSliceSource(handle) orelse return error.Type;
        const base_start = numericArrayFirstAxisSliceRowStart(handle) orelse return error.Type;
        const base_step = numericArrayFirstAxisSliceRowStep(handle) orelse return error.Type;
        const start_i64 = @as(i64, @intCast(base_start)) + @as(i64, @intCast(slice.start)) * @as(i64, base_step);
        const step_i64 = @as(i64, base_step) * @as(i64, slice.step);
        if (start_i64 < 0) return error.Type;
        const composed_step = std.math.cast(i32, step_i64) orelse return error.Unsupported;
        return try newFirstAxisSliceValueWithStep(self, source, @intCast(start_i64), slice.len, composed_step);
    }
    if (numericArrayIsFirstAxisIndex(handle)) {
        const source = numericArrayFirstAxisIndexSource(handle) orelse return error.Type;
        const row_indices = numericArrayFirstAxisIndexRows(handle) orelse return error.Type;
        var selected = std.ArrayList(i64).empty;
        defer selected.deinit(self.allocator);
        try selected.ensureTotalCapacity(self.allocator, slice.len);
        for (0..slice.len) |idx| {
            const row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(idx)) * @as(i64, slice.step);
            if (row_i64 < 0) return error.Type;
            try selected.append(self.allocator, try numericIntAt(row_indices, @intCast(row_i64)));
        }
        const selected_value = try self.createManagedHostIntArray(selected.items);
        defer self.releaseValue(selected_value);
        return try newFirstAxisIndexValue(self, source, selected_value);
    }
    if (numericArrayIsReshapeView(handle) and handle.rank > 1 and slice.step == 1) {
        const source = numericArrayReshapeSource(handle) orelse return error.Type;
        const block_len = numericShapeInnerBlockLen(handle);
        const source_slice = try newFlatSliceValue(self, source, slice.start * block_len, slice.len * block_len);
        errdefer self.releaseValue(source_slice);
        const out_shape = numericShapeFirstAxisSliceSnapshot(handle, slice.len) orelse return source_slice;
        const reshaped = try newReshapeViewValue(self, source_slice, out_shape);
        self.releaseValue(source_slice);
        return reshaped;
    }
    if (!numericArrayIsRangeIota(handle)) return null;
    if (handle.rank > 1) {
        if (slice.step == 1) {
            const block_len = numericShapeInnerBlockLen(handle);
            const out_len = slice.len * block_len;
            const start_idx = slice.start * block_len;
            const start = if (out_len == 0)
                handle.range_iota.start
            else
                try numericArrayRangeIotaValueAt(handle, start_idx);
            return try newRangeIotaValueWithShape(
                self,
                .managed,
                out_len,
                start,
                handle.range_iota.step,
                numericShapeFirstAxisSliceSnapshot(handle, slice.len),
            );
        }
        return try newFirstAxisSliceValueWithStep(self, Value.array(@constCast(handle)), slice.start, slice.len, slice.step);
    }

    const len = numericArrayRangeLen(handle);
    if (slice.start > len) return error.Type;
    if (slice.len == 0) return try newRangeIotaValue(self, .managed, 0);
    const start = try numericArrayRangeIotaValueAt(handle, slice.start);
    const step = @as(i64, handle.range_iota.step) * @as(i64, slice.step);
    return try newRangeIotaValueWithParams(self, .managed, slice.len, start, step);
}

fn numericStructuralContiguousSliceValue(self: *Session, view: NumericStructuralView, slice: ContiguousIndexSlice) KError!?Value {
    return try numericStructuralArithmeticSliceValue(self, view, .{
        .start = slice.start,
        .len = slice.len,
        .step = 1,
    });
}

fn numericStructuralTakeValue(self: *Session, view: NumericStructuralView, raw_count: i64) KError!?Value {
    const handle = view.handle;
    if (!numericArrayIsRangeIota(handle)) return null;
    if (handle.rank > 1) {
        const rows: usize = @intCast(handle.shape[0]);
        const count: usize = @intCast(@abs(raw_count));
        if (count == 0) return try numericStructuralContiguousSliceValue(self, view, .{ .start = 0, .len = 0 });
        if (count <= rows) {
            const start = if (raw_count >= 0) 0 else rows - count;
            return try numericStructuralContiguousSliceValue(self, view, .{ .start = start, .len = count });
        }
        return null;
    }

    const count: usize = @intCast(@abs(raw_count));
    if (count == 0) return try newRangeIotaValue(self, .managed, 0);
    const len = numericArrayRangeLen(handle);
    if (len == 0) return error.Type;
    if (count <= len) {
        const start = if (raw_count >= 0) 0 else len - count;
        return try numericStructuralContiguousSliceValue(self, view, .{ .start = start, .len = count });
    }
    return null;
}

fn numericStructuralDropValue(self: *Session, view: NumericStructuralView, raw_count: i64) KError!?Value {
    const handle = view.handle;
    if (!numericArrayIsRangeIota(handle)) return null;
    const len = if (handle.rank > 1)
        @as(usize, @intCast(handle.shape[0]))
    else
        numericArrayRangeLen(handle);
    const drop_count: usize = if (raw_count >= 0)
        @min(@as(usize, @intCast(raw_count)), len)
    else
        len - @min(@as(usize, @intCast(-raw_count)), len);
    const start: usize = if (raw_count >= 0) drop_count else 0;
    const end: usize = if (raw_count >= 0) len else drop_count;
    return try numericStructuralContiguousSliceValue(self, view, .{ .start = start, .len = end - start });
}

fn numericStructuralDenseMonadValue(self: *Session, value: Value, view: NumericStructuralView, op: BuiltinId) KError!?Value {
    const handle = view.handle;
    if (!numericArrayIsRangeIota(handle)) return null;
    return switch (op) {
        .add => self.shareValue(value),
        .sub => blk: {
            const len = numericArrayRangeLen(handle);
            const start = try checkedIntOp(.sub, 0, handle.range_iota.start);
            const step = try checkedIntOp(.sub, 0, handle.range_iota.step);
            break :blk try newRangeIotaValueWithShape(
                self,
                .managed,
                len,
                start,
                step,
                numericShapeSnapshotFromHandle(handle),
            );
        },
        else => null,
    };
}

fn numericStructuralGradeValue(self: *Session, view: NumericStructuralView, ascending: bool) KError!?Value {
    const handle = view.handle;
    if (!numericArrayIsRangeIota(handle)) return null;
    const len = if (handle.rank > 1)
        @as(usize, @intCast(handle.shape[0]))
    else
        numericArrayRangeLen(handle);
    if (len == 0) return try newRangeIotaValue(self, .managed, 0);
    if (handle.range_iota.step == 0 or
        (ascending and handle.range_iota.step > 0) or
        (!ascending and handle.range_iota.step < 0))
    {
        return try newRangeIotaValue(self, .managed, len);
    }
    const start: i64 = @intCast(len - 1);
    return try newRangeIotaValueWithParams(self, .managed, len, start, -1);
}

fn numericValueFirstAxisCellValue(self: *Session, value: Value, handle: *const NumericArray, raw_index: i64) KError!Value {
    if (handle.rank <= 1) return error.Type;

    const outer_len: usize = @intCast(handle.shape[0]);
    const outer_idx = try normalizeIndex(raw_index, outer_len);
    const block_len = numericShapeInnerBlockLen(handle);
    if (handle.rank == 2) {
        return try newFlatSliceValue(self, value, outer_idx * block_len, block_len);
    }

    const first_axis_slice = try newFirstAxisSliceValue(self, value, outer_idx, 1);
    errdefer self.releaseValue(first_axis_slice);

    const reshaped = try newReshapeViewValue(self, first_axis_slice, numericShapeTailSnapshot(handle) orelse return error.Type);
    self.releaseValue(first_axis_slice);
    return reshaped;
}

fn numericValueScalarIndexValue(self: *Session, value: Value, raw_index: i64) KError!?Value {
    if (NumericStructuralView.init(value)) |structural| {
        if (try numericStructuralScalarIndexValue(self, structural, raw_index)) |result| return result;
    }
    const handle = shapedNumericHandle(value) orelse return null;
    if (handle.rank <= 1) return null;
    return try numericValueFirstAxisCellValue(self, value, handle, raw_index);
}

fn createManagedHostNumericMatrixRowRange(self: *Session, array: *const HostArray, start_row: usize, row_count: usize, cols: usize) KError!Value {
    var row_indices = std.ArrayList(usize).empty;
    defer row_indices.deinit(self.allocator);
    try row_indices.ensureTotalCapacity(self.allocator, row_count);
    for (start_row..start_row + row_count) |row_idx| try row_indices.append(self.allocator, row_idx);
    return try self.createManagedHostNumericMatrixRows(array, row_indices.items, cols);
}

fn numericValueFirstAxisArithmeticSliceValue(self: *Session, value: Value, slice: ArithmeticIndexSlice) KError!?Value {
    if (NumericStructuralView.init(value)) |structural| {
        if (try numericStructuralArithmeticSliceValue(self, structural, slice)) |result| return result;
    }
    const handle = shapedNumericHandle(value) orelse return null;
    const rows: usize = @intCast(handle.shape[0]);
    if (slice.len == 0) return try newFirstAxisSliceValue(self, value, 0, 0);
    const last_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(slice.len - 1)) * @as(i64, slice.step);
    if (last_i64 < 0 or last_i64 >= rows) return error.Type;
    return try newFirstAxisSliceValueWithStep(self, value, slice.start, slice.len, slice.step);
}

fn numericValueArithmeticSliceValue(self: *Session, value: Value, slice: ArithmeticIndexSlice) KError!?Value {
    if (NumericStructuralView.init(value)) |structural| {
        if (try numericStructuralArithmeticSliceValue(self, structural, slice)) |result| return result;
    }
    if (slice.step != 1) return null;
    _ = numericVectorLen(value) orelse return null;
    return try newFlatSliceValue(self, value, slice.start, slice.len);
}

fn numericValueFirstAxisContiguousSliceValue(self: *Session, value: Value, slice: ContiguousIndexSlice) KError!?Value {
    return try numericValueFirstAxisArithmeticSliceValue(self, value, .{
        .start = slice.start,
        .len = slice.len,
        .step = 1,
    });
}

fn selectorUsesBitMaskEncoding(selector: Value) bool {
    const host = hostArrayIfPresent(selector) orelse return false;
    return std.meta.activeTag(host.storage) == .bit;
}

fn numericValueArithmeticSelectorSlice(value: Value, selector: Value) KError!?ArithmeticIndexSlice {
    const len = if (shapedNumericHandle(value)) |handle|
        @as(usize, @intCast(handle.shape[0]))
    else
        numericVectorLen(value) orelse return null;
    const view = valueHostIntStructuralView(selector) orelse return null;
    return try hostIntDenseViewArithmeticSlice(view, len);
}

fn numericValueContiguousSelectorSlice(value: Value, selector: Value) KError!?ContiguousIndexSlice {
    if (try numericValueArithmeticSelectorSlice(value, selector)) |slice| {
        if (slice.step == 1) return .{ .start = slice.start, .len = slice.len };
    }
    return null;
}

fn numericValueFirstAxisIndexSelectorValue(self: *Session, value: Value, selector: Value) KError!?Value {
    const handle = shapedNumericHandle(value) orelse return null;
    const view = valueHostIntStructuralView(selector) orelse return null;
    const rows: usize = @intCast(handle.shape[0]);
    if (selectorUsesBitMaskEncoding(selector)) {
        if (hostIntDenseViewLen(view) != rows) return error.Type;
        var selected = std.ArrayList(i64).empty;
        defer selected.deinit(self.allocator);
        for (0..rows) |idx| {
            if (try hostIntDenseViewItem(view, idx) == 0) continue;
            try selected.append(self.allocator, @intCast(idx));
        }
        const selected_value = try self.createManagedHostIntArray(selected.items);
        defer self.releaseValue(selected_value);
        return try newFirstAxisIndexValue(self, value, selected_value);
    }

    var selected = std.ArrayList(i64).empty;
    defer selected.deinit(self.allocator);
    try selected.ensureTotalCapacity(self.allocator, hostIntDenseViewLen(view));
    for (0..hostIntDenseViewLen(view)) |idx| {
        const row_i64 = try hostIntDenseViewItem(view, idx);
        try selected.append(self.allocator, @intCast(try normalizeIndex(row_i64, rows)));
    }
    const selected_value = try self.createManagedHostIntArray(selected.items);
    defer self.releaseValue(selected_value);
    return try newFirstAxisIndexValue(self, value, selected_value);
}

fn valueMlxBoolMaskLen(value: Value) ?usize {
    const array = mlxArrayIfPresent(value) orelse return null;
    if (array.array.dtype() != c.MLX_BOOL or array.array.ndim() != 1) return null;
    return std.math.cast(usize, array.array.shape()[0]);
}

fn tryApplyMlxBoolMaskIndex(self: *Session, callee: Value, selector: Value) KError!?Value {
    const mask_len = valueMlxBoolMaskLen(selector) orelse return null;
    if (valueNumericMode(callee) == null) return null;

    const outer_len: usize = if (shapedNumericHandle(callee)) |handle|
        if (handle.rank == 0) return error.Type else @intCast(handle.shape[0])
    else
        numericVectorLen(callee) orelse return null;
    if (mask_len != outer_len) return error.Type;

    var mask = try self.materializeMlxArray(selector);
    defer mask.deinit();
    if (mask.dtype() != c.MLX_BOOL or mask.ndim() != 1) return error.Type;

    var source = try self.materializeMlxArray(callee);
    defer source.deinit();
    if (source.ndim() == 0) return error.Type;

    const ctx = try self.mlxContext();
    var indices = mlx.Array.boolWhereIndices(ctx.*, mask) catch |err| return mapMlxError(err);
    defer indices.deinit();
    const out = mlx.Array.takeAxis(ctx.*, source, indices, 0) catch |err| return mapMlxError(err);
    return try self.wrapManagedMlxArray(out);
}

fn applyNumericShapeSnapshot(handle: *NumericArray, snapshot: NumericShapeSnapshot) void {
    handle.rank = snapshot.rank;
    handle.shape = snapshot.shape;
}

fn applyNonVectorNumericShapeToValue(self: *Session, value: Value, snapshot: ?NumericShapeSnapshot) !Value {
    const shape = snapshot orelse return value;
    if (shape.rank <= 1) return value;
    const handle, const canonical = switch (value.tag()) {
        .array => switch (value.arraySubkind()) {
            .numeric_array => .{ @constCast(value.asNumericArray()), value },
            .host_array => blk: {
                if (hostArrayNumericMode(value.asHostArray()) == null) return error.Type;
                const wrapped = try wrapOwnedHostArrayValue(self, @constCast(value.asHostArray()));
                break :blk .{ @constCast(wrapped.asNumericArray()), wrapped };
            },
            .mlx_array => blk: {
                const wrapped = try wrapOwnedMlxArrayValue(self, @constCast(value.asMlxArray()));
                break :blk .{ @constCast(wrapped.asNumericArray()), wrapped };
            },
            else => return error.Type,
        },
        else => return error.Type,
    };
    applyNumericShapeSnapshot(handle, shape);
    syncNumericArrayChildren(handle);
    return canonical;
}

fn nonVectorNumericShapeForDyad(left: Value, right: Value) KError!?NumericShapeSnapshot {
    if (rowwiseMatrixVectorDyad(left, right)) |shape| {
        return numericShapeSnapshotMatrix(shape.rows, shape.cols);
    }
    const left_shape = valueNonVectorNumericShape(left);
    const right_shape = valueNonVectorNumericShape(right);
    if (left_shape == null and right_shape == null) return null;
    if (left.tag() == .array and right.tag() == .array) {
        if (left_shape == null or right_shape == null) return error.Type;
        const lhs = left_shape.?;
        const rhs = right_shape.?;
        if (lhs.rank != rhs.rank or !std.mem.eql(i32, lhs.shapeSlice(), rhs.shapeSlice())) return error.Type;
        return lhs;
    }
    return left_shape orelse right_shape;
}

fn hostArrayShapeHandle(array: *const HostArray) ?*const NumericArray {
    if (hostArrayNumericMode(array) == null) return null;
    return array.logical_handle;
}

fn hostArrayNonVectorShape(array: *const HostArray) ?*const NumericArray {
    const handle = hostArrayShapeHandle(array) orelse return null;
    return if (handle.rank > 1) handle else null;
}

fn hostNumericMatrixShape(array: *const HostArray) ?NumericMatrixShape {
    const handle = hostArrayNonVectorShape(array) orelse return null;
    if (handle.rank != 2) return null;
    return .{
        .rows = @intCast(handle.shape[0]),
        .cols = @intCast(handle.shape[1]),
    };
}

fn hostArrayShapeDims(array: *const HostArray, dims_buf: *[numeric_array_max_rank]i32) []const i32 {
    if (hostArrayShapeHandle(array)) |handle| {
        if (handle.rank != 0) return handle.shapeSlice();
    }
    dims_buf[0] = @intCast(array.len());
    for (1..numeric_array_max_rank) |idx| dims_buf[idx] = 0;
    return dims_buf[0..1];
}

fn valueNumericMatrixShape(value: Value) ?NumericMatrixShape {
    if (value.tag() != .array or valueNumericMode(value) == null) return null;
    const shape = valueNonVectorNumericShape(value) orelse return null;
    if (shape.rank != 2) return null;
    return .{
        .rows = @intCast(shape.shape[0]),
        .cols = @intCast(shape.shape[1]),
    };
}

fn valueNumericMatrixView(value: Value) ?NumericMatrixView {
    const shape = valueNumericMatrixShape(value) orelse return null;
    const handle = valueNumericHandle(value) orelse return null;
    const mode = valueNumericMode(value) orelse return null;
    return .{
        .value = value,
        .handle = handle,
        .shape = shape,
        .mode = mode,
    };
}

const RowwiseMatrixVectorDyad = struct {
    matrix_on_left: bool,
    rows: usize,
    cols: usize,

    fn operandIndex(self: RowwiseMatrixVectorDyad, use_left: bool, result_idx: usize) usize {
        if (self.matrix_on_left == use_left) return result_idx;
        return result_idx / self.cols;
    }
};

fn rowwiseMatrixVectorDyad(left: Value, right: Value) ?RowwiseMatrixVectorDyad {
    const left_matrix = valueNumericMatrixShape(left);
    const right_matrix = valueNumericMatrixShape(right);
    const left_vector_len = if (left_matrix == null) numericVectorLen(left) else null;
    const right_vector_len = if (right_matrix == null) numericVectorLen(right) else null;

    if (left_matrix) |shape| {
        if (right_matrix == null and right_vector_len != null and right_vector_len.? == shape.rows) {
            return .{ .matrix_on_left = true, .rows = shape.rows, .cols = shape.cols };
        }
    }
    if (right_matrix) |shape| {
        if (left_matrix == null and left_vector_len != null and left_vector_len.? == shape.rows) {
            return .{ .matrix_on_left = false, .rows = shape.rows, .cols = shape.cols };
        }
    }
    return null;
}

fn valueIsRenderableMatrixLike(value: Value) bool {
    if (valueNumericMatrixShape(value) != null) return true;
    if (value.tag() != .array or value.arrayKind() != .host_array or std.meta.activeTag(value.asHostArray().storage) != .boxed) return false;
    return isRenderableMatrix(value.asHostArray().storage.boxed);
}

fn numericMatrixRowsEqual(self: *Session, view: NumericMatrixView, lhs_row: usize, rhs_row: usize) KError!bool {
    if (view.handle.mlx != null) {
        _ = try tryEnsureHostRealizationForHandle(self, @constCast(view.handle)) orelse return error.Type;
    }
    const lhs_base = lhs_row * view.shape.cols;
    const rhs_base = rhs_row * view.shape.cols;
    return switch (view.mode) {
        .float => {
            for (0..view.shape.cols) |col| {
                if (try numericFloatAt(view.value, lhs_base + col) != try numericFloatAt(view.value, rhs_base + col)) return false;
            }
            return true;
        },
        .int => {
            for (0..view.shape.cols) |col| {
                if (try numericIntAt(view.value, lhs_base + col) != try numericIntAt(view.value, rhs_base + col)) return false;
            }
            return true;
        },
    };
}

fn numericMatrixRowOrder(self: *Session, view: NumericMatrixView, lhs_row: usize, rhs_row: usize) KError!std.math.Order {
    if (view.handle.mlx != null) {
        _ = try tryEnsureHostRealizationForHandle(self, @constCast(view.handle)) orelse return error.Type;
    }
    const lhs_base = lhs_row * view.shape.cols;
    const rhs_base = rhs_row * view.shape.cols;
    return switch (view.mode) {
        .float => {
            for (0..view.shape.cols) |col| {
                const order = std.math.order(
                    try numericFloatAt(view.value, lhs_base + col),
                    try numericFloatAt(view.value, rhs_base + col),
                );
                if (order != .eq) return order;
            }
            return .eq;
        },
        .int => {
            for (0..view.shape.cols) |col| {
                const order = std.math.order(
                    try numericIntAt(view.value, lhs_base + col),
                    try numericIntAt(view.value, rhs_base + col),
                );
                if (order != .eq) return order;
            }
            return .eq;
        },
    };
}

fn rowIndicesArithmeticSlice(row_indices: []const usize) ?ArithmeticIndexSlice {
    if (row_indices.len == 0) return .{ .start = 0, .len = 0, .step = 1 };
    const start = row_indices[0];
    if (row_indices.len == 1) return .{ .start = start, .len = 1, .step = 1 };
    const second_i64 = std.math.cast(i64, row_indices[1]) orelse return null;
    const start_i64 = std.math.cast(i64, start) orelse return null;
    const step_i64 = second_i64 - start_i64;
    if (step_i64 == 0) return null;
    const step = std.math.cast(i32, step_i64) orelse return null;
    for (1..row_indices.len) |idx| {
        const expected_i64 = start_i64 + @as(i64, @intCast(idx)) * @as(i64, step);
        const actual_i64 = std.math.cast(i64, row_indices[idx]) orelse return null;
        if (actual_i64 != expected_i64) return null;
    }
    return .{ .start = start, .len = row_indices.len, .step = step };
}

const FirstAxisMatrixSegment = struct {
    value: Value,
    rows: usize,
    owned: bool = false,
};

const FlatNumericSegment = struct {
    value: Value,
    len: usize,
    owned: bool = false,
};

fn releaseOwnedFirstAxisMatrixSegment(self: *Session, segment: FirstAxisMatrixSegment) void {
    if (segment.owned) self.releaseValue(segment.value);
}

fn releaseOwnedFirstAxisMatrixSegments(self: *Session, segments: []const FirstAxisMatrixSegment) void {
    for (segments) |segment| releaseOwnedFirstAxisMatrixSegment(self, segment);
}

fn releaseOwnedFlatNumericSegment(self: *Session, segment: FlatNumericSegment) void {
    if (segment.owned) self.releaseValue(segment.value);
}

fn releaseOwnedFlatNumericSegments(self: *Session, segments: []const FlatNumericSegment) void {
    for (segments) |segment| releaseOwnedFlatNumericSegment(self, segment);
}

fn numericValueMatrixRowsForCols(value: Value, cols: usize) KError!usize {
    if (valueNumericMatrixShape(value)) |shape| {
        if (shape.cols != cols) return error.Type;
        return shape.rows;
    }
    const len = numericFlatLen(value) orelse return error.Type;
    if (len != cols) return error.Type;
    return 1;
}

fn collectFirstAxisMatrixSegments(allocator: std.mem.Allocator, value: Value, cols: usize, out: *std.ArrayList(FirstAxisMatrixSegment)) KError!void {
    if (value.tag() == .array) {
        if (valueNumericHandle(value)) |handle| {
            if (numericArrayIsFirstAxisConcat(handle)) {
                try collectFirstAxisMatrixSegments(allocator, numericArrayFirstAxisConcatLeft(handle) orelse return error.Type, cols, out);
                try collectFirstAxisMatrixSegments(allocator, numericArrayFirstAxisConcatRight(handle) orelse return error.Type, cols, out);
                return;
            }
        }
    }
    try out.append(allocator, .{
        .value = value,
        .rows = try numericValueMatrixRowsForCols(value, cols),
        .owned = false,
    });
}

fn collectFlatNumericSegments(allocator: std.mem.Allocator, value: Value, out: *std.ArrayList(FlatNumericSegment)) KError!void {
    if (value.tag() == .array) {
        if (valueNumericHandle(value)) |handle| {
            if (numericArrayIsFlatConcat(handle)) {
                try collectFlatNumericSegments(allocator, numericArrayFlatConcatLeft(handle) orelse return error.Type, out);
                try collectFlatNumericSegments(allocator, numericArrayFlatConcatRight(handle) orelse return error.Type, out);
                return;
            }
            if (numericArrayIsFlatSegments(handle)) {
                const segments = numericArrayFlatSegmentsValues(handle) orelse return error.Type;
                try out.ensureUnusedCapacity(allocator, segments.len);
                for (segments) |segment| {
                    out.appendAssumeCapacity(.{
                        .value = segment,
                        .len = numericVectorLen(segment) orelse return error.Type,
                        .owned = false,
                    });
                }
                return;
            }
        }
    }
    try out.append(allocator, .{
        .value = value,
        .len = numericVectorLen(value) orelse return error.Type,
        .owned = false,
    });
}

fn tryFuseStructuredFlatNumericSegments(self: *Session, left: FlatNumericSegment, right: FlatNumericSegment) KError!?FlatNumericSegment {
    if (valueRangeIotaHandle(left.value)) |left_handle| {
        if (valueRangeIotaHandle(right.value)) |right_handle| {
            if (left_handle.rank == 1 and right_handle.rank == 1 and left_handle.range_iota.step == right_handle.range_iota.step) {
                const left_len_i64 = std.math.cast(i64, left.len) orelse return error.Unsupported;
                const offset = std.math.mul(i64, left_handle.range_iota.step, left_len_i64) catch return error.Unsupported;
                const expected_right_start = std.math.add(i64, left_handle.range_iota.start, offset) catch return error.Unsupported;
                if (right_handle.range_iota.start == expected_right_start) {
                    const value = try newRangeIotaValueWithParams(self, .managed, left.len + right.len, left_handle.range_iota.start, left_handle.range_iota.step);
                    return .{ .value = value, .len = left.len + right.len, .owned = true };
                }
            }
        }
    }
    if (left.value.tag() == .array and right.value.tag() == .array) {
        if (valueNumericHandle(left.value)) |left_handle| {
            if (valueNumericHandle(right.value)) |right_handle| {
                if (numericArrayIsFlatSlice(left_handle) and numericArrayIsFlatSlice(right_handle)) {
                    const left_source = numericArrayFlatSliceSource(left_handle) orelse return error.Type;
                    const right_source = numericArrayFlatSliceSource(right_handle) orelse return error.Type;
                    if (left_source.raw == right_source.raw) {
                        const left_start = numericArrayFlatSliceStart(left_handle) orelse return error.Type;
                        const right_start = numericArrayFlatSliceStart(right_handle) orelse return error.Type;
                        if (left_start + left.len == right_start) {
                            const value = try newFlatSliceValue(self, left_source, left_start, left.len + right.len);
                            return .{ .value = value, .len = left.len + right.len, .owned = true };
                        }
                    }
                }
            }
        }
    }
    return null;
}

fn buildFlatNumericComposition(self: *Session, segments: []FlatNumericSegment) KError!Value {
    if (segments.len == 0) return error.Type;

    errdefer releaseOwnedFlatNumericSegments(self, segments);
    var fused = std.ArrayList(FlatNumericSegment).empty;
    defer fused.deinit(self.allocator);
    errdefer releaseOwnedFlatNumericSegments(self, fused.items);
    try fused.ensureTotalCapacity(self.allocator, segments.len);
    for (segments) |*segment| {
        const incoming = segment.*;
        if (fused.items.len != 0) {
            if (try tryFuseStructuredFlatNumericSegments(self, fused.items[fused.items.len - 1], incoming)) |combined| {
                releaseOwnedFlatNumericSegment(self, fused.items[fused.items.len - 1]);
                releaseOwnedFlatNumericSegment(self, incoming);
                segment.owned = false;
                fused.items[fused.items.len - 1] = combined;
                continue;
            }
        }
        segment.owned = false;
        try fused.append(self.allocator, incoming);
    }

    if (fused.items.len == 1) {
        const segment = fused.items[0];
        if (segment.owned) return segment.value;
        return self.shareValue(segment.value);
    }
    if (fused.items.len == 2) {
        const left = fused.items[0];
        const right = fused.items[1];
        const combined = try newFlatConcatPairValue(self, left.value, right.value);
        releaseOwnedFlatNumericSegments(self, fused.items);
        return combined;
    }

    const combined = try newFlatSegmentsValue(self, fused.items);
    releaseOwnedFlatNumericSegments(self, fused.items);
    return combined;
}

fn numericValueFirstAxisSegmentRowValue(self: *Session, value: Value, row_idx: usize) KError!Value {
    if (valueNumericMatrixShape(value) != null) return (try numericValueScalarIndexValue(self, value, @intCast(row_idx))) orelse error.Type;
    if (row_idx == 0) return self.shareValue(value);
    return error.Type;
}

fn numericValueFirstAxisSegmentSliceValue(self: *Session, value: Value, start: usize, len: usize, cols: usize) KError!Value {
    if (valueNumericMatrixShape(value) != null) {
        return (try numericValueFirstAxisArithmeticSliceValue(self, value, .{
            .start = start,
            .len = len,
            .step = 1,
        })) orelse error.Type;
    }
    if (start != 0 or len != 1) return error.Type;
    const shape = numericShapeSnapshotMatrix(1, cols);
    return try newReshapeViewValue(self, value, shape);
}

fn tryFuseFirstAxisMatrixSegments(self: *Session, left: FirstAxisMatrixSegment, right: FirstAxisMatrixSegment, cols: usize) KError!?FirstAxisMatrixSegment {
    const shape = NumericMatrixShape{
        .rows = left.rows + right.rows,
        .cols = cols,
    };
    if (try tryConcatFirstAxisSliceNumericMatrix(self, left.value, right.value, shape)) |result| {
        return .{ .value = result, .rows = shape.rows, .owned = true };
    }
    if (try tryConcatStructuredNumericMatrix(self, left.value, right.value, shape)) |result| {
        return .{ .value = result, .rows = shape.rows, .owned = true };
    }
    return null;
}

fn buildFirstAxisMatrixComposition(self: *Session, segments: []FirstAxisMatrixSegment, cols: usize) KError!Value {
    if (segments.len == 0) return error.Type;

    errdefer releaseOwnedFirstAxisMatrixSegments(self, segments);
    var fused = std.ArrayList(FirstAxisMatrixSegment).empty;
    defer fused.deinit(self.allocator);
    errdefer releaseOwnedFirstAxisMatrixSegments(self, fused.items);
    try fused.ensureTotalCapacity(self.allocator, segments.len);
    for (segments) |*segment| {
        const incoming = segment.*;
        if (fused.items.len != 0) {
            if (try tryFuseFirstAxisMatrixSegments(self, fused.items[fused.items.len - 1], incoming, cols)) |combined| {
                releaseOwnedFirstAxisMatrixSegment(self, fused.items[fused.items.len - 1]);
                releaseOwnedFirstAxisMatrixSegment(self, incoming);
                segment.owned = false;
                fused.items[fused.items.len - 1] = combined;
                continue;
            }
        }
        segment.owned = false;
        try fused.append(self.allocator, incoming);
    }

    if (fused.items.len == 1) {
        const segment = fused.items[0];
        if (valueNumericMatrixShape(segment.value) != null) {
            if (segment.owned) return segment.value;
            return self.shareValue(segment.value);
        }
        const reshaped = try newReshapeViewValue(self, segment.value, numericShapeSnapshotMatrix(segment.rows, cols));
        releaseOwnedFirstAxisMatrixSegment(self, segment);
        return reshaped;
    }

    var current = try numericValueFirstAxisSegmentSliceValue(self, fused.items[0].value, 0, fused.items[0].rows, cols);
    errdefer self.releaseValue(current);
    var current_rows = fused.items[0].rows;
    for (fused.items[1..]) |segment| {
        const next = try numericValueFirstAxisSegmentSliceValue(self, segment.value, 0, segment.rows, cols);
        defer self.releaseValue(next);
        const combined = try newFirstAxisConcatValue(self, current, next, .{
            .rows = current_rows + segment.rows,
            .cols = cols,
        });
        self.releaseValue(current);
        current = combined;
        current_rows += segment.rows;
    }
    releaseOwnedFirstAxisMatrixSegments(self, fused.items);
    return current;
}

fn numericValueMatrixSelectRows(self: *Session, value: Value, row_indices: []const usize) KError!Value {
    const view = valueNumericMatrixView(value) orelse return error.Type;
    if (rowIndicesArithmeticSlice(row_indices)) |slice| {
        if (slice.start == 0 and slice.len == view.shape.rows and slice.step == 1) return self.shareValue(value);
        return (try numericValueFirstAxisArithmeticSliceValue(self, value, slice)) orelse error.Type;
    }
    var selected = std.ArrayList(i64).empty;
    defer selected.deinit(self.allocator);
    try selected.ensureTotalCapacity(self.allocator, row_indices.len);
    for (row_indices) |row_idx| {
        if (row_idx >= view.shape.rows) return error.Type;
        try selected.append(self.allocator, @intCast(row_idx));
    }
    const selected_value = try self.createManagedHostIntArray(selected.items);
    defer self.releaseValue(selected_value);
    return try newFirstAxisIndexValue(self, value, selected_value);
}

fn concatNumericMatrixShape(self: *Session, left: Value, right: Value) KError!?NumericMatrixShape {
    _ = self;
    if (left.tag() != .array or right.tag() != .array) return null;
    if (valueNumericMode(left) == null or valueNumericMode(right) == null) return null;

    const left_matrix = valueNumericMatrixShape(left);
    const right_matrix = valueNumericMatrixShape(right);
    if (left_matrix == null and right_matrix == null) return null;

    const left_len = numericFlatLen(left) orelse return null;
    const right_len = numericFlatLen(right) orelse return null;
    const cols = if (left_matrix) |shape| shape.cols else left_len;
    if (right_matrix) |shape| {
        if (shape.cols != cols) return null;
    } else if (right_len != cols) {
        return null;
    }

    return .{
        .rows = (if (left_matrix) |shape| shape.rows else 1) + (if (right_matrix) |shape| shape.rows else 1),
        .cols = cols,
    };
}

fn valueNumericBitSlice(value: Value) ?HostBitSlice {
    if (value.tag() != .array) return null;
    return switch (value.arrayKind()) {
        .host_array => switch (value.asHostArray().storage) {
            .bit => |words| .{ .words = words, .len = value.asHostArray().logical_len },
            else => null,
        },
        .numeric_array => blk: {
            const handle = value.asNumericArray();
            const array = handle.host orelse break :blk null;
            break :blk switch (array.storage) {
                .bit => |words| .{ .words = words, .len = array.logical_len },
                else => null,
            };
        },
        .mlx_array => blk: {
            const handle = valueNumericHandle(value) orelse break :blk null;
            const array = handle.host orelse break :blk null;
            break :blk switch (array.storage) {
                .bit => |words| .{ .words = words, .len = array.logical_len },
                else => null,
            };
        },
        else => null,
    };
}

fn tryConcatStructuredNumericMatrix(self: *Session, left: Value, right: Value, shape: NumericMatrixShape) KError!?Value {
    const left_handle = valueRangeIotaHandle(left) orelse return null;
    const right_handle = valueRangeIotaHandle(right) orelse return null;
    if (left_handle.range_iota.step != right_handle.range_iota.step) return null;
    const left_len = numericFlatLen(left) orelse return null;
    const right_len = numericFlatLen(right) orelse return null;
    const total_len = left_len + right_len;
    const start = if (left_len != 0)
        left_handle.range_iota.start
    else
        right_handle.range_iota.start;
    if (left_len != 0 and right_len != 0) {
        const left_len_i64 = std.math.cast(i64, left_len) orelse return error.Unsupported;
        const offset = std.math.mul(i64, left_handle.range_iota.step, left_len_i64) catch return error.Unsupported;
        const expected_right_start = std.math.add(i64, left_handle.range_iota.start, offset) catch return error.Unsupported;
        if (right_handle.range_iota.start != expected_right_start) return null;
    }
    return try newRangeIotaValueWithShape(
        self,
        .managed,
        total_len,
        start,
        left_handle.range_iota.step,
        numericShapeSnapshotMatrix(shape.rows, shape.cols),
    );
}

fn tryConcatFirstAxisSliceNumericMatrix(self: *Session, left: Value, right: Value, shape: NumericMatrixShape) KError!?Value {
    const left_handle = valueNumericHandle(left) orelse return null;
    const right_handle = valueNumericHandle(right) orelse return null;
    if (!numericArrayIsFirstAxisSlice(left_handle) or !numericArrayIsFirstAxisSlice(right_handle)) return null;

    const left_slice = left_handle.first_axis_slice orelse return error.Type;
    const right_slice = right_handle.first_axis_slice orelse return error.Type;
    if (left_slice.source.raw != right_slice.source.raw) return null;
    if (left_slice.step != right_slice.step) return null;

    const left_rows: usize = @intCast(left_handle.shape[0]);
    const right_rows: usize = @intCast(right_handle.shape[0]);
    const start = if (left_rows != 0) left_slice.start else right_slice.start;
    if (left_rows != 0 and right_rows != 0) {
        const expected_i64 = @as(i64, @intCast(left_slice.start)) + @as(i64, @intCast(left_rows)) * left_slice.step;
        if (expected_i64 < 0 or right_slice.start != @as(usize, @intCast(expected_i64))) return null;
    }
    return try newFirstAxisSliceValueWithStep(self, left_slice.source, start, shape.rows, left_slice.step);
}

fn concatNumericMatrixValue(self: *Session, left: Value, right: Value, shape: NumericMatrixShape) KError!?Value {
    var segments = std.ArrayList(FirstAxisMatrixSegment).empty;
    defer segments.deinit(self.allocator);
    try collectFirstAxisMatrixSegments(self.allocator, left, shape.cols, &segments);
    try collectFirstAxisMatrixSegments(self.allocator, right, shape.cols, &segments);
    return try buildFirstAxisMatrixComposition(self, segments.items, shape.cols);
}

fn combineAddMonotonicFlags(left_flags: u8, right_flags: u8) u8 {
    const left_mono = monotonicFlags(left_flags);
    const right_mono = monotonicFlags(right_flags);
    return (if ((left_mono & host_array_flag_asc) != 0 and (right_mono & host_array_flag_asc) != 0) host_array_flag_asc else 0) |
        (if ((left_mono & host_array_flag_dsc) != 0 and (right_mono & host_array_flag_dsc) != 0) host_array_flag_dsc else 0);
}

fn combineSubMonotonicFlags(left_flags: u8, right_flags: u8) u8 {
    return combineAddMonotonicFlags(left_flags, invertMonotonicFlags(right_flags));
}

fn scalarMulMonotonicFlags(array_flags: u8, scalar: i64) u8 {
    if (scalar == 0) return host_array_flag_asc | host_array_flag_dsc;
    if (scalar > 0) return monotonicFlags(array_flags);
    return invertMonotonicFlags(array_flags);
}

fn intArrayScalarResultFlags(op: BuiltinId, array_flags: u8, scalar: i64, scalar_left: bool) u8 {
    const mono = switch (op) {
        .add => monotonicFlags(array_flags),
        .sub => if (scalar_left) invertMonotonicFlags(array_flags) else monotonicFlags(array_flags),
        .mul => scalarMulMonotonicFlags(array_flags, scalar),
        .minimum, .maximum, .div => 0,
        else => 0,
    };
    return host_array_flag_normalized | mono;
}

fn intArrayArrayResultFlags(op: BuiltinId, left_flags: u8, right_flags: u8) u8 {
    const mono = switch (op) {
        .add => combineAddMonotonicFlags(left_flags, right_flags),
        .sub => combineSubMonotonicFlags(left_flags, right_flags),
        .minimum, .maximum, .mul, .div => 0,
        else => 0,
    };
    return host_array_flag_normalized | mono;
}

fn intNegResultFlags(input_flags: u8) u8 {
    return host_array_flag_normalized | invertMonotonicFlags(input_flags);
}

fn analyzeIntSlice(items: []const i64) HostIntAnalysis {
    if (items.len == 0) {
        return .{
            .range = .{ .min = 0, .max = 0 },
            .kind = .int8,
            .flags = host_array_flag_normalized | host_array_flag_asc | host_array_flag_dsc,
        };
    }

    var min_value = items[0];
    var max_value = items[0];
    var asc = true;
    var dsc = true;
    var prev = items[0];
    for (items[1..]) |item| {
        min_value = @min(min_value, item);
        max_value = @max(max_value, item);
        if (prev > item) asc = false;
        if (prev < item) dsc = false;
        prev = item;
    }

    return .{
        .range = .{ .min = min_value, .max = max_value },
        .kind = hostIntStorageKindForRange(min_value, max_value),
        .flags = host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc),
    };
}

fn exactIntFromFloat(value: f64) ?i64 {
    if (!std.math.isFinite(value)) return null;
    const truncated = @trunc(value);
    if (value != truncated) return null;
    if (truncated < @as(f64, @floatFromInt(std.math.minInt(i64))) or truncated > @as(f64, @floatFromInt(std.math.maxInt(i64)))) return null;
    return @intFromFloat(truncated);
}

const HostFloatSqueezeAnalysis = struct {
    flags: u8,
    int_analysis: ?HostIntAnalysis,
};

fn analyzeFloatSlice(items: []const f64) HostFloatSqueezeAnalysis {
    if (items.len == 0) {
        return .{
            .flags = host_array_flag_normalized | host_array_flag_asc | host_array_flag_dsc,
            .int_analysis = .{
                .range = .{ .min = 0, .max = 0 },
                .kind = .int8,
                .flags = host_array_flag_normalized | host_array_flag_asc | host_array_flag_dsc,
            },
        };
    }

    var asc = true;
    var dsc = true;
    var prev = items[0];
    var all_int = true;
    var min_value: i64 = 0;
    var max_value: i64 = 0;
    for (items, 0..) |item, idx| {
        if (idx != 0) {
            if (prev > item) asc = false;
            if (prev < item) dsc = false;
            prev = item;
        }

        if (all_int) {
            const int_value = exactIntFromFloat(item) orelse {
                all_int = false;
                continue;
            };
            if (idx == 0) {
                min_value = int_value;
                max_value = int_value;
            } else {
                min_value = @min(min_value, int_value);
                max_value = @max(max_value, int_value);
            }
        }
    }

    return .{
        .flags = host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc),
        .int_analysis = if (all_int) .{
            .range = .{ .min = min_value, .max = max_value },
            .kind = hostIntStorageKindForRange(min_value, max_value),
            .flags = host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc),
        } else null,
    };
}

fn hostIntRangeForValue(value: i64) HostIntRange {
    return .{ .min = value, .max = value };
}

fn bitWordCount(len: usize) usize {
    return if (len == 0) 0 else (len + host_bit_word_bits - 1) / host_bit_word_bits;
}

fn bitTailMask(len: usize) u64 {
    const tail = len % host_bit_word_bits;
    if (tail == 0) return std.math.maxInt(u64);
    return (@as(u64, 1) << @intCast(tail)) - 1;
}

fn bitGet(words: []const u64, idx: usize) bool {
    const word_index = idx / host_bit_word_bits;
    const bit_index = idx % host_bit_word_bits;
    return ((words[word_index] >> @intCast(bit_index)) & 1) != 0;
}

fn bitSet(words: []u64, idx: usize, value: bool) void {
    const word_index = idx / host_bit_word_bits;
    const bit_index = idx % host_bit_word_bits;
    const mask: u64 = @as(u64, 1) << @intCast(bit_index);
    if (value) {
        words[word_index] |= mask;
    } else {
        words[word_index] &= ~mask;
    }
}

fn bitClearUnusedTail(words: []u64, len: usize) void {
    if (words.len == 0) return;
    words[words.len - 1] &= bitTailMask(len);
}

fn bitFill(words: []u64, len: usize, value: bool) void {
    @memset(words, if (value) std.math.maxInt(u64) else 0);
    bitClearUnusedTail(words, len);
}

fn bitWordActiveLen(len: usize, word_idx: usize, word_count: usize) usize {
    if (word_idx + 1 < word_count) return host_bit_word_bits;
    const tail = len % host_bit_word_bits;
    return if (tail == 0) host_bit_word_bits else tail;
}

fn bitWordMasked(words: []const u64, len: usize, word_idx: usize) u64 {
    const word = words[word_idx];
    return if (word_idx + 1 == words.len) word & bitTailMask(len) else word;
}

fn bitWordsAllTrue(items: HostBitSlice) bool {
    for (items.words, 0..) |_, word_idx| {
        const expected = if (word_idx + 1 == items.words.len) bitTailMask(items.len) else std.math.maxInt(u64);
        if (bitWordMasked(items.words, items.len, word_idx) != expected) return false;
    }
    return true;
}

fn fillBitNotWords(out: []u64, items: HostBitSlice) void {
    for (items.words, 0..) |word, word_idx| out[word_idx] = ~word;
    bitClearUnusedTail(out, items.len);
}

fn hostIntRangeFromWide(min_value: i128, max_value: i128) ?HostIntRange {
    if (min_value < std.math.minInt(i64) or max_value > std.math.maxInt(i64)) return null;
    return .{
        .min = @intCast(min_value),
        .max = @intCast(max_value),
    };
}

fn hostIntInitialResultKind(op: BuiltinId, left_kind: HostIntStorageKind, right_kind: HostIntStorageKind) HostIntStorageKind {
    return switch (op) {
        .add, .sub, .mul, .minimum, .maximum => maxHostIntStorageKind(left_kind, right_kind),
        .div => unreachable,
        else => unreachable,
    };
}

fn hostNegInitialResultKind(kind: HostIntStorageKind) HostIntStorageKind {
    return kind;
}

fn nextWiderHostIntStorageKind(kind: HostIntStorageKind) ?HostIntStorageKind {
    return switch (kind) {
        .bit => .int8,
        .int8 => .int16,
        .int16 => .int32,
        .int32 => .int64,
        .int64 => null,
    };
}

fn hostIntUncheckedSafeForOutput(left_kind: HostIntStorageKind, right_kind: HostIntStorageKind, out_kind: HostIntStorageKind) bool {
    return hostIntStorageRank(out_kind) > hostIntStorageRank(maxHostIntStorageKind(left_kind, right_kind));
}

fn hostNegUncheckedSafeForOutput(input_kind: HostIntStorageKind, out_kind: HostIntStorageKind) bool {
    return hostIntStorageRank(out_kind) > hostIntStorageRank(input_kind);
}

fn retryWiderHostIntKind(kind: *HostIntStorageKind) KError!void {
    kind.* = nextWiderHostIntStorageKind(kind.*) orelse return error.Unsupported;
}

fn hostIntNegRange(input: HostIntRange) ?HostIntRange {
    return hostIntRangeFromWide(-@as(i128, input.max), -@as(i128, input.min));
}

fn hostIntDyadRange(op: BuiltinId, left: HostIntRange, right: HostIntRange) ?HostIntRange {
    return switch (op) {
        .add => hostIntRangeFromWide(@as(i128, left.min) + @as(i128, right.min), @as(i128, left.max) + @as(i128, right.max)),
        .sub => hostIntRangeFromWide(@as(i128, left.min) - @as(i128, right.max), @as(i128, left.max) - @as(i128, right.min)),
        .minimum => .{
            .min = @min(left.min, right.min),
            .max = @min(left.max, right.max),
        },
        .maximum => .{
            .min = @max(left.min, right.min),
            .max = @max(left.max, right.max),
        },
        .mul => blk: {
            const products = [_]i128{
                @as(i128, left.min) * @as(i128, right.min),
                @as(i128, left.min) * @as(i128, right.max),
                @as(i128, left.max) * @as(i128, right.min),
                @as(i128, left.max) * @as(i128, right.max),
            };
            var min_value = products[0];
            var max_value = products[0];
            for (products[1..]) |product| {
                min_value = @min(min_value, product);
                max_value = @max(max_value, product);
            }
            break :blk hostIntRangeFromWide(min_value, max_value);
        },
        .div => null,
        else => null,
    };
}

fn hostIntDyadResultKindForRange(op: BuiltinId, left_kind: HostIntStorageKind, right_kind: HostIntStorageKind, range: HostIntRange) HostIntStorageKind {
    if (op == .mul and left_kind == .bit and right_kind == .bit and range.min >= 0 and range.max <= 1) {
        return .bit;
    }
    return hostIntStorageKindForRange(range.min, range.max);
}

