fn derivedCode(kind: DerivedVerbKind) *const Code {
    return switch (kind) {
        .each => &derived_each_code,
        .fold => &derived_fold_code,
        .scan => &derived_scan_code,
        .each_right => &derived_each_right_code,
        .each_left => &derived_each_left_code,
        .each_prior => &derived_each_prior_code,
        .grad => &derived_grad_code,
        .valuegrad => &derived_valuegrad_code,
    };
}

fn closureDerivedKind(closure: *const Closure) ?DerivedVerbKind {
    if (closure.code.bytes.len != 1 or
        closure.code.globals.len != 0 or
        closure.code.templates.len != 0 or
        closure.code.constants.len != 0)
        return null;
    return switch (closure.code.bytes[0]) {
        0 => .each,
        1 => .fold,
        2 => .scan,
        3 => .each_right,
        4 => .each_left,
        5 => .each_prior,
        6 => .grad,
        7 => .valuegrad,
        else => null,
    };
}

fn closureIsProjection(closure: *const Closure) bool {
    return closure.code.bytes.len == 1 and
        closure.code.globals.len == 0 and
        closure.code.templates.len == 0 and
        closure.code.constants.len == 0 and
        closure.code.bytes[0] == projection_code_bytes[0];
}

fn closureIsInnerProduct(closure: *const Closure) bool {
    return closure.code.bytes.len == 1 and
        closure.code.globals.len == 0 and
        closure.code.templates.len == 0 and
        closure.code.constants.len == 0 and
        closure.code.bytes[0] == inner_product_code_bytes[0];
}

const ScratchCode = struct {
    instructions: InstructionBuffer = .{},
    code: Code = .{
        .arity = 0,
        .bytes = &[_]u8{},
        .globals = &[_]u16{},
        .templates = &[_]*const LambdaTemplate{},
        .constants = &[_]Value{},
    },

    fn reset(self: *ScratchCode) void {
        self.instructions = .{};
        self.code = .{
            .arity = 0,
            .bytes = &[_]u8{},
            .globals = &[_]u16{},
            .templates = &[_]*const LambdaTemplate{},
            .constants = &[_]Value{},
        };
    }

    fn finalize(self: *ScratchCode, arity: u8) *Code {
        self.code = .{
            .arity = arity,
            .bytes = self.instructions.byteSlice(),
            .globals = self.instructions.globalSlice(),
            .templates = self.instructions.templateSlice(),
            .constants = self.instructions.constantSlice(),
        };
        return &self.code;
    }
};

fn duplicateCodeFromInstructions(allocator: std.mem.Allocator, arity: u8, instructions: *const InstructionBuffer) !*Code {
    const code = try allocator.create(Code);
    code.* = .{
        .arity = arity,
        .bytes = try allocator.dupe(u8, instructions.byteSlice()),
        .globals = try allocator.dupe(u16, instructions.globalSlice()),
        .templates = try allocator.dupe(*const LambdaTemplate, instructions.templateSlice()),
        .constants = try allocator.dupe(Value, instructions.constantSlice()),
    };
    return code;
}

fn finishCompiledInstructions(out: *InstructionBuffer, mode: PostCompileMode) KError!void {
    out.applyPostCompile(mode);
    try out.appendOp(.@"return");
}

fn tryCompileSimpleTopLevelInto(
    session: *Session,
    source: []const u8,
    code_allocator: std.mem.Allocator,
    compile_mode: CompileMode,
    instructions: *InstructionBuffer,
) KError!bool {
    var cursor: usize = 0;
    const statement = nextTopLevelStatement(source, &cursor) orelse return false;
    if (nextTopLevelStatement(source, &cursor) != null) return false;

    var compiler = try Compiler.init(session, source, code_allocator, compile_mode);
    var scope = Scope{};
    defer scope.deinit(session.allocator);

    if (!(try compiler.tryCompileSimpleExprSlice(instructions, &scope, statement))) return false;
    if (scope.arity != 0) return false;
    try finishCompiledInstructions(instructions, .top_level);
    return true;
}

