            .allocator = allocator,
            .arena = std.heap.ArenaAllocator.init(allocator),
            .scratch_arena = std.heap.ArenaAllocator.init(allocator),
            .prng = Prng.initEntropy(),
            .device_preference = device_preference,
            .global_slots = std.StringHashMap(u16).init(allocator),
            .interned_strings = std.StringHashMap(*HostText).init(allocator),
            .interned_symbols = std.StringHashMap(*HostText).init(allocator),
            .code_cache = std.StringHashMap(*const Code).init(allocator),
            .dense_autodiff_cache = std.AutoHashMap(DenseAutodiffCacheKey, DenseAutodiffLowerResult).init(allocator),
        };
    }

    pub fn deinit(self: *Session) void {
        if (self.last_result) |value| self.releaseValue(value);
        self.last_result = null;
        for (self.global_values.items, self.global_initialized.items) |value, initialized| {
            if (initialized) self.releaseValue(value);
        }
        while (self.managed_numeric_registry_head) |handle| self.recycleManagedNumericArray(handle);
        self.global_values.deinit(self.allocator);
        self.global_initialized.deinit(self.allocator);
        self.global_slots.deinit();
        self.global_names.deinit(self.allocator);
        self.interned_strings.deinit();
        self.interned_symbols.deinit();
        self.code_cache.deinit();
        self.dense_autodiff_cache.deinit();
        if (self.mlx_ctx) |*ctx| ctx.deinit();
        while (self.free_boxed_float_len > 0) {
            self.free_boxed_float_len -= 1;
            self.allocator.destroy(self.free_boxed_floats[self.free_boxed_float_len].?);
        }
        while (self.free_boxed_int_len > 0) {
            self.free_boxed_int_len -= 1;
            self.allocator.destroy(self.free_boxed_ints[self.free_boxed_int_len].?);
        }
        while (self.free_closure_len > 0) {
            self.free_closure_len -= 1;
            self.allocator.destroy(self.free_closures[self.free_closure_len].?);
        }
        while (self.free_numeric_array_len > 0) {
            self.free_numeric_array_len -= 1;
            self.allocator.destroy(self.free_numeric_arrays[self.free_numeric_array_len].?);
        }
        while (self.free_host_array_len > 0) {
            self.free_host_array_len -= 1;
            self.allocator.destroy(self.free_host_arrays[self.free_host_array_len].?);
        }
        while (self.free_mlx_array_len > 0) {
            self.free_mlx_array_len -= 1;
            self.allocator.destroy(self.free_mlx_arrays[self.free_mlx_array_len].?);
        }
        self.scratch_arena.deinit();
        self.arena.deinit();
    }

    pub fn resetStringPerf(self: *Session) void {
        if (comptime enable_string_instrumentation) self.string_perf = .{};
    }

    pub fn stringPerfSnapshot(self: *const Session) StringPerfSnapshot {
        if (comptime enable_string_instrumentation) {
            return .{
                .contains_calls = self.string_perf.contains_calls,
                .split_calls = self.string_perf.split_calls,
                .join_calls = self.string_perf.join_calls,
                .contains_opcode_ns = self.string_perf.contains_opcode_ns,
                .split_opcode_ns = self.string_perf.split_opcode_ns,
                .join_opcode_ns = self.string_perf.join_opcode_ns,
                .contains_helper_ns = self.string_perf.contains_helper_ns,
                .split_helper_ns = self.string_perf.split_helper_ns,
                .join_helper_ns = self.string_perf.join_helper_ns,
                .split_search_ns = self.string_perf.split_search_ns,
                .split_append_ns = self.string_perf.split_append_ns,
                .split_result_ns = self.string_perf.split_result_ns,
                .join_result_ns = self.string_perf.join_result_ns,
            };
        }
        return .{};
    }

    pub fn setSamplingProfileEnabled(self: *Session, enabled: bool) void {
        if (comptime !enable_sampling_profile) {
            return;
        }
        self.profile_sampling_enabled.store(@intFromBool(enabled), .unordered);
        if (!enabled) {
            self.profile_current_label.store(@intFromEnum(SamplingProfileLabel.idle), .unordered);
            self.profile_current_op.store(sampling_profile_no_op, .unordered);
            self.profile_current_code_id.store(sampling_profile_no_code, .unordered);
            self.profile_current_callable_slot.store(sampling_profile_no_callable_slot, .unordered);
        }
    }

    pub fn samplingProfileState(self: *const Session) SamplingProfileState {
        if (comptime !enable_sampling_profile) {
            return .{
                .label = .idle,
                .op = null,
                .code_id = sampling_profile_no_code,
                .callable_slot = sampling_profile_no_callable_slot,
            };
        }
        const raw_label = self.profile_current_label.load(.unordered);
        const raw_op = self.profile_current_op.load(.unordered);
        return .{
            .label = std.meta.intToEnum(SamplingProfileLabel, raw_label) catch .idle,
            .op = if (raw_op == sampling_profile_no_op)
                null
            else
                std.meta.intToEnum(DebugOp, raw_op) catch null,
            .code_id = self.profile_current_code_id.load(.unordered),
            .callable_slot = self.profile_current_callable_slot.load(.unordered),
        };
    }

    pub fn samplingProfileLabelName(label: SamplingProfileLabel) []const u8 {
        return @tagName(label);
    }

    pub fn samplingProfileCodeKindName(kind: SamplingProfileCodeKind) []const u8 {
        return @tagName(kind);
    }

    pub fn samplingProfileCodeInfo(self: *const Session, id: u16) ?SamplingProfileCodeInfo {
        if (comptime !enable_sampling_profile) {
            return null;
        }
        if (staticSamplingProfileCodeInfo(id)) |info| return info;
        if (id == sampling_profile_no_code or id >= self.profile_dynamic_code_used.len) return null;
        if (!self.profile_dynamic_code_used[id]) return null;
        return self.profile_dynamic_code_infos[id];
    }

    pub fn samplingProfileCallableName(self: *const Session, slot: u16) ?[]const u8 {
        if (comptime !enable_sampling_profile) {
            return null;
        }
        if (slot == sampling_profile_no_callable_slot or slot >= self.global_names.items.len) return null;
        return self.global_names.items[slot];
    }

    pub fn cachedCodeCount(self: *Session) usize {
        return self.code_cache.count();
    }

    pub fn evalSource(self: *Session, source: []const u8) KError!Value {
        const code = try self.compileCached(source);
        return try self.runCode(code, &[_]Value{});
    }

    pub fn evalSourceFresh(self: *Session, source: []const u8) KError!Value {
        var temp_arena = std.heap.ArenaAllocator.init(self.allocator);
        defer temp_arena.deinit();

        const code = try self.compileScratch(&temp_arena, source);
        return try self.runCode(code, &[_]Value{});
    }

    pub fn evalSourceWarm(self: *Session, compile_arena: *std.heap.ArenaAllocator, source: []const u8) KError!Value {
        const code = try self.compileScratch(compile_arena, source);
        return try self.runCode(code, &[_]Value{});
    }

    pub fn evalSourceWarmEphemeral(self: *Session, compile_arena: *std.heap.ArenaAllocator, source: []const u8) KError!Value {
        const code = try self.compileScratch(compile_arena, source);
        return try self.runCodeMode(code, &[_]Value{}, false);
    }

    pub fn parseOnly(self: *Session, source: []const u8) KError!void {
        var temp_arena = std.heap.ArenaAllocator.init(self.allocator);
        defer temp_arena.deinit();

        _ = try self.compileScratch(&temp_arena, source);
    }

    pub fn parseOnlyWarm(self: *Session, compile_arena: *std.heap.ArenaAllocator, source: []const u8) KError!void {
        _ = try self.compileScratch(compile_arena, source);
    }

    pub fn lastDenseAutodiffExecPath(self: *const Session) ?[]const u8 {
        if (comptime !enable_probe_instrumentation) return null;
        return if (self.last_dense_autodiff_exec_backend) |backend| switch (backend) {
            .host => "host",
            .mlx => "mlx",
        } else null;
    }

    pub fn compile(self: *Session, source: []const u8) KError!*const Code {
        return try self.compileCached(source);
    }

    fn compilerAssignTopLevelProfile(self: *Session, code: *Code, source: []const u8, compile_mode: CompileMode) void {
        if (comptime !enable_sampling_profile) {
            code.profile_kind = .none;
            code.profile_source = "";
            code.profile_id = sampling_profile_no_code;
            return;
        }
        code.profile_kind = .top_level;
        code.profile_source = std.mem.trim(u8, source, " \t\r\n");
        if (compile_mode != .frozen) {
            code.profile_id = sampling_profile_no_code;
            return;
        }
        code.profile_id = self.nextSamplingProfileCodeId();
        self.rememberSamplingProfileCodeInfo(code.profile_id, code.profile_kind, code.profile_source);
    }

    pub fn evalCode(self: *Session, code: *const Code) KError!Value {
        return try self.runCode(code, &[_]Value{});
    }

    pub fn evalCodeEphemeral(self: *Session, code: *const Code) KError!Value {
        return try self.runCodeMode(code, &[_]Value{}, false);
    }

    pub fn forceValue(self: *Session, value: Value) KError!void {
        _ = self;
        switch (value.tag()) {
            .array => switch (value.arrayKind()) {
                .mlx_array => {
                    var owned = value.asMlxArray().array.clone() catch |err| return mapMlxError(err);
                    defer owned.deinit();
                    owned.eval() catch |err| return mapMlxError(err);
                },
                .numeric_array => {
                    if (value.asNumericArray().mlx) |array| {
                        var owned = array.array.clone() catch |err| return mapMlxError(err);
                        defer owned.deinit();
                        owned.eval() catch |err| return mapMlxError(err);
                    }
                },
                .host_array, .host_string, .host_symbol, .host_string_list, .host_string_view => {},
                else => return error.Internal,
            },
            .int, .float, .bool, .builtin, .closure => {},
        }
    }

    pub fn debugScratchHostArrayAllocCount(self: *Session) usize {
        if (comptime !enable_probe_instrumentation) return 0;
        return self.debug_scratch_host_array_alloc_count;
    }

    pub fn resetDebugScratchHostArrayAllocCount(self: *Session) void {
        if (comptime !enable_probe_instrumentation) return;
        self.debug_scratch_host_array_alloc_count = 0;
    }

    pub fn debugManagedNumericHandleCount(self: *const Session) usize {
        var count: usize = 0;
        var current = self.managed_numeric_registry_head;
        while (current) |handle| : (current = handle.registry_next) {
            if (handle.header.owner == .managed and handle.tracked_in_session) count += 1;
        }
        return count;
    }

    pub fn debugDumpManagedNumericHandles(self: *const Session) void {
        if (comptime zig_builtin.target.cpu.arch == .wasm32) return;
        var current = self.managed_numeric_registry_head;
        while (current) |handle| : (current = handle.registry_next) {
            if (handle.header.owner != .managed or !handle.tracked_in_session) continue;
            var sample0: i64 = 0;
            var sample1: i64 = 0;
            if (handle.host) |host| {
                if (hostArrayNumericMode(host) == .int and host.len() > 0) sample0 = hostArrayIntAt(host, 0) catch 0;
                if (hostArrayNumericMode(host) == .int and host.len() > 1) sample1 = hostArrayIntAt(host, 1) catch 0;
            }
            std.debug.print(
                "handle {*}: structural={s} ref={d} rank={d} host={} mlx={} sample={d},{d} last={}\n",
                .{
                    handle,
                    @tagName(handle.structural),
                    handle.header.ref_count,
                    handle.rank,
                    handle.host != null,
                    handle.mlx != null,
                    sample0,
                    sample1,
                    if (self.last_result) |value|
                        (value.tag() == .array and value.arraySubkind() == .numeric_array and value.asNumericArray() == handle)
                    else
                        false,
                },
            );
        }
    }

