    pub fn setGlobalHostIntVector(self: *Session, name: []const u8, data: []const i64) !void {
        const value = try self.createManagedHostIntArray(data);
        defer self.releaseValue(value);
        try self.storeGlobalSlot(try self.internGlobalSlot(name), value);
    }

    pub fn setGlobalHostBitVector(self: *Session, name: []const u8, data: []const bool) !void {
        const value = try self.createManagedHostBitArray(data);
