    pub fn setGlobalHostStringList(self: *Session, name: []const u8, items: []const []const u8) !void {
        const value = try self.createManagedHostStringListFromSlices(items);
        defer self.releaseValue(value);
        try self.storeGlobalSlot(try self.internGlobalSlot(name), value);
