    inline fn readOp(frame: *CallFrame) KError!Op {
        const byte = try readByte(frame);
        return std.meta.intToEnum(Op, byte) catch error.Internal;
    }

    inline fn readByte(frame: *CallFrame) KError!u8 {
        if (frame.ip >= frame.code.bytes.len) return error.Internal;
        const value = frame.code.bytes[frame.ip];
        frame.ip += 1;
        return value;
    }

    inline fn readU64(frame: *CallFrame) KError!u64 {
        const end = frame.ip + 8;
        if (end > frame.code.bytes.len) return error.Internal;
        var value: u64 = 0;
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) {
            value |= @as(u64, frame.code.bytes[frame.ip + idx]) << @intCast(idx * 8);
        }
        frame.ip = end;
        return value;
    }

    inline fn readI64(frame: *CallFrame) KError!i64 {
        return @bitCast(try readU64(frame));
    }

    inline fn readU16(frame: *CallFrame) KError!usize {
        const lo = try readByte(frame);
        const hi = try readByte(frame);
        return @as(usize, lo) | (@as(usize, hi) << 8);
    }

    inline fn readGlobalSlot(frame: *CallFrame) KError!u16 {
        const slot = try readByte(frame);
        if (slot >= frame.code.globals.len) return error.Internal;
        return frame.code.globals[slot];
    }

    inline fn readTemplate(frame: *CallFrame) KError!*const LambdaTemplate {
        const slot = try readByte(frame);
        if (slot >= frame.code.templates.len) return error.Internal;
        return frame.code.templates[slot];
    }

    inline fn readConstant(frame: *CallFrame) KError!Value {
        const slot = try readByte(frame);
        if (slot >= frame.code.constants.len) return error.Internal;
        return frame.code.constants[slot];
    }

    fn readLocal(self: *Session, frame: *const CallFrame, slot: u8) KError!Value {
        const index = frame.base + slot;
        if (index >= self.stack_len) return error.Internal;
        return self.stack[index];
    }

    fn readInlineLocal(self: *Session, slot: u8) KError!Value {
        const base = self.currentInlineBase() orelse return error.Internal;
        const index = base + slot;
        if (index >= self.stack_len) return error.Internal;
        return self.stack[index];
    }

    fn readCapture(self: *Session, frame: *const CallFrame, slot: u8) KError!Value {
        _ = self;
        if (slot >= frame.captures.len) return error.Internal;
        return frame.captures[slot];
    }

    fn currentInlineBase(self: *const Session) ?usize {
        if (self.inline_len == 0) return null;
        return self.inline_bases[self.inline_len - 1];
    }

    fn retainedFrameOwner(self: *Session, value: Value) ?Value {
        return if (isManagedValue(value)) self.retainValue(value) else null;
    }

    fn pushInlineBase(self: *Session, argc: u8) KError!void {
        const argc_usize: usize = argc;
        if (self.stack_len < argc_usize) return error.Internal;
        if (self.inline_len >= self.inline_bases.len) return error.Unsupported;
        self.inline_bases[self.inline_len] = self.stack_len - argc_usize;
        self.inline_len += 1;
    }

    fn leaveInline(self: *Session, argc: u8) KError!void {
        _ = argc;
        if (self.inline_len == 0 or self.stack_len == 0) return error.Internal;
        const base = self.inline_bases[self.inline_len - 1];
        self.inline_len -= 1;
        const result = self.pop();
        if (base > self.stack_len) return error.Internal;
        self.dropStackFrom(base);
        try self.push(result);
    }

    fn instantiateLambda(self: *Session, template: *const LambdaTemplate, frame: *const CallFrame) KError!*const Closure {
        return try self.allocManagedClosure(template.code, try self.resolveTemplateCaptures(template, frame, true));
    }

    fn resolveTemplateCaptures(
        self: *Session,
        template: *const LambdaTemplate,
        frame: *const CallFrame,
        comptime stabilize: bool,
    ) KError![]const Value {
        if (template.captures.len == 0) return &[_]Value{};

        const owned_allocator = if (stabilize) self.allocator else self.scratch_arena.allocator();
        const captures = try owned_allocator.alloc(Value, template.captures.len);
        for (template.captures, 0..) |capture, idx| {
            const value = switch (capture) {
                .local => |slot| blk: {
                    const stack_index = frame.base + slot;
                    if (stack_index >= self.stack_len) return error.Internal;
                    break :blk self.stack[stack_index];
                },
                .inline_local => |slot| blk: {
                    const base = self.currentInlineBase() orelse return error.Internal;
                    const stack_index = base + slot;
                    if (stack_index >= self.stack_len) return error.Internal;
                    break :blk self.stack[stack_index];
                },
                .capture => |slot| blk: {
                    if (slot >= frame.captures.len) return error.Internal;
                    break :blk frame.captures[slot];
                },
            };
            captures[idx] = if (stabilize) try self.retainEscapedValue(value) else value;
        }
        return captures;
    }

    fn replaceCurrentFrameWithClosure1(self: *Session, frame_index: usize, owner: Value, closure: *const Closure, arg0: Value) KError!void {
        const retained_owner = self.retainValue(owner);
        const retained_arg0 = self.retainValue(arg0);
        const base = self.frames[frame_index].base;
        const old_owner = self.frames[frame_index].owner;
        self.dropStackFrom(base);
        if (old_owner) |owned| self.releaseValue(owned);
        self.stack_len = base;
        try self.push(retained_arg0);
        self.frames[frame_index] = .{
            .code = closure.code,
            .ip = 0,
            .base = base,
            .captures = closure.captures,
            .owner = retained_owner,
            .callable_global_slot = sampling_profile_no_callable_slot,
        };
    }

    fn replaceCurrentFrameWithBorrowedClosure1(self: *Session, frame_index: usize, callee: Value, closure: *const Closure, callable_slot: u16) KError!void {
        if (self.stack_len < 1) return error.Internal;

        const base = self.frames[frame_index].base;
        const arg0_index = self.stack_len - 1;
        const arg0 = self.stack[arg0_index];
        const old_owner = self.frames[frame_index].owner;

        var idx = self.stack_len;
        while (idx > base) {
            idx -= 1;
            if (idx == arg0_index) continue;
            self.releaseValue(self.stack[idx]);
        }

        self.stack[base] = arg0;
        self.stack_len = base + 1;
        if (old_owner) |owned| self.releaseValue(owned);
        self.frames[frame_index] = .{
            .code = closure.code,
            .ip = 0,
            .base = base,
            .captures = closure.captures,
            .owner = self.retainedFrameOwner(callee),
            .callable_global_slot = callable_slot,
        };
    }

    fn replaceCurrentFrameWithClosure2(self: *Session, frame_index: usize, owner: Value, closure: *const Closure, arg0: Value, arg1: Value) KError!void {
        const retained_owner = self.retainValue(owner);
        const retained_arg0 = self.retainValue(arg0);
        const retained_arg1 = self.retainValue(arg1);
        const base = self.frames[frame_index].base;
        const old_owner = self.frames[frame_index].owner;
        self.dropStackFrom(base);
        if (old_owner) |owned| self.releaseValue(owned);
        self.stack_len = base;
        try self.push(retained_arg0);
        try self.push(retained_arg1);
        self.frames[frame_index] = .{
            .code = closure.code,
            .ip = 0,
            .base = base,
            .captures = closure.captures,
            .owner = retained_owner,
            .callable_global_slot = sampling_profile_no_callable_slot,
        };
    }

    // Tail global calls can keep current-frame args in place and only borrow the callee.
    fn replaceCurrentFrameWithBorrowedClosure2(self: *Session, frame_index: usize, callee: Value, closure: *const Closure, callable_slot: u16) KError!void {
        if (self.stack_len < 2) return error.Internal;

        const base = self.frames[frame_index].base;
        const arg0_index = self.stack_len - 2;
        const arg1_index = self.stack_len - 1;
        const arg0 = self.stack[arg0_index];
        const arg1 = self.stack[arg1_index];
        const old_owner = self.frames[frame_index].owner;

        var idx = self.stack_len;
        while (idx > base) {
            idx -= 1;
            if (idx == arg0_index or idx == arg1_index) continue;
            self.releaseValue(self.stack[idx]);
        }

        self.stack[base] = arg0;
        self.stack[base + 1] = arg1;
        self.stack_len = base + 2;
        if (old_owner) |owned| self.releaseValue(owned);
        self.frames[frame_index] = .{
            .code = closure.code,
            .ip = 0,
            .base = base,
            .captures = closure.captures,
            .owner = self.retainedFrameOwner(callee),
            .callable_global_slot = callable_slot,
        };
    }

    // Tail stack calls consume the callee slot into frame ownership instead of re-retaining it.
    fn replaceCurrentFrameWithConsumedClosure1(self: *Session, frame_index: usize, callee: Value, closure: *const Closure) KError!void {
        if (self.stack_len < 2) return error.Internal;

        const base = self.frames[frame_index].base;
        const callee_index = self.stack_len - 2;
        const arg0_index = self.stack_len - 1;
        const arg0 = self.stack[arg0_index];
        const old_owner = self.frames[frame_index].owner;

        var idx = self.stack_len;
        while (idx > base) {
            idx -= 1;
            if (idx == callee_index or idx == arg0_index) continue;
            self.releaseValue(self.stack[idx]);
        }

        self.stack[base] = arg0;
        self.stack_len = base + 1;
        if (old_owner) |owned| self.releaseValue(owned);
        self.frames[frame_index] = .{
            .code = closure.code,
            .ip = 0,
            .base = base,
            .captures = closure.captures,
            .owner = callee,
            .callable_global_slot = sampling_profile_no_callable_slot,
        };
    }

    fn replaceCurrentFrameWithConsumedClosure2(self: *Session, frame_index: usize, callee: Value, closure: *const Closure) KError!void {
        if (self.stack_len < 3) return error.Internal;

        const base = self.frames[frame_index].base;
        const callee_index = self.stack_len - 3;
        const arg0_index = self.stack_len - 2;
        const arg1_index = self.stack_len - 1;
        const arg0 = self.stack[arg0_index];
        const arg1 = self.stack[arg1_index];
        const old_owner = self.frames[frame_index].owner;

        var idx = self.stack_len;
        while (idx > base) {
            idx -= 1;
            if (idx == callee_index or idx == arg0_index or idx == arg1_index) continue;
            self.releaseValue(self.stack[idx]);
        }

        self.stack[base] = arg0;
        self.stack[base + 1] = arg1;
        self.stack_len = base + 2;
        if (old_owner) |owned| self.releaseValue(owned);
        self.frames[frame_index] = .{
            .code = closure.code,
            .ip = 0,
            .base = base,
            .captures = closure.captures,
            .owner = callee,
            .callable_global_slot = sampling_profile_no_callable_slot,
        };
    }

    inline fn directBinaryArg(arg0: Value, arg1: Value, slot: u8) ?Value {
        return switch (slot) {
            0 => arg0,
            1 => arg1,
            else => null,
        };
    }

    inline fn directReadI64(bytes: []const u8, start: usize) ?i64 {
        const end = start + 8;
        if (end > bytes.len) return null;
        var value: u64 = 0;
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) {
            value |= @as(u64, bytes[start + idx]) << @intCast(idx * 8);
        }
        return @bitCast(value);
    }

    inline fn directReadU16(bytes: []const u8, start: usize) ?u16 {
        const end = start + 2;
        if (end > bytes.len) return null;
        return @as(u16, bytes[start]) | (@as(u16, bytes[start + 1]) << 8);
    }

    const DirectConditionalAtom = enum {
        arg0,
        arg1,
        zero,
    };

const DenseElementwiseKind = union(enum) {
        dyad: struct {
            op: BuiltinId,
            swap: bool,
        },
        keep_left_if_more,
    };

    const DirectUnarySelfTransform = enum {
        grade_up,
        grade_down,
    };

    const DirectUnaryLiftedKind = struct {
        base: Value,
        transform: DirectUnarySelfTransform,
    };

    fn classifyDenseBuiltin(op: BuiltinId) ?DenseElementwiseKind {
        return switch (op) {
            .add, .sub, .mul, .minimum, .maximum, .less, .more => .{ .dyad = .{ .op = op, .swap = false } },
            else => null,
        };
    }

    fn applyDenseElementwiseKind(self: *Session, kind: DenseElementwiseKind, arg0: Value, arg1: Value) KError!Value {
        return switch (kind) {
            .dyad => |dyad| blk: {
                const left = if (dyad.swap) arg1 else arg0;
                const right = if (dyad.swap) arg0 else arg1;
                break :blk switch (dyad.op) {
                    .add => try self.addValues(left, right),
                    .sub => try self.subValues(left, right),
                    .mul => try self.mulValues(left, right),
                    .minimum => blk2: {
                        const mask = try self.lessValues(left, right);
                        defer self.releaseValue(mask);
                        const delta = try self.subValues(left, right);
                        defer self.releaseValue(delta);
                        const kept = try self.mulValues(mask, delta);
                        defer self.releaseValue(kept);
                        break :blk2 try self.addValues(right, kept);
                    },
                    .maximum => blk2: {
                        const mask = try self.moreValues(left, right);
                        defer self.releaseValue(mask);
                        const delta = try self.subValues(left, right);
                        defer self.releaseValue(delta);
                        const kept = try self.mulValues(mask, delta);
                        defer self.releaseValue(kept);
                        break :blk2 try self.addValues(right, kept);
                    },
                    .less => try self.lessValues(left, right),
                    .more => try self.moreValues(left, right),
                    else => return error.Internal,
                };
            },
            .keep_left_if_more => blk: {
                const mask = try self.moreValues(arg0, arg1);
                defer self.releaseValue(mask);
                break :blk try self.mulValues(arg0, mask);
            },
        };
    }

    fn classifyDirectCompareClosure2(bytes: []const u8) ?DenseElementwiseKind {
        if (bytes.len != 6 or bytes[5] != @intFromEnum(Op.@"return")) return null;
        const left_load: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        const right_load: Op = std.meta.intToEnum(Op, bytes[2]) catch return null;
        if (left_load != .load_local or right_load != .load_local) return null;
        const left_slot = bytes[1];
        const right_slot = bytes[3];
        if (!((left_slot == 0 and right_slot == 1) or (left_slot == 1 and right_slot == 0))) return null;
        const cmp: Op = std.meta.intToEnum(Op, bytes[4]) catch return null;
        const op: BuiltinId = switch (cmp) {
            .less => .less,
            .more => .more,
            else => return null,
        };
        return .{ .dyad = .{
            .op = op,
            .swap = left_slot == 1,
        } };
    }

    fn directReadConditionalAtom(bytes: []const u8, idx: *usize) ?DirectConditionalAtom {
        if (idx.* >= bytes.len) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.*]) catch return null;
        switch (op) {
            .load_local => {
                if (idx.* + 2 > bytes.len) return null;
                const slot = bytes[idx.* + 1];
                idx.* += 2;
                return switch (slot) {
                    0 => .arg0,
                    1 => .arg1,
                    else => null,
                };
            },
            .const_int => {
                const value = directReadI64(bytes, idx.* + 1) orelse return null;
                if (value != 0) return null;
                idx.* += 9;
                return .zero;
            },
            else => return null,
        }
    }

    fn tryApplyDirectConditionalClosure2(self: *Session, bytes: []const u8, arg0: Value, arg1: Value) KError!?Value {
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const lhs = directReadConditionalAtom(bytes, &idx) orelse return null;
        const rhs = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (lhs != .arg0 or rhs != .arg1 or idx >= bytes.len) return null;

        const cmp: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (cmp != .more and cmp != .less) return null;
        idx += 1;

        if (idx + 3 > bytes.len or bytes[idx] != @intFromEnum(Op.jump_if_false)) return null;
        const false_target = directReadU16(bytes, idx + 1) orelse return null;
        idx += 3;

        const when_true = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (idx + 3 > bytes.len or bytes[idx] != @intFromEnum(Op.jump)) return null;
        const end_target = directReadU16(bytes, idx + 1) orelse return null;
        idx += 3;
        if (false_target != idx) return null;

        const when_false = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (end_target != idx or idx != bytes.len - 1) return null;

        return switch (when_true) {
            .arg0 => switch (when_false) {
                .arg1 => blk: {
                    const mask = switch (cmp) {
                        .more => try self.moreValues(arg0, arg1),
                        .less => try self.lessValues(arg0, arg1),
                        else => unreachable,
                    };
                    defer self.releaseValue(mask);
                    const delta = try self.subValues(arg0, arg1);
                    defer self.releaseValue(delta);
                    const kept = try self.mulValues(mask, delta);
                    defer self.releaseValue(kept);
                    break :blk try self.addValues(arg1, kept);
                },
                .zero => if (cmp == .more) blk: {
                    const mask = try self.moreValues(arg0, arg1);
                    defer self.releaseValue(mask);
                    break :blk try self.mulValues(arg0, mask);
                } else null,
                else => null,
            },
            else => null,
        };
    }

    fn classifyDenseConditionalClosure2(bytes: []const u8) ?DenseElementwiseKind {
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const lhs = directReadConditionalAtom(bytes, &idx) orelse return null;
        const rhs = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (lhs != .arg0 or rhs != .arg1 or idx >= bytes.len) return null;

        const cmp: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (cmp != .more and cmp != .less) return null;
        idx += 1;

        if (idx + 3 > bytes.len or bytes[idx] != @intFromEnum(Op.jump_if_false)) return null;
        const false_target = directReadU16(bytes, idx + 1) orelse return null;
        idx += 3;

        const when_true = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (idx + 3 > bytes.len or bytes[idx] != @intFromEnum(Op.jump)) return null;
        const end_target = directReadU16(bytes, idx + 1) orelse return null;
        idx += 3;
        if (false_target != idx) return null;

        const when_false = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (end_target != idx or idx != bytes.len - 1) return null;

        return switch (when_true) {
            .arg0 => switch (when_false) {
                .arg1 => switch (cmp) {
                    .more => .{ .dyad = .{ .op = .maximum, .swap = false } },
                    .less => .{ .dyad = .{ .op = .minimum, .swap = false } },
                    else => null,
                },
                .zero => if (cmp == .more) .keep_left_if_more else null,
                else => null,
            },
            else => null,
        };
    }

    fn classifyDenseElementwiseClosure(closure: *const Closure) ?DenseElementwiseKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const bytes = closure.code.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        const op: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        switch (op) {
            .add_local_local, .sub_local_local, .mul_local_local => {
                if (bytes.len != 4) return null;
                const left_slot = bytes[1];
                const right_slot = bytes[2];
                if (!((left_slot == 0 and right_slot == 1) or (left_slot == 1 and right_slot == 0))) return null;
                return .{ .dyad = .{
                    .op = switch (op) {
                        .add_local_local => .add,
                        .sub_local_local => .sub,
                        .mul_local_local => .mul,
                        else => unreachable,
                    },
                    .swap = left_slot == 1,
                } };
            },
            .load_local => return classifyDenseConditionalClosure2(bytes),
            else => return null,
        }
    }

    fn classifyDenseElementwiseWrapperClosure(self: *Session, closure: *const Closure) KError!?DenseElementwiseKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const bytes = closure.code.bytes;
        if (bytes.len < 8 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const base_value = blk: {
            const op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
            switch (op) {
                .const_builtin => {
                    if (idx + 2 > bytes.len) return null;
                    const builtin: BuiltinId = @enumFromInt(bytes[idx + 1]);
                    idx += 2;
                    break :blk Value.builtin(builtin);
                },
                .const_value => {
                    if (idx + 2 > bytes.len) return null;
                    const slot = bytes[idx + 1];
                    if (slot >= closure.code.constants.len) return null;
                    idx += 2;
                    break :blk closure.code.constants[slot];
                },
                .load_global => {
                    if (idx + 2 > bytes.len) return null;
                    const slot_idx = bytes[idx + 1];
                    if (slot_idx >= closure.code.globals.len) return null;
                    idx += 2;
                    break :blk try self.loadGlobalSlot(closure.code.globals[slot_idx]);
                },
                else => return null,
            }
        };

        if (idx + 8 != bytes.len) return null;
        if (bytes[idx] != @intFromEnum(Op.make_adverb)) return null;
        const kind: DerivedVerbKind = @enumFromInt(bytes[idx + 1]);
        if (kind != .each) return null;
        idx += 2;
        if (bytes[idx] != @intFromEnum(Op.load_local) or bytes[idx + 1] != 0) return null;
        idx += 2;
        if (bytes[idx] != @intFromEnum(Op.load_local) or bytes[idx + 1] != 1) return null;
        idx += 2;
        const call_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (call_op != .call2 and call_op != .tail_call2) return null;

        return try self.classifyDenseElementwiseBaseRuntime(base_value);
    }

    fn classifyDenseElementwiseClosureRuntime(self: *Session, closure: *const Closure) KError!?DenseElementwiseKind {
        if (classifyDenseElementwiseClosure(closure)) |kind| return kind;
        if (classifyDirectCompareClosure2(closure.code.bytes)) |kind| return kind;
        return try self.classifyDenseElementwiseWrapperClosure(closure);
    }

    fn classifyDenseElementwiseBaseRuntime(self: *Session, base: Value) KError!?DenseElementwiseKind {
        return switch (base.tag()) {
            .builtin => classifyDenseBuiltin(base.asBuiltin()),
            .closure => try self.classifyDenseElementwiseClosureRuntime(base.asClosure()),
            else => null,
        };
    }

    fn directReadClosureBaseValue(self: *Session, closure: *const Closure, bytes: []const u8, idx: *usize) KError!?Value {
        if (idx.* >= bytes.len) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.*]) catch return null;
        return switch (op) {
            .const_builtin => blk: {
                if (idx.* + 2 > bytes.len) return null;
                const builtin: BuiltinId = @enumFromInt(bytes[idx.* + 1]);
                idx.* += 2;
                break :blk Value.builtin(builtin);
            },
            .const_value => blk: {
                if (idx.* + 2 > bytes.len) return null;
                const slot = bytes[idx.* + 1];
                if (slot >= closure.code.constants.len) return null;
                idx.* += 2;
                break :blk closure.code.constants[slot];
            },
            .load_global => blk: {
                if (idx.* + 2 > bytes.len) return null;
                const slot_idx = bytes[idx.* + 1];
                if (slot_idx >= closure.code.globals.len) return null;
                idx.* += 2;
                break :blk try self.loadGlobalSlot(closure.code.globals[slot_idx]);
            },
            else => null,
        };
    }

    fn directReadScalarValue(self: *Session, closure: *const Closure, bytes: []const u8, idx: *usize) KError!?Value {
        if (idx.* >= bytes.len) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.*]) catch return null;
        return switch (op) {
            .const_false => blk: {
                idx.* += 1;
                break :blk Value.fromBool(false);
            },
            .const_true => blk: {
                idx.* += 1;
                break :blk Value.fromBool(true);
            },
            .const_int => blk: {
                const value = directReadI64(bytes, idx.* + 1) orelse return null;
                idx.* += 9;
                break :blk try self.intValue(value);
            },
            .const_value, .load_global => blk: {
                const value = (try self.directReadClosureBaseValue(closure, bytes, idx)) orelse return null;
                break :blk switch (value.tag()) {
                    .int, .bool, .float => value,
                    else => null,
                };
            },
            else => null,
        };
    }

    fn directReadUnarySelfTransform(bytes: []const u8, idx: *usize) ?DirectUnarySelfTransform {
        if (idx.* + 3 > bytes.len) return null;
        if (bytes[idx.*] != @intFromEnum(Op.load_local) or bytes[idx.* + 1] != 0) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.* + 2]) catch return null;
        idx.* += 3;
        return switch (op) {
            .grade_up => .grade_up,
            .grade_down => .grade_down,
            else => null,
        };
    }

    fn classifyDirectUnaryLiftedClosure(self: *Session, closure: *const Closure) KError!?DirectUnaryLiftedKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const bytes = closure.code.bytes;
        if (bytes.len < 10 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const base_value = (try self.directReadClosureBaseValue(closure, bytes, &idx)) orelse return null;
        if (idx >= bytes.len or bytes[idx] != @intFromEnum(Op.make_adverb)) return null;
        if (idx + 2 > bytes.len) return null;
        const kind: DerivedVerbKind = @enumFromInt(bytes[idx + 1]);
        if (kind != .each_right) return null;
        idx += 2;

        const transform = directReadUnarySelfTransform(bytes, &idx) orelse return null;
        const second = directReadUnarySelfTransform(bytes, &idx) orelse return null;
        if (transform != second) return null;

        if (idx + 2 != bytes.len) return null;
        const call_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (call_op != .call2 and call_op != .tail_call2) return null;

        _ = try self.classifyDenseElementwiseBaseRuntime(base_value) orelse return null;
        return .{ .base = base_value, .transform = transform };
    }

    fn applyDirectUnaryLiftedKind(self: *Session, kind: DirectUnaryLiftedKind, arg0: Value) KError!Value {
        const transformed = switch (kind.transform) {
            .grade_up => try self.gradeValue(arg0, true),
            .grade_down => try self.gradeValue(arg0, false),
        };
        defer self.releaseValue(transformed);
        return try self.applyEachRightDerived(kind.base, &[_]Value{ transformed, transformed });
    }

    fn tryApplyDirectUnaryScaledGlobalCall1(self: *Session, closure: *const Closure, arg0: Value) KError!?Value {
        const bytes = closure.code.bytes;
        if (bytes.len < 9 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        if (bytes[idx] != @intFromEnum(Op.load_local) or bytes[idx + 1] != 0) return null;
        idx += 2;

        const scale = (try self.directReadScalarValue(closure, bytes, &idx)) orelse return null;

        if (idx + 7 != bytes.len) return null;
        if (bytes[idx] != @intFromEnum(Op.load_local) or bytes[idx + 1] != 0) return null;
        idx += 2;

        const call_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (call_op != .call_global1 and call_op != .tail_call_global1) return null;
        const global_idx = bytes[idx + 1];
        if (global_idx >= closure.code.globals.len) return error.Internal;
        idx += 2;

        const mul_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (mul_op != .mul) return null;
        idx += 1;

        const final_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (final_op != .add and final_op != .sub) return null;

        const called = (try self.tryApplyDirectGlobalCall1(closure.code.globals[global_idx], arg0)) orelse return null;
        defer self.releaseValue(called);
        const scaled = try self.mulValues(scale, called);
        defer self.releaseValue(scaled);
        return switch (final_op) {
            .add => try self.addValues(arg0, scaled),
            .sub => try self.subValues(arg0, scaled),
            else => unreachable,
        };
    }

    fn tryApplyDirectGlobalCall1(self: *Session, slot: u16, arg0: Value) KError!?Value {
        const callee = try self.loadGlobalSlot(slot);
        return switch (callee.tag()) {
            .builtin => try self.applyBuiltinCall(callee.asBuiltin(), &[_]Value{arg0}),
            .closure => blk: {
                const closure = callee.asClosure();
                if (try self.applyDerivedClosure(closure, &[_]Value{arg0})) |result| break :blk result;
                if (closure.code.arity != 1) return error.Arity;
                break :blk try self.tryApplyDirectClosure1(closure, arg0);
            },
            .array => try self.applyArrayCall1(callee, arg0),
            else => error.Type,
        };
    }

    fn tryApplyDirectGlobalCall2(self: *Session, slot: u16, arg0: Value, arg1: Value) KError!?Value {
        const callee = try self.loadGlobalSlot(slot);
        return switch (callee.tag()) {
            .builtin => try self.applyBuiltinCall(callee.asBuiltin(), &[_]Value{ arg0, arg1 }),
            .closure => blk: {
                const closure = callee.asClosure();
                if (try self.applyDerivedClosure(closure, &[_]Value{ arg0, arg1 })) |result| break :blk result;
                if (closure.code.arity != 2) return error.Arity;
                break :blk try self.tryApplyDirectClosure2(closure, arg0, arg1);
            },
            .array => error.Arity,
            else => error.Type,
        };
    }

    fn tryApplyDirectClosure1(self: *Session, closure: *const Closure, arg0: Value) KError!?Value {
        if (closure.header.owner != .frozen) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_not_frozen_count += 1;
            return null;
        }
        if (closure.captures.len != 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_captures_count += 1;
            return null;
        }
        const bytes = closure.code.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const op: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        var result: ?Value = switch (op) {
            .neg_local => blk: {
                if (bytes.len != 3 or bytes[1] != 0) break :blk null;
                break :blk try self.negateValue(arg0);
            },
            .sqrt_local => blk: {
                if (bytes.len != 3 or bytes[1] != 0) break :blk null;
                break :blk try self.sqrtValue(arg0);
            },
            .add_local_const, .sub_local_const, .mul_local_const => blk: {
                if (bytes.len != 11 or bytes[1] != 0) break :blk null;
                const rhs = directReadI64(bytes, 2) orelse break :blk null;
                const right = try self.intValue(rhs);
                break :blk switch (op) {
                    .add_local_const => try self.addValues(arg0, right),
                    .sub_local_const => try self.subValues(arg0, right),
                    .mul_local_const => try self.mulValues(arg0, right),
                    else => unreachable,
                };
            },
            .add_const_local, .sub_const_local, .mul_const_local => blk: {
                if (bytes.len != 11 or bytes[9] != 0) break :blk null;
                const lhs = directReadI64(bytes, 1) orelse break :blk null;
                const left = try self.intValue(lhs);
                break :blk switch (op) {
                    .add_const_local => try self.addValues(left, arg0),
                    .sub_const_local => try self.subValues(left, arg0),
                    .mul_const_local => try self.mulValues(left, arg0),
                    else => unreachable,
                };
            },
            .tail_call_global1 => blk: {
                if (bytes.len != 3) break :blk null;
                const global_idx = bytes[1];
                if (global_idx >= closure.code.globals.len) return error.Internal;
                break :blk try self.tryApplyDirectGlobalCall1(closure.code.globals[global_idx], arg0);
            },
            else => null,
        };
        if (result == null) {
            result = try self.tryApplyDirectUnaryScaledGlobalCall1(closure, arg0);
        }
        if (result == null) {
            if (try self.classifyDirectUnaryLiftedClosure(closure)) |kind| {
                result = try self.applyDirectUnaryLiftedKind(kind, arg0);
            }
        }
        if (self.debugDetailedProbeActive()) {
            if (result != null) self.debug_direct_closure1_hit_count += 1 else self.debug_direct_closure_miss_unsupported_shape_count += 1;
        }
        return result;
    }

    fn tryApplyDirectClosure2(self: *Session, closure: *const Closure, arg0: Value, arg1: Value) KError!?Value {
        if (closure.header.owner != .frozen) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_not_frozen_count += 1;
            return null;
        }
        if (closure.captures.len != 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_captures_count += 1;
            return null;
        }
        const bytes = closure.code.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const op: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        var result: ?Value = switch (op) {
            .add_local_local, .sub_local_local, .mul_local_local => blk: {
                if (bytes.len != 4) break :blk null;
                const left = directBinaryArg(arg0, arg1, bytes[1]) orelse break :blk null;
                const right = directBinaryArg(arg0, arg1, bytes[2]) orelse break :blk null;
                break :blk switch (op) {
                    .add_local_local => try self.addValues(left, right),
                    .sub_local_local => try self.subValues(left, right),
                    .mul_local_local => try self.mulValues(left, right),
                    else => unreachable,
                };
            },
            .tail_call_global2 => blk: {
                if (bytes.len != 3) break :blk null;
                const global_idx = bytes[1];
                if (global_idx >= closure.code.globals.len) return error.Internal;
                break :blk try self.tryApplyDirectGlobalCall2(closure.code.globals[global_idx], arg0, arg1);
            },
            else => null,
        };
        if (result == null and op == .load_local) {
            result = try self.tryApplyDirectConditionalClosure2(bytes, arg0, arg1);
            if (result == null) {
                if (classifyDirectCompareClosure2(bytes)) |kind| {
                    result = try self.applyDenseElementwiseKind(kind, arg0, arg1);
                }
            }
        }
        if (self.debugDetailedProbeActive()) {
            if (result != null) self.debug_direct_closure2_hit_count += 1 else self.debug_direct_closure_miss_unsupported_shape_count += 1;
        }
        return result;
    }

    fn tryApplyDirectClosure3(self: *Session, closure: *const Closure, arg0: Value, arg1: Value, arg2: Value) KError!?Value {
        if (closure.header.owner != .frozen) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_not_frozen_count += 1;
            return null;
        }
        if (closure.captures.len != 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_captures_count += 1;
            return null;
        }
        const bytes = closure.code.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const op: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        const result: ?Value = switch (op) {
            .add_local_local => blk: {
                if (bytes.len != 7 or bytes[1] != 0 or bytes[2] != 1) break :blk null;
                if (bytes[3] != @intFromEnum(Op.load_local) or bytes[4] != 2 or bytes[5] != @intFromEnum(Op.add)) break :blk null;
                const tmp = try self.addValues(arg0, arg1);
                defer self.releaseValue(tmp);
                break :blk try self.addValues(tmp, arg2);
            },
            else => null,
        };
        if (self.debugDetailedProbeActive()) {
            if (result != null) self.debug_direct_closure3_hit_count += 1 else self.debug_direct_closure_miss_unsupported_shape_count += 1;
        }
        return result;
    }

    fn hostStringListItemValue(self: *Session, list: *const HostStringList, idx: usize) KError!Value {
        if (idx >= list.len) return error.Type;
        return switch (list.storage) {
            .eager => |items| switch (items[idx]) {
                .owned => |text| try self.retainEscapedValue(Value.array(text)),
                .view => |view| blk: {
                    const base = list.base orelse return error.Internal;
                    break :blk try self.managedHostStringView(base, view);
                },
            },
            .split_scalar => |lazy| blk: {
                const base = list.base orelse return error.Internal;
                const src = hostTextBytes(base);
                var piece_idx: usize = 0;
                var start: usize = 0;
                while (std.mem.indexOfScalarPos(u8, src, start, lazy.sep)) |sep_idx| {
                    if (piece_idx == idx) break :blk try self.managedHostStringView(base, .{
                        .start = start,
                        .len = sep_idx - start,
                    });
                    piece_idx += 1;
                    start = sep_idx + 1;
                }
                if (piece_idx != idx) return error.Type;
                break :blk try self.managedHostStringView(base, .{
                    .start = start,
                    .len = src.len - start,
                });
            },
        };
    }

    fn derivedSequenceLen(value: Value) ?usize {
        if (value.tag() != .array) return null;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank == 0) return null;
            return @intCast(handle.shape[0]);
        }
        if (numericVectorLen(value)) |len| return len;
        if (value.arraySubkind() == .host_string_list) return value.asHostStringList().len;
        if (value.arraySubkind() == .host_array and hostArrayNumericMode(value.asHostArray()) == null) {
            return value.asHostArray().len();
        }
        return null;
    }

    fn derivedSequenceItemValue(self: *Session, value: Value, idx: usize) KError!Value {
        if (value.tag() != .array) return error.Type;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank > 1) {
                return (try numericValueScalarIndexValue(self, value, @intCast(idx))) orelse error.Type;
            }
        }
        if (valueNumericMatrixShape(value) != null) {
            return (try numericValueScalarIndexValue(self, value, @intCast(idx))) orelse error.Type;
        }
        if (numericVectorLen(value) != null) {
            return try self.derivedDenseVectorItemValue(value, idx);
        }
        if (value.arraySubkind() == .host_string_list) {
            return try self.hostStringListItemValue(value.asHostStringList(), idx);
        }
        if (value.arraySubkind() == .host_array and hostArrayNumericMode(value.asHostArray()) == null) {
            return try self.hostArrayIndexScalar(value.asHostArray(), @intCast(idx));
        }
        return error.Type;
    }

    fn derivedDenseVectorItemValue(self: *Session, value: Value, idx: usize) KError!Value {
        const view = try hostDenseView(self, value);
        return switch (valueNumericMode(value) orelse return error.Type) {
            .int => switch (view) {
                .scalar_int => |item| blk: {
                    if (idx != 0) return error.Internal;
                    break :blk try self.intValue(item);
                },
                .int_array => |items| try self.intValue(try hostIntDenseViewItem(items, idx)),
                else => error.Type,
            },
            .float => switch (view) {
                .scalar_float => |item| blk: {
                    if (idx != 0) return error.Internal;
                    break :blk try self.floatValue(item);
                },
                .float_array => |items| try self.floatValue(try hostFloatDenseViewItem(items, idx)),
                else => error.Type,
            },
        };
    }

    fn releaseDerivedStepArgs(self: *Session, source_args: []const Value, step_args: []const Value, start_idx: usize) void {
        for (source_args[start_idx..], start_idx..) |arg, arg_idx| {
            if (derivedSequenceLen(arg) != null) self.releaseValue(step_args[arg_idx]);
        }
    }

    fn createManagedArrayLikeFromValues(self: *Session, values: []const Value) KError!Value {
        return try self.makeArrayFromValues(values);
    }

    fn nextSamplingProfileCodeId(self: *Session) u16 {
        if (comptime !enable_sampling_profile) {
            return sampling_profile_no_code;
        }
        if (self.next_profile_code_id >= sampling_profile_max_code_count) return sampling_profile_no_code;
        const id = self.next_profile_code_id;
        self.next_profile_code_id += 1;
        return id;
    }

    fn rememberSamplingProfileCodeInfo(self: *Session, id: u16, kind: SamplingProfileCodeKind, source: []const u8) void {
        if (comptime !enable_sampling_profile) {
            return;
        }
        if (id == sampling_profile_no_code) return;
        if (staticSamplingProfileCodeInfo(id) != null) return;
        if (id >= self.profile_dynamic_code_used.len) return;
        self.profile_dynamic_code_infos[id] = .{
            .id = id,
            .kind = kind,
            .source = source,
        };
        self.profile_dynamic_code_used[id] = true;
    }

    fn invokeValueInCurrentRun(self: *Session, callee: Value, args: []const Value) KError!Value {
        const call_base = self.stack_len;
        const prior_frame_len = self.frame_len;

        try self.push(self.retainValue(callee));
        for (args) |arg| try self.push(self.retainValue(arg));

        switch (args.len) {
            1 => try self.execCall1(),
            2 => try self.execCall2(),
            else => {
                const argc = std.math.cast(u8, args.len) orelse return error.Unsupported;
                try self.execCall(argc);
            },
        }

        if (self.frame_len > prior_frame_len) {
            if (try self.runFramesUntil(prior_frame_len)) |final| return final;
        }

        if (self.stack_len != call_base + 1) return error.Internal;
        return self.pop();
    }

    fn applyDerivedBase(self: *Session, callee: Value, args: []const Value) KError!Value {
        return try self.invokeValueInCurrentRun(callee, args);
    }

    fn projectionInfoFromClosure(self: *Session, closure: *const Closure) KError!?ProjectionInfo {
        _ = self;
        if (!closureIsProjection(closure)) return null;
        if (closure.captures.len < 3) return error.Internal;
        const slot_count_i64 = scalarIntLikeValue(closure.captures[1]) orelse return error.Internal;
        const hole_mask_i64 = scalarIntLikeValue(closure.captures[2]) orelse return error.Internal;
        if (slot_count_i64 < 0) return error.Internal;
        const slot_count = std.math.cast(usize, slot_count_i64) orelse return error.Internal;
        if (slot_count > 63) return error.Unsupported;
        const hole_mask = std.math.cast(u64, hole_mask_i64) orelse return error.Internal;
        if ((hole_mask >> @intCast(slot_count)) != 0) return error.Internal;
        if (closure.captures.len != 3 + slot_count) return error.Internal;
        return .{
            .callee = closure.captures[0],
            .slot_count = slot_count,
            .hole_mask = hole_mask,
            .slot_values = closure.captures[3..],
        };
    }

    fn innerProductInfoFromClosure(self: *Session, closure: *const Closure) KError!?InnerProductInfo {
        _ = self;
        if (!closureIsInnerProduct(closure)) return null;
        if (closure.captures.len != 2) return error.Internal;
        if (closure.captures[0].tag() != .builtin or closure.captures[1].tag() != .builtin) return error.Internal;
        return .{
            .reduce = closure.captures[0].asBuiltin(),
            .map = closure.captures[1].asBuiltin(),
        };
    }

    fn valueAsDotArgs(self: *Session, value: Value) KError![]const Value {
        if (derivedSequenceLen(value)) |len| {
            const args = try self.scratch_arena.allocator().alloc(Value, len);
            for (0..len) |idx| args[idx] = try self.derivedSequenceItemValue(value, idx);
            return args;
        }
        const args = try self.scratch_arena.allocator().alloc(Value, 1);
        args[0] = value;
        return args;
    }

    fn deepIndexValue(self: *Session, base: Value, selectors: []const Value) KError!Value {
        if (selectors.len == 0) return self.shareValue(base);
        var current = try self.applyArrayCall1(base, selectors[0]);
        var idx: usize = 1;
        while (idx < selectors.len) : (idx += 1) {
            const next = try self.applyArrayCall1(current, selectors[idx]);
            self.releaseValue(current);
            current = next;
        }
        return current;
    }

    const AmendKind = enum {
        unary,
        assign,
        binary,
        deep_unary,
        deep_assign,
        deep_binary,
    };

    fn applyAmend(self: *Session, base: Value, selector: Value, kind: AmendKind, func_or_value: Value, arg: Value) KError!Value {
        return switch (kind) {
            .unary => try self.applyShallowAmend(base, selector, .unary, func_or_value, arg),
            .assign => try self.applyShallowAmend(base, selector, .assign, func_or_value, arg),
            .binary => try self.applyShallowAmend(base, selector, .binary, func_or_value, arg),
            .deep_unary, .deep_assign, .deep_binary => blk: {
                const mode: ShallowAmendMode = switch (kind) {
                    .deep_unary => .unary,
                    .deep_assign => .assign,
                    .deep_binary => .binary,
                    else => unreachable,
                };
                const selectors = try self.materializeSelectorPath(selector);
                defer self.releaseArgs(selectors);
                break :blk try self.applyDeepAmend(base, selectors, mode, func_or_value, arg);
            },
        };
    }

    const ShallowAmendMode = enum {
        unary,
        assign,
        binary,
    };

    fn materializeSelectorPath(self: *Session, selector: Value) KError![]Value {
        var items = std.ArrayList(Value).empty;
        errdefer {
            for (items.items) |value| self.releaseValue(value);
            items.deinit(self.allocator);
        }

        switch (selector.tag()) {
            .int, .bool => {
                try items.append(self.allocator, try self.retainEscapedValue(selector));
            },
            .array => switch (selector.arrayKind()) {
                .host_array, .mlx_array, .numeric_array => {
                    const array = try hostStructuralArrayValue(self, selector);
                    switch (array.storage) {
                        .boxed => |boxed| {
                            for (boxed) |value| try items.append(self.allocator, try self.retainEscapedValue(value));
                        },
                        else => {
                            const len = array.len();
                            for (0..len) |idx| {
                                try items.append(self.allocator, try self.hostArrayIndexScalar(array, @intCast(idx)));
                            }
                        },
                    }
                },
                else => return error.Type,
            },
            else => return error.Type,
        }

        return try items.toOwnedSlice(self.allocator);
    }

    fn applyDeepAmend(self: *Session, base: Value, selectors: []const Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!Value {
        if (selectors.len == 0) return error.Type;
        if (selectors.len == 1) return try self.applyShallowAmend(base, selectors[0], mode, func_or_value, arg);

        const selected = try self.applyArrayCall1(base, selectors[0]);
        defer self.releaseValue(selected);
        const amended = try self.applyDeepAmend(selected, selectors[1..], mode, func_or_value, arg);
        defer self.releaseValue(amended);
        return try self.applyShallowAmend(base, selectors[0], .assign, amended, Value.fromBool(false));
    }

    fn applyShallowAmend(self: *Session, base: Value, selector: Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!Value {
        if (base.tag() != .array) return error.Type;
        const selectors = try self.collectSelectorIndices(base, selector);
        defer self.allocator.free(selectors);

        const items = try self.materializeTopLevelItems(base);
        defer {
            for (items) |value| self.releaseValue(value);
            self.allocator.free(items);
        }

        if (selectors.len == 0) return try self.rebuildTopLevelItems(base, items);

        var rhs_items: ?[]Value = null;
        defer if (rhs_items) |values| {
            for (values) |value| self.releaseValue(value);
            self.allocator.free(values);
        };

        const rhs_source = switch (mode) {
            .assign => func_or_value,
            .binary => arg,
            .unary => Value.fromBool(false),
        };
        if (mode != .unary and rhs_source.tag() == .array) {
            const maybe = try self.tryMaterializeTopLevelItems(rhs_source);
            if (maybe) |values| rhs_items = values;
        }

        var idx: usize = 0;
        while (idx < selectors.len) : (idx += 1) {
            const target_idx = selectors[idx];
            const current = items[target_idx];
            const next = switch (mode) {
                .assign => if (rhs_items) |values|
                    if (values.len == selectors.len) values[idx] else try self.retainEscapedValue(func_or_value)
                else
                    try self.retainEscapedValue(func_or_value),
                .unary => try self.applyValue(func_or_value, &[_]Value{current}),
                .binary => blk: {
                    const rhs = if (rhs_items) |values|
                        if (values.len == selectors.len) values[idx] else arg
                    else
                        arg;
                    break :blk try self.applyValue(func_or_value, &[_]Value{ current, rhs });
                },
            };
            self.releaseValue(items[target_idx]);
            items[target_idx] = next;
        }

        return try self.rebuildTopLevelItems(base, items);
    }

    fn collectSelectorIndices(self: *Session, base: Value, selector: Value) KError![]usize {
        const top_len = try self.topLevelLen(base);
        var indices = std.ArrayList(usize).empty;
        defer indices.deinit(self.allocator);

        switch (selector.tag()) {
            .int, .bool => {
                try indices.append(self.allocator, try normalizeIndex(scalarIntLikeValue(selector).?, top_len));
            },
            .array => {
                const array = try hostStructuralArrayValue(self, selector);
                if (hostIntArrayView(array)) |view| switch (view) {
                    .bit => |bits| {
                        if (bits.len != top_len) return error.Type;
                        for (0..bits.len) |idx| {
                            if (!bitGet(bits.words, idx)) continue;
                            try indices.append(self.allocator, idx);
                        }
                    },
                    else => {
                        const len = hostIntArrayViewLen(view);
                        try indices.ensureTotalCapacity(self.allocator, len);
                        for (0..len) |idx| {
                            try indices.append(self.allocator, try normalizeIndex(hostIntViewItem(view, idx), top_len));
                        }
                    },
                } else return error.Type;
            },
            else => return error.Type,
        }

        return try indices.toOwnedSlice(self.allocator);
    }

    fn topLevelLen(self: *Session, value: Value) KError!usize {
        const array = try hostStructuralArrayValue(self, value);
        if (hostArrayNonVectorShape(array)) |shape| {
            if (shape.rank != 2) return error.Unsupported;
            return @intCast(shape.shape[0]);
        }
        return array.len();
    }

    fn materializeTopLevelItems(self: *Session, value: Value) KError![]Value {
        const array = try hostStructuralArrayValue(self, value);
        const len = try self.topLevelLen(value);
        const items = try self.allocator.alloc(Value, len);
        errdefer self.allocator.free(items);
        var initialized: usize = 0;
        errdefer {
            for (items[0..initialized]) |item| self.releaseValue(item);
        }
        for (0..len) |idx| {
            items[idx] = try self.hostArrayIndexScalar(array, @intCast(idx));
            initialized += 1;
        }
        return items;
    }

    fn tryMaterializeTopLevelItems(self: *Session, value: Value) KError!?[]Value {
        if (value.tag() != .array) return null;
        return try self.materializeTopLevelItems(value);
    }

    fn rebuildTopLevelItems(self: *Session, base: Value, items: []const Value) KError!Value {
        const rebuilt = try self.makeArrayFromValues(items);
        if (try self.promoteRenderableMatrixValue(rebuilt)) |promoted| {
            if (promoted.raw != rebuilt.raw and isManagedValue(rebuilt)) self.releaseValue(rebuilt);
            return promoted;
        }
        if (valueNumericMatrixShape(base)) |shape| {
            return try applyNonVectorNumericShapeToValue(self, rebuilt, numericShapeSnapshotMatrix(shape.rows, shape.cols));
        }
        return rebuilt;
    }

    fn applyDot(self: *Session, left: Value, right: Value) KError!Value {
        return switch (left.tag()) {
            .builtin, .closure => try self.applyValue(left, try self.valueAsDotArgs(right)),
            .array => try self.deepIndexValue(left, try self.valueAsDotArgs(right)),
            else => error.Type,
        };
    }

    fn applyProjectionClosure(self: *Session, info: ProjectionInfo, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_projection);
        defer profile_scope.end();
        if (self.debugDetailedProbeActive()) self.debug_apply_projection_count += 1;
        const full_slot_values = try self.scratch_arena.allocator().alloc(Value, info.slot_count);
        var next_hole_mask: u64 = 0;
        var arg_idx: usize = 0;

        for (0..info.slot_count) |slot_idx| {
            if (((info.hole_mask >> @intCast(slot_idx)) & 1) != 0) {
                if (arg_idx < args.len) {
                    full_slot_values[slot_idx] = args[arg_idx];
                    arg_idx += 1;
                } else {
                    full_slot_values[slot_idx] = Value.fromBool(false);
                    next_hole_mask |= (@as(u64, 1) << @intCast(slot_idx));
                }
            } else {
                full_slot_values[slot_idx] = info.slot_values[slot_idx];
            }
        }

        if (next_hole_mask != 0) {
            return try self.allocManagedProjectionClosure(
                info.callee,
                std.math.cast(u8, info.slot_count) orelse return error.Unsupported,
                next_hole_mask,
                full_slot_values,
            );
        }

        const extra_count = args.len - arg_idx;
        const apply_args = try self.scratch_arena.allocator().alloc(Value, info.slot_count + extra_count);
        @memcpy(apply_args[0..info.slot_count], full_slot_values);
        for (args[arg_idx..], 0..) |arg, idx| apply_args[info.slot_count + idx] = arg;
        return try self.invokeValueInCurrentRun(info.callee, apply_args);
    }

    fn applyDerivedClosure(self: *Session, closure: *const Closure, args: []const Value) KError!?Value {
        if (self.debugDetailedProbeActive()) self.debug_apply_derived_closure_count += 1;
        if (try self.projectionInfoFromClosure(closure)) |info| {
            return try self.applyProjectionClosure(info, args);
        }
        if (try self.innerProductInfoFromClosure(closure)) |info| {
            return try self.applyInnerProductClosure(info, args);
        }
        const kind = closureDerivedKind(closure) orelse return null;
        return try self.applyDerivedKind(kind, closure.captures, args);
    }

    fn builtinSupportsMonad(op: BuiltinId) bool {
        return switch (op) {
            .add,
            .sub,
            .mul,
            .div,
            .exp,
            .log,
            .tanh,
            .sigmoid,
            .iota,
            .maximum,
            .reverse,
            .less,
            .more,
            .grade_up,
            .grade_down,
            .not,
            .count,
            .floor,
            .sort,
            .stringify,
            .unique,
            .eval_string,
            => true,
            .minimum, .concat, .take, .drop, .equal, .reshape, .cast, .contains, .split, .join, .find, .grad, .valuegrad, .prng => false,
        };
    }

    fn builtinSupportsDyad(op: BuiltinId) bool {
        return switch (op) {
            .add,
            .sub,
            .mul,
            .div,
            .minimum,
            .maximum,
            .less,
            .more,
            .concat,
            .count,
            .floor,
            .sort,
            .equal,
            .stringify,
            .contains,
            .split,
            .join,
            .unique,
            => true,
            .exp, .log, .tanh, .sigmoid, .iota, .reverse, .grade_up, .grade_down, .not, .take, .drop, .reshape, .cast, .find, .eval_string, .grad, .valuegrad, .prng => false,
        };
    }

    fn convergeUsesMonadicBase(base: Value) bool {
        return switch (base.tag()) {
            .builtin => builtinSupportsMonad(base.asBuiltin()) and !builtinSupportsDyad(base.asBuiltin()),
            .closure => blk: {
                const closure = base.asClosure();
                if (closureDerivedKind(closure) != null) break :blk false;
                break :blk closure.code.arity == 1;
            },
            .array => true,
            else => false,
        };
    }

    fn applyDerivedKind(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!Value {
        if (try self.tryApplyStringDerivedKind(kind, captures, args)) |value| return value;
        return switch (kind) {
            .each => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachDerived(captures[0], args);
            },
            .fold => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk if (args.len == 1 and convergeUsesMonadicBase(captures[0]))
                    try self.applyConvergeDerived(captures[0], args[0], false)
                else
                    try self.applyFoldDerived(captures[0], args, false);
            },
            .scan => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk if (args.len == 1 and convergeUsesMonadicBase(captures[0]))
                    try self.applyConvergeDerived(captures[0], args[0], true)
                else
                    try self.applyFoldDerived(captures[0], args, true);
            },
            .each_right => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachRightDerived(captures[0], args);
            },
            .each_left => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachLeftDerived(captures[0], args);
            },
            .each_prior => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachPriorDerived(captures[0], args);
            },
            .grad => try self.applyAutogradDerived(.grad, captures, args),
            .valuegrad => try self.applyAutogradDerived(.valuegrad, captures, args),
        };
    }

    fn tryApplyStringDerivedKind(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!?Value {
        if (captures.len != 1) return null;
        if (captures[0].tag() == .builtin and captures[0].asBuiltin() == .concat) {
            return switch (kind) {
                .fold => try self.tryApplyStringJoinDerived(args),
                .scan => try self.tryApplyStringSplitDerived(args),
                else => null,
            };
        }
        if (stringBytes(captures[0]) != null) {
            return switch (kind) {
                .fold => if (args.len == 1 and isJoinableStringSequence(args[0]))
                    try self.joinValues(captures[0], args[0])
                else
                    null,
                .scan => if (args.len == 1 and stringBytes(args[0]) != null)
                    try self.splitValues(captures[0], args[0])
                else
                    null,
                else => null,
            };
        }
        return switch (kind) {
            else => null,
        };
    }

    fn tryApplyStringJoinDerived(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 1) {
            if (!isJoinableStringSequence(args[0])) return null;
            const empty = try self.frozenHostString(&.{});
            defer self.releaseValue(empty);
            return try self.joinValues(empty, args[0]);
        }
        if (args.len == 2 and stringBytes(args[0]) != null and isJoinableStringSequence(args[1])) {
            return try self.joinValues(args[0], args[1]);
        }
        return null;
    }

    fn tryApplyStringSplitDerived(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 2 and stringBytes(args[0]) != null and stringBytes(args[1]) != null) {
            return try self.splitValues(args[0], args[1]);
        }
        return null;
    }

    fn valuesExactlyEqual(self: *Session, left: Value, right: Value) KError!bool {
        if (left.tag() != .array and right.tag() != .array) {
            const eq = try self.equalValues(left, right);
            return eq.asBool();
        }
        if (left.tag() != .array or right.tag() != .array) return false;

        const left_shape = valueNonVectorNumericShape(left);
        const right_shape = valueNonVectorNumericShape(right);
        if (left_shape == null and right_shape != null) return false;
        if (left_shape != null and right_shape == null) return false;
        if (left_shape) |lhs| {
            const rhs = right_shape.?;
            if (lhs.rank != rhs.rank or !std.mem.eql(i32, lhs.shapeSlice(), rhs.shapeSlice())) return false;
        }

        if (valueNumericMode(left) != null and valueNumericMode(right) != null) {
            const left_len = numericVectorLen(left) orelse return false;
            const right_len = numericVectorLen(right) orelse return false;
            if (left_len != right_len) return false;
            for (0..left_len) |idx| {
                if (try numericFloatAt(left, idx) != try numericFloatAt(right, idx)) return false;
            }
            return true;
        }

        const left_array = try hostStructuralArrayValue(self, left);
        const right_array = try hostStructuralArrayValue(self, right);
        if (left_array.len() != right_array.len()) return false;
        for (0..left_array.len()) |idx| {
            const lhs = try self.hostArrayIndexScalar(left_array, @intCast(idx));
            const rhs = try self.hostArrayIndexScalar(right_array, @intCast(idx));
            defer self.releaseValue(lhs);
            defer self.releaseValue(rhs);
            if (!(try self.valuesExactlyEqual(lhs, rhs))) return false;
        }
        return true;
    }

    fn applyConvergeDerived(self: *Session, base: Value, input: Value, collect: bool) KError!Value {
        var current = self.shareValue(input);
        errdefer self.releaseValue(current);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        if (collect) try results.append(self.allocator, self.shareValue(current));

        while (true) {
            const next = try self.applyDerivedBase(base, &[_]Value{current});
            const converged = try self.valuesExactlyEqual(current, next);
            if (converged) {
                self.releaseValue(current);
                if (!collect) return next;
                self.releaseValue(next);
                return try self.createManagedArrayLikeFromValues(results.items);
            }
            self.releaseValue(current);
            current = next;
            if (collect) try results.append(self.allocator, self.shareValue(current));
        }
    }

    fn applyEachDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_each);
        defer profile_scope.end();
        if (try self.tryFastUnaryLiftedEachDerived(base, args)) |value| return value;
        if (try self.tryFastMlxMatrixRowFoldEachDerived(base, args)) |value| return value;
        if (try self.tryFastDenseEachDerived(base, args)) |value| return value;
        var len: ?usize = null;
        var saw_array = false;
        for (args) |arg| {
            if (derivedSequenceLen(arg)) |arg_len| {
                saw_array = true;
                if (len) |existing| {
                    if (existing != arg_len) return error.Type;
                } else {
                    len = arg_len;
                }
            }
        }
        if (!saw_array) return try self.applyDerivedBase(base, args);
        if (comptime enable_probe_instrumentation) self.debug_apply_each_generic_count += 1;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        const out_len = len.?;
        try results.ensureTotalCapacity(self.allocator, out_len);
        for (0..out_len) |idx| {
            var step_args_buf: [8]Value = undefined;
            if (args.len > step_args_buf.len) return error.Unsupported;
            for (args, 0..) |arg, arg_idx| {
                step_args_buf[arg_idx] = if (derivedSequenceLen(arg) != null) try self.derivedSequenceItemValue(arg, idx) else arg;
            }
            const result = blk: {
                defer self.releaseDerivedStepArgs(args, step_args_buf[0..args.len], 0);
                break :blk try self.applyDerivedBase(base, step_args_buf[0..args.len]);
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastMlxMatrixRowFoldEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (comptime !runtime_has_mlx) return null;
        if (args.len != 1) return null;

        const op: BuiltinId = if (isDerivedBuiltinClosure(base, .fold, .add))
            .add
        else if (isDerivedBuiltinClosure(base, .fold, .mul))
            .mul
        else if (isDerivedBuiltinClosure(base, .fold, .minimum))
            .minimum
        else if (isDerivedBuiltinClosure(base, .fold, .maximum))
            .maximum
        else
            return null;

        const matrix = args[0];
        const shape = valueNumericMatrixShape(matrix) orelse return null;
        if (shape.rows == 0 or shape.cols == 0) return null;

        const has_mlx_residency = isMlxBackedArray(matrix) or hasMlxRealization(matrix);
        const planned_backend: DenseExecBackend = switch (self.dense_backend_override) {
            .host => return null,
            .mlx => .mlx,
            .auto => if (has_mlx_residency) .mlx else return null,
        };
        const actual_backend = actualDenseBackend(self, true, planned_backend);
        if (actual_backend != .mlx) return null;

        var arr = try self.materializeMlxArray(matrix);
        defer arr.deinit();
        if (arr.ndim() != 2) return null;
        try castMlxBoolArrayTo(self, &arr, c.MLX_INT32);

        const ctx = try self.mlxContext();
        var transposed = mlx.Array.transpose(ctx.*, arr) catch |err| return mapMlxError(err);
        defer transposed.deinit();

        const out = switch (op) {
            .add => mlx.Array.sumAxis0(ctx.*, transposed) catch |err| return mapMlxError(err),
            .mul => mlx.Array.prodAxis0(ctx.*, transposed) catch |err| return mapMlxError(err),
            .minimum => mlx.Array.minAxis0(ctx.*, transposed) catch |err| return mapMlxError(err),
            .maximum => mlx.Array.maxAxis0(ctx.*, transposed) catch |err| return mapMlxError(err),
            else => return null,
        };
        noteDensePlanDecision(
            self,
            .reduce,
            planned_backend,
            actual_backend,
            if (has_mlx_residency) .already_mlx_resident else .large_problem,
        );
        return try self.wrapManagedMlxArray(out);
    }

    fn tryFastUnaryLiftedEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 1 or base.tag() != .closure) return null;
        const closure = base.asClosure();
        const kind = (try self.classifyDirectUnaryLiftedClosure(closure)) orelse return null;
        const len = derivedSequenceLen(args[0]) orelse return null;
        if (self.debugDetailedProbeActive()) self.debug_apply_each_fast_unary_lifted_count += 1;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(args[0], idx);
            const result = blk: {
                defer self.releaseValue(item);
                break :blk try self.applyDirectUnaryLiftedKind(kind, item);
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastDenseEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 2) return null;
        const kind = try self.classifyDenseElementwiseBaseRuntime(base) orelse {
            self.noteDenseEachMiss(.unsupported_base);
            return null;
        };
        if (args[0].tag() != .array and args[1].tag() != .array) {
            self.noteDenseEachMiss(.non_dense_args_or_shape);
            return null;
        }
        if (!wholeArrayEachDyadSafe(args[0], args[1])) {
            self.noteDenseEachMiss(.non_dense_args_or_shape);
            return null;
        }
        if (self.debugDetailedProbeActive()) self.debug_apply_each_fast_dense_count += 1;
        return try self.applyDenseElementwiseKind(kind, args[0], args[1]);
    }

    fn wholeArrayEachDyadSafe(left: Value, right: Value) bool {
        if (left.tag() != .array or right.tag() != .array) return true;
        if (valueNumericMode(left) == null or valueNumericMode(right) == null) return false;
        const left_shape = valueNonVectorNumericShape(left);
        const right_shape = valueNonVectorNumericShape(right);
        if (left_shape == null and right_shape == null) return true;
        if (left_shape == null or right_shape == null) return false;
        const lhs = left_shape.?;
        const rhs = right_shape.?;
        return lhs.rank == rhs.rank and std.mem.eql(i32, lhs.shapeSlice(), rhs.shapeSlice());
    }

    fn tryFastHostFoldDerived(self: *Session, base: Value, args: []const Value, collect: bool) KError!?Value {
        if (base.tag() != .builtin) return null;
        if (!collect) {
            if (try self.tryFastHostShapedFold(base.asBuiltin(), args)) |value| return value;
        }
        return switch (base.asBuiltin()) {
            .add => try self.tryFastHostAddFoldScan(args, collect),
            .sub => if (!collect) try self.tryFastHostSubFold(args) else null,
            .mul => try self.tryFastHostMulFoldScan(args, collect),
            .minimum, .maximum => if (!collect) try self.tryFastHostMinMaxFold(base.asBuiltin(), args) else null,
            else => null,
        };
    }

    fn tryFastMlxFoldDerived(self: *Session, base: Value, args: []const Value, collect: bool) KError!?Value {
        if (base.tag() != .builtin) return null;
        return switch (base.asBuiltin()) {
            .add => try self.tryFastMlxAddFoldScan(args, collect),
            .sub => if (!collect) try self.tryFastMlxSubFold(args) else null,
            .mul, .minimum, .maximum => if (!collect) try self.tryFastMlxReduceUnary(base.asBuiltin(), args) else null,
            else => null,
        };
    }

    fn tryFastMlxReduceUnary(self: *Session, op: BuiltinId, args: []const Value) KError!?Value {
        if (args.len != 1) return null;
        const vector = args[0];
        if (planDenseReduceScanBackend(self, false, vector) != .mlx) return null;

        var arr = try self.materializeMlxArray(vector);
        defer arr.deinit();
        if (arr.ndim() == 0) return null;
        if (@as(usize, @intCast(arr.shape()[0])) == 0) return error.Type;
        try castMlxBoolArrayTo(self, &arr, c.MLX_INT32);

        const ctx = try self.mlxContext();
        const out = switch (op) {
            .add => mlx.Array.sumAxis0(ctx.*, arr) catch |err| return mapMlxError(err),
            .mul => mlx.Array.prodAxis0(ctx.*, arr) catch |err| return mapMlxError(err),
            .minimum => mlx.Array.minAxis0(ctx.*, arr) catch |err| return mapMlxError(err),
            .maximum => mlx.Array.maxAxis0(ctx.*, arr) catch |err| return mapMlxError(err),
            else => return null,
        };
        return try self.wrapManagedMlxArray(out);
    }

    fn tryFastMlxAddFoldScan(self: *Session, args: []const Value, collect: bool) KError!?Value {
        if (args.len != 1) return null;
        const vector = args[0];
        if (planDenseReduceScanBackend(self, collect, vector) != .mlx) return null;

        var arr = try self.materializeMlxArray(vector);
        defer arr.deinit();
        if (arr.ndim() == 0) return null;
        if (@as(usize, @intCast(arr.shape()[0])) == 0) return error.Type;
        try castMlxBoolArrayTo(self, &arr, c.MLX_INT32);

        const ctx = try self.mlxContext();
        const out = if (collect)
            mlx.Array.cumsum0Inclusive(ctx.*, arr) catch |err| return mapMlxError(err)
        else
            mlx.Array.sumAxis0(ctx.*, arr) catch |err| return mapMlxError(err);
        return try self.wrapManagedMlxArray(out);
    }

    fn sliceMlxAxis0Range(self: *Session, value: mlx.Array, start: usize, count: usize) KError!mlx.Array {
        const ndim = value.ndim();
        if (ndim == 0) return error.Type;
        var start_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
        var stop_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
        var stride_buf: [numeric_array_max_rank]i32 = [_]i32{1} ** numeric_array_max_rank;
        const shape = value.shape();
        for (0..ndim) |idx| stop_buf[idx] = shape[idx];
        start_buf[0] = std.math.cast(i32, start) orelse return error.Unsupported;
        stop_buf[0] = std.math.cast(i32, start + count) orelse return error.Unsupported;
        return mlx.Array.slice(
            (try self.mlxContext()).*,
            value,
            start_buf[0..ndim],
            stop_buf[0..ndim],
            stride_buf[0..ndim],
        ) catch |err| return mapMlxError(err);
    }

    fn tryFastMlxSubFold(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        const vector = args[args.len - 1];
        if (planDenseReduceScanBackend(self, false, vector) != .mlx) return null;

        var arr = try self.materializeMlxArray(vector);
        defer arr.deinit();
        if (arr.ndim() == 0) return null;
        const outer_len: usize = @intCast(arr.shape()[0]);
        if (args.len == 1 and outer_len == 0) return error.Type;

        if (outer_len <= 1) return null;

        try castMlxBoolArrayTo(self, &arr, c.MLX_INT32);

        const ctx = try self.mlxContext();
        const reduced = if (args.len == 2) blk: {
            var total = mlx.Array.sumAxis0(ctx.*, arr) catch |err| return mapMlxError(err);
            errdefer total.deinit();
            var seed = try self.materializeMlxArray(args[0]);
            defer seed.deinit();
            try castMlxBoolArrayTo(self, &seed, c.MLX_INT32);
            break :blk mlx.Array.sub(ctx.*, seed, total) catch |err| return mapMlxError(err);
        } else blk: {
            var head = try self.sliceMlxAxis0Range(arr, 0, 1);
            defer head.deinit();
            var tail = try self.sliceMlxAxis0Range(arr, 1, outer_len - 1);
            defer tail.deinit();
            var first = mlx.Array.sumAxis0(ctx.*, head) catch |err| return mapMlxError(err);
            errdefer first.deinit();
            var rest = mlx.Array.sumAxis0(ctx.*, tail) catch |err| return mapMlxError(err);
            errdefer rest.deinit();
            break :blk mlx.Array.sub(ctx.*, first, rest) catch |err| return mapMlxError(err);
        };
        return try self.wrapManagedMlxArray(reduced);
    }

    fn fastRangeIotaAddFoldScan(self: *Session, handle: *const NumericArray, seed: ?i64, collect: bool) KError!Value {
        const len = numericArrayRangeLen(handle);
        if (seed == null and len == 0) return error.Type;

        if (!collect) {
            const len_i128: i128 = @intCast(len);
            const last_idx_i128: i128 = @intCast(if (len == 0) 0 else len - 1);
            const start_i128: i128 = handle.range_iota.start;
            const step_i128: i128 = handle.range_iota.step;
            var total_i128 = start_i128 * len_i128;
            total_i128 += step_i128 * @divTrunc(len_i128 * last_idx_i128, 2);
            if (seed) |seed_value| total_i128 += seed_value;
            const total_i64 = std.math.cast(i64, total_i128) orelse return error.Unsupported;
            return try self.intValue(total_i64);
        }

        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);

        var current = handle.range_iota.start;
        if (seed) |seed_value| {
            var acc = seed_value;
            for (0..len) |_| {
                acc = try checkedIntOp(.add, acc, current);
                try out.append(self.allocator, acc);
                current = try checkedIntOp(.add, current, handle.range_iota.step);
            }
        } else {
            var acc = current;
            try out.append(self.allocator, acc);
            current = try checkedIntOp(.add, current, handle.range_iota.step);
            for (1..len) |_| {
                acc = try checkedIntOp(.add, acc, current);
                try out.append(self.allocator, acc);
                current = try checkedIntOp(.add, current, handle.range_iota.step);
            }
        }
        return try self.createManagedHostIntArray(out.items);
    }

    fn tryFastHostAddFoldScan(self: *Session, args: []const Value, collect: bool) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        if (valueNonVectorNumericShape(vector) != null) return null;
        if (vector.tag() == .array and vector.arrayKind() == .numeric_array) {
            const handle = vector.asNumericArray();
            if (numericArrayIsVectorRangeIota(handle)) {
                const len = numericArrayRangeLen(handle);
                if (args.len == 1 and len == 0) return error.Type;

                if (len <= 1) return null;

                if (args.len == 2) {
                    if (scalarIntLikeValue(args[0])) |seed_int| {
                        noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                        return try self.fastRangeIotaAddFoldScan(handle, seed_int, collect);
                    }
                    return null;
                }
                noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                return try self.fastRangeIotaAddFoldScan(handle, null, collect);
            }
        }
        const array = hostArrayIfPresent(vector) orelse return null;
        if (hostArrayNumericMode(array) == null) return null;
        const len = array.len();

        if (args.len == 1 and len == 0) return error.Type;

        if (len <= 1) return null;

        if (hostIntArrayView(array)) |int_view| {
            if (args.len == 2) {
                if (scalarIntLikeValue(args[0])) |seed_int| {
                    noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                    return if (collect)
                        try self.fastHostAddScanInt(vector, int_view, seed_int)
                    else
                        try self.fastHostAddFoldInt(array, int_view, seed_int);
                }
                const seed_float = scalarNumericValue(args[0]) catch return null;
                noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                return if (collect)
                    try self.fastHostAddScanFloatFromInt(vector, int_view, seed_float)
                else
                    try self.fastHostAddFoldFloatFromInt(int_view, seed_float);
            }

            noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
            return if (collect)
                try self.fastHostAddScanIntUnseeded(vector, int_view)
            else
                try self.fastHostAddFoldIntUnseeded(array, int_view);
        }

        return switch (array.storage) {
            .float64 => |items| blk: {
                if (args.len == 2) {
                    const seed = scalarNumericValue(args[0]) catch break :blk null;
                    noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                    break :blk if (collect)
                        try self.fastHostAddScanFloat(vector, items, seed)
                    else
                        try self.fastHostAddFoldFloat(items, seed);
                }
                noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                break :blk if (collect)
                    try self.fastHostAddScanFloatUnseeded(vector, items)
                else
                    try self.fastHostAddFoldFloatUnseeded(items);
            },
            else => null,
        };
    }

    fn fastRangeIotaSubFold(self: *Session, handle: *const NumericArray, seed: ?i64) KError!Value {
        const len = numericArrayRangeLen(handle);
        if (seed == null and len == 0) return error.Type;

        var acc = seed orelse handle.range_iota.start;
        var current = if (seed == null)
            try checkedIntOp(.add, handle.range_iota.start, handle.range_iota.step)
        else
            handle.range_iota.start;
        const start_idx: usize = if (seed == null) 1 else 0;
        for (start_idx..len) |_| {
            acc = try checkedIntOp(.sub, acc, current);
            current = try checkedIntOp(.add, current, handle.range_iota.step);
        }
        return try self.intValue(acc);
    }

    fn fastHostSubFoldIntUnseeded(self: *Session, view: HostIntArrayView) KError!Value {
        var acc = hostIntViewItem(view, 0);
        for (1..hostIntArrayViewLen(view)) |idx| {
            acc = try checkedIntOp(.sub, acc, hostIntViewItem(view, idx));
        }
        return try self.intValue(acc);
    }

    fn fastHostSubFoldInt(self: *Session, view: HostIntArrayView, seed: i64) KError!Value {
        var acc = seed;
        for (0..hostIntArrayViewLen(view)) |idx| {
            acc = try checkedIntOp(.sub, acc, hostIntViewItem(view, idx));
        }
        return try self.intValue(acc);
    }

    fn fastHostSubFoldFloatUnseeded(self: *Session, items: []const f64) KError!Value {
        var acc = items[0];
        for (items[1..]) |item| acc -= item;
        return try self.floatValue(acc);
    }

    fn fastHostSubFoldFloat(self: *Session, items: []const f64, seed: f64) KError!Value {
        var acc = seed;
        for (items) |item| acc -= item;
        return try self.floatValue(acc);
    }

    fn fastHostSubFoldFloatFromInt(self: *Session, view: HostIntArrayView, seed: f64) KError!Value {
        var acc = seed;
        switch (view) {
            .bit => |items| {
                for (0..items.len) |idx| acc -= @floatFromInt(@intFromBool(bitGet(items.words, idx)));
            },
            .int8 => |items| {
                for (items) |item| acc -= @floatFromInt(item);
            },
            .int16 => |items| {
                for (items) |item| acc -= @floatFromInt(item);
            },
            .int32 => |items| {
                for (items) |item| acc -= @floatFromInt(item);
            },
            .int64 => |items| {
                for (items) |item| acc -= @floatFromInt(item);
            },
        }
        return try self.floatValue(acc);
    }

    fn tryFastHostSubFold(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        if (valueNonVectorNumericShape(vector) != null) return null;
        if (vector.tag() == .array and vector.arrayKind() == .numeric_array) {
            const handle = vector.asNumericArray();
            if (numericArrayIsVectorRangeIota(handle)) {
                const len = numericArrayRangeLen(handle);
                if (args.len == 1 and len == 0) return error.Type;
                if (len <= 1) return null;

                if (args.len == 2) {
                    if (scalarIntLikeValue(args[0])) |seed_int| {
                        noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                        return try self.fastRangeIotaSubFold(handle, seed_int);
                    }
                    return null;
                }
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastRangeIotaSubFold(handle, null);
            }
        }

        const array = hostArrayIfPresent(vector) orelse return null;
        if (hostArrayNumericMode(array) == null) return null;
        const len = array.len();
        if (args.len == 1 and len == 0) return error.Type;
        if (len <= 1) return null;

        if (hostIntArrayView(array)) |int_view| {
            if (args.len == 2) {
                if (scalarIntLikeValue(args[0])) |seed_int| {
                    noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                    return try self.fastHostSubFoldInt(int_view, seed_int);
                }
                const seed_float = scalarNumericValue(args[0]) catch return null;
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastHostSubFoldFloatFromInt(int_view, seed_float);
            }

            noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
            return try self.fastHostSubFoldIntUnseeded(int_view);
        }

        return switch (array.storage) {
            .float64 => |items| blk: {
                if (args.len == 2) {
                    const seed = scalarNumericValue(args[0]) catch break :blk null;
                    noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                    break :blk try self.fastHostSubFoldFloat(items, seed);
                }
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                break :blk try self.fastHostSubFoldFloatUnseeded(items);
            },
            else => null,
        };
    }

    fn tryFastHostMulFoldScan(self: *Session, args: []const Value, collect: bool) KError!?Value {
        if (collect or args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        if (valueNonVectorNumericShape(vector) != null) return null;
        const array = hostArrayIfPresent(vector) orelse return null;
        if (hostArrayNumericMode(array) == null) return null;
        if (array.storage != .bit) return null;

        const len = array.len();
        if (args.len == 1 and len == 0) return error.Type;

        if (len <= 1) return null;

        const bits = HostBitSlice{ .words = array.storage.bit, .len = len };
        if (args.len == 2) {
            if (scalarIntLikeValue(args[0])) |seed_int| {
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastHostMulFoldBit(bits, seed_int);
            }
            const seed_float = scalarNumericValue(args[0]) catch return null;
            noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
            return try self.fastHostMulFoldFloatFromBit(bits, seed_float);
        }
        noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
        return try self.fastHostMulFoldBitUnseeded(bits);
    }

    fn tryFastHostMinMaxFold(self: *Session, op: BuiltinId, args: []const Value) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        if (valueNonVectorNumericShape(vector) != null) return null;
        if (planDenseRegionDecision(.reduce, denseReduceScanFacts(vector)).backend != .host) return null;

        const view = hostDenseView(self, vector) catch return null;
        const len = switch (view) {
            .int_array => |items| hostIntDenseViewLen(items),
            .float_array => |items| hostFloatDenseViewLen(items),
            else => return null,
        };

        if (args.len == 1 and len == 0) return error.Type;
        if (args.len == 2 and len == 0) {
            noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
            return self.shareValue(args[0]);
        }

        switch (view) {
            .int_array => |items| {
                const bounds = hostIntDenseViewRange(items);
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                if (args.len == 1) {
                    return try self.intValue(switch (op) {
                        .minimum => bounds.min,
                        .maximum => bounds.max,
                        else => unreachable,
                    });
                }
                if (scalarIntLikeValue(args[0])) |seed_int| {
                    return try self.intValue(switch (op) {
                        .minimum => @min(seed_int, bounds.min),
                        .maximum => @max(seed_int, bounds.max),
                        else => unreachable,
                    });
                }
                const seed = scalarNumericValue(args[0]) catch return null;
                return try self.floatValue(switch (op) {
                    .minimum => @min(seed, @as(f64, @floatFromInt(bounds.min))),
                    .maximum => @max(seed, @as(f64, @floatFromInt(bounds.max))),
                    else => unreachable,
                });
            },
            .float_array => |items| {
                const bounds = try hostFloatDenseViewBounds(items);
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                if (args.len == 1) {
                    return try self.floatValue(switch (op) {
                        .minimum => bounds.min,
                        .maximum => bounds.max,
                        else => unreachable,
                    });
                }
                const seed = scalarNumericValue(args[0]) catch return null;
                return try self.floatValue(switch (op) {
                    .minimum => @min(seed, bounds.min),
                    .maximum => @max(seed, bounds.max),
                    else => unreachable,
                });
            },
            else => return null,
        }
    }

    fn tryFastHostShapedFold(self: *Session, op: BuiltinId, args: []const Value) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const value = args[args.len - 1];
        const handle = shapedNumericHandle(value) orelse return null;
        if (planDenseRegionDecision(.reduce, denseReduceScanFacts(value)).backend != .host) return null;

        const outer_len: usize = @intCast(handle.shape[0]);
        if (args.len == 1 and outer_len == 0) return error.Type;

        if (outer_len <= 1) return null;

        const block_len = numericShapeInnerBlockLen(handle);
        const view = hostDenseView(self, value) catch return null;

        switch (view) {
            .int_array => |items| {
                if (args.len == 2) {
                    if (scalarIntLikeValue(args[0])) |seed_int| {
                        noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                        return try self.fastHostShapedIntFold(handle, items, op, seed_int);
                    }
                    const seed = scalarNumericValue(args[0]) catch return null;
                    noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                    return try self.fastHostShapedFloatFoldFromInt(handle, items, op, block_len, outer_len, seed);
                }
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastHostShapedIntFoldUnseeded(handle, items, op);
            },
            .float_array => |items| {
                const seed = if (args.len == 2) scalarNumericValue(args[0]) catch return null else null;
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastHostShapedFloatFold(handle, items, op, block_len, outer_len, seed);
            },
            else => return null,
        }
    }

    fn finishHostReducedIntResult(self: *Session, handle: *const NumericArray, items: []const i64) KError!Value {
        const value = try self.createManagedHostIntArray(items);
        return try applyNonVectorNumericShapeToValue(self, value, numericShapeTailSnapshot(handle));
    }

    fn finishHostReducedFloatResult(self: *Session, handle: *const NumericArray, items: []const f64) KError!Value {
        const value = try self.createManagedHostFloatArray(items);
        return try applyNonVectorNumericShapeToValue(self, value, numericShapeTailSnapshot(handle));
    }

    fn fillHostShapedIntFold(out: []i64, view: HostIntDenseView, op: BuiltinId, block_len: usize, outer_len: usize, seed: ?i64) KError!void {
        const start_row: usize = if (seed) |seed_value| blk: {
            @memset(out, seed_value);
            break :blk 0;
        } else blk: {
            for (0..block_len) |col_idx| out[col_idx] = try hostIntDenseViewItem(view, col_idx);
            break :blk 1;
        };

        for (start_row..outer_len) |row_idx| {
            const row_base = row_idx * block_len;
            for (0..block_len) |col_idx| {
                out[col_idx] = try checkedIntOp(op, out[col_idx], try hostIntDenseViewItem(view, row_base + col_idx));
            }
        }
    }

    fn fillHostShapedFloatFold(out: []f64, view: HostFloatDenseView, op: BuiltinId, block_len: usize, outer_len: usize, seed: ?f64) KError!void {
        const start_row: usize = if (seed) |seed_value| blk: {
            @memset(out, seed_value);
            break :blk 0;
        } else blk: {
            for (0..block_len) |col_idx| out[col_idx] = try hostFloatDenseViewItem(view, col_idx);
            break :blk 1;
        };

        for (start_row..outer_len) |row_idx| {
            const row_base = row_idx * block_len;
            for (0..block_len) |col_idx| {
                out[col_idx] = applyFloatOp(op, out[col_idx], try hostFloatDenseViewItem(view, row_base + col_idx));
            }
        }
    }

    fn fillHostShapedFloatFoldFromInt(out: []f64, view: HostIntDenseView, op: BuiltinId, block_len: usize, outer_len: usize, seed: f64) KError!void {
        @memset(out, seed);
        for (0..outer_len) |row_idx| {
            const row_base = row_idx * block_len;
            for (0..block_len) |col_idx| {
                out[col_idx] = applyFloatOp(op, out[col_idx], @floatFromInt(try hostIntDenseViewItem(view, row_base + col_idx)));
            }
        }
    }

    fn fastHostShapedIntFoldUnseeded(self: *Session, handle: *const NumericArray, view: HostIntDenseView, op: BuiltinId) KError!Value {
        const block_len = numericShapeInnerBlockLen(handle);
        const outer_len: usize = @intCast(handle.shape[0]);
        const out = try self.allocator.alloc(i64, block_len);
        defer self.allocator.free(out);
        try fillHostShapedIntFold(out, view, op, block_len, outer_len, null);
        return try self.finishHostReducedIntResult(handle, out);
    }

    fn fastHostShapedIntFold(self: *Session, handle: *const NumericArray, view: HostIntDenseView, op: BuiltinId, seed: i64) KError!Value {
        const block_len = numericShapeInnerBlockLen(handle);
        const outer_len: usize = @intCast(handle.shape[0]);
        const out = try self.allocator.alloc(i64, block_len);
        defer self.allocator.free(out);
        try fillHostShapedIntFold(out, view, op, block_len, outer_len, seed);
        return try self.finishHostReducedIntResult(handle, out);
    }

    fn fastHostShapedFloatFold(self: *Session, handle: *const NumericArray, view: HostFloatDenseView, op: BuiltinId, block_len: usize, outer_len: usize, seed: ?f64) KError!Value {
        const out = try self.allocator.alloc(f64, block_len);
        defer self.allocator.free(out);
        try fillHostShapedFloatFold(out, view, op, block_len, outer_len, seed);
        return try self.finishHostReducedFloatResult(handle, out);
    }

    fn fastHostShapedFloatFoldFromInt(self: *Session, handle: *const NumericArray, view: HostIntDenseView, op: BuiltinId, block_len: usize, outer_len: usize, seed: f64) KError!Value {
        const out = try self.allocator.alloc(f64, block_len);
        defer self.allocator.free(out);
        try fillHostShapedFloatFoldFromInt(out, view, op, block_len, outer_len, seed);
        return try self.finishHostReducedFloatResult(handle, out);
    }

    fn fastHostAddFoldIntUnseeded(self: *Session, array: *const HostArray, view: HostIntArrayView) KError!Value {
        const range = hostArrayCachedIntRange(array) orelse hostIntArrayViewEndpointRange(view, array.flags);
        return try self.intValue(try foldAddIntViewMaybeUnchecked(view, range, null));
    }

    fn fastHostAddFoldInt(self: *Session, array: *const HostArray, view: HostIntArrayView, seed: i64) KError!Value {
        const range = hostArrayCachedIntRange(array) orelse hostIntArrayViewEndpointRange(view, array.flags);
        return try self.intValue(try foldAddIntViewMaybeUnchecked(view, range, seed));
    }

    fn fastHostAddFoldFloatUnseeded(self: *Session, items: []const f64) KError!Value {
        return try self.floatValue(foldAddFloatSlice(items, null));
    }

    fn fastHostAddFoldFloat(self: *Session, items: []const f64, seed: f64) KError!Value {
        return try self.floatValue(foldAddFloatSlice(items, seed));
    }

    fn fastHostAddFoldFloatFromInt(self: *Session, view: HostIntArrayView, seed: f64) KError!Value {
        return try self.floatValue(foldAddFloatIntView(view, seed));
    }

    fn fastHostMulFoldBitUnseeded(self: *Session, items: HostBitSlice) KError!Value {
        return try self.intValue(if (bitWordsAllTrue(items)) 1 else 0);
    }

    fn fastHostMulFoldBit(self: *Session, items: HostBitSlice, seed: i64) KError!Value {
        return try self.intValue(if (bitWordsAllTrue(items)) seed else 0);
    }

    fn fastHostMulFoldFloatFromBit(self: *Session, items: HostBitSlice, seed: f64) KError!Value {
        return try self.floatValue(if (bitWordsAllTrue(items)) seed else 0.0);
    }

    fn fastHostAddScanIntUnseeded(self: *Session, source_value: Value, view: HostIntArrayView) KError!Value {
        return try self.fastHostAddScanIntMaybeSeed(source_value, view, null);
    }

    fn fastHostAddScanInt(self: *Session, source_value: Value, view: HostIntArrayView, seed: i64) KError!Value {
        return try self.fastHostAddScanIntMaybeSeed(source_value, view, seed);
    }

    fn fastHostAddScanIntMaybeSeed(self: *Session, source_value: Value, view: HostIntArrayView, seed: ?i64) KError!Value {
        const analysis = try analyzeAddScanIntView(view, seed);
        const len = hostIntArrayViewLen(view);
        var plan = try self.planHostIntUnaryOutput(
            source_value,
            hostIntArrayViewKind(view),
            analysis.kind,
            len,
            true,
            true,
        );
        fillAddScanIntResult(&plan.output, view, seed);
        return try self.finishHostIntOutput(plan, analysis.flags);
    }

    fn fastHostAddScanFloatUnseeded(self: *Session, source_value: Value, items: []const f64) KError!Value {
        return try self.fastHostAddScanFloatMaybeSeed(source_value, items, null);
    }

    fn fastHostAddScanFloat(self: *Session, source_value: Value, items: []const f64, seed: f64) KError!Value {
        return try self.fastHostAddScanFloatMaybeSeed(source_value, items, seed);
    }

    fn fastHostAddScanFloatMaybeSeed(self: *Session, source_value: Value, items: []const f64, seed: ?f64) KError!Value {
        const len = items.len;
        const plan = try self.planHostFloatUnaryOutput(source_value, len, true);
        fillAddScanFloatSlice(plan.output.items, items, seed);
        return try self.finishHostFloatOutput(plan, addScanFloatFlags(items));
    }

    fn fastHostAddScanFloatFromInt(self: *Session, source_value: Value, view: HostIntArrayView, seed: f64) KError!Value {
        const len = hostIntArrayViewLen(view);
        const plan = try self.planHostFloatUnaryOutput(source_value, len, false);
        fillAddScanFloatIntView(plan.output.items, view, seed);
        return try self.finishHostFloatOutput(plan, addScanIntFlags(hostIntArrayViewRange(view)));
    }

    fn applyFoldDerived(self: *Session, base: Value, args: []const Value, collect: bool) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(if (collect) .apply_scan else .apply_fold);
        defer profile_scope.end();
        if (args.len == 0) return error.Arity;
        if (try self.tryFastMlxFoldDerived(base, args, collect)) |value| return value;
        if (try self.tryFastHostFoldDerived(base, args, collect)) |value| {
            self.noteHostFoldScanFast(collect);
            return value;
        }
        if (base.tag() == .builtin) {
            self.noteHostFoldScanMiss(self.classifyHostFoldScanMiss(base.asBuiltin(), args, collect));
        }
        if (comptime enable_probe_instrumentation) {
            if (collect) {
                self.debug_apply_scan_generic_count += 1;
            } else {
                self.debug_apply_fold_generic_count += 1;
            }
        }

        if (args.len == 1) {
            const vector = args[0];
            const len = derivedSequenceLen(vector) orelse return error.Type;
            if (len == 0) return error.Type;

            var acc = try self.derivedSequenceItemValue(vector, 0);
            if (!collect) {
                for (1..len) |idx| {
                    const item = try self.derivedSequenceItemValue(vector, idx);
                    const next = blk: {
                        defer self.releaseValue(item);
                        break :blk try self.applyDerivedBase(base, &[_]Value{ acc, item });
                    };
                    self.releaseValue(acc);
                    acc = next;
                }
                return acc;
            }

            var results = std.ArrayList(Value).empty;
            defer {
                for (results.items) |value| self.releaseValue(value);
                results.deinit(self.allocator);
            }
            try results.ensureTotalCapacity(self.allocator, len);
            try results.append(self.allocator, self.shareValue(acc));
            for (1..len) |idx| {
                const item = try self.derivedSequenceItemValue(vector, idx);
                const next = blk: {
                    defer self.releaseValue(item);
                    break :blk try self.applyDerivedBase(base, &[_]Value{ acc, item });
                };
                self.releaseValue(acc);
                acc = next;
                try results.append(self.allocator, self.shareValue(acc));
            }
            defer self.releaseValue(acc);
            return try self.createManagedArrayLikeFromValues(results.items);
        }

        var len: ?usize = null;
        for (args[1..]) |arg| {
            const arg_len = derivedSequenceLen(arg) orelse return error.Type;
            if (len) |existing| {
                if (existing != arg_len) return error.Type;
            } else {
                len = arg_len;
            }
        }

        var acc = self.shareValue(args[0]);
        if (!collect) {
            for (0..len.?) |idx| {
                var step_args_buf: [8]Value = undefined;
                if (args.len > step_args_buf.len) return error.Unsupported;
                step_args_buf[0] = acc;
                for (args[1..], 1..) |arg, arg_idx| step_args_buf[arg_idx] = try self.derivedSequenceItemValue(arg, idx);
                const next = blk: {
                    defer self.releaseDerivedStepArgs(args, step_args_buf[0..args.len], 1);
                    break :blk try self.applyDerivedBase(base, step_args_buf[0..args.len]);
                };
                self.releaseValue(acc);
                acc = next;
            }
            return acc;
        }

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len.?);
        for (0..len.?) |idx| {
            var step_args_buf: [8]Value = undefined;
            if (args.len > step_args_buf.len) return error.Unsupported;
            step_args_buf[0] = acc;
            for (args[1..], 1..) |arg, arg_idx| step_args_buf[arg_idx] = try self.derivedSequenceItemValue(arg, idx);
            const next = blk: {
                defer self.releaseDerivedStepArgs(args, step_args_buf[0..args.len], 1);
                break :blk try self.applyDerivedBase(base, step_args_buf[0..args.len]);
            };
            self.releaseValue(acc);
            acc = next;
            try results.append(self.allocator, self.shareValue(acc));
        }
        defer self.releaseValue(acc);
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn applyEachRightDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_each_right);
        defer profile_scope.end();
        if (args.len != 2) return error.Arity;
        if (try self.tryFastHostEachRightStringContains(base, args[0], args[1])) |value| {
            if (comptime enable_probe_instrumentation) self.debug_apply_each_right_fast_string_contains_count += 1;
            return value;
        }
        if (try self.tryFastDenseEachRightDerived(base, args)) |value| return value;
        if (comptime enable_probe_instrumentation) self.debug_apply_each_right_generic_count += 1;
        const len = derivedSequenceLen(args[1]) orelse return error.Type;
        const preserved_left = try self.retainEscapedValue(args[0]);
        defer self.releaseValue(preserved_left);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(args[1], idx);
            const result = blk: {
                defer self.releaseValue(item);
                break :blk try self.applyDerivedBase(base, &[_]Value{ preserved_left, item });
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastDenseEachRightDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 2) return null;
        if (args[1].tag() != .array) {
            self.noteDenseEachRightMiss(.non_vector_right);
            return null;
        }
        if (valueNonVectorNumericShape(args[1]) != null) {
            self.noteDenseEachRightMiss(.non_vector_right);
            return null;
        }
        const kind = try self.classifyDenseElementwiseBaseRuntime(base) orelse {
            self.noteDenseEachRightMiss(.unsupported_base);
            return null;
        };
        const len = derivedSequenceLen(args[1]) orelse return null;
        const preserved_left = try self.retainEscapedValue(args[0]);
        defer self.releaseValue(preserved_left);
        if (self.debugDetailedProbeActive()) self.debug_apply_each_right_fast_dense_count += 1;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(args[1], idx);
            const result = blk: {
                defer self.releaseValue(item);
                break :blk try self.applyDenseElementwiseKind(kind, preserved_left, item);
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastHostEachRightStringContains(self: *Session, base: Value, left: Value, right: Value) KError!?Value {
        if (base.tag() != .builtin or base.asBuiltin() != .contains) return null;
        const needle = stringBytes(left) orelse {
            if (self.debugDetailedProbeActive()) self.debug_each_right_fast_string_contains_miss_non_string_left_count += 1;
            return null;
        };
        if (right.tag() != .array) {
            if (self.debugDetailedProbeActive()) self.debug_each_right_fast_string_contains_miss_non_string_right_count += 1;
            return null;
        }
        return switch (right.arrayKind()) {
            .host_string_list => try self.fastHostStringListContainsEachRight(needle, right.asHostStringList()),
            .host_array => switch (right.asHostArray().storage) {
                .boxed => |items| try self.fastHostBoxedStringContainsEachRight(needle, items),
                else => blk: {
                    if (self.debugDetailedProbeActive()) self.debug_each_right_fast_string_contains_miss_non_string_right_count += 1;
                    break :blk null;
                },
            },
            else => blk: {
                if (self.debugDetailedProbeActive()) self.debug_each_right_fast_string_contains_miss_non_string_right_count += 1;
                break :blk null;
            },
        };
    }

    fn fastHostStringListContainsEachRight(self: *Session, needle: []const u8, list: *const HostStringList) KError!Value {
        const out = try self.allocator.alloc(bool, list.len);
        defer self.allocator.free(out);
        if (needle.len == 0) {
            @memset(out, true);
            return try self.createManagedHostBitArray(out);
        }
        switch (list.storage) {
            .eager => |items| {
                for (items, 0..) |item, idx| {
                    out[idx] = std.mem.indexOf(u8, hostStringPieceBytes(list.base, item), needle) != null;
                }
            },
            .split_scalar => |lazy| {
                const base = list.base orelse return error.Internal;
                const src = hostTextBytes(base);
                var piece_idx: usize = 0;
                var start: usize = 0;
                while (std.mem.indexOfScalarPos(u8, src, start, lazy.sep)) |sep_idx| {
                    out[piece_idx] = std.mem.indexOf(u8, src[start..sep_idx], needle) != null;
                    piece_idx += 1;
                    start = sep_idx + 1;
                }
                std.debug.assert(piece_idx < out.len or out.len == 0);
                if (out.len != 0) out[piece_idx] = std.mem.indexOf(u8, src[start..], needle) != null;
            },
        }
        return try self.createManagedHostBitArray(out);
    }

    fn fastHostBoxedStringContainsEachRight(self: *Session, needle: []const u8, items: []const Value) KError!?Value {
        const out = try self.allocator.alloc(bool, items.len);
        defer self.allocator.free(out);
        if (needle.len == 0) {
            @memset(out, true);
            return try self.createManagedHostBitArray(out);
        }
        for (items, 0..) |item, idx| {
            const haystack = stringBytes(item) orelse return null;
            out[idx] = std.mem.indexOf(u8, haystack, needle) != null;
        }
        return try self.createManagedHostBitArray(out);
    }

    fn applyEachLeftDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_each_left);
        defer profile_scope.end();
        if (args.len != 2) return error.Arity;
        if (base.tag() == .closure) {
            if (try self.innerProductInfoFromClosure(base.asClosure())) |info| {
                if (info.reduce == .add and info.map == .mul and valueIsRenderableMatrixLike(args[0])) {
                    return try self.applyMatmulValues(args[0], args[1]);
                }
            }
        }
        if (comptime enable_probe_instrumentation) self.debug_apply_each_left_generic_count += 1;
        const len = derivedSequenceLen(args[0]) orelse return error.Type;
        const preserved_right = try self.retainEscapedValue(args[1]);
        defer self.releaseValue(preserved_right);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(args[0], idx);
            const result = blk: {
                defer self.releaseValue(item);
                break :blk try self.applyDerivedBase(base, &[_]Value{ item, preserved_right });
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn applyEachPriorDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        if (args.len != 1) return error.Arity;
        const vector = args[0];
        const len = derivedSequenceLen(vector) orelse return error.Type;
        if (len == 0) return try self.createManagedHostIntArray(&[_]i64{});

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);

        var prev = try self.derivedSequenceItemValue(vector, 0);
        try results.append(self.allocator, self.shareValue(prev));
        for (1..len) |idx| {
            const current = try self.derivedSequenceItemValue(vector, idx);
            const value = try self.applyDerivedBase(base, &[_]Value{ prev, current });
            self.releaseValue(prev);
            prev = current;
            try results.append(self.allocator, value);
        }
        defer self.releaseValue(prev);
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn execCall(self: *Session, argc: u8) KError!void {
        const total = @as(usize, argc) + 1;
        if (self.stack_len < total) return error.Internal;

        const callee_index = self.stack_len - total;
        const callee = self.stack[callee_index];
        const args = self.stack[callee_index + 1 .. self.stack_len];

        switch (callee.tag()) {
            .builtin => {
                const result = try self.applyBuiltinCall(callee.asBuiltin(), args);
                self.dropStackFrom(callee_index);
                try self.push(result);
            },
            .closure => {
                const closure = callee.asClosure();
                if (try self.applyDerivedClosure(closure, args)) |result| {
                    self.dropStackFrom(callee_index);
                    try self.push(result);
                    return;
                }
                if (argc != closure.code.arity) return error.Arity;
                if (argc == 1) {
                    if (try self.tryApplyDirectClosure1(closure, args[0])) |result| {
                        self.dropStackFrom(callee_index);
                        try self.push(result);
                        return;
                    }
                } else if (argc == 2) {
                    if (try self.tryApplyDirectClosure2(closure, args[0], args[1])) |result| {
                        self.dropStackFrom(callee_index);
                        try self.push(result);
                        return;
                    }
                }
                var i: usize = 0;
                while (i < argc) : (i += 1) {
                    self.stack[callee_index + i] = self.stack[callee_index + 1 + i];
                }
                self.stack_len -= 1;
                try self.pushFrame(.{
                    .code = closure.code,
                    .ip = 0,
                    .base = callee_index,
                    .captures = closure.captures,
                    .owner = callee,
                    .callable_global_slot = sampling_profile_no_callable_slot,
                });
            },
            .array => {
                const result = try self.applyArrayCall(callee, args);
                self.dropStackFrom(callee_index);
                try self.push(result);
            },
            else => return error.Type,
        }
    }

    fn classifyHostFoldScanMiss(self: *Session, op: BuiltinId, args: []const Value, collect: bool) DebugHostFoldScanMiss {
        if (args.len == 0 or args.len > 2) return .unsupported_input;
        if (collect and op != .add) return .unsupported_builtin;
        switch (op) {
            .add, .sub, .mul, .minimum, .maximum => {},
            else => return .unsupported_builtin,
        }
        if (self.dense_backend_override == .mlx) return .backend_override_mlx;

        const value = args[args.len - 1];
        if (!collect) {
            if (shapedNumericHandle(value)) |handle| {
                if (planDenseRegionDecision(.reduce, denseReduceScanFacts(value)).backend != .host) return .planner_non_host;
                const outer_len: usize = @intCast(handle.shape[0]);
                if (outer_len <= 1) return .preserve_generic_semantics;
                return .unsupported_input;
            }
        }

        if (valueNonVectorNumericShape(value) != null) return .non_numeric_or_shape;
        if ((op == .minimum or op == .maximum) and planDenseRegionDecision(.reduce, denseReduceScanFacts(value)).backend != .host) {
            return .planner_non_host;
        }

        if (value.tag() == .array and value.arrayKind() == .numeric_array) {
            const handle = value.asNumericArray();
            if (numericArrayIsVectorRangeIota(handle)) {
                if (numericArrayRangeLen(handle) <= 1) return .preserve_generic_semantics;
                return .unsupported_input;
            }
        }

        const array = hostArrayIfPresent(value) orelse return .unsupported_input;
        if (hostArrayNumericMode(array) == null) return .non_numeric_or_shape;
        if (array.len() <= 1) return .preserve_generic_semantics;
        return .unsupported_input;
    }

    fn execTailCall1(self: *Session, frame_index: usize) KError!?Value {
        if (self.stack_len < 2) return error.Internal;

        const callee_index = self.stack_len - 2;
        const callee = self.stack[callee_index];
        const arg0 = self.stack[callee_index + 1];

        switch (callee.tag()) {
            .builtin => {
                const result = try self.applyBuiltinCall(callee.asBuiltin(), &[_]Value{arg0});
                return try self.finishFrame(frame_index, result);
            },
            .closure => {
                const closure = callee.asClosure();
                if (try self.applyDerivedClosure(closure, &[_]Value{arg0})) |result| {
                    return try self.finishFrame(frame_index, result);
                }
                if (closure.code.arity != 1) return error.Arity;
                try self.replaceCurrentFrameWithConsumedClosure1(frame_index, callee, closure);
                return null;
            },
            .array => {
                const result = try self.applyArrayCall1(callee, arg0);
                return try self.finishFrame(frame_index, result);
            },
            else => return error.Type,
        }
    }

