    fn applyBuiltinCall(self: *Session, op: BuiltinId, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_builtin);
        defer profile_scope.end();
        if (op == .prng) return try self.applyPrngBuiltin(args);
        if (op == .grad or op == .valuegrad) return try self.applyAutogradBuiltin(op, args);
        return switch (args.len) {
            0 => error.Arity,
            1 => self.applyMonad(op, args[0]),
            2 => self.applyDyad(op, args[0], args[1]),
            else => error.Arity,
        };
    }

    fn applyArrayCall(self: *Session, callee: Value, args: []const Value) KError!Value {
        if (args.len == 0) return error.Arity;
        return try self.deepIndexValue(callee, args);
    }

    fn applyArrayCall1(self: *Session, callee: Value, selector: Value) KError!Value {
        if (callee.tag() != .array) return error.Type;
        switch (selector.tag()) {
            .int, .bool => if (try numericValueScalarIndexValue(self, callee, scalarIntLikeValue(selector).?)) |result| return result,
            .array => if (try numericValueArithmeticSelectorSlice(callee, selector)) |slice| {
                if (try numericValueArithmeticSliceValue(self, callee, slice)) |result| return result;
                if (try numericValueFirstAxisArithmeticSliceValue(self, callee, slice)) |result| return result;
            },
            else => {},
        }
        if (selector.tag() == .array) {
            if (try numericValueFirstAxisIndexSelectorValue(self, callee, selector)) |result| return result;
            if (try tryApplyMlxBoolMaskIndex(self, callee, selector)) |result| return result;
        }
        if (valueRangeIotaHandle(callee)) |handle| return try self.applyRangeIotaIndex(handle, selector);
        if (valueNumericHandle(callee)) |handle| return try self.applyHostArrayIndex(try hostStructuralArrayForHandle(self, @constCast(handle)), selector);
        return switch (callee.arrayKind()) {
            .host_array, .mlx_array => try self.applyHostArrayIndex(try hostStructuralArrayValue(self, callee), selector),
            .host_string_list => switch (selector.tag()) {
                .int, .bool => try self.hostStringListItemValue(callee.asHostStringList(), @intCast(try normalizeIndex(scalarIntLikeValue(selector).?, callee.asHostStringList().len))),
                else => error.Type,
            },
            else => error.Internal,
        };
    }

    fn applyValue(self: *Session, callee: Value, args: []const Value) KError!Value {
        return switch (callee.tag()) {
            .builtin => try self.applyBuiltinCall(callee.asBuiltin(), args),
            .closure => blk: {
                const closure = callee.asClosure();
                if (try self.applyDerivedClosure(closure, args)) |result| break :blk result;
                switch (args.len) {
                    1 => if (try self.tryApplyDirectClosure1(closure, args[0])) |result| break :blk result,
                    2 => if (try self.tryApplyDirectClosure2(closure, args[0], args[1])) |result| break :blk result,
                    3 => if (try self.tryApplyDirectClosure3(closure, args[0], args[1], args[2])) |result| break :blk result,
                    else => {},
                }
                if (closure.code.arity != args.len) return error.Arity;
                break :blk try self.runClosureMode(closure, args, false);
            },
            .array => try self.applyArrayCall(callee, args),
            else => error.Type,
        };
    }

    const AutogradTargetBackend = enum {
        host,
        mlx,
    };

    const dense_autodiff_max_nodes = 16;
    const DenseAutodiffNodeIndex = u8;
    const dense_autodiff_no_slot = std.math.maxInt(u8);

    pub const DebugDenseAutodiffLowering = enum {
        ok,
        wrong_arity,
        non_vector_target,
        non_scalar_result,
        unsupported_opcode,
        unsupported_shape_flow,
        unsupported_builtin,
        capture_or_global_dependency,
        non_dense_operand,
    };
    const debug_dense_autodiff_lowering_count = @typeInfo(DebugDenseAutodiffLowering).@"enum".fields.len;

    const DenseAutodiffNode = union(enum) {
        input,
        const_scalar: f64,
        scan_add: DenseAutodiffNodeIndex,
        unary_map: struct {
            op: BuiltinId,
            src: DenseAutodiffNodeIndex,
        },
        neg: DenseAutodiffNodeIndex,
        add: struct {
            left: DenseAutodiffNodeIndex,
            right: DenseAutodiffNodeIndex,
        },
        sub: struct {
            left: DenseAutodiffNodeIndex,
            right: DenseAutodiffNodeIndex,
        },
        mul: struct {
            left: DenseAutodiffNodeIndex,
            right: DenseAutodiffNodeIndex,
        },
        reduce_add: DenseAutodiffNodeIndex,
    };

    const DenseAutodiffNodeKind = enum {
        vector,
        scalar,
    };

    const DenseAutodiffProgram = struct {
        nodes: [dense_autodiff_max_nodes]DenseAutodiffNode = undefined,
        kinds: [dense_autodiff_max_nodes]DenseAutodiffNodeKind = undefined,
        len: DenseAutodiffNodeIndex = 0,
        root: DenseAutodiffNodeIndex = 0,

        fn push(self: *DenseAutodiffProgram, node: DenseAutodiffNode, kind: DenseAutodiffNodeKind) DenseAutodiffNodeIndex {
            std.debug.assert(self.len < dense_autodiff_max_nodes);
            const idx = self.len;
            self.nodes[idx] = node;
            self.kinds[idx] = kind;
            self.len += 1;
            return idx;
        }
    };

    const DenseAutodiffExecPlan = struct {
        forward_slots: [dense_autodiff_max_nodes]u8 = [_]u8{dense_autodiff_no_slot} ** dense_autodiff_max_nodes,
        adjoint_slots: [dense_autodiff_max_nodes]u8 = [_]u8{dense_autodiff_no_slot} ** dense_autodiff_max_nodes,
        forward_slot_count: u8 = 0,
        adjoint_slot_count: u8 = 0,
    };

    const DenseAutodiffExecBackend = enum {
        host,
        mlx,
    };

    const DenseAutodiffCacheKey = struct {
        closure: *const Closure,
        input_kind: DenseAutodiffNodeKind,
    };

    const DenseAutodiffLowerResult = union(enum) {
        program: DenseAutodiffProgram,
        reject: DebugDenseAutodiffLowering,
    };

    const DenseAutodiffLowerStackItem = union(enum) {
        node: DenseAutodiffNodeIndex,
        derived_add_fold,
        derived_add_scan,
        builtin: BuiltinId,
    };

    const AutogradTarget = struct {
        values: []f64,
        shape: []i32,
        is_scalar: bool,
        backend: AutogradTargetBackend,
    };

    fn applyAutogradBuiltin(self: *Session, op: BuiltinId, args: []const Value) KError!Value {
        if (args.len == 0 or args.len > 2) return error.Arity;
        switch (args[0].tag()) {
            .builtin, .closure => {},
            else => return error.Type,
        }

        var captures_buf: [2]Value = .{ args[0], Value.fromBool(false) };
        var capture_len: usize = 1;
        if (args.len == 2) {
            const arg_index = scalarIntLikeValue(args[1]) orelse return error.Type;
            if (arg_index < 0) return error.Type;
            captures_buf[1] = try self.intValue(arg_index);
            capture_len = 2;
        }

        const kind: DerivedVerbKind = if (op == .grad) .grad else .valuegrad;
        if (self.debugDetailedProbeActive()) switch (op) {
            .grad => self.debug_autograd_builtin_grad_count += 1,
            .valuegrad => self.debug_autograd_builtin_valuegrad_count += 1,
            else => {},
        };
        const closure = try self.allocFrozenDerivedClosureWithCaptures(kind, captures_buf[0..capture_len]);
        return Value.closure(closure);
    }

    fn applyAutogradDerived(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!Value {
        if (captures.len == 0 or captures.len > 2) return error.Internal;

        const base = captures[0];
        const arg_index: usize = if (captures.len == 2) blk: {
            const raw = scalarIntLikeValue(captures[1]) orelse return error.Internal;
            if (raw < 0) return error.Internal;
            break :blk @intCast(raw);
        } else 0;
        if (arg_index >= args.len) return error.Arity;

        if (try self.tryFastDenseAutograd(kind, base, args, arg_index)) |value| return value;
        if (self.debugDetailedProbeActive()) self.debug_autograd_slow_finite_difference_count += 1;

        var sibling = try self.initSiblingSession();
        defer sibling.deinit();

        const sibling_args = try sibling.retainArgs(args);
        defer sibling.releaseArgs(sibling_args);
        const original = try sibling.applyValue(base, sibling_args);
        const original_scalar = try self.scalarNumericAutogradResult(original);
        sibling.releaseValue(original);

        const target = try materializeAutogradTarget(self.allocator, args[arg_index]);
        defer self.allocator.free(target.values);
        defer self.allocator.free(target.shape);

        const grad = try self.allocator.alloc(f64, target.values.len);
        defer self.allocator.free(grad);

        const eps = 0.25;
        for (0..target.values.len) |idx| {
            const p2 = try sibling.evalAutogradPerturbed(base, args, arg_index, target, idx, 2.0 * eps);
            const p1 = try sibling.evalAutogradPerturbed(base, args, arg_index, target, idx, eps);
            const m1 = try sibling.evalAutogradPerturbed(base, args, arg_index, target, idx, -eps);
            const m2 = try sibling.evalAutogradPerturbed(base, args, arg_index, target, idx, -2.0 * eps);
            grad[idx] = (-p2 + 8.0 * p1 - 8.0 * m1 + m2) / (12.0 * eps);
        }

        const grad_value = if (target.is_scalar)
            try self.floatValue(grad[0])
        else switch (target.backend) {
            .host => try self.createManagedHostFloatArray(grad),
            .mlx => blk: {
                const items = try self.allocator.alloc(f32, grad.len);
                defer self.allocator.free(items);
                for (grad, 0..) |item, idx| items[idx] = @floatCast(item);
                break :blk try self.wrapManagedMlxArray(mlx.Array.fromFloatSlice(items, target.shape));
            },
        };

        if (kind == .grad) return grad_value;

        const rooted_original = try self.numericScalarValueFromF64(original_scalar);
        defer self.releaseValue(rooted_original);
        defer self.releaseValue(grad_value);
        const pair = [_]Value{ rooted_original, grad_value };
        return try self.createManagedHostBoxedArray(&pair);
    }

    fn tryFastDenseAutograd(self: *Session, kind: DerivedVerbKind, base: Value, args: []const Value, arg_index: usize) KError!?Value {
        if (args.len != 1 or arg_index != 0) return null;
        const scratch = self.scratch_arena.allocator();
        const target = try materializeAutogradTarget(scratch, args[0]);
        if (!target.is_scalar and target.shape.len != 1) return null;
        const input_kind: DenseAutodiffNodeKind = if (target.is_scalar) .scalar else .vector;
        const program = self.detectDenseAutodiffProgramForInput(base, input_kind) orelse return null;
        self.last_dense_autodiff_exec_backend = null;

        if (!target.is_scalar and self.chooseDenseAutodiffExecBackend(&program, args[0]) == .mlx) {
            if (try self.tryFastDenseAutogradMlx(kind, &program, args[0])) |value| return value;
        }

        const grad = try scratch.alloc(f64, target.values.len);

        const original_scalar = try executeDenseAutodiffProgram(scratch, &program, target.values, grad);

        const grad_value = try self.autogradGradientValue(target, grad);
        if (comptime enable_probe_instrumentation) self.last_dense_autodiff_exec_backend = .host;
        if (kind == .grad) return grad_value;

        const original_value = try self.numericScalarValueFromF64(original_scalar);
        defer self.releaseValue(original_value);
        defer self.releaseValue(grad_value);
        const pair = [_]Value{ original_value, grad_value };
        return try self.createManagedHostBoxedArray(&pair);
    }

    fn tryFastDenseAutogradMlx(self: *Session, kind: DerivedVerbKind, program: *const DenseAutodiffProgram, value: Value) KError!?Value {
        var input = try materializeMlxAutogradInput(self, value);
        defer input.deinit();
        if (input.ndim() != 1) return null;

        const result = try executeDenseAutodiffProgramMlx(self, program, input);
        input = mlx.Array.empty();
        var original_value = result.value;
        defer original_value.deinit();
        var grad_value = result.grad;
        errdefer grad_value.deinit();

        const wrapped_grad = try self.wrapManagedMlxArray(grad_value);
        if (comptime enable_probe_instrumentation) self.last_dense_autodiff_exec_backend = .mlx;
        if (kind == .grad) return wrapped_grad;

        const original_scalar = try scalarNumericMlxArrayResultOwned(&original_value);
        const original_host = try self.numericScalarValueFromF64(original_scalar);
        defer self.releaseValue(original_host);
        defer self.releaseValue(wrapped_grad);
        const pair = [_]Value{ original_host, wrapped_grad };
        return try self.createManagedHostBoxedArray(&pair);
    }

    fn chooseDenseAutodiffExecBackend(self: *Session, program: *const DenseAutodiffProgram, value: Value) DenseAutodiffExecBackend {
        _ = program;
        if (comptime !runtime_has_mlx or mlx.backend_kind == .wasm_bridge) return .host;
        return switch (planDenseAutodiffBackend(self, value)) {
            .host => .host,
            .mlx => .mlx,
        };
    }

    fn autogradGradientValue(self: *Session, target: AutogradTarget, grad: []const f64) KError!Value {
        if (target.is_scalar) return try self.floatValue(grad[0]);
        return switch (target.backend) {
            .host => try self.createManagedHostFloatArray(grad),
            .mlx => blk: {
                const items = try self.allocator.alloc(f32, grad.len);
                defer self.allocator.free(items);
                for (grad, 0..) |item, idx| items[idx] = @floatCast(item);
                break :blk try self.wrapManagedMlxArray(mlx.Array.fromFloatSlice(items, target.shape));
            },
        };
    }

    fn numericScalarValueFromF64(self: *Session, value: f64) KError!Value {
        const rounded = @round(value);
        if (rounded == value) {
            const as_i64 = std.math.lossyCast(i64, rounded);
            if (@as(f64, @floatFromInt(as_i64)) == value) return try self.intValue(as_i64);
        }
        return try self.floatValue(value);
    }

    fn initSiblingSession(self: *Session) !Session {
        var sibling = try Session.initWithDevice(self.allocator, self.device_preference);
        errdefer sibling.deinit();
        try self.cloneGlobalsInto(&sibling);
        return sibling;
    }

    fn cloneGlobalsInto(self: *Session, sibling: *Session) !void {
        try sibling.global_values.resize(self.allocator, self.global_values.items.len);
        try sibling.global_initialized.resize(self.allocator, self.global_initialized.items.len);
        try sibling.global_names.resize(self.allocator, self.global_names.items.len);
        for (sibling.global_initialized.items, 0..) |*initialized, idx| {
            initialized.* = false;
            sibling.global_values.items[idx] = Value.fromBool(false);
        }
        for (self.global_names.items, 0..) |name, idx| {
            sibling.global_names.items[idx] = try sibling.arena.allocator().dupe(u8, name);
        }

        var it = self.global_slots.iterator();
        while (it.next()) |entry| {
            try sibling.global_slots.put(sibling.global_names.items[entry.value_ptr.*], entry.value_ptr.*);
        }

        for (self.global_values.items, self.global_initialized.items, 0..) |value, initialized, idx| {
            if (!initialized) continue;
            sibling.global_values.items[idx] = try sibling.retainEscapedValue(value);
            sibling.global_initialized.items[idx] = true;
        }
    }

    fn retainArgs(self: *Session, args: []const Value) ![]Value {
        const retained = try self.allocator.alloc(Value, args.len);
        errdefer self.allocator.free(retained);
        var initialized: usize = 0;
        errdefer {
            for (retained[0..initialized]) |value| self.releaseValue(value);
        }
        for (args, 0..) |arg, idx| {
            retained[idx] = try self.retainEscapedValue(arg);
            initialized += 1;
        }
        return retained;
    }

    fn releaseArgs(self: *Session, args: []Value) void {
        for (args) |value| self.releaseValue(value);
        self.allocator.free(args);
    }

    fn evalAutogradPerturbed(self: *Session, base: Value, args: []const Value, arg_index: usize, target: AutogradTarget, perturb_index: usize, delta: f64) KError!f64 {
        var call_args = try self.allocator.alloc(Value, args.len);
        defer self.allocator.free(call_args);
        var initialized: usize = 0;
        defer {
            for (call_args[0..initialized]) |value| self.releaseValue(value);
        }

        for (args, 0..) |arg, idx| {
            call_args[idx] = if (idx == arg_index)
                try self.makePerturbedArgument(arg, target, perturb_index, delta)
            else
                try self.retainEscapedValue(arg);
            initialized += 1;
        }

        const value = try self.applyValue(base, call_args);
        defer self.releaseValue(value);
        return try self.scalarNumericAutogradResult(value);
    }

    fn makePerturbedArgument(self: *Session, original: Value, target: AutogradTarget, perturb_index: usize, delta: f64) KError!Value {
        if (target.is_scalar) return try self.floatValue(target.values[0] + delta);

        const items = try self.allocator.dupe(f64, target.values);
        defer self.allocator.free(items);
        items[perturb_index] += delta;
        _ = original;
        return switch (target.backend) {
            .host => try self.createManagedHostFloatArray(items),
            .mlx => blk: {
                const converted = try self.allocator.alloc(f32, items.len);
                defer self.allocator.free(converted);
                for (items, 0..) |item, idx| converted[idx] = @floatCast(item);
                break :blk try self.wrapManagedMlxArray(mlx.Array.fromFloatSlice(converted, target.shape));
            },
        };
    }

    fn scalarNumericAutogradResult(self: *Session, value: Value) KError!f64 {
        _ = self;
        return switch (value.tag()) {
            .int, .bool, .float => try scalarNumericValue(value),
            .array => switch (value.activeArrayKind()) {
                .mlx_array => blk: {
                    var owned = value.asMlxArray().array.clone() catch |err| return mapMlxError(err);
                    defer owned.deinit();
                    owned.eval() catch |err| return mapMlxError(err);
                    if (owned.ndim() != 0) return error.Type;
                    break :blk switch (owned.dtype()) {
                        c.MLX_BOOL => @floatFromInt(@intFromBool(owned.boolItem() catch |err| return mapMlxError(err))),
                        c.MLX_INT32, c.MLX_INT64, c.MLX_UINT32 => @floatFromInt(owned.intItem() catch |err| return mapMlxError(err)),
                        c.MLX_FLOAT32, c.MLX_FLOAT64 => owned.floatItem() catch |err| return mapMlxError(err),
                        else => return error.Type,
                    };
                },
                else => error.Type,
            },
            else => error.Type,
        };
    }

    pub fn debugDenseAutodiffLowering(self: *Session, value: Value) Session.DebugDenseAutodiffLowering {
        return switch (self.detectDenseAutodiffProgramDetailedForInput(value, .vector)) {
            .program => .ok,
            .reject => |reason| reason,
        };
    }

    fn detectDenseAutodiffProgram(self: *Session, base: Value) ?DenseAutodiffProgram {
        return self.detectDenseAutodiffProgramForInput(base, .vector);
    }

    fn detectDenseAutodiffProgramForInput(self: *Session, base: Value, input_kind: DenseAutodiffNodeKind) ?DenseAutodiffProgram {
        return switch (self.detectDenseAutodiffProgramDetailedForInput(base, input_kind)) {
            .program => |program| blk: {
                if (self.debugDetailedProbeActive()) self.debug_dense_autodiff_lower_success_count += 1;
                break :blk program;
            },
            .reject => |reason| blk: {
                self.noteDenseAutodiffReject(reason);
                break :blk null;
            },
        };
    }

    fn detectDenseAutodiffProgramDetailed(self: *Session, base: Value) DenseAutodiffLowerResult {
        return self.detectDenseAutodiffProgramDetailedForInput(base, .vector);
    }

    fn detectDenseAutodiffProgramDetailedForInput(self: *Session, base: Value, input_kind: DenseAutodiffNodeKind) DenseAutodiffLowerResult {
        if (base.tag() != .closure) return .{ .reject = .unsupported_shape_flow };
        const closure = base.asClosure();
        const cacheable = closure.header.owner == .frozen;
        const cache_key = DenseAutodiffCacheKey{
            .closure = closure,
            .input_kind = input_kind,
        };
        if (cacheable) {
            if (self.dense_autodiff_cache.get(cache_key)) |cached| {
                if (self.debugDetailedProbeActive()) self.debug_dense_autodiff_cache_hit_count += 1;
                return cached;
            }
            if (self.debugDetailedProbeActive()) self.debug_dense_autodiff_cache_miss_count += 1;
        } else if (closure.header.owner != .scratch) {
            return .{ .reject = .capture_or_global_dependency };
        }
        if (closure.captures.len != 0 or closure.code.globals.len != 0 or closure.code.templates.len != 0) {
            const result: DenseAutodiffLowerResult = .{ .reject = .capture_or_global_dependency };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        }
        if (closure.code.arity != 1) {
            const result: DenseAutodiffLowerResult = .{ .reject = .wrong_arity };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        }

        var program = DenseAutodiffProgram{};
        const input = program.push(.input, input_kind);

        var stack: [dense_autodiff_max_nodes * 2]DenseAutodiffLowerStackItem = undefined;
        var stack_len: usize = 0;

        var ip: usize = 0;
        while (ip < closure.code.bytes.len) {
            const raw = closure.code.bytes[ip];
            ip += 1;
            const op = std.meta.intToEnum(Op, raw) catch return .{ .reject = .unsupported_opcode };
            switch (op) {
                .const_int => {
                    const value = denseAutodiffReadI64(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const node = program.push(.{ .const_scalar = @floatFromInt(value) }, .scalar);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .const_false => {
                    const node = program.push(.{ .const_scalar = 0.0 }, .scalar);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .const_true => {
                    const node = program.push(.{ .const_scalar = 1.0 }, .scalar);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .const_value => {
                    const slot = denseAutodiffReadByte(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    if (slot >= closure.code.constants.len) return .{ .reject = .unsupported_shape_flow };
                    const value = closure.code.constants[slot];
                    if (denseAutodiffScalarConstFromValue(value)) |scalar| {
                        const node = program.push(.{ .const_scalar = scalar }, .scalar);
                        denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                    } else if (isDerivedBuiltinClosure(value, .fold, .add)) {
                        denseAutodiffPushStack(&stack, &stack_len, .derived_add_fold) orelse return .{ .reject = .unsupported_shape_flow };
                    } else if (isDerivedBuiltinClosure(value, .scan, .add)) {
                        denseAutodiffPushStack(&stack, &stack_len, .derived_add_scan) orelse return .{ .reject = .unsupported_shape_flow };
                    } else {
                        return .{ .reject = .unsupported_builtin };
                    }
                },
                .const_builtin => {
                    const raw_builtin = denseAutodiffReadByte(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const builtin: BuiltinId = @enumFromInt(raw_builtin);
                    switch (builtin) {
                        .add, .exp, .log, .tanh, .sigmoid => {
                            denseAutodiffPushStack(&stack, &stack_len, .{ .builtin = builtin }) orelse return .{ .reject = .unsupported_shape_flow };
                        },
                        else => return .{ .reject = .unsupported_builtin },
                    }
                },
                .make_adverb => {
                    const raw_kind = denseAutodiffReadByte(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const kind: DerivedVerbKind = @enumFromInt(raw_kind);
                    const base_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                    switch (base_item) {
                        .builtin => |builtin| switch (builtin) {
                            .add => switch (kind) {
                                .fold => denseAutodiffPushStack(&stack, &stack_len, .derived_add_fold) orelse return .{ .reject = .unsupported_shape_flow },
                                .scan => denseAutodiffPushStack(&stack, &stack_len, .derived_add_scan) orelse return .{ .reject = .unsupported_shape_flow },
                                else => return .{ .reject = .unsupported_builtin },
                            },
                            else => return .{ .reject = .unsupported_builtin },
                        },
                        else => return .{ .reject = .unsupported_builtin },
                    }
                },
                .make_projection => return .{ .reject = .unsupported_builtin },
                .load_local => {
                    const slot = denseAutodiffReadByte(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    if (slot != 0) return .{ .reject = .wrong_arity };
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = input }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .load_inline_local => {
                    const slot = denseAutodiffReadByte(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    if (slot != 0) return .{ .reject = .wrong_arity };
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = input }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .add_local_local => {
                    const left = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const right = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const node = denseAutodiffPushBinary(&program, .add, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .sub_local_local => {
                    const left = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const right = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const node = denseAutodiffPushBinary(&program, .sub, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .mul_local_local => {
                    const left = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const right = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const node = denseAutodiffPushBinary(&program, .mul, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .neg_local => {
                    const src = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const node = program.push(.{ .neg = src }, program.kinds[src]);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .add_local_const => {
                    const left = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const right_value = denseAutodiffReadI64(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const right = program.push(.{ .const_scalar = @floatFromInt(right_value) }, .scalar);
                    const node = denseAutodiffPushBinary(&program, .add, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .add_const_local => {
                    const left_value = denseAutodiffReadI64(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const left = program.push(.{ .const_scalar = @floatFromInt(left_value) }, .scalar);
                    const right = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const node = denseAutodiffPushBinary(&program, .add, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .sub_local_const => {
                    const left = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const right_value = denseAutodiffReadI64(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const right = program.push(.{ .const_scalar = @floatFromInt(right_value) }, .scalar);
                    const node = denseAutodiffPushBinary(&program, .sub, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .sub_const_local => {
                    const left_value = denseAutodiffReadI64(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const left = program.push(.{ .const_scalar = @floatFromInt(left_value) }, .scalar);
                    const right = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const node = denseAutodiffPushBinary(&program, .sub, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .mul_local_const => {
                    const left = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const right_value = denseAutodiffReadI64(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const right = program.push(.{ .const_scalar = @floatFromInt(right_value) }, .scalar);
                    const node = denseAutodiffPushBinary(&program, .mul, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .mul_const_local => {
                    const left_value = denseAutodiffReadI64(closure.code.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const left = program.push(.{ .const_scalar = @floatFromInt(left_value) }, .scalar);
                    const right = denseAutodiffLowerLocalNode(&program, closure.code.bytes, &ip, input) orelse return .{ .reject = .wrong_arity };
                    const node = denseAutodiffPushBinary(&program, .mul, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .add, .sub, .mul => {
                    const right_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                    const left_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                    const left = denseAutodiffNodeFromStackItem(left_item) orelse return .{ .reject = .unsupported_builtin };
                    const right = denseAutodiffNodeFromStackItem(right_item) orelse return .{ .reject = .unsupported_builtin };
                    const node = denseAutodiffPushBinary(&program, switch (op) {
                        .add => .add,
                        .sub => .sub,
                        .mul => .mul,
                        else => unreachable,
                    }, left, right);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .negate => {
                    const item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                    const src = denseAutodiffNodeFromStackItem(item) orelse return .{ .reject = .unsupported_builtin };
                    const node = program.push(.{ .neg = src }, program.kinds[src]);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .call1, .tail_call1 => {
                    const first_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                    const second_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };

                    var arg = denseAutodiffNodeFromStackItem(first_item);
                    var callee_item = second_item;
                    if (arg == null and denseAutodiffNodeFromStackItem(second_item) != null) {
                        arg = denseAutodiffNodeFromStackItem(second_item);
                        callee_item = first_item;
                    }
                    const node_arg = arg orelse return .{ .reject = .unsupported_builtin };
                    const node = switch (callee_item) {
                        .derived_add_fold => blk: {
                            if (program.kinds[node_arg] != .vector) return .{ .reject = .non_vector_target };
                            break :blk program.push(.{ .reduce_add = node_arg }, .scalar);
                        },
                        .derived_add_scan => blk: {
                            if (program.kinds[node_arg] != .vector) return .{ .reject = .non_vector_target };
                            break :blk program.push(.{ .scan_add = node_arg }, .vector);
                        },
                        .builtin => |builtin| switch (builtin) {
                            .exp, .log, .tanh, .sigmoid => program.push(.{ .unary_map = .{ .op = builtin, .src = node_arg } }, program.kinds[node_arg]),
                            else => return .{ .reject = .unsupported_builtin },
                        },
                        else => return .{ .reject = .unsupported_builtin },
                    };
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                .@"return" => break,
                else => return .{ .reject = .unsupported_opcode },
            }
        }

        if (stack_len != 1) {
            const result: DenseAutodiffLowerResult = .{ .reject = .unsupported_shape_flow };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        }
        const root_item = stack[0];
        const root = denseAutodiffNodeFromStackItem(root_item) orelse {
            const result: DenseAutodiffLowerResult = .{ .reject = .unsupported_builtin };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        };
        if (program.kinds[root] != .scalar) {
            const result: DenseAutodiffLowerResult = .{ .reject = .non_scalar_result };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        }
        program.root = root;
        const result: DenseAutodiffLowerResult = .{ .program = program };
        if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
        return result;
    }

    fn denseAutodiffReadByte(bytes: []const u8, ip: *usize) ?u8 {
        if (ip.* >= bytes.len) return null;
        const value = bytes[ip.*];
        ip.* += 1;
        return value;
    }

    fn denseAutodiffReadI64(bytes: []const u8, ip: *usize) ?i64 {
        const end = ip.* + 8;
        if (end > bytes.len) return null;
        var value: u64 = 0;
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) {
            value |= @as(u64, bytes[ip.* + idx]) << @intCast(idx * 8);
        }
        ip.* = end;
        return @bitCast(value);
    }

    fn denseAutodiffScalarConstFromValue(value: Value) ?f64 {
        return switch (value.tag()) {
            .int => @floatFromInt(value.asInt()),
            .bool => @floatFromInt(@intFromBool(value.asBool())),
            .float => value.asFloat(),
            else => null,
        };
    }

    fn denseAutodiffLowerLocalNode(program: *DenseAutodiffProgram, bytes: []const u8, ip: *usize, input: DenseAutodiffNodeIndex) ?DenseAutodiffNodeIndex {
        _ = program;
        const slot = denseAutodiffReadByte(bytes, ip) orelse return null;
        if (slot != 0) return null;
        return input;
    }

    fn denseAutodiffPushStack(stack: *[dense_autodiff_max_nodes * 2]DenseAutodiffLowerStackItem, len: *usize, item: DenseAutodiffLowerStackItem) ?void {
        if (len.* >= stack.len) return null;
        stack[len.*] = item;
        len.* += 1;
    }

    fn denseAutodiffPopStack(stack: *[dense_autodiff_max_nodes * 2]DenseAutodiffLowerStackItem, len: *usize) ?DenseAutodiffLowerStackItem {
        if (len.* == 0) return null;
        len.* -= 1;
        return stack[len.*];
    }

    fn denseAutodiffNodeFromStackItem(item: DenseAutodiffLowerStackItem) ?DenseAutodiffNodeIndex {
        return switch (item) {
            .node => |node| node,
            else => null,
        };
    }

    const DenseAutodiffBinaryTag = enum { add, sub, mul };

    fn denseAutodiffPushBinary(program: *DenseAutodiffProgram, tag: DenseAutodiffBinaryTag, left: DenseAutodiffNodeIndex, right: DenseAutodiffNodeIndex) DenseAutodiffNodeIndex {
        const kind: DenseAutodiffNodeKind = if (program.kinds[left] == .vector or program.kinds[right] == .vector) .vector else .scalar;
        return program.push(switch (tag) {
            .add => .{ .add = .{ .left = left, .right = right } },
            .sub => .{ .sub = .{ .left = left, .right = right } },
            .mul => .{ .mul = .{ .left = left, .right = right } },
        }, kind);
    }

    fn isDerivedBuiltinClosure(value: Value, kind: DerivedVerbKind, builtin: BuiltinId) bool {
        if (value.tag() != .closure) return false;
        const closure = value.asClosure();
        return closure.header.owner == .frozen and
            closureDerivedKind(closure) == kind and
            closure.captures.len == 1 and
            closure.captures[0].tag() == .builtin and
            closure.captures[0].asBuiltin() == builtin;
    }

    fn evalSourceIsolated(self: *Session, source: []const u8) KError!Value {
        var sibling = try self.initSiblingSession();
        defer sibling.deinit();
        const value = try sibling.evalSource(source);
        return try self.retainEscapedValue(value);
    }

    fn setNumericMatrixShapeOnValue(self: *Session, value: Value, rows: usize, cols: usize) !Value {
        const handle, const canonical = switch (value.tag()) {
            .array => switch (value.arraySubkind()) {
                .numeric_array => .{ @constCast(value.asNumericArray()), value },
                .host_array => blk: {
                    if (hostArrayNumericMode(value.asHostArray()) == null) return error.Type;
                    const wrapped = try wrapOwnedHostArrayValue(self, @constCast(value.asHostArray()));
                    break :blk .{ @constCast(wrapped.asNumericArray()), wrapped };
                },
                .mlx_array => blk: {
                    const wrapped = try wrapOwnedMlxArrayValue(self, @constCast(value.asMlxArray()));
                    break :blk .{ @constCast(wrapped.asNumericArray()), wrapped };
                },
                else => return error.Type,
            },
            else => return error.Type,
        };
        numericArraySetMatrixShape(handle, rows, cols);
        syncNumericArrayChildren(handle);
        return canonical;
    }

    fn hostNumericMatrixRow(self: *Session, array: *const HostArray, row_idx: usize, cols: usize) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_host_matrix_row_copy_count += 1;
        const start = row_idx * cols;
        return switch (array.storage) {
            .bit => blk: {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, cols);
                for (0..cols) |col| try out.append(self.allocator, bitGet(array.storage.bit, start + col));
                break :blk try self.createManagedHostBitArray(out.items);
            },
            .float64 => |items| try self.createManagedHostFloatArray(items[start .. start + cols]),
            .boxed => error.Type,
            else => blk: {
                const view = hostIntArrayView(array) orelse return error.Type;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, cols);
                for (0..cols) |col| try out.append(self.allocator, hostIntViewItem(view, start + col));
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn createManagedHostNumericMatrixRows(self: *Session, array: *const HostArray, row_indices: []const usize, cols: usize) KError!Value {
        const shape = numericShapeSnapshotMatrix(row_indices.len, cols);
        switch (array.storage) {
            .bit => {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, row_indices.len * cols);
                for (row_indices) |row_idx| {
                    const base = row_idx * cols;
                    for (0..cols) |col| try out.append(self.allocator, bitGet(array.storage.bit, base + col));
                }
                const value = try self.createManagedHostBitArray(out.items);
                return try applyNonVectorNumericShapeToValue(self, value, shape);
            },
            .float64 => |items| {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, row_indices.len * cols);
                for (row_indices) |row_idx| {
                    const base = row_idx * cols;
                    try out.appendSlice(self.allocator, items[base .. base + cols]);
                }
                const value = try self.createManagedHostFloatArray(out.items);
                return try applyNonVectorNumericShapeToValue(self, value, shape);
            },
            .boxed => return error.Type,
            else => {
                const view = hostIntArrayView(array) orelse return error.Type;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, row_indices.len * cols);
                for (row_indices) |row_idx| {
                    const base = row_idx * cols;
                    for (0..cols) |col| try out.append(self.allocator, hostIntViewItem(view, base + col));
                }
                const value = try self.createManagedHostIntArray(out.items);
                return try applyNonVectorNumericShapeToValue(self, value, shape);
            },
        }
    }

    fn hostNumericMatrixIndexByIntVector(self: *Session, array: *const HostArray, selector: HostIntArrayView, rows: usize, cols: usize) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_host_matrix_index_copy_count += 1;
        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        try row_indices.ensureTotalCapacity(self.allocator, hostIntArrayViewLen(selector));
        for (0..hostIntArrayViewLen(selector)) |sel_idx| {
            try row_indices.append(self.allocator, try normalizeIndex(hostIntViewItem(selector, sel_idx), rows));
        }
        return try self.createManagedHostNumericMatrixRows(array, row_indices.items, cols);
    }

    fn hostNumericMatrixIndexByIntDenseView(self: *Session, array: *const HostArray, selector: HostIntDenseView, rows: usize, cols: usize) KError!Value {
        if (selector == .dense) return try self.hostNumericMatrixIndexByIntVector(array, selector.dense, rows, cols);
        if (comptime enable_probe_instrumentation) self.debug_host_matrix_index_copy_count += 1;
        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        try row_indices.ensureTotalCapacity(self.allocator, hostIntDenseViewLen(selector));
        for (0..hostIntDenseViewLen(selector)) |sel_idx| {
            try row_indices.append(self.allocator, try normalizeIndex(try hostIntDenseViewItem(selector, sel_idx), rows));
        }
        return try self.createManagedHostNumericMatrixRows(array, row_indices.items, cols);
    }

    fn hostNumericMatrixIndexMask(self: *Session, array: *const HostArray, mask: HostBitSlice, rows: usize, cols: usize) KError!Value {
        if (mask.len != rows) return error.Type;
        if (comptime enable_probe_instrumentation) self.debug_host_matrix_mask_copy_count += 1;
        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        for (0..rows) |row| {
            if (!bitGet(mask.words, row)) continue;
            try row_indices.append(self.allocator, row);
        }
        return try self.createManagedHostNumericMatrixRows(array, row_indices.items, cols);
    }

    fn applyHostArrayIndex(self: *Session, array: *const HostArray, selector: Value) KError!Value {
        return switch (selector.tag()) {
            .int, .bool => try self.hostArrayIndexScalar(array, scalarIntLikeValue(selector).?),
            .array => switch (selector.arrayKind()) {
                .host_array, .mlx_array, .numeric_array => if (valueHostIntStructuralView(selector)) |view|
                    try self.hostArrayIndexDenseSelector(array, view)
                else
                    error.Type,
                else => error.Internal,
            },
            else => error.Type,
        };
    }

    fn hostArrayIndexScalar(self: *Session, array: *const HostArray, raw_index: i64) KError!Value {
        if (hostArrayShapeHandle(array)) |handle| {
            if (handle.rank > 1) return try numericValueScalarIndexValue(self, Value.array(@constCast(handle)), raw_index) orelse error.Type;
        }
        const idx = try normalizeIndex(raw_index, array.len());
        return switch (array.storage) {
            .bit => |words| Value.fromBool(bitGet(words, idx)),
            .int8, .int16, .int32, .int64 => try self.intValue(hostIntViewItem(hostIntArrayView(array).?, idx)),
            .float64 => |items| try self.floatValue(items[idx]),
            .boxed => |items| self.shareValue(items[idx]),
        };
    }

    fn hostArrayIndexVector(self: *Session, array: *const HostArray, selector: *const HostArray) KError!Value {
        if (hostIntArrayView(selector)) |selector_view| {
            return switch (selector_view) {
                .bit => |bits| try self.hostArrayIndexMask(array, bits),
                else => try self.hostArrayIndexByIntVector(array, selector_view),
            };
        }
        return error.Type;
    }

    fn hostArrayIndexDenseSelector(self: *Session, array: *const HostArray, selector: HostIntDenseView) KError!Value {
        return switch (selector) {
            .dense => |view| switch (view) {
                .bit => |bits| try self.hostArrayIndexMask(array, bits),
                else => try self.hostArrayIndexByIntVector(array, view),
            },
            .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => try self.hostArrayIndexByIntDenseView(array, selector),
        };
    }

    fn hostArrayIndexMask(self: *Session, array: *const HostArray, mask: HostBitSlice) KError!Value {
        if (hostArrayNonVectorShape(array)) |shape| {
            if (shape.rank != 2) return error.Unsupported;
            return try self.hostNumericMatrixIndexMask(array, mask, @intCast(shape.shape[0]), @intCast(shape.shape[1]));
        }
        if (mask.len != array.len()) return error.Type;
        if (comptime enable_probe_instrumentation) self.debug_host_mask_copy_count += 1;
        switch (array.storage) {
            .bit => {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                for (0..mask.len) |idx| {
                    if (!bitGet(mask.words, idx)) continue;
                    try out.append(self.allocator, bitGet(array.storage.bit, idx));
                }
                return try self.createManagedHostBitArray(out.items);
            },
            .float64 => |items| {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                for (0..mask.len) |idx| {
                    if (!bitGet(mask.words, idx)) continue;
                    try out.append(self.allocator, items[idx]);
                }
                return try self.createManagedHostFloatArray(out.items);
            },
            .boxed => |items| {
                var out = std.ArrayList(Value).empty;
                defer out.deinit(self.allocator);
                for (0..mask.len) |idx| {
                    if (!bitGet(mask.words, idx)) continue;
                    try out.append(self.allocator, items[idx]);
                }
                return try self.createManagedHostBoxedArray(out.items);
            },
            else => {
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                const view = hostIntArrayView(array).?;
                for (0..mask.len) |idx| {
                    if (!bitGet(mask.words, idx)) continue;
                    try out.append(self.allocator, hostIntViewItem(view, idx));
                }
                return try self.createManagedHostIntArray(out.items);
            },
        }
    }

