    fn hostArrayIndexByIntDenseView(self: *Session, array: *const HostArray, selector: HostIntDenseView) KError!Value {
        if (selector == .dense) return try self.hostArrayIndexByIntVector(array, selector.dense);
        if (hostArrayNonVectorShape(array)) |shape| {
            if (shape.rank != 2) return error.Unsupported;
            return try self.hostNumericMatrixIndexByIntDenseView(array, selector, @intCast(shape.shape[0]), @intCast(shape.shape[1]));
        }
        if (comptime enable_probe_instrumentation) self.debug_host_index_copy_count += 1;
        const len = hostIntDenseViewLen(selector);
        switch (array.storage) {
            .bit => {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, len);
                for (0..len) |idx| {
                    const source_idx = try normalizeIndex(try hostIntDenseViewItem(selector, idx), array.len());
                    try out.append(self.allocator, bitGet(array.storage.bit, source_idx));
                }
                return try self.createManagedHostBitArray(out.items);
            },
            .float64 => |items| {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, len);
                for (0..len) |idx| {
                    const source_idx = try normalizeIndex(try hostIntDenseViewItem(selector, idx), items.len);
                    try out.append(self.allocator, items[source_idx]);
                }
                return try self.createManagedHostFloatArray(out.items);
            },
            .boxed => |items| {
                var out = std.ArrayList(Value).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, len);
                for (0..len) |idx| {
                    const source_idx = try normalizeIndex(try hostIntDenseViewItem(selector, idx), items.len);
                    try out.append(self.allocator, items[source_idx]);
                }
                return try self.createManagedHostBoxedArray(out.items);
            },
            else => {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, len);
                for (0..len) |idx| {
                    const source_idx = try normalizeIndex(try hostIntDenseViewItem(selector, idx), hostIntArrayViewLen(view));
                    try out.append(self.allocator, hostIntViewItem(view, source_idx));
                }
                return try self.createManagedHostIntArray(out.items);
            },
        }
    }

    fn applyRangeIotaIndex(self: *Session, handle: *const NumericArray, selector: Value) KError!Value {
        const structural = NumericStructuralView{ .handle = handle };
        return switch (selector.tag()) {
            .int, .bool => (try numericStructuralScalarIndexValue(self, structural, scalarIntLikeValue(selector).?)).?,
            .array => if (valueHostIntStructuralView(selector)) |view|
                if (handle.rank > 1) blk: {
                    const outer_len: usize = @intCast(handle.shape[0]);
                    if (try hostIntDenseViewArithmeticSlice(view, outer_len)) |slice| {
                        break :blk (try numericStructuralArithmeticSliceValue(self, structural, slice)).?;
                    }
                    break :blk try self.applyHostArrayIndex(try hostStructuralArrayValue(self, Value.array(handle)), selector);
                } else switch (view) {
                    .dense => |dense| switch (dense) {
                        .bit => |bits| blk: {
                            if (bits.len != numericArrayRangeLen(handle)) return error.Type;
                            var out = std.ArrayList(i64).empty;
                            defer out.deinit(self.allocator);
                            for (0..bits.len) |idx| {
                                if (!bitGet(bits.words, idx)) continue;
                                try out.append(self.allocator, try numericArrayRangeIotaValueAt(handle, idx));
                            }
                            break :blk try self.createManagedHostIntArray(out.items);
                        },
                        else => blk: {
                            var out = std.ArrayList(i64).empty;
                            defer out.deinit(self.allocator);
                            try out.ensureTotalCapacity(self.allocator, hostIntArrayViewLen(dense));
                            for (0..hostIntArrayViewLen(dense)) |idx| {
                                const source_idx = try normalizeIndex(hostIntViewItem(dense, idx), numericArrayRangeLen(handle));
                                try out.append(self.allocator, try numericArrayRangeIotaValueAt(handle, source_idx));
                            }
                            break :blk try self.createManagedHostIntArray(out.items);
                        },
                    },
                    .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => blk: {
                        var out = std.ArrayList(i64).empty;
                        defer out.deinit(self.allocator);
                        try out.ensureTotalCapacity(self.allocator, hostIntDenseViewLen(view));
                        for (0..hostIntDenseViewLen(view)) |idx| {
                            const source_idx = try normalizeIndex(try hostIntDenseViewItem(view, idx), numericArrayRangeLen(handle));
                            try out.append(self.allocator, try numericArrayRangeIotaValueAt(handle, source_idx));
                        }
                        break :blk try self.createManagedHostIntArray(out.items);
                    },
                }
            else
                error.Type,
            else => error.Type,
        };
    }

    fn applyMonad(self: *Session, op: BuiltinId, value: Value) KError!Value {
        return switch (op) {
            .add => try self.flipValue(value),
            .sub => blk: {
                if (try self.tryScalarIntBoolMonad(.sub, value)) |result| break :blk result;
                break :blk switch (value.tag()) {
                    .float => try self.floatValue(-value.asFloat()),
                    .array => try self.applyDenseMonad(.sub, value),
                    else => error.Type,
                };
            },
            .div => blk: {
                if (try self.tryScalarIntBoolMonad(.div, value)) |result| break :blk result;
                break :blk switch (value.tag()) {
                    .float => try self.floatValue(std.math.sqrt(value.asFloat())),
                    .array => try self.applyDenseMonad(.div, value),
                    else => error.Type,
                };
            },
            .mul => switch (value.tag()) {
                .array => self.shareValue(value),
                else => error.Type,
            },
            .exp, .log, .tanh, .sigmoid => blk: {
                if (scalarIntLikeValue(value)) |int_value| break :blk try self.floatValue(applyFloatMonadOp(op, @floatFromInt(int_value)));
                break :blk switch (value.tag()) {
                    .float => try self.floatValue(applyFloatMonadOp(op, value.asFloat())),
                    .array => try self.applyDenseMonad(op, value),
                    else => error.Type,
                };
            },
            .iota => try self.iotaValue(value),
            .minimum => error.Arity,
            .maximum => try self.reverseValue(value),
            .reverse => try self.reverseValue(value),
            .less => try self.gradeValue(value, true),
            .more => try self.gradeValue(value, false),
            .grade_up => try self.gradeValue(value, true),
            .grade_down => try self.gradeValue(value, false),
            .not => try self.notValue(value),
            .concat => error.Arity,
            .count => try self.countValue(value),
            .take => error.Arity,
            .floor => try self.floorValue(value),
            .drop => error.Arity,
            .sort => try self.sortValue(value),
            .equal => error.Arity,
            .reshape => error.Arity,
            .stringify => try self.stringifyValue(value),
            .cast => error.Arity,
            .contains => error.Arity,
            .split => error.Arity,
            .join => error.Arity,
            .unique => if (scalarRandomCountValue(value)) |count|
                try self.randomUniformValue(count)
            else
                try self.uniqueValue(value),
            .find => error.Arity,
            .eval_string => try self.evalStringValue(value),
            .grad, .valuegrad => error.Type,
            .prng => error.Arity,
        };
    }

    fn flipValue(self: *Session, value: Value) KError!Value {
        if (valueNumericMode(value) != null and valueNumericMatrixShape(value) != null) {
            return try newTransposeViewValue(self, value);
        }
        const transposed: ?Value = self.transposeValue(value) catch |err| switch (err) {
            error.Type => null,
            else => return err,
        };
        if (transposed) |result| return result;

        if (numericVectorLen(value)) |len| {
            return try newReshapeViewValue(self, value, numericShapeSnapshotMatrix(1, len));
        }

        return switch (value.tag()) {
            .int, .bool => blk: {
                const items = [_]Value{value};
                const singleton = try self.createManagedHostIntArrayFromValues(&items);
                break :blk try newReshapeViewValue(self, singleton, numericShapeSnapshotMatrix(1, 1));
            },
            .float => blk: {
                const items = [_]Value{value};
                const singleton = try self.createManagedHostFloatArrayFromValues(&items);
                break :blk try newReshapeViewValue(self, singleton, numericShapeSnapshotMatrix(1, 1));
            },
            .array => switch (value.arrayKind()) {
                .host_array => blk: {
                    if (std.meta.activeTag(value.asHostArray().storage) != .boxed) break :blk error.Type;
                    break :blk try self.createManagedHostBoxedArray(&[_]Value{value});
                },
                .host_string, .host_string_view => try self.createManagedHostBoxedArray(&[_]Value{value}),
                .host_symbol => blk: {
                    const inner = try self.createManagedHostBoxedArray(&[_]Value{value});
                    errdefer self.releaseValue(inner);
                    const outer = try self.createManagedHostBoxedArray(&[_]Value{inner});
                    self.releaseValue(inner);
                    break :blk outer;
                },
                else => error.Type,
            },
            else => error.Type,
        };
    }

    fn negateValue(self: *Session, value: Value) KError!Value {
        if (try self.tryScalarIntBoolMonad(.sub, value)) |result| return result;
        return switch (value.tag()) {
            .float => try self.floatValue(-value.asFloat()),
            .array => try self.applyDenseMonad(.sub, value),
            else => error.Type,
        };
    }

    fn sqrtValue(self: *Session, value: Value) KError!Value {
        if (try self.tryScalarIntBoolMonad(.div, value)) |result| return result;
        return switch (value.tag()) {
            .float => try self.floatValue(std.math.sqrt(value.asFloat())),
            .array => try self.applyDenseMonad(.div, value),
            else => error.Type,
        };
    }

    fn scalarIntLikeValue(value: Value) ?i64 {
        return switch (value.raw & Value.tag_mask) {
            Value.int_tag => @as(i64, @bitCast(value.raw)) >> Value.tag_bits,
            Value.boxed_int_tag => value.asBoxedInt().value,
            Value.bool_tag => @intFromBool(value.asBool()),
            else => null,
        };
    }

    fn tryScalarIntBoolDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!?Value {
        const left_value = scalarIntLikeValue(left) orelse return null;
        const right_value = scalarIntLikeValue(right) orelse return null;
        return switch (op) {
            .add => try self.addIntValue(left_value, right_value),
            .sub => try self.subIntValue(left_value, right_value),
            .mul => try self.mulIntValue(left_value, right_value),
            .div => try self.floatValue(@as(f64, @floatFromInt(left_value)) / @as(f64, @floatFromInt(right_value))),
            .minimum => try self.intValue(@min(left_value, right_value)),
            .maximum => try self.intValue(@max(left_value, right_value)),
            .less => Value.fromBool(left_value < right_value),
            .more => Value.fromBool(left_value > right_value),
            else => return error.Unsupported,
        };
    }

    fn tryScalarIntBoolMonad(self: *Session, op: BuiltinId, value: Value) KError!?Value {
        const int_value = scalarIntLikeValue(value) orelse return null;
        return switch (op) {
            .add => try self.intValue(int_value),
            .sub => try self.negateIntValue(int_value),
            .mul => return error.Unsupported,
            .div => try self.floatValue(std.math.sqrt(@as(f64, @floatFromInt(int_value)))),
            else => return error.Unsupported,
        };
    }

    fn scalarRandomCountValue(value: Value) ?i64 {
        return switch (value.raw & Value.tag_mask) {
            Value.int_tag => @as(i64, @bitCast(value.raw)) >> Value.tag_bits,
            Value.boxed_int_tag => value.asBoxedInt().value,
            else => null,
        };
    }

    fn containsValues(self: *Session, left: Value, right: Value) KError!Value {
        const helper_start = stringPerfNow();
        const needle = stringBytes(left) orelse return error.Type;
        const haystack = stringBytes(right) orelse return error.Type;
        const result = if (needle.len == 0)
            Value.fromBool(true)
        else
            Value.fromBool(std.mem.indexOf(u8, haystack, needle) != null);
        if (comptime enable_string_instrumentation) {
            self.string_perf.contains_helper_ns += @intCast(stringPerfNow() - helper_start);
        }
        return result;
    }

    fn splitValues(self: *Session, left: Value, right: Value) KError!Value {
        const helper_start = stringPerfNow();
        const sep = stringBytes(left) orelse return error.Type;
        const src_info = stringSourceInfo(right) orelse return error.Type;
        const src = src_info.bytes();
        if (sep.len == 0) return error.Type;

        if (sep.len == 1 and src_info.span.start == 0 and src_info.span.len == src_info.base.len) {
            const search_start = stringPerfNow();
            const parts = countScalarSplits(src, sep[0]);
            if (comptime enable_string_instrumentation) {
                self.string_perf.split_search_ns += @intCast(stringPerfNow() - search_start);
            }
            const result_start = stringPerfNow();
            const result = try self.createManagedHostStringListLazyScalar(src_info.base, sep[0], parts);
            if (comptime enable_string_instrumentation) {
                self.string_perf.split_result_ns += @intCast(stringPerfNow() - result_start);
                self.string_perf.split_helper_ns += @intCast(stringPerfNow() - helper_start);
            }
            return result;
        }

        var parts = std.ArrayList(HostStringPiece).empty;
        defer parts.deinit(self.allocator);

        var start: usize = 0;
        while (true) {
            const search_start = stringPerfNow();
            const maybe_idx = std.mem.indexOfPos(u8, src, start, sep);
            if (comptime enable_string_instrumentation) {
                self.string_perf.split_search_ns += @intCast(stringPerfNow() - search_start);
            }
            const idx = maybe_idx orelse break;
            const append_start = stringPerfNow();
            try parts.append(self.allocator, .{
                .view = .{
                    .start = src_info.span.start + start,
                    .len = idx - start,
                },
            });
            if (comptime enable_string_instrumentation) {
                self.string_perf.split_append_ns += @intCast(stringPerfNow() - append_start);
            }
            start = idx + sep.len;
        }
        const tail_append_start = stringPerfNow();
        try parts.append(self.allocator, .{
            .view = .{
                .start = src_info.span.start + start,
                .len = src.len - start,
            },
        });
        if (comptime enable_string_instrumentation) {
            self.string_perf.split_append_ns += @intCast(stringPerfNow() - tail_append_start);
        }
        const result_start = stringPerfNow();
        const result = try self.createManagedHostStringListPieces(src_info.base, parts.items);
        if (comptime enable_string_instrumentation) {
            self.string_perf.split_result_ns += @intCast(stringPerfNow() - result_start);
            self.string_perf.split_helper_ns += @intCast(stringPerfNow() - helper_start);
        }
        return result;
    }

    fn joinValues(self: *Session, left: Value, right: Value) KError!Value {
        const helper_start = stringPerfNow();
        const sep = stringBytes(left) orelse return error.Type;
        if (right.tag() != .array) return error.Type;

        switch (right.arrayKind()) {
            .host_string_list => {
                const result = try self.joinHostStringList(right.asHostStringList(), sep);
                if (comptime enable_string_instrumentation) {
                    self.string_perf.join_helper_ns += @intCast(stringPerfNow() - helper_start);
                }
                return result;
            },
            .host_array => switch (right.asHostArray().storage) {
                .boxed => |boxed| {
                    var bytes_len: usize = 0;
                    for (boxed) |item| {
                        const piece = stringBytes(item) orelse return error.Type;
                        bytes_len = std.math.add(usize, bytes_len, piece.len) catch return error.Unsupported;
                    }
                    const result = try self.joinBoxedStringValues(boxed, sep, bytes_len);
                    if (comptime enable_string_instrumentation) {
                        self.string_perf.join_helper_ns += @intCast(stringPerfNow() - helper_start);
                    }
                    return result;
                },
                else => return error.Type,
            },
            else => return error.Type,
        }
    }

    fn isJoinableStringSequence(value: Value) bool {
        if (value.tag() != .array) return false;
        return switch (value.arrayKind()) {
            .host_string_list => true,
            .host_array => switch (value.asHostArray().storage) {
                .boxed => |boxed| blk: {
                    for (boxed) |item| {
                        if (stringBytes(item) == null) break :blk false;
                    }
                    break :blk true;
                },
                else => false,
            },
            else => false,
        };
    }

    fn joinHostStringList(self: *Session, list: *const HostStringList, sep: []const u8) KError!Value {
        if (sep.len == 0 and hostStringListIsContiguousBaseViews(list)) {
            return try self.retainEscapedValue(Value.array(list.base.?));
        }
        return switch (list.storage) {
            .eager => |items| self.joinHostStringPiecesKnownTotal(list.base, sep, items, list.bytes_len),
            .split_scalar => |lazy| self.joinLazyScalarSplit(list, lazy.sep, sep),
        };
    }

    fn joinLazyScalarSplit(self: *Session, list: *const HostStringList, split_sep: u8, join_sep: []const u8) KError!Value {
        const base = list.base orelse unreachable;
        if (join_sep.len == 1 and join_sep[0] == split_sep) return try self.retainEscapedValue(Value.array(base));

        const sep_count = list.len -| 1;
        const total_len = std.math.add(usize, list.bytes_len, sep_count * join_sep.len) catch return error.Unsupported;

        const result_start = stringPerfNow();
        const buf = try hostTextAllocSlice(self.allocator, total_len);
        errdefer self.allocator.free(buf);
        const text = hostTextFromAlloc(buf);
        const payload = hostTextBytesFromAlloc(buf, total_len);

        const src = hostTextBytes(base);
        switch (join_sep.len) {
            0 => {
                var offset: usize = 0;
                var start: usize = 0;
                while (std.mem.indexOfScalarPos(u8, src, start, split_sep)) |idx| {
                    const piece = src[start..idx];
                    @memcpy(payload[offset .. offset + piece.len], piece);
                    offset += piece.len;
                    start = idx + 1;
                }
                const tail = src[start..];
                @memcpy(payload[offset .. offset + tail.len], tail);
                offset += tail.len;
                std.debug.assert(offset == total_len);
            },
            1 => {
                var offset: usize = 0;
                var start: usize = 0;
                var first = true;
                while (std.mem.indexOfScalarPos(u8, src, start, split_sep)) |idx| {
                    if (!first) {
                        payload[offset] = join_sep[0];
                        offset += 1;
                    }
                    first = false;
                    const piece = src[start..idx];
                    @memcpy(payload[offset .. offset + piece.len], piece);
                    offset += piece.len;
                    start = idx + 1;
                }
                if (!first) {
                    payload[offset] = join_sep[0];
                    offset += 1;
                }
                const tail = src[start..];
                @memcpy(payload[offset .. offset + tail.len], tail);
                offset += tail.len;
                std.debug.assert(offset == total_len);
            },
            2 => {
                var offset: usize = 0;
                var start: usize = 0;
                var first = true;
                while (std.mem.indexOfScalarPos(u8, src, start, split_sep)) |idx| {
                    if (!first) {
                        payload[offset] = join_sep[0];
                        payload[offset + 1] = join_sep[1];
                        offset += 2;
                    }
                    first = false;
                    const piece = src[start..idx];
                    @memcpy(payload[offset .. offset + piece.len], piece);
                    offset += piece.len;
                    start = idx + 1;
                }
                if (!first) {
                    payload[offset] = join_sep[0];
                    payload[offset + 1] = join_sep[1];
                    offset += 2;
                }
                const tail = src[start..];
                @memcpy(payload[offset .. offset + tail.len], tail);
                offset += tail.len;
                std.debug.assert(offset == total_len);
            },
            else => {
                var offset: usize = 0;
                var start: usize = 0;
                var first = true;
                while (std.mem.indexOfScalarPos(u8, src, start, split_sep)) |idx| {
                    if (!first) {
                        @memcpy(payload[offset .. offset + join_sep.len], join_sep);
                        offset += join_sep.len;
                    }
                    first = false;
                    const piece = src[start..idx];
                    @memcpy(payload[offset .. offset + piece.len], piece);
                    offset += piece.len;
                    start = idx + 1;
                }
                if (!first) {
                    @memcpy(payload[offset .. offset + join_sep.len], join_sep);
                    offset += join_sep.len;
                }
                const tail = src[start..];
                @memcpy(payload[offset .. offset + tail.len], tail);
                offset += tail.len;
                std.debug.assert(offset == total_len);
            },
        }
        text.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = total_len,
        };
        if (comptime enable_string_instrumentation) {
            self.string_perf.join_result_ns += @intCast(stringPerfNow() - result_start);
        }
        return Value.array(text);
    }

    fn joinHostStringPieces(self: *Session, base: ?*const HostText, sep: []const u8, items: []const HostStringPiece) KError!Value {
        var bytes_len: usize = 0;
        for (items) |item| {
            const piece = hostStringPieceBytes(base, item);
            bytes_len = std.math.add(usize, bytes_len, piece.len) catch return error.Unsupported;
        }
        return self.joinHostStringPiecesKnownTotal(base, sep, items, bytes_len);
    }

    fn joinCopyHostStringPiecesSep0(payload: []u8, base: ?*const HostText, items: []const HostStringPiece) void {
        var offset: usize = 0;
        for (items) |item| {
            const piece = hostStringPieceBytes(base, item);
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinCopyHostStringPiecesSep1(payload: []u8, base: ?*const HostText, sep: u8, items: []const HostStringPiece) void {
        var offset: usize = 0;
        for (items, 0..) |item, idx| {
            const piece = hostStringPieceBytes(base, item);
            if (idx != 0) {
                payload[offset] = sep;
                offset += 1;
            }
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinCopyHostStringPiecesSep2(payload: []u8, base: ?*const HostText, sep0: u8, sep1: u8, items: []const HostStringPiece) void {
        var offset: usize = 0;
        for (items, 0..) |item, idx| {
            const piece = hostStringPieceBytes(base, item);
            if (idx != 0) {
                payload[offset] = sep0;
                payload[offset + 1] = sep1;
                offset += 2;
            }
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinHostStringPiecesKnownTotal(self: *Session, base: ?*const HostText, sep: []const u8, items: []const HostStringPiece, bytes_len: usize) KError!Value {
        const total_len = std.math.add(usize, bytes_len, (items.len -| 1) * sep.len) catch return error.Unsupported;

        const result_start = stringPerfNow();
        const buf = try hostTextAllocSlice(self.allocator, total_len);
        errdefer self.allocator.free(buf);
        const text = hostTextFromAlloc(buf);
        const payload = hostTextBytesFromAlloc(buf, total_len);

        if (sep.len == 0) {
            joinCopyHostStringPiecesSep0(payload, base, items);
        } else if (sep.len == 1) {
            joinCopyHostStringPiecesSep1(payload, base, sep[0], items);
        } else if (sep.len == 2) {
            joinCopyHostStringPiecesSep2(payload, base, sep[0], sep[1], items);
        } else {
            var offset: usize = 0;
            for (items, 0..) |item, idx| {
                const piece = hostStringPieceBytes(base, item);
                if (idx != 0) {
                    @memcpy(payload[offset .. offset + sep.len], sep);
                    offset += sep.len;
                }
                @memcpy(payload[offset .. offset + piece.len], piece);
                offset += piece.len;
            }
            std.debug.assert(offset == total_len);
        }
        text.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = total_len,
        };
        if (comptime enable_string_instrumentation) {
            self.string_perf.join_result_ns += @intCast(stringPerfNow() - result_start);
        }
        return Value.array(text);
    }

    fn joinCopyBoxedStringValuesSep0(payload: []u8, items: []const Value) KError!void {
        var offset: usize = 0;
        for (items) |item| {
            const piece = stringBytes(item) orelse return error.Type;
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinCopyBoxedStringValuesSep1(payload: []u8, sep: u8, items: []const Value) KError!void {
        var offset: usize = 0;
        for (items, 0..) |item, idx| {
            const piece = stringBytes(item) orelse return error.Type;
            if (idx != 0) {
                payload[offset] = sep;
                offset += 1;
            }
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinCopyBoxedStringValuesSep2(payload: []u8, sep0: u8, sep1: u8, items: []const Value) KError!void {
        var offset: usize = 0;
        for (items, 0..) |item, idx| {
            const piece = stringBytes(item) orelse return error.Type;
            if (idx != 0) {
                payload[offset] = sep0;
                payload[offset + 1] = sep1;
                offset += 2;
            }
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinBoxedStringValues(self: *Session, items: []const Value, sep: []const u8, bytes_len: usize) KError!Value {
        const total_len = std.math.add(usize, bytes_len, (items.len -| 1) * sep.len) catch return error.Unsupported;

        const result_start = stringPerfNow();
        const buf = try hostTextAllocSlice(self.allocator, total_len);
        errdefer self.allocator.free(buf);
        const text = hostTextFromAlloc(buf);
        const payload = hostTextBytesFromAlloc(buf, total_len);

        if (sep.len == 0) {
            try joinCopyBoxedStringValuesSep0(payload, items);
        } else if (sep.len == 1) {
            try joinCopyBoxedStringValuesSep1(payload, sep[0], items);
        } else if (sep.len == 2) {
            try joinCopyBoxedStringValuesSep2(payload, sep[0], sep[1], items);
        } else {
            var offset: usize = 0;
            for (items, 0..) |item, idx| {
                const piece = stringBytes(item) orelse return error.Type;
                if (idx != 0) {
                    @memcpy(payload[offset .. offset + sep.len], sep);
                    offset += sep.len;
                }
                @memcpy(payload[offset .. offset + piece.len], piece);
                offset += piece.len;
            }
            std.debug.assert(offset == total_len);
        }
        text.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = total_len,
        };
        if (comptime enable_string_instrumentation) {
            self.string_perf.join_result_ns += @intCast(stringPerfNow() - result_start);
        }
        return Value.array(text);
    }

    fn applyDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        return switch (op) {
            .add => self.addValues(left, right),
            .sub => self.subValues(left, right),
            .mul => self.mulValues(left, right),
            .div => self.divValues(left, right),
            .minimum => self.minimumValues(left, right),
            .maximum => self.maximumValues(left, right),
            .concat => self.concatValues(left, right),
            .take => self.takeValues(left, right),
            .drop => self.dropValues(left, right),
            .less => self.lessValues(left, right),
            .more => self.moreValues(left, right),
            .equal => self.equalValues(left, right),
            .reshape => self.reshapeValues(left, right),
            .cast => self.castValues(left, right),
            .contains => self.containsValues(left, right),
            .split => self.splitValues(left, right),
            .join => self.joinValues(left, right),
            .find => if (scalarRandomCountValue(left)) |count|
                self.randomDyadValue(count, right)
            else
                self.findValues(left, right),
            .prng => error.Arity,
            else => error.Arity,
        };
    }

    fn boolLikeValue(value: Value) ?bool {
        return switch (value.tag()) {
            .bool => value.asBool(),
            .int => value.asInt() != 0,
            .float => value.asFloat() != 0.0,
            else => null,
        };
    }

    fn scalarNumericFloatValue(value: Value) ?f64 {
        return switch (value.tag()) {
            .int => @floatFromInt(value.asInt()),
            .bool => @floatFromInt(@intFromBool(value.asBool())),
            .float => value.asFloat(),
            else => null,
        };
    }

    fn stringBytes(value: Value) ?[]const u8 {
        return if (stringSourceInfo(value)) |source| source.bytes() else null;
    }

    fn symbolBytes(value: Value) ?[]const u8 {
        if (value.tag() != .array or value.arrayKind() != .host_symbol) return null;
        return hostTextBytes(value.asHostSymbol());
    }

    fn valueStructuralEqual(self: *Session, left: Value, right: Value) KError!bool {
        if (left.tag() != right.tag()) {
            if ((left.tag() == .int or left.tag() == .bool or left.tag() == .float) and
                (right.tag() == .int or right.tag() == .bool or right.tag() == .float))
            {
                if (left.tag() == .float or right.tag() == .float) {
                    const lhs = switch (left.tag()) {
                        .float => left.asFloat(),
                        .int => @as(f64, @floatFromInt(left.asInt())),
                        .bool => @as(f64, @floatFromInt(@intFromBool(left.asBool()))),
                        else => unreachable,
                    };
                    const rhs = switch (right.tag()) {
                        .float => right.asFloat(),
                        .int => @as(f64, @floatFromInt(right.asInt())),
                        .bool => @as(f64, @floatFromInt(@intFromBool(right.asBool()))),
                        else => unreachable,
                    };
                    return lhs == rhs;
                }
                return scalarIntLikeValue(left).? == scalarIntLikeValue(right).?;
            }
            return false;
        }
        return switch (left.tag()) {
            .int => left.asInt() == right.asInt(),
            .float => left.asFloat() == right.asFloat(),
            .bool => left.asBool() == right.asBool(),
            .builtin => left.asBuiltin() == right.asBuiltin(),
            .closure => left.asClosure() == right.asClosure(),
            .array => switch (left.arrayKind()) {
                .host_string, .host_string_view => if (stringBytes(right)) |right_text|
                    std.mem.eql(u8, stringBytes(left).?, right_text)
                else
                    false,
                .host_symbol => right.arrayKind() == .host_symbol and std.mem.eql(u8, hostTextBytes(left.asHostSymbol()), hostTextBytes(right.asHostSymbol())),
                .host_array, .mlx_array, .numeric_array => blk: {
                    switch (right.arrayKind()) {
                        .host_array, .mlx_array, .numeric_array => {},
                        else => break :blk false,
                    }
                    const lhs = try hostStructuralArrayValue(self, left);
                    const rhs = try hostStructuralArrayValue(self, right);
                    if (lhs.len() != rhs.len()) break :blk false;
                    if (hostArrayNumericMode(lhs) != null and hostArrayNumericMode(rhs) != null) {
                        var lhs_dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
                        var rhs_dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
                        if (!std.mem.eql(i32, hostArrayShapeDims(lhs, &lhs_dims_buf), hostArrayShapeDims(rhs, &rhs_dims_buf))) break :blk false;
                        for (0..lhs.len()) |idx| {
                            if (try numericFloatAt(left, idx) != try numericFloatAt(right, idx)) break :blk false;
                        }
                        break :blk true;
                    }
                    switch (lhs.storage) {
                        .boxed => |left_items| {
                            if (std.meta.activeTag(rhs.storage) != .boxed) break :blk false;
                            const right_items = rhs.storage.boxed;
                            for (left_items, right_items) |left_item, right_item| {
                                if (!try self.valueStructuralEqual(left_item, right_item)) break :blk false;
                            }
                            break :blk true;
                        },
                        else => {
                            if (std.meta.activeTag(rhs.storage) == .boxed) break :blk false;
                            for (0..lhs.len()) |idx| {
                                const left_item = try self.hostArrayIndexScalar(lhs, @intCast(idx));
                                const right_item = try self.hostArrayIndexScalar(rhs, @intCast(idx));
                                if (!try self.valueStructuralEqual(left_item, right_item)) break :blk false;
                            }
                            break :blk true;
                        },
                    }
                },
                else => false,
            },
        };
    }

    fn stringifyValue(self: *Session, value: Value) KError!Value {
        const rendered = self.renderValue(value) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => return error.Internal,
        };
        defer self.allocator.free(rendered);
        return try self.managedHostString(rendered);
    }

    fn castValues(self: *Session, left: Value, right: Value) KError!Value {
        const kind = symbolBytes(left) orelse return error.Type;
        const text = stringBytes(right) orelse return error.Type;
        if (std.mem.eql(u8, kind, "i")) {
            const parsed = std.fmt.parseInt(i64, text, 10) catch return error.Type;
            return try self.intValue(parsed);
        }
        return error.Unsupported;
    }

    fn evalStringValue(self: *Session, value: Value) KError!Value {
        const text = stringBytes(value) orelse return error.Type;
        return try self.evalSourceIsolated(text);
    }

    fn uniqueValue(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| {
            var out = std.ArrayList(u8).empty;
            defer out.deinit(self.allocator);
            var seen = [_]bool{false} ** 256;
            for (text) |ch| {
                if (seen[ch]) continue;
                seen[ch] = true;
                try out.append(self.allocator, ch);
            }
            return try self.managedHostString(out.items);
        }
        if (valueNumericMatrixView(value)) |matrix| {
            if (numericArrayIsRangeIota(matrix.handle)) {
                if (matrix.shape.rows <= 1 or matrix.handle.range_iota.step != 0) return self.shareValue(value);
                return (try numericValueFirstAxisContiguousSliceValue(self, value, .{ .start = 0, .len = 1 })) orelse error.Type;
            }
            if (matrix.shape.rows == 0) return self.shareValue(value);
            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            for (0..matrix.shape.rows) |row_idx| {
                var seen = false;
                for (row_indices.items) |existing| {
                    if (try numericMatrixRowsEqual(self, matrix, row_idx, existing)) {
                        seen = true;
                        break;
                    }
                }
                if (!seen) try row_indices.append(self.allocator, row_idx);
            }
            return try numericValueMatrixSelectRows(self, value, row_indices.items);
        }
        if (valueNumericMode(value)) |mode| {
            const len = numericFlatLen(value) orelse return error.Type;
            if (len == 0) return self.shareValue(value);
            if (mode == .float) {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                for (0..len) |idx| {
                    const item = try numericFloatAt(value, idx);
                    var seen = false;
                    for (out.items) |existing| {
                        if (existing == item) {
                            seen = true;
                            break;
                        }
                    }
                    if (!seen) try out.append(self.allocator, item);
                }
                return try self.createManagedHostFloatArray(out.items);
            }
            var out = std.ArrayList(i64).empty;
            defer out.deinit(self.allocator);
            for (0..len) |idx| {
                const item = try numericIntAt(value, idx);
                var seen = false;
                for (out.items) |existing| {
                    if (existing == item) {
                        seen = true;
                        break;
                    }
                }
                if (!seen) try out.append(self.allocator, item);
            }
            return try self.createManagedHostIntArray(out.items);
        }
        if (value.tag() != .array or value.arrayKind() != .host_array or std.meta.activeTag(value.asHostArray().storage) != .boxed) return error.Type;
        const items = value.asHostArray().storage.boxed;
        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        for (items) |item| {
            var seen = false;
            for (out.items) |existing| {
                if (try self.valueStructuralEqual(existing, item)) {
                    seen = true;
                    break;
                }
            }
            if (!seen) try out.append(self.allocator, item);
        }
        return try self.createManagedHostBoxedArray(out.items);
    }

    fn randomCountParts(count_value: i64) KError!struct { count: usize, distinct: bool } {
        if (count_value >= 0) return .{ .count = @intCast(count_value), .distinct = false };
        if (count_value == std.math.minInt(i64)) return error.Type;
        return .{ .count = @intCast(-count_value), .distinct = true };
    }

    fn prngStateValue(self: *Session) KError!Value {
        const words = self.prng.publicState();
        const state = [_]i64{
            @bitCast(words[0]),
            @bitCast(words[1]),
            @bitCast(words[2]),
            @bitCast(words[3]),
        };
        return try self.createManagedHostIntArray(&state);
    }

    fn setPrngState(self: *Session, words: [4]u64) KError!void {
        try self.prng.setPublicState(words);
    }

    fn setPrngFromValue(self: *Session, value: Value) KError!void {
        if (scalarIntLikeValue(value)) |seed| {
            self.prng.seedFromInt(seed);
            return;
        }
        if (valueNumericMode(value) == .int) {
            const len = numericFlatLen(value) orelse return error.Type;
            if (len != 4) return error.Type;
            var state: [4]u64 = undefined;
            for (0..4) |idx| state[idx] = @bitCast(try numericIntAt(value, idx));
            try self.setPrngState(state);
            return;
        }
        return error.Type;
    }

    fn applyPrngBuiltin(self: *Session, args: []const Value) KError!Value {
        switch (args.len) {
            0 => return try self.prngStateValue(),
            1 => {
                try self.setPrngFromValue(args[0]);
                return try self.prngStateValue();
            },
            else => return error.Arity,
        }
    }

    fn randomUniformValue(self: *Session, count_value: i64) KError!Value {
        if (count_value < 0) return error.Type;
        const count: usize = @intCast(count_value);
        const out = try self.allocator.alloc(f64, count);
        defer self.allocator.free(out);
        for (out) |*item| item.* = self.prng.nextFloat01();
        return try self.createManagedHostFloatArray(out);
    }

    fn randomWordBelow(self: *Session, limit: usize) usize {
        const limit_u64: u64 = @intCast(limit);
        var random = self.prng.random();
        if ((limit_u64 >> 32) != 0) return @intCast(random.uintLessThan(u64, limit_u64));
        return @intCast(random.uintLessThan(u32, @intCast(limit_u64)));
    }

    fn randomIndices(self: *Session, count: usize, limit: usize, distinct: bool, full_range_when_zero: bool) KError![]i64 {
        const out = try self.allocator.alloc(i64, count);
        errdefer self.allocator.free(out);

        if (!distinct) {
            if (limit == 0) {
                if (!full_range_when_zero and count != 0) return error.Type;
                const raw = try self.allocator.alloc(u64, count);
                defer self.allocator.free(raw);
                self.prng.copyFreshWords(raw);
                for (out, raw) |*item, word| item.* = @bitCast(word);
                return out;
            }
            for (out) |*item| item.* = @intCast(self.randomWordBelow(limit));
            return out;
        }

        if (count > limit) return error.Type;
        if (count == 0) return out;

        const pool = try self.allocator.alloc(i64, limit);
        defer self.allocator.free(pool);
        for (pool, 0..) |*item, idx| item.* = @intCast(idx);
        for (0..count) |idx| {
            const choice = idx + self.randomWordBelow(limit - idx);
            std.mem.swap(i64, &pool[idx], &pool[choice]);
            out[idx] = pool[idx];
        }
        return out;
    }

    fn randomSelectableLen(value: Value) ?usize {
        if (value.tag() != .array) return null;
        if (stringBytes(value)) |text| return text.len;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank != 0) return @intCast(handle.shape[0]);
        }
        return switch (value.arrayKind()) {
            .host_array => value.asHostArray().len(),
            .mlx_array => @intCast(value.asMlxArray().array.shape()[0]),
            .numeric_array => null,
            else => null,
        };
    }

    fn randomSelectStringValue(self: *Session, count_value: i64, text: []const u8) KError!Value {
        const parts = try randomCountParts(count_value);
        if (text.len == 0) {
            if (parts.count == 0) return try self.managedHostString(&.{});
            if (parts.distinct) return error.Type;
            const spaces = try self.allocator.alloc(u8, parts.count);
            defer self.allocator.free(spaces);
            @memset(spaces, ' ');
            return try self.managedHostString(spaces);
        }
        const indices = try self.randomIndices(parts.count, text.len, parts.distinct, false);
        defer self.allocator.free(indices);
        const out = try self.allocator.alloc(u8, parts.count);
        defer self.allocator.free(out);
        for (indices, 0..) |idx, out_idx| out[out_idx] = text[@intCast(idx)];
        return try self.managedHostString(out);
    }

    fn randomScaleFloatValue(self: *Session, count_value: i64, scale: f64) KError!Value {
        const parts = try randomCountParts(count_value);
        if (parts.distinct) return error.Type;
        const out = try self.allocator.alloc(f64, parts.count);
        defer self.allocator.free(out);
        for (out) |*item| item.* = self.prng.nextFloat01() * scale;
        return try self.createManagedHostFloatArray(out);
    }

    fn randomIntValue(self: *Session, count_value: i64, bound: i64) KError!Value {
        if (bound < 0) return error.Type;
        const parts = try randomCountParts(count_value);
        const limit: usize = @intCast(bound);
        const values = try self.randomIndices(parts.count, limit, parts.distinct, true);
        defer self.allocator.free(values);
        return try self.createManagedHostIntArray(values);
    }

    fn randomSelectValue(self: *Session, count_value: i64, value: Value) KError!Value {
        const len = randomSelectableLen(value) orelse return error.Type;
        const parts = try randomCountParts(count_value);
        if (len == 0 and parts.count != 0) return error.Type;
        const indices = try self.randomIndices(parts.count, len, parts.distinct, false);
        defer self.allocator.free(indices);
        const selector = try self.createManagedHostIntArray(indices);
        defer self.releaseValue(selector);
        return try self.applyValue(value, &[_]Value{selector});
    }

    fn randomDyadValue(self: *Session, count_value: i64, right: Value) KError!Value {
        return switch (right.tag()) {
            .int => try self.randomIntValue(count_value, right.asInt()),
            .float => try self.randomScaleFloatValue(count_value, right.asFloat()),
            .array => if (stringBytes(right)) |text|
                try self.randomSelectStringValue(count_value, text)
            else
                switch (right.arrayKind()) {
                    .host_array, .mlx_array, .numeric_array => try self.randomSelectValue(count_value, right),
                    else => error.Type,
                },
            .bool, .builtin, .closure => error.Type,
        };
    }

    fn numericRowQueryLen(value: Value) ?usize {
        if (valueNumericMode(value) == null) return null;
        if (value.tag() != .array) return 1;
        if (valueNonVectorNumericShape(value)) |shape| {
            if (shape.rank == 2 and shape.shape[0] == 1) return @intCast(shape.shape[1]);
            return null;
        }
        return numericFlatLen(value);
    }

    fn numericValuesEqualAt(left: Value, left_idx: usize, right: Value, right_idx: usize) KError!bool {
        const left_mode = valueNumericMode(left) orelse return error.Type;
        const right_mode = valueNumericMode(right) orelse return error.Type;
        if (left_mode == .float or right_mode == .float) {
            return try numericFloatAt(left, left_idx) == try numericFloatAt(right, right_idx);
        }
        return try numericIntAt(left, left_idx) == try numericIntAt(right, right_idx);
    }

    fn findNumericMatrixRowValue(self: *Session, left: Value, right: Value, shape: NumericMatrixShape) KError!?Value {
        const query_len = numericRowQueryLen(right) orelse return null;
        if (query_len != shape.cols) return error.Type;
        for (0..shape.rows) |row_idx| {
            const base = row_idx * shape.cols;
            var matched = true;
            for (0..shape.cols) |col_idx| {
                if (!try numericValuesEqualAt(left, base + col_idx, right, col_idx)) {
                    matched = false;
                    break;
                }
            }
            if (matched) return try self.intValue(@intCast(row_idx));
        }
        return try self.intValue(@intCast(shape.rows));
    }

    fn findNumericVectorValue(self: *Session, left: Value, right: Value) KError!?Value {
        if (valueNumericMode(left) == null or valueNumericMatrixShape(left) != null) return null;
        const left_len = numericFlatLen(left) orelse return null;
        const query_len = numericRowQueryLen(right) orelse return null;
        if (query_len != 1) return error.Type;
        for (0..left_len) |idx| {
            if (try numericValuesEqualAt(left, idx, right, 0)) return try self.intValue(@intCast(idx));
        }
        return try self.intValue(@intCast(left_len));
    }

    fn findValues(self: *Session, left: Value, right: Value) KError!Value {
        if (valueNumericMatrixShape(left)) |shape| {
            if (try self.findNumericMatrixRowValue(left, right, shape)) |result| return result;
        }
        if (try self.findNumericVectorValue(left, right)) |result| return result;
        if (left.tag() == .array and left.arrayKind() == .host_array and std.meta.activeTag(left.asHostArray().storage) == .boxed and symbolBytes(right) != null) {
            const items = left.asHostArray().storage.boxed;
            for (items, 0..) |item, idx| {
                if (try self.valueStructuralEqual(item, right)) return try self.intValue(@intCast(idx));
            }
            return try self.intValue(@intCast(items.len));
        }
        return error.Type;
    }

    fn countValue(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| return try self.intValue(@intCast(text.len));
        return switch (value.tag()) {
            .array => blk: {
                if (valueNumericHandle(value)) |handle| {
                    if (handle.rank != 0) break :blk try self.intValue(@intCast(handle.shape[0]));
                }
                break :blk switch (value.arrayKind()) {
                    .host_array => try self.intValue(@intCast(value.asHostArray().len())),
                    .mlx_array => try self.intValue(@intCast(value.asMlxArray().array.shape()[0])),
                    else => error.Internal,
                };
            },
            else => try self.intValue(1),
        };
    }

    fn floorValue(self: *Session, value: Value) KError!Value {
        return switch (value.tag()) {
            .int, .bool => self.shareValue(value),
            .float => blk: {
                const floored = @floor(value.asFloat());
                const int_value = std.math.lossyCast(i64, floored);
                break :blk try self.intValue(int_value);
            },
            .array => switch (value.arrayKind()) {
                .host_array, .mlx_array, .numeric_array => if (valueHostIntStructuralView(value) != null)
                    self.shareValue(value)
                else switch ((try hostStructuralArrayValue(self, value)).storage) {
                    .float64 => |items| blk: {
                        var out = std.ArrayList(i64).empty;
                        defer out.deinit(self.allocator);
                        try out.ensureTotalCapacity(self.allocator, items.len);
                        for (items) |item| try out.append(self.allocator, std.math.lossyCast(i64, @floor(item)));
                        break :blk try self.createManagedHostIntArray(out.items);
                    },
                    .boxed => |items| {
                        if (items.len == 0) return error.Type;
                        return self.shareValue(items[0]);
                    },
                    else => self.shareValue(value),
                },
                else => error.Internal,
            },
            else => error.Type,
        };
    }

    fn iotaValue(self: *Session, value: Value) KError!Value {
        if (scalarIntLikeValue(value)) |count_value| {
            if (count_value < 0) return error.Type;
            const count: usize = @intCast(count_value);
            return try newRangeIotaValue(self, .managed, count);
        }
        if (valueHostIntStructuralView(value)) |view| {
            var out = std.ArrayList(i64).empty;
            defer out.deinit(self.allocator);
            for (0..hostIntDenseViewLen(view)) |idx| {
                if (try hostIntDenseViewItem(view, idx) != 0) try out.append(self.allocator, @intCast(idx));
            }
            return try self.createManagedHostIntArray(out.items);
        }
        return error.Type;
    }

    fn reverseValue(self: *Session, value: Value) KError!Value {
        if (value.tag() == .array) switch (value.arrayKind()) {
            .host_string => return try self.reverseHostString(value.asHostString()),
            .host_string_view => return try self.reverseStringBytes(hostStringViewBytes(value.asHostStringView())),
            .host_string_list => return try self.reverseHostStringList(value.asHostStringList()),
            else => {},
        };
        if (valueVectorRangeIotaHandle(value)) |handle| {
            const len = numericArrayRangeLen(handle);
            const start = if (len == 0)
                handle.range_iota.start
            else
                try numericArrayRangeIotaValueAt(handle, len - 1);
            const step = try checkedIntOp(.sub, 0, handle.range_iota.step);
            return try newRangeIotaValueWithParams(self, .managed, len, start, step);
        }
        if (shapedNumericHandle(value)) |handle| {
            const rows: usize = @intCast(handle.shape[0]);
            const start = if (rows == 0) 0 else rows - 1;
            if (try numericValueFirstAxisArithmeticSliceValue(self, value, .{
                .start = start,
                .len = rows,
                .step = -1,
            })) |result| return result;
        }
        const array = try hostStructuralArrayValue(self, value);
        if (hostNumericMatrixShape(array)) |shape| {
            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, shape.rows);
            var idx = shape.rows;
            while (idx > 0) {
                idx -= 1;
                try row_indices.append(self.allocator, idx);
            }
            return try self.createManagedHostNumericMatrixRows(array, row_indices.items, shape.cols);
        }
        return switch (array.storage) {
            .bit => blk: {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, array.len());
                var idx = array.len();
                while (idx > 0) {
                    idx -= 1;
                    try out.append(self.allocator, bitGet(array.storage.bit, idx));
                }
                break :blk try self.createManagedHostBitArray(out.items);
            },
            .float64 => |items| blk: {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, items.len);
                var idx = items.len;
                while (idx > 0) {
                    idx -= 1;
                    try out.append(self.allocator, items[idx]);
                }
                break :blk try self.createManagedHostFloatArray(out.items);
            },
            .boxed => |items| blk: {
                var out = std.ArrayList(Value).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, items.len);
                var idx = items.len;
                while (idx > 0) {
                    idx -= 1;
                    try out.append(self.allocator, items[idx]);
                }
                break :blk try self.createManagedHostBoxedArray(out.items);
            },
            else => blk: {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, array.len());
                var idx = hostIntArrayViewLen(view);
                while (idx > 0) {
                    idx -= 1;
                    try out.append(self.allocator, hostIntViewItem(view, idx));
                }
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn reverseHostString(self: *Session, text: *const HostText) KError!Value {
        return try self.reverseStringBytes(hostTextBytes(text));
    }

    fn reverseStringBytes(self: *Session, src: []const u8) KError!Value {
        const buf = try hostTextAllocSlice(self.allocator, src.len);
        errdefer self.allocator.free(buf);
        const out = hostTextBytesFromAlloc(buf, src.len);
        var idx: usize = src.len;
        var out_idx: usize = 0;
        while (idx > 0) {
            idx -= 1;
            out[out_idx] = src[idx];
            out_idx += 1;
        }
        const owned = hostTextFromAlloc(buf);
        owned.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = src.len,
        };
        return Value.array(owned);
    }

    fn reverseHostStringList(self: *Session, list: *const HostStringList) KError!Value {
        return switch (list.storage) {
            .eager => |items| blk: {
                const reversed = try self.allocator.alloc(HostStringPiece, items.len);
                defer self.allocator.free(reversed);
                var idx: usize = items.len;
                var out_idx: usize = 0;
                while (idx > 0) {
                    idx -= 1;
                    reversed[out_idx] = items[idx];
                    out_idx += 1;
                }
                break :blk try self.createManagedHostStringListPieces(list.base, reversed);
            },
            .split_scalar => |lazy| blk: {
                const base = list.base orelse unreachable;
                const src = hostTextBytes(base);
                const reversed = try self.allocator.alloc(HostStringPiece, list.len);
                defer self.allocator.free(reversed);
                var piece_idx: usize = list.len;
                var start: usize = 0;
                while (std.mem.indexOfScalarPos(u8, src, start, lazy.sep)) |sep_idx| {
                    piece_idx -= 1;
                    reversed[piece_idx] = .{ .view = .{
                        .start = start,
                        .len = sep_idx - start,
                    } };
                    start = sep_idx + 1;
                }
                piece_idx -= 1;
                reversed[piece_idx] = .{ .view = .{
                    .start = start,
                    .len = src.len - start,
                } };
                break :blk try self.createManagedHostStringListPieces(base, reversed);
            },
        };
    }

    fn notValue(self: *Session, value: Value) KError!Value {
        if (boolLikeValue(value)) |truthy| return Value.fromBool(!truthy);
        if (valueHostIntStructuralView(value)) |view| {
            var out = std.ArrayList(bool).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, hostIntDenseViewLen(view));
            for (0..hostIntDenseViewLen(view)) |idx| try out.append(self.allocator, try hostIntDenseViewItem(view, idx) == 0);
            return try self.createManagedHostBitArray(out.items);
        }
        const array = try hostStructuralArrayValue(self, value);
        switch (array.storage) {
            .bit => |words| {
                const plan = try self.planHostIntUnaryOutput(hostArraySourceValue(array), .bit, .bit, array.len(), true, true);
                fillBitNotWords(plan.output.bit.words, .{ .words = words, .len = array.len() });
                const result = try self.finishHostIntOutput(plan, host_array_flag_normalized | invertMonotonicFlags(array.flags));
                hostArraySetCachedIntRange(@constCast(result.asHostArray()), .{ .min = 0, .max = 1 });
                return result;
            },
            .float64 => |items| {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, items.len);
                for (items) |item| try out.append(self.allocator, item == 0.0);
                return try self.createManagedHostBitArray(out.items);
            },
            else => {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, hostIntArrayViewLen(view));
                for (0..hostIntArrayViewLen(view)) |idx| try out.append(self.allocator, hostIntViewItem(view, idx) == 0);
                return try self.createManagedHostBitArray(out.items);
            },
        }
    }

    fn hostNumericMatrixRowOrder(array: *const HostArray, lhs_row: usize, rhs_row: usize, cols: usize) std.math.Order {
        const left_base = lhs_row * cols;
        const right_base = rhs_row * cols;
        return switch (array.storage) {
            .bit => {
                for (0..cols) |col| {
                    const order = std.math.order(
                        @intFromBool(bitGet(array.storage.bit, left_base + col)),
                        @intFromBool(bitGet(array.storage.bit, right_base + col)),
                    );
                    if (order != .eq) return order;
                }
                return .eq;
            },
            .float64 => |items| {
                for (0..cols) |col| {
                    const order = std.math.order(items[left_base + col], items[right_base + col]);
                    if (order != .eq) return order;
                }
                return .eq;
            },
            .boxed => unreachable,
            else => {
                const view = hostIntArrayView(array).?;
                for (0..cols) |col| {
                    const order = std.math.order(hostIntViewItem(view, left_base + col), hostIntViewItem(view, right_base + col));
                    if (order != .eq) return order;
                }
                return .eq;
            },
        };
    }

    fn hostItemOrder(array: *const HostArray, lhs: usize, rhs: usize) std.math.Order {
        if (hostNumericMatrixShape(array)) |shape| return hostNumericMatrixRowOrder(array, lhs, rhs, shape.cols);
        return switch (array.storage) {
            .bit => std.math.order(@intFromBool(bitGet(array.storage.bit, lhs)), @intFromBool(bitGet(array.storage.bit, rhs))),
            .float64 => std.math.order(array.storage.float64[lhs], array.storage.float64[rhs]),
            else => std.math.order(hostIntViewItem(hostIntArrayView(array).?, lhs), hostIntViewItem(hostIntArrayView(array).?, rhs)),
        };
    }

    fn orderComesBefore(order: std.math.Order, ascending: bool) bool {
        return if (ascending) order == .lt else order == .gt;
    }

    fn hostIndexedOrder(_: *Session, array: *const HostArray, lhs: usize, rhs: usize) KError!std.math.Order {
        return hostItemOrder(array, lhs, rhs);
    }

    fn numericVectorIndexedOrder(_: *Session, value: Value, lhs: usize, rhs: usize) KError!std.math.Order {
        return switch (valueNumericMode(value) orelse return error.Type) {
            .float => std.math.order(try numericFloatAt(value, lhs), try numericFloatAt(value, rhs)),
            .int => std.math.order(try numericIntAt(value, lhs), try numericIntAt(value, rhs)),
        };
    }

    fn numericMatrixIndexedOrder(self: *Session, view: NumericMatrixView, lhs: usize, rhs: usize) KError!std.math.Order {
        return try numericMatrixRowOrder(self, view, lhs, rhs);
    }

    fn stableMergeSortIndices(
        self: *Session,
        idxs: []usize,
        ascending: bool,
        context: anytype,
        comptime orderFn: fn (*Session, @TypeOf(context), usize, usize) KError!std.math.Order,
    ) KError!void {
        if (idxs.len <= 1) return;
        const scratch = try self.allocator.alloc(usize, idxs.len);
        defer self.allocator.free(scratch);

        var src: []usize = idxs;
        var dst: []usize = scratch;
        var width: usize = 1;
        var flipped = false;
        while (width < idxs.len) {
            var start: usize = 0;
            while (start < src.len) : (start += width * 2) {
                const mid = @min(start + width, src.len);
                const end = @min(start + width * 2, src.len);
                var left = start;
                var right = mid;
                var out = start;
                while (left < mid and right < end) : (out += 1) {
                    const order = try orderFn(self, context, src[right], src[left]);
                    if (orderComesBefore(order, ascending)) {
                        dst[out] = src[right];
                        right += 1;
                    } else {
                        dst[out] = src[left];
                        left += 1;
                    }
                }
                while (left < mid) : ({
                    left += 1;
                    out += 1;
                }) dst[out] = src[left];
                while (right < end) : ({
                    right += 1;
                    out += 1;
                }) dst[out] = src[right];
            }
            const next_width = if (width > idxs.len / 2) idxs.len else width * 2;
            const tmp = src;
            src = dst;
            dst = tmp;
            width = next_width;
            flipped = !flipped;
        }
        if (flipped) @memcpy(idxs, src);
    }

    fn managedHostIndexArrayValue(self: *Session, idxs: []const usize) KError!Value {
        var out = try self.allocator.alloc(i64, idxs.len);
        defer self.allocator.free(out);
        for (idxs, 0..) |idx, out_idx| out[out_idx] = @intCast(idx);
        return try self.createManagedHostIntArray(out);
    }

    fn gradeValue(self: *Session, value: Value, ascending: bool) KError!Value {
        if (NumericStructuralView.init(value)) |structural| {
            if (try numericStructuralGradeValue(self, structural, ascending)) |result| {
                if (self.debugDetailedProbeActive()) self.debug_grade_structural_numeric_fast_count += 1;
                return result;
            }
        }
        if (valueNumericMode(value) != null) {
            if (numericVectorLen(value)) |len| {
                if (hostArrayIfPresent(value) != null or numericValueSupportsStructuralFlatItemsWithoutHost(value)) {
                    const idxs = try self.allocator.alloc(usize, len);
                    defer self.allocator.free(idxs);
                    for (idxs, 0..) |*slot, idx| slot.* = idx;
                    try self.stableMergeSortIndices(idxs, ascending, value, numericVectorIndexedOrder);
                    if (self.debugDetailedProbeActive()) self.debug_grade_structural_numeric_fast_count += 1;
                    return try self.managedHostIndexArrayValue(idxs);
                }
            }
        }
        if (valueNumericMatrixView(value)) |matrix| {
            const idxs = try self.allocator.alloc(usize, matrix.shape.rows);
            defer self.allocator.free(idxs);
            for (idxs, 0..) |*slot, idx| slot.* = idx;
            try self.stableMergeSortIndices(idxs, ascending, matrix, numericMatrixIndexedOrder);
            if (self.debugDetailedProbeActive()) self.debug_grade_structural_numeric_fast_count += 1;
            return try self.managedHostIndexArrayValue(idxs);
        }
        const array = try hostStructuralArrayValue(self, value);
        const len = if (hostNumericMatrixShape(array)) |shape| shape.rows else array.len();
        const idxs = try self.allocator.alloc(usize, len);
        defer self.allocator.free(idxs);
        for (idxs, 0..) |*slot, idx| slot.* = idx;
        try self.stableMergeSortIndices(idxs, ascending, array, hostIndexedOrder);
        return try self.managedHostIndexArrayValue(idxs);
    }

    fn sortValue(self: *Session, value: Value) KError!Value {
        if (valueRangeIotaHandle(value)) |handle| {
            if (handle.rank > 1) {
                if (handle.range_iota.step >= 0) return self.shareValue(value);
            } else if (handle.range_iota.step >= 0) {
                return self.shareValue(value);
            } else {
                const len = numericArrayRangeLen(handle);
                const start = if (len == 0)
                    handle.range_iota.start
                else
                    try numericArrayRangeIotaValueAt(handle, len - 1);
                const step = try checkedIntOp(.sub, 0, handle.range_iota.step);
                return try newRangeIotaValueWithParams(self, .managed, len, start, step);
            }
        }
        if (valueNumericMatrixView(value)) |matrix| {
            const idxs = try self.allocator.alloc(usize, matrix.shape.rows);
            defer self.allocator.free(idxs);
            for (idxs, 0..) |*slot, idx| slot.* = idx;
            try self.stableMergeSortIndices(idxs, true, matrix, numericMatrixIndexedOrder);
            return try numericValueMatrixSelectRows(self, value, idxs);
        }
        const array = try hostStructuralArrayValue(self, value);
        if (hostNumericMatrixShape(array)) |shape| {
            const idxs = try self.allocator.alloc(usize, shape.rows);
            defer self.allocator.free(idxs);
            for (idxs, 0..) |*slot, idx| slot.* = idx;
            try self.stableMergeSortIndices(idxs, true, array, hostIndexedOrder);
            return try self.createManagedHostNumericMatrixRows(array, idxs, shape.cols);
        }
        return switch (array.storage) {
            .bit => blk: {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                var count_one: usize = 0;
                for (0..array.len()) |idx| {
                    if (bitGet(array.storage.bit, idx)) count_one += 1;
                }
                try out.resize(self.allocator, array.len());
                for (out.items, 0..) |*slot, idx| slot.* = idx >= (array.len() - count_one);
                break :blk try self.createManagedHostBitArray(out.items);
            },
            .float64 => |items| blk: {
                var out = try self.allocator.dupe(f64, items);
                defer self.allocator.free(out);
                var i: usize = 1;
                while (i < out.len) : (i += 1) {
                    const current = out[i];
                    var j = i;
                    while (j > 0 and current < out[j - 1]) : (j -= 1) out[j] = out[j - 1];
                    out[j] = current;
                }
                break :blk try self.createManagedHostFloatArray(out);
            },
            else => blk: {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, hostIntArrayViewLen(view));
                for (0..hostIntArrayViewLen(view)) |idx| try out.append(self.allocator, hostIntViewItem(view, idx));
                var i: usize = 1;
                while (i < out.items.len) : (i += 1) {
                    const current = out.items[i];
                    var j = i;
                    while (j > 0 and current < out.items[j - 1]) : (j -= 1) out.items[j] = out.items[j - 1];
                    out.items[j] = current;
                }
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn concatValues(self: *Session, left: Value, right: Value) KError!Value {
        if (try concatNumericMatrixShape(self, left, right)) |shape| {
            if (try concatNumericMatrixValue(self, left, right, shape)) |result| return result;
            var values = std.ArrayList(Value).empty;
            defer values.deinit(self.allocator);
            try self.appendConcatValue(&values, left);
            try self.appendConcatValue(&values, right);
            const result = try self.makeArrayFromValues(values.items);
            return try self.setNumericMatrixShapeOnValue(result, shape.rows, shape.cols);
        }
        if (left.tag() == .array and right.tag() == .array and
            valueNumericMode(left) != null and valueNumericMode(right) != null and
            numericVectorLen(left) != null and numericVectorLen(right) != null)
        {
            return try newFlatConcatValue(self, left, right);
        }
        var values = std.ArrayList(Value).empty;
        defer values.deinit(self.allocator);
        try self.appendConcatValue(&values, left);
        try self.appendConcatValue(&values, right);
        return try self.makeArrayFromValues(values.items);
    }

    fn appendConcatValue(self: *Session, values: *std.ArrayList(Value), value: Value) KError!void {
        if (value.tag() != .array) {
            switch (value.tag()) {
                .int, .bool, .float => try values.append(self.allocator, value),
                else => return error.Type,
            }
            return;
        }
        if (valueHostIntStructuralView(value)) |view| {
            for (0..hostIntDenseViewLen(view)) |idx| try values.append(self.allocator, try self.intValue(try hostIntDenseViewItem(view, idx)));
            return;
        }
        const array = try hostStructuralArrayValue(self, value);
        switch (array.storage) {
            .bit => |words| for (0..array.len()) |idx| try values.append(self.allocator, Value.fromBool(bitGet(words, idx))),
            .float64 => |items| for (items) |item| try values.append(self.allocator, try self.floatValue(item)),
            else => {
                const view = hostIntArrayView(array).?;
                for (0..hostIntArrayViewLen(view)) |idx| try values.append(self.allocator, try self.intValue(hostIntViewItem(view, idx)));
            },
        }
    }

    fn takeValues(self: *Session, left: Value, right: Value) KError!Value {
        const raw_count = scalarIntLikeValue(left) orelse return error.Type;
        if (right.tag() != .array) {
            if (right.tag() != .int and right.tag() != .bool and right.tag() != .float) return error.Type;
            return try self.takeScalarValue(raw_count, right);
        }
        if (valueNumericMatrixView(right)) |matrix| {
            const count: usize = @intCast(@abs(raw_count));
            if (count == 0) return try numericValueMatrixSelectRows(self, right, &.{});
            if (matrix.shape.rows == 0) return error.Type;

            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, count);
            if (raw_count >= 0) {
                for (0..count) |idx| try row_indices.append(self.allocator, idx % matrix.shape.rows);
            } else {
                const pad = if (count > matrix.shape.rows) count - matrix.shape.rows else 0;
                for (0..pad) |_| try row_indices.append(self.allocator, 0);
                const start = if (count >= matrix.shape.rows) 0 else matrix.shape.rows - count;
                for (start..matrix.shape.rows) |idx| try row_indices.append(self.allocator, idx);
            }
            return try numericValueMatrixSelectRows(self, right, row_indices.items);
        }
        if (shapedNumericHandle(right)) |handle| {
            const rows: usize = @intCast(handle.shape[0]);
            const count: usize = @intCast(@abs(raw_count));
            if (count == 0) {
                if (try numericValueFirstAxisContiguousSliceValue(self, right, .{ .start = 0, .len = 0 })) |result| return result;
            } else if (count <= rows) {
                const start = if (raw_count >= 0) 0 else rows - count;
                if (try numericValueFirstAxisContiguousSliceValue(self, right, .{ .start = start, .len = count })) |result| return result;
            }
        }
        if (NumericStructuralView.init(right)) |structural| {
            if (try numericStructuralTakeValue(self, structural, raw_count)) |result| return result;
        }
        if (valueNumericMode(right) != null) {
            if (numericVectorLen(right)) |len| {
                const count: usize = @intCast(@abs(raw_count));
                if (count == 0) return try newFlatSliceValue(self, right, 0, 0);
                if (len == 0) return error.Type;
                if (count <= len) {
                    const start = if (raw_count >= 0) 0 else len - count;
                    return try newFlatSliceValue(self, right, start, count);
                }
            }
        }
        return try self.takeHostArray(raw_count, try hostStructuralArrayValue(self, right));
    }

    fn takeScalarValue(self: *Session, raw_count: i64, value: Value) KError!Value {
        if (raw_count == 0) return try self.createManagedHostIntArray(&.{});
        const count: usize = @intCast(@abs(raw_count));
        switch (value.tag()) {
            .bool => {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                for (0..count) |_| try out.append(self.allocator, value.asBool());
                return try self.createManagedHostBitArray(out.items);
            },
            .float => {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                for (0..count) |_| try out.append(self.allocator, value.asFloat());
                return try self.createManagedHostFloatArray(out.items);
            },
            .int => {
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                for (0..count) |_| try out.append(self.allocator, value.asInt());
                return try self.createManagedHostIntArray(out.items);
            },
            else => return error.Type,
        }
    }

    fn takeHostArray(self: *Session, raw_count: i64, array: *const HostArray) KError!Value {
        if (hostNumericMatrixShape(array)) |shape| {
            const count: usize = @intCast(@abs(raw_count));
            if (count == 0) {
                const value = switch (array.storage) {
                    .bit => try self.createManagedHostBitArray(&.{}),
                    .float64 => try self.createManagedHostFloatArray(&.{}),
                    else => try self.createManagedHostIntArray(&.{}),
                };
                return try self.setNumericMatrixShapeOnValue(value, 0, shape.cols);
            }
            if (shape.rows == 0) return error.Type;

            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, count);
            if (raw_count >= 0) {
                for (0..count) |idx| try row_indices.append(self.allocator, idx % shape.rows);
            } else {
                const pad = if (count > shape.rows) count - shape.rows else 0;
                for (0..pad) |_| try row_indices.append(self.allocator, 0);
                const start = if (count >= shape.rows) 0 else shape.rows - count;
                for (start..shape.rows) |idx| try row_indices.append(self.allocator, idx);
            }
            return try self.createManagedHostNumericMatrixRows(array, row_indices.items, shape.cols);
        }
        const count: usize = @intCast(@abs(raw_count));
        if (count == 0) {
            return switch (array.storage) {
                .bit => try self.createManagedHostBitArray(&.{}),
                .float64 => try self.createManagedHostFloatArray(&.{}),
                else => try self.createManagedHostIntArray(&.{}),
            };
        }
        if (array.len() == 0) return error.Type;
        if (raw_count >= 0) {
            return switch (array.storage) {
                .bit => blk: {
                    var out = std.ArrayList(bool).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, count);
                    for (0..count) |idx| try out.append(self.allocator, bitGet(array.storage.bit, idx % array.len()));
                    break :blk try self.createManagedHostBitArray(out.items);
                },
                .float64 => |items| blk: {
                    var out = std.ArrayList(f64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, count);
                    for (0..count) |idx| try out.append(self.allocator, items[idx % items.len]);
                    break :blk try self.createManagedHostFloatArray(out.items);
                },
                else => blk: {
                    const view = hostIntArrayView(array).?;
                    var out = std.ArrayList(i64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, count);
                    for (0..count) |idx| try out.append(self.allocator, hostIntViewItem(view, idx % hostIntArrayViewLen(view)));
                    break :blk try self.createManagedHostIntArray(out.items);
                },
            };
        }
        return switch (array.storage) {
            .bit => blk: {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                const pad = if (count > array.len()) count - array.len() else 0;
                for (0..pad) |_| try out.append(self.allocator, bitGet(array.storage.bit, 0));
                const start = if (count >= array.len()) 0 else array.len() - count;
                for (start..array.len()) |idx| try out.append(self.allocator, bitGet(array.storage.bit, idx));
                break :blk try self.createManagedHostBitArray(out.items);
            },
            .float64 => |items| blk: {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                const pad = if (count > items.len) count - items.len else 0;
                for (0..pad) |_| try out.append(self.allocator, items[0]);
                const start = if (count >= items.len) 0 else items.len - count;
                for (items[start..]) |item| try out.append(self.allocator, item);
                break :blk try self.createManagedHostFloatArray(out.items);
            },
            else => blk: {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                const pad = if (count > hostIntArrayViewLen(view)) count - hostIntArrayViewLen(view) else 0;
                const first = hostIntViewItem(view, 0);
                for (0..pad) |_| try out.append(self.allocator, first);
                const start = if (count >= hostIntArrayViewLen(view)) 0 else hostIntArrayViewLen(view) - count;
                for (start..hostIntArrayViewLen(view)) |idx| try out.append(self.allocator, hostIntViewItem(view, idx));
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn dropValues(self: *Session, left: Value, right: Value) KError!Value {
        const raw_count = scalarIntLikeValue(left) orelse return error.Type;
        if (valueNumericMatrixView(right)) |matrix| {
            const drop_count: usize = if (raw_count >= 0)
                @min(@as(usize, @intCast(raw_count)), matrix.shape.rows)
            else
                matrix.shape.rows - @min(@as(usize, @intCast(-raw_count)), matrix.shape.rows);
            const start: usize = if (raw_count >= 0) drop_count else 0;
            const end: usize = if (raw_count >= 0) matrix.shape.rows else drop_count;
            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, end - start);
            for (start..end) |idx| try row_indices.append(self.allocator, idx);
            return try numericValueMatrixSelectRows(self, right, row_indices.items);
        }
        if (shapedNumericHandle(right)) |handle| {
            const rows: usize = @intCast(handle.shape[0]);
            const drop_count: usize = if (raw_count >= 0)
                @min(@as(usize, @intCast(raw_count)), rows)
            else
                rows - @min(@as(usize, @intCast(-raw_count)), rows);
            const start: usize = if (raw_count >= 0) drop_count else 0;
            const end: usize = if (raw_count >= 0) rows else drop_count;
            if (try numericValueFirstAxisContiguousSliceValue(self, right, .{ .start = start, .len = end - start })) |result| return result;
        }
        if (NumericStructuralView.init(right)) |structural| {
            if (try numericStructuralDropValue(self, structural, raw_count)) |result| return result;
        }
        if (valueNumericMode(right) != null) {
            if (numericVectorLen(right)) |len| {
                const drop_count: usize = if (raw_count >= 0)
                    @min(@as(usize, @intCast(raw_count)), len)
                else
                    len - @min(@as(usize, @intCast(-raw_count)), len);
                const start: usize = if (raw_count >= 0) drop_count else 0;
                const end: usize = if (raw_count >= 0) len else drop_count;
                return try newFlatSliceValue(self, right, start, end - start);
            }
        }
        const array = try hostStructuralArrayValue(self, right);
        if (hostNumericMatrixShape(array)) |shape| {
            const drop_count: usize = if (raw_count >= 0)
                @min(@as(usize, @intCast(raw_count)), shape.rows)
            else
                shape.rows - @min(@as(usize, @intCast(-raw_count)), shape.rows);
            const start: usize = if (raw_count >= 0) drop_count else 0;
            const end: usize = if (raw_count >= 0) shape.rows else drop_count;
            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, end - start);
            for (start..end) |idx| try row_indices.append(self.allocator, idx);
            return try self.createManagedHostNumericMatrixRows(array, row_indices.items, shape.cols);
        }
        const len = array.len();
        const drop_count: usize = if (raw_count >= 0)
            @min(@as(usize, @intCast(raw_count)), len)
        else
            len - @min(@as(usize, @intCast(-raw_count)), len);
        const start: usize = if (raw_count >= 0) drop_count else 0;
        const end: usize = if (raw_count >= 0) len else drop_count;
        return switch (array.storage) {
            .bit => blk: {
                var out = std.ArrayList(bool).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, end - start);
                for (start..end) |idx| try out.append(self.allocator, bitGet(array.storage.bit, idx));
                break :blk try self.createManagedHostBitArray(out.items);
            },
            .float64 => |items| try self.createManagedHostFloatArray(items[start..end]),
            else => blk: {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, end - start);
                for (start..end) |idx| try out.append(self.allocator, hostIntViewItem(view, idx));
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn reshapeValues(self: *Session, left: Value, right: Value) KError!Value {
        const row_len_value = scalarIntLikeValue(left) orelse return error.Type;
        if (row_len_value <= 0) return error.Type;

        const row_len: usize = @intCast(row_len_value);
        const total = numericFlatLen(right) orelse if (right.tag() == .array)
            (try hostStructuralArrayValue(self, right)).len()
        else
            return error.Type;
        if (total == 0 or total % row_len != 0) return error.Unsupported;

        const rows = total / row_len;
        if (valueRangeIotaHandle(right)) |handle| {
            return try newRangeIotaValueWithShape(
                self,
                .managed,
                total,
                handle.range_iota.start,
                handle.range_iota.step,
                numericShapeSnapshotMatrix(rows, row_len),
            );
        }
        if (valueNumericMode(right) != null) {
            return try newReshapeViewValue(self, right, numericShapeSnapshotMatrix(rows, row_len));
        }

        const source = try hostStructuralArrayValue(self, right);
        if (hostArrayNumericMode(source) != null) {
            const value = switch (source.storage) {
                .bit => blk: {
                    var out = std.ArrayList(bool).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, total);
                    for (0..total) |idx| try out.append(self.allocator, bitGet(source.storage.bit, idx));
                    break :blk try self.createManagedHostBitArray(out.items);
                },
                .float64 => |items| try self.createManagedHostFloatArray(items),
                .boxed => return error.Type,
                else => blk: {
                    const view = hostIntArrayView(source) orelse return error.Type;
                    var out = std.ArrayList(i64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, total);
                    for (0..total) |idx| try out.append(self.allocator, hostIntViewItem(view, idx));
                    break :blk try self.createManagedHostIntArray(out.items);
                },
            };
            return try self.setNumericMatrixShapeOnValue(value, rows, row_len);
        }

        var outer = std.ArrayList(Value).empty;
        defer {
            for (outer.items) |value| self.releaseValue(value);
            outer.deinit(self.allocator);
        }
        try outer.ensureTotalCapacity(self.allocator, rows);

        for (0..rows) |row_idx| {
            var inner = std.ArrayList(Value).empty;
            defer inner.deinit(self.allocator);
            try inner.ensureTotalCapacity(self.allocator, row_len);
            const start = row_idx * row_len;
            for (0..row_len) |col_idx| {
                try inner.append(self.allocator, try self.hostArrayIndexScalar(source, @intCast(start + col_idx)));
            }
            try outer.append(self.allocator, try self.createManagedArrayLikeFromValues(inner.items));
        }
        return try self.createManagedArrayLikeFromValues(outer.items);
    }

fn equalValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.equalValues(operands.left, operands.right);
    }
    if (left.tag() != .array and right.tag() != .array) {
            if (left.tag() == .float or right.tag() == .float) {
                const lhs = switch (left.tag()) {
                    .float => left.asFloat(),
                    .int => @as(f64, @floatFromInt(left.asInt())),
                    .bool => @as(f64, @floatFromInt(@intFromBool(left.asBool()))),
                    else => return error.Type,
                };
                const rhs = switch (right.tag()) {
                    .float => right.asFloat(),
                    .int => @as(f64, @floatFromInt(right.asInt())),
                    .bool => @as(f64, @floatFromInt(@intFromBool(right.asBool()))),
                    else => return error.Type,
                };
                return Value.fromBool(lhs == rhs);
            }
            const lhs = scalarIntLikeValue(left) orelse return error.Type;
            const rhs = scalarIntLikeValue(right) orelse return error.Type;
            return Value.fromBool(lhs == rhs);
        }
        return try self.equalArrayValues(left, right);
    }

    fn compareScalars(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        _ = self;
        if (left.tag() == .float or right.tag() == .float) {
            const lhs = switch (left.tag()) {
                .float => left.asFloat(),
                .int => @as(f64, @floatFromInt(left.asInt())),
                .bool => @as(f64, @floatFromInt(@intFromBool(left.asBool()))),
                else => return error.Type,
            };
            const rhs = switch (right.tag()) {
                .float => right.asFloat(),
                .int => @as(f64, @floatFromInt(right.asInt())),
                .bool => @as(f64, @floatFromInt(@intFromBool(right.asBool()))),
                else => return error.Type,
            };
            return Value.fromBool(switch (op) {
                .less => lhs < rhs,
                .more => lhs > rhs,
                else => return error.Internal,
            });
        }
        const lhs = scalarIntLikeValue(left) orelse return error.Type;
        const rhs = scalarIntLikeValue(right) orelse return error.Type;
        return Value.fromBool(switch (op) {
            .less => lhs < rhs,
            .more => lhs > rhs,
            else => return error.Internal,
        });
    }

fn compareNumericArrayValues(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
    if (planCompareMaskBackend(self, op, left, right) == .mlx) return try self.applyMlxArrayDyad(op, left, right);
    const len = try arrayResultLen(left, right);
    const shape = try nonVectorNumericShapeForDyad(left, right);
    const rowwise = rowwiseMatrixVectorDyad(left, right);
    var out = std.ArrayList(bool).empty;
    defer out.deinit(self.allocator);
    try out.ensureTotalCapacity(self.allocator, len);
    for (0..len) |idx| {
        const lhs = if (left.tag() == .array)
            try numericFloatAt(left, if (rowwise) |info| info.operandIndex(true, idx) else idx)
        else
            scalarNumericFloatValue(left).?;
        const rhs = if (right.tag() == .array)
            try numericFloatAt(right, if (rowwise) |info| info.operandIndex(false, idx) else idx)
        else
            scalarNumericFloatValue(right).?;
        try out.append(self.allocator, switch (op) {
            .less => lhs < rhs,
            .more => lhs > rhs,
                else => return error.Internal,
            });
        }
        const result = try self.createManagedHostBitArray(out.items);
        return try applyNonVectorNumericShapeToValue(self, result, shape);
    }

    fn transposeHostDenseMatrixValue(self: *Session, value: Value, shape: NumericMatrixShape) KError!?Value {
        const out_shape = numericShapeSnapshotMatrix(shape.cols, shape.rows);
        const view = hostDenseView(self, value) catch |err| switch (err) {
            error.Type => return null,
            else => return err,
        };
        return switch (view) {
            .float_array => |items| blk: {
                const out = try self.allocManagedHostFloatResult(shape.rows * shape.cols);
                for (0..shape.cols) |col_idx| {
                    for (0..shape.rows) |row_idx| {
                        out.items[col_idx * shape.rows + row_idx] = try hostFloatDenseViewItem(items, row_idx * shape.cols + col_idx);
                    }
                }
                const transposed = try out.value(self);
                break :blk try applyNonVectorNumericShapeToValue(self, transposed, out_shape);
            },
            .int_array => |items| blk: {
                const range = hostIntDenseValueRange(value, items);
                const kind = hostIntStorageKindForRange(range.min, range.max);
                var out = try self.allocManagedHostIntResult(kind, shape.rows * shape.cols);
                for (0..shape.cols) |col_idx| {
                    for (0..shape.rows) |row_idx| {
                        try out.set(col_idx * shape.rows + row_idx, try hostIntDenseViewItem(items, row_idx * shape.cols + col_idx));
                    }
                }
                const transposed = try out.value(self);
                hostArraySetFlags(@constCast(transposed.asHostArray()), if (range.min >= 0 and range.max <= 1) host_array_flag_normalized else 0);
                hostArraySetCachedIntRange(@constCast(transposed.asHostArray()), range);
                break :blk try applyNonVectorNumericShapeToValue(self, transposed, out_shape);
            },
            else => null,
        };
    }

    fn transposeMlxMatrixValue(self: *Session, value: Value) KError!Value {
        var input = try self.materializeMlxArray(value);
        defer input.deinit();
        const ctx = try self.mlxContext();
        const out = mlx.Array.transpose(ctx.*, input) catch |err| return mapMlxError(err);
        return try self.wrapManagedMlxArray(out);
    }

    fn transposeValue(self: *Session, value: Value) KError!Value {
        if (valueNumericMatrixView(value)) |matrix| {
            const elem_count = matrix.shape.rows * matrix.shape.cols;
            if (planTransposeBackend(self, value, elem_count) == .mlx) {
                return try self.transposeMlxMatrixValue(value);
            }
            if (try self.transposeHostDenseMatrixValue(value, matrix.shape)) |result| return result;

            const out_shape = numericShapeSnapshotMatrix(matrix.shape.cols, matrix.shape.rows);
            switch (matrix.mode) {
                .float => {
                    var out = std.ArrayList(f64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, elem_count);
                    for (0..matrix.shape.cols) |col_idx| {
                        for (0..matrix.shape.rows) |row_idx| {
                            try out.append(self.allocator, try numericFloatAt(value, row_idx * matrix.shape.cols + col_idx));
                        }
                    }
                    const transposed = try self.createManagedHostFloatArray(out.items);
                    return try applyNonVectorNumericShapeToValue(self, transposed, out_shape);
                },
                .int => {
                    var out = std.ArrayList(i64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, elem_count);
                    for (0..matrix.shape.cols) |col_idx| {
                        for (0..matrix.shape.rows) |row_idx| {
                            try out.append(self.allocator, try numericIntAt(value, row_idx * matrix.shape.cols + col_idx));
                        }
                    }
                    const transposed = try self.createManagedHostIntArray(out.items);
                    return try applyNonVectorNumericShapeToValue(self, transposed, out_shape);
                },
            }
        }
        if (value.tag() != .array or value.arrayKind() != .host_array or std.meta.activeTag(value.asHostArray().storage) != .boxed) return error.Type;
        const items = value.asHostArray().storage.boxed;
        if (!isRenderableMatrix(items)) return error.Type;
        const rows = items.len;
        const cols = numericVectorLen(items[0]) orelse return error.Type;
        const out_shape = numericShapeSnapshotMatrix(cols, rows);
        var saw_float = false;
        for (items) |row| {
            if ((valueNumericMode(row) orelse return error.Type) == .float) saw_float = true;
        }
        if (saw_float) {
            var out = std.ArrayList(f64).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, rows * cols);
            for (0..cols) |col_idx| {
                for (items) |row| {
                    try out.append(self.allocator, try numericFloatAt(row, col_idx));
                }
            }
            const transposed = try self.createManagedHostFloatArray(out.items);
            return try applyNonVectorNumericShapeToValue(self, transposed, out_shape);
        }
        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, rows * cols);
        for (0..cols) |col_idx| {
            for (items) |row| {
                try out.append(self.allocator, try numericIntAt(row, col_idx));
            }
        }
        const transposed = try self.createManagedHostIntArray(out.items);
        return try applyNonVectorNumericShapeToValue(self, transposed, out_shape);
    }

fn minimumValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.minimumValues(operands.left, operands.right);
    }
    if (left.tag() == .bool and right.tag() == .bool) return Value.fromBool(left.asBool() and right.asBool());
        if (try self.tryScalarIntBoolDyad(.minimum, left, right)) |result| return result;
        if (valueNumericMode(left) != null and valueNumericMode(right) != null and (left.tag() == .array or right.tag() == .array)) {
            return try self.applyDenseDyad(.minimum, left, right);
        }
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.minimum, left, right);
        if (left.tag() == .float or right.tag() == .float) {
            const lhs = scalarNumericFloatValue(left) orelse return error.Type;
            const rhs = scalarNumericFloatValue(right) orelse return error.Type;
            return try self.floatValue(@min(lhs, rhs));
        }
        const lhs = scalarIntLikeValue(left) orelse return error.Type;
        const rhs = scalarIntLikeValue(right) orelse return error.Type;
        return try self.intValue(@min(lhs, rhs));
    }

fn maximumValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.maximumValues(operands.left, operands.right);
    }
    if (left.tag() == .bool and right.tag() == .bool) return Value.fromBool(left.asBool() or right.asBool());
        if (try self.tryScalarIntBoolDyad(.maximum, left, right)) |result| return result;
        if (valueNumericMode(left) != null and valueNumericMode(right) != null and (left.tag() == .array or right.tag() == .array)) {
            return try self.applyDenseDyad(.maximum, left, right);
        }
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.maximum, left, right);
        if (left.tag() == .float or right.tag() == .float) {
            const lhs = scalarNumericFloatValue(left) orelse return error.Type;
            const rhs = scalarNumericFloatValue(right) orelse return error.Type;
            return try self.floatValue(@max(lhs, rhs));
        }
        const lhs = scalarIntLikeValue(left) orelse return error.Type;
        const rhs = scalarIntLikeValue(right) orelse return error.Type;
        return try self.intValue(@max(lhs, rhs));
    }

fn lessValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.lessValues(operands.left, operands.right);
    }
    if (try self.tryScalarIntBoolDyad(.less, left, right)) |result| return result;
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.less, left, right);
        if (valueNumericMode(left) != null and valueNumericMode(right) != null and (left.tag() == .array or right.tag() == .array)) {
            return try self.compareNumericArrayValues(.less, left, right);
        }
        return try self.compareScalars(.less, left, right);
    }

fn moreValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.moreValues(operands.left, operands.right);
    }
    if (try self.tryScalarIntBoolDyad(.more, left, right)) |result| return result;
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.more, left, right);
        if (valueNumericMode(left) != null and valueNumericMode(right) != null and (left.tag() == .array or right.tag() == .array)) {
            return try self.compareNumericArrayValues(.more, left, right);
        }
        return try self.compareScalars(.more, left, right);
    }

fn equalArrayValues(self: *Session, left: Value, right: Value) KError!Value {
    if (valueNumericMode(left) != null and valueNumericMode(right) != null) {
        if (planCompareMaskBackend(self, .equal, left, right) == .mlx) return try self.applyMlxArrayDyad(.equal, left, right);
        const len = try arrayResultLen(left, right);
        const shape = try nonVectorNumericShapeForDyad(left, right);
        const rowwise = rowwiseMatrixVectorDyad(left, right);
        var out = std.ArrayList(bool).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const lhs = if (left.tag() == .array)
                try numericFloatAt(left, if (rowwise) |info| info.operandIndex(true, idx) else idx)
            else
                scalarNumericFloatValue(left).?;
            const rhs = if (right.tag() == .array)
                try numericFloatAt(right, if (rowwise) |info| info.operandIndex(false, idx) else idx)
            else
                scalarNumericFloatValue(right).?;
            try out.append(self.allocator, lhs == rhs);
        }
        const result = try self.createManagedHostBitArray(out.items);
            return try applyNonVectorNumericShapeToValue(self, result, shape);
        }
        const left_array = if (left.tag() == .array) try hostStructuralArrayValue(self, left) else null;
        const right_array = if (right.tag() == .array) try hostStructuralArrayValue(self, right) else null;
        const len = if (left_array != null and right_array != null) blk: {
            if (left_array.?.len() != right_array.?.len()) return error.Type;
            break :blk left_array.?.len();
        } else if (left_array != null) left_array.?.len() else right_array.?.len();

        var out = std.ArrayList(bool).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const lhs = if (left_array) |array| try self.hostArrayIndexScalar(array, @intCast(idx)) else left;
            const rhs = if (right_array) |array| try self.hostArrayIndexScalar(array, @intCast(idx)) else right;
            defer if (left_array != null) self.releaseValue(lhs);
            defer if (right_array != null) self.releaseValue(rhs);
            const eq = try self.equalValues(lhs, rhs);
            defer if (eq.tag() != .bool) self.releaseValue(eq);
            try out.append(self.allocator, eq.asBool());
        }
        return try self.createManagedHostBitArray(out.items);
    }

fn addValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.addValues(operands.left, operands.right);
    }
    if (try self.tryScalarIntBoolDyad(.add, left, right)) |result| return result;
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.add, left, right);
        if (left.tag() == .array or right.tag() == .array) return try self.applyDenseDyad(.add, left, right);
        return switch (left.tag()) {
            .int => switch (right.tag()) {
                .float => try self.floatValue(@as(f64, @floatFromInt(left.asInt())) + right.asFloat()),
                else => error.Type,
            },
            .bool => switch (right.tag()) {
                .float => try self.floatValue(@as(f64, @floatFromInt(@intFromBool(left.asBool()))) + right.asFloat()),
                else => error.Type,
            },
            .float => switch (right.tag()) {
                .int, .bool => try self.floatValue(left.asFloat() + @as(f64, @floatFromInt(scalarIntLikeValue(right).?))),
                .float => try self.floatValue(left.asFloat() + right.asFloat()),
                else => error.Type,
            },
            else => error.Type,
        };
    }

fn subValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.subValues(operands.left, operands.right);
    }
    if (try self.tryScalarIntBoolDyad(.sub, left, right)) |result| return result;
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.sub, left, right);
        if (left.tag() == .array or right.tag() == .array) return try self.applyDenseDyad(.sub, left, right);
        return switch (left.tag()) {
            .int => switch (right.tag()) {
                .float => try self.floatValue(@as(f64, @floatFromInt(left.asInt())) - right.asFloat()),
                else => error.Type,
            },
            .bool => switch (right.tag()) {
                .float => try self.floatValue(@as(f64, @floatFromInt(@intFromBool(left.asBool()))) - right.asFloat()),
                else => error.Type,
            },
            .float => switch (right.tag()) {
                .int, .bool => try self.floatValue(left.asFloat() - @as(f64, @floatFromInt(scalarIntLikeValue(right).?))),
                .float => try self.floatValue(left.asFloat() - right.asFloat()),
                else => error.Type,
            },
            else => error.Type,
        };
    }

fn mulValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.mulValues(operands.left, operands.right);
    }
    if (try self.tryScalarIntBoolDyad(.mul, left, right)) |result| return result;
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.mul, left, right);
        if (left.tag() == .array or right.tag() == .array) return try self.applyDenseDyad(.mul, left, right);
        return switch (left.tag()) {
            .int => switch (right.tag()) {
                .float => try self.floatValue(@as(f64, @floatFromInt(left.asInt())) * right.asFloat()),
                else => error.Type,
            },
            .bool => switch (right.tag()) {
                .float => try self.floatValue(@as(f64, @floatFromInt(@intFromBool(left.asBool()))) * right.asFloat()),
                else => error.Type,
            },
            .float => switch (right.tag()) {
                .int, .bool => try self.floatValue(left.asFloat() * @as(f64, @floatFromInt(scalarIntLikeValue(right).?))),
                .float => try self.floatValue(left.asFloat() * right.asFloat()),
                else => error.Type,
            },
            else => error.Type,
        };
    }

fn divValues(self: *Session, left: Value, right: Value) KError!Value {
    if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
        return try self.divValues(operands.left, operands.right);
    }
    if (try self.tryScalarIntBoolDyad(.div, left, right)) |result| return result;
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.div, left, right);
        if (left.tag() == .array or right.tag() == .array) return try self.applyDenseDyad(.div, left, right);
        const left_float = switch (left.tag()) {
            .int => @as(f64, @floatFromInt(left.asInt())),
            .bool => @as(f64, @floatFromInt(@intFromBool(left.asBool()))),
            .float => left.asFloat(),
            else => return error.Type,
        };
        const right_float = switch (right.tag()) {
            .int => @as(f64, @floatFromInt(right.asInt())),
            .bool => @as(f64, @floatFromInt(@intFromBool(right.asBool()))),
            .float => right.asFloat(),
            else => return error.Type,
        };
        return try self.floatValue(left_float / right_float);
    }

    const MatmulShape = struct {
        left_rank: u8,
        right_rank: u8,
        result_rank: u8,
        left_rows: usize,
        left_cols: usize,
        right_rows: usize,
        right_cols: usize,
        result_rows: usize,
        result_cols: usize,
        result_len: usize,
        result_mode: HostArrayElem,
    };

    fn matmulShapeForValues(left: Value, right: Value) KError!?MatmulShape {
        const left_mode = valueNumericMode(left) orelse return null;
        const right_mode = valueNumericMode(right) orelse return null;

        const left_matrix = valueNumericMatrixShape(left);
        const right_matrix = valueNumericMatrixShape(right);
        const left_vector_len = numericVectorLen(left);
        const right_vector_len = numericVectorLen(right);

        if (left_matrix == null and left_vector_len == null) return null;
        if (right_matrix == null and right_vector_len == null) return null;

        const left_rank: u8 = if (left_matrix != null) 2 else 1;
        const right_rank: u8 = if (right_matrix != null) 2 else 1;
        const left_rows = if (left_matrix) |shape| shape.rows else 1;
        const left_cols = if (left_matrix) |shape| shape.cols else left_vector_len.?;
        const right_rows = if (right_matrix) |shape| shape.rows else right_vector_len.?;
        const right_cols = if (right_matrix) |shape| shape.cols else 1;
        if (left_cols != right_rows) return error.Type;

        const result_rank: u8 = if (left_rank == 1 and right_rank == 1) 0 else if (left_rank == 2 and right_rank == 2) 2 else 1;
        const result_rows = if (left_rank == 2) left_rows else 1;
        const result_cols = if (right_rank == 2) right_cols else 1;
        return .{
            .left_rank = left_rank,
            .right_rank = right_rank,
            .result_rank = result_rank,
            .left_rows = left_rows,
            .left_cols = left_cols,
            .right_rows = right_rows,
            .right_cols = right_cols,
            .result_rows = result_rows,
            .result_cols = result_cols,
            .result_len = result_rows * result_cols,
            .result_mode = if (left_mode == .float or right_mode == .float) .float else .int,
        };
    }

    fn hostDenseViewFloatItem(view: HostDenseView, idx: usize) KError!f64 {
        return switch (view) {
            .scalar_int => |value| @floatFromInt(value),
            .scalar_float => |value| value,
            .int_array => |items| @floatFromInt(try hostIntDenseViewItem(items, idx)),
            .float_array => |items| try hostFloatDenseViewItem(items, idx),
        };
    }

    fn hostDenseViewIntItem(view: HostDenseView, idx: usize) KError!i64 {
        return switch (view) {
            .scalar_int => |value| value,
            .int_array => |items| try hostIntDenseViewItem(items, idx),
            else => error.Type,
        };
    }

    fn finishHostMatmulFloatResult(self: *Session, shape: MatmulShape, out: HostFloatResult) KError!Value {
        if (shape.result_rank == 0) return try self.floatValue(out.items[0]);
        const value = try out.value(self);
        const analysis = analyzeFloatSlice(out.items);
        hostArraySetFlags(@constCast(value.asHostArray()), analysis.flags);
        if (shape.result_rank == 2) return try newReshapeViewValue(self, value, numericShapeSnapshotMatrix(shape.result_rows, shape.result_cols));
        return value;
    }

    fn finishHostMatmulIntResult(self: *Session, shape: MatmulShape, items: []const i64) KError!Value {
        if (shape.result_rank == 0) return try self.intValue(items[0]);
        const value = try self.createManagedHostIntArray(items);
        if (shape.result_rank == 2) return try newReshapeViewValue(self, value, numericShapeSnapshotMatrix(shape.result_rows, shape.result_cols));
        return value;
    }

    fn transposeDenseFloatMatrixBlocked(out: []f64, input: []const f64, rows: usize, cols: usize) void {
        const tile: usize = 32;
        var row0: usize = 0;
        while (row0 < rows) : (row0 += tile) {
            const row_end = @min(row0 + tile, rows);
            var col0: usize = 0;
            while (col0 < cols) : (col0 += tile) {
                const col_end = @min(col0 + tile, cols);
                var row_idx = row0;
                while (row_idx < row_end) : (row_idx += 1) {
                    const input_row = input[row_idx * cols ..][0..cols];
                    var col_idx = col0;
                    while (col_idx < col_end) : (col_idx += 1) {
                        out[col_idx * rows + row_idx] = input_row[col_idx];
                    }
                }
            }
        }
    }

    fn denseFloatDot(lhs: []const f64, rhs: []const f64) f64 {
        const lane_count = 4;
        const Vec = @Vector(lane_count, f64);
        var acc_vec: Vec = @splat(0.0);
        var idx: usize = 0;
        const vector_limit = lhs.len - (lhs.len % lane_count);
        while (idx < vector_limit) : (idx += lane_count) {
            const lhs_vec: Vec = lhs[idx..][0..lane_count].*;
            const rhs_vec: Vec = rhs[idx..][0..lane_count].*;
            acc_vec += lhs_vec * rhs_vec;
        }
        var acc = @reduce(.Add, acc_vec);
        while (idx < lhs.len) : (idx += 1) acc += lhs[idx] * rhs[idx];
        return acc;
    }

    fn applyHostMatmulFloatDense(self: *Session, left_items: []const f64, right_items: []const f64, shape: MatmulShape) KError!Value {
        if (shape.result_rank == 0) {
            return try self.floatValue(denseFloatDot(left_items[0..shape.left_cols], right_items[0..shape.left_cols]));
        }

        const right_t = try self.allocator.alloc(f64, right_items.len);
        defer self.allocator.free(right_t);
        transposeDenseFloatMatrixBlocked(right_t, right_items, shape.right_rows, shape.right_cols);

        const out = try self.allocManagedHostFloatResult(shape.result_len);
        for (0..shape.result_rows) |row_idx| {
            const out_row = out.items[row_idx * shape.result_cols ..][0..shape.result_cols];
            const left_row = left_items[row_idx * shape.left_cols ..][0..shape.left_cols];
            for (0..shape.result_cols) |col_idx| {
                const right_col = right_t[col_idx * shape.left_cols ..][0..shape.left_cols];
                out_row[col_idx] = denseFloatDot(left_row, right_col);
            }
        }
        return try self.finishHostMatmulFloatResult(shape, out);
    }

    fn applyHostMatmulGeneric(self: *Session, left: Value, right: Value, shape: MatmulShape) KError!Value {
        const left_view = try hostDenseView(self, left);
        const right_view = try hostDenseView(self, right);

        if (shape.result_mode == .float) {
            if (left_view == .float_array and left_view.float_array == .dense and right_view == .float_array and right_view.float_array == .dense) {
                return try self.applyHostMatmulFloatDense(left_view.float_array.dense, right_view.float_array.dense, shape);
            }

            if (shape.result_rank == 0) {
                var acc: f64 = 0.0;
                for (0..shape.left_cols) |inner_idx| {
                    acc += (try hostDenseViewFloatItem(left_view, inner_idx)) *
                        (try hostDenseViewFloatItem(right_view, inner_idx));
                }
                return try self.floatValue(acc);
            }

            const out = try self.allocManagedHostFloatResult(shape.result_len);
            @memset(out.items, 0.0);
            for (0..shape.result_rows) |row_idx| {
                const out_row = out.items[row_idx * shape.result_cols ..][0..shape.result_cols];
                for (0..shape.left_cols) |inner_idx| {
                    const left_value = try hostDenseViewFloatItem(left_view, row_idx * shape.left_cols + inner_idx);
                    const right_base = inner_idx * shape.right_cols;
                    for (0..shape.result_cols) |col_idx| {
                        out_row[col_idx] += left_value * (try hostDenseViewFloatItem(right_view, right_base + col_idx));
                    }
                }
            }
            return try self.finishHostMatmulFloatResult(shape, out);
        }

        var out_items = try self.allocator.alloc(i64, shape.result_len);
        defer self.allocator.free(out_items);

        if (shape.result_rank == 0) {
            var acc: i128 = 0;
            for (0..shape.left_cols) |inner_idx| {
                acc += @as(i128, try hostDenseViewIntItem(left_view, inner_idx)) *
                    @as(i128, try hostDenseViewIntItem(right_view, inner_idx));
            }
            out_items[0] = std.math.cast(i64, acc) orelse return error.Unsupported;
            return try self.finishHostMatmulIntResult(shape, out_items);
        }

        for (0..shape.result_rows) |row_idx| {
            for (0..shape.result_cols) |col_idx| {
                var acc: i128 = 0;
                for (0..shape.left_cols) |inner_idx| {
                    const left_value = @as(i128, try hostDenseViewIntItem(left_view, row_idx * shape.left_cols + inner_idx));
                    const right_value = @as(i128, try hostDenseViewIntItem(right_view, inner_idx * shape.right_cols + col_idx));
                    acc += left_value * right_value;
                }
                out_items[row_idx * shape.result_cols + col_idx] = std.math.cast(i64, acc) orelse return error.Unsupported;
            }
        }
        return try self.finishHostMatmulIntResult(shape, out_items);
    }

fn promoteRenderableMatrixValue(self: *Session, value: Value) KError!?Value {
    if (valueNumericMatrixShape(value) != null) return value;
    if (value.tag() != .array or value.arrayKind() != .host_array or std.meta.activeTag(value.asHostArray().storage) != .boxed) return null;

        const items = value.asHostArray().storage.boxed;
        if (!isRenderableMatrix(items)) return null;

        const rows = items.len;
        const cols = numericVectorLen(items[0]) orelse return error.Type;
        const out_shape = numericShapeSnapshotMatrix(rows, cols);

        var saw_float = false;
        for (items) |row| {
            if ((valueNumericMode(row) orelse return error.Type) == .float) saw_float = true;
        }

        if (saw_float) {
            var out = std.ArrayList(f64).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, rows * cols);
            for (items) |row| {
                for (0..cols) |col_idx| {
                    try out.append(self.allocator, try numericFloatAt(row, col_idx));
                }
            }
            const promoted = try self.createManagedHostFloatArray(out.items);
            return try applyNonVectorNumericShapeToValue(self, promoted, out_shape);
        }

        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, rows * cols);
        for (items) |row| {
            for (0..cols) |col_idx| {
                try out.append(self.allocator, try numericIntAt(row, col_idx));
            }
        }
    const promoted = try self.createManagedHostIntArray(out.items);
    return try applyNonVectorNumericShapeToValue(self, promoted, out_shape);
}

const NumericDyadOperands = struct {
    left: Value,
    right: Value,
};

fn promoteRenderableNumericDyadOperands(self: *Session, left: Value, right: Value) KError!?NumericDyadOperands {
    var promoted_left = left;
    var promoted_right = right;
    var changed = false;

    if (try self.promoteRenderableMatrixValue(left)) |value| {
        if (value.raw != left.raw) {
            promoted_left = value;
            changed = true;
        }
    }
    if (try self.promoteRenderableMatrixValue(right)) |value| {
        if (value.raw != right.raw) {
            promoted_right = value;
            changed = true;
        }
    }
    if (!changed) return null;
    return .{ .left = promoted_left, .right = promoted_right };
}

    fn applyMlxMatmulValues(self: *Session, left: Value, right: Value) KError!Value {
        var left_arr = try self.dotTensor(left);
        defer left_arr.deinit();
        var right_arr = try self.dotTensor(right);
        defer right_arr.deinit();

        const ctx = try self.mlxContext();
        const out = mlx.Array.matmul(ctx.*, left_arr, right_arr) catch |err| return mapMlxError(err);
        return try self.wrapManagedMlxArray(out);
    }

    fn applyMatmulValues(self: *Session, left: Value, right: Value) KError!Value {
        const promoted_left = (try self.promoteRenderableMatrixValue(left)) orelse left;
        const promoted_right = (try self.promoteRenderableMatrixValue(right)) orelse right;
        const shape = (try matmulShapeForValues(promoted_left, promoted_right)) orelse return error.Type;
        return switch (planMatmulBackend(self, promoted_left, promoted_right)) {
            .host => try self.applyHostMatmulGeneric(promoted_left, promoted_right, shape),
            .mlx => try self.applyMlxMatmulValues(promoted_left, promoted_right),
        };
    }

    fn applyInnerProductClosure(self: *Session, info: InnerProductInfo, args: []const Value) KError!Value {
        if (args.len != 2) return error.Arity;
        if (info.reduce == .add and info.map == .mul) return try self.applyMatmulValues(args[0], args[1]);
        return error.Unsupported;
    }

    fn dotValues(self: *Session, left: Value, right: Value) KError!Value {
        return try self.applyDot(left, right);
    }

    fn applyDenseMonad(self: *Session, op: BuiltinId, value: Value) KError!Value {
        if (NumericStructuralView.init(value)) |structural| {
            if (try numericStructuralDenseMonadValue(self, value, structural, op)) |result| return result;
        }
        if (value.tag() == .array and value.arraySubkind() == .numeric_array) {
            const handle = value.asNumericArray();
            if (supportsMlxMonad(op) and handle.host == null and hasMlxRealization(value)) {
                return try self.applyMlxArrayMonad(op, value);
            }
            if (handle.host == null and handle.structural != .materialized) {
                const view = try hostDenseView(self, value);
                return try self.applyHostDenseViewMonad(op, value, view);
            }
        }
        return switch (value.tag()) {
            .array => switch (value.arrayKind()) {
                .host_array => self.applyHostArrayMonad(op, value.asHostArray()),
                .mlx_array => self.applyMlxArrayMonad(op, value),
                .numeric_array => self.applyHostArrayMonad(op, try hostStructuralArrayForHandle(self, @constCast(value.asNumericArray()))),
                else => error.Internal,
            },
            else => error.Type,
        };
    }

    fn applyHostDenseViewMonad(self: *Session, op: BuiltinId, source_value: Value, view: HostDenseView) KError!Value {
        return switch (view) {
            .int_array => |items| switch (op) {
                .add, .mul => self.shareValue(source_value),
                .sub => blk: {
                    const input_kind = hostIntDenseViewKind(items);
                    const input_range = hostIntDenseValueRange(source_value, items);
                    const input_flags = hostIntDenseValueFlags(source_value, items);
                    const len = hostIntDenseViewLen(items);
                    if (hostIntNegRange(input_range)) |result_range| {
                        const result_kind = hostIntStorageKindForRange(result_range.min, result_range.max);
                        var plan = try self.planHostIntUnaryOutput(source_value, input_kind, result_kind, len, false, true);
                        try fillIntNegDenseResult(&plan.output, items, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intNegResultFlags(input_flags));
                    }
                    var attempt_kind = hostNegInitialResultKind(input_kind);
                    while (true) {
                        var plan = try self.planHostIntUnaryOutput(
                            source_value,
                            input_kind,
                            attempt_kind,
                            len,
                            false,
                            hostNegUncheckedSafeForOutput(input_kind, attempt_kind),
                        );
                        fillIntNegDenseResult(&plan.output, items, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intNegResultFlags(input_flags));
                    }
                },
                .div => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostIntDenseViewLen(items), false);
                    fillFloatUnaryIntDenseView(plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .exp, .log, .tanh, .sigmoid => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostIntDenseViewLen(items), false);
                    fillFloatUnaryIntDenseView(plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                else => error.Type,
            },
            .float_array => |items| switch (op) {
                .add, .mul => self.shareValue(source_value),
                .sub => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostFloatDenseViewLen(items), false);
                    fillFloatNegDenseView(plan.output.items, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .div => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostFloatDenseViewLen(items), false);
                    fillFloatUnaryDenseView(plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .exp, .log, .tanh, .sigmoid => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostFloatDenseViewLen(items), false);
                    fillFloatUnaryDenseView(plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                else => error.Type,
            },
            else => error.Type,
        };
    }

fn applyDenseDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
    const promoted_left = if (try self.promoteRenderableMatrixValue(left)) |value| value else left;
    const promoted_right = if (try self.promoteRenderableMatrixValue(right)) |value| value else right;
    if (planDenseNumericDyadBackend(self, op, promoted_left, promoted_right) == .mlx) {
        self.noteHostDenseDyadMiss(.planner_mlx);
        return self.applyMlxArrayDyad(op, promoted_left, promoted_right);
    }
    return self.applyHostArrayDyad(op, promoted_left, promoted_right);
}

    fn applyGenericArrayDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        const len = try arrayResultLen(left, right);
        const left_array = if (left.tag() == .array) try hostStructuralArrayValue(self, left) else null;
        const right_array = if (right.tag() == .array) try hostStructuralArrayValue(self, right) else null;
        var out = std.ArrayList(Value).empty;
        defer {
            for (out.items) |value| self.releaseValue(value);
            out.deinit(self.allocator);
        }
        try out.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const lhs = if (left_array) |array| try self.hostArrayIndexScalar(array, @intCast(idx)) else left;
            defer if (left_array != null) self.releaseValue(lhs);
            const rhs = if (right_array) |array| try self.hostArrayIndexScalar(array, @intCast(idx)) else right;
            defer if (right_array != null) self.releaseValue(rhs);
            try out.append(self.allocator, switch (op) {
                .add => try self.addValues(lhs, rhs),
                .sub => try self.subValues(lhs, rhs),
                .mul => try self.mulValues(lhs, rhs),
                .div => try self.divValues(lhs, rhs),
                .minimum => try self.minimumValues(lhs, rhs),
                .maximum => try self.maximumValues(lhs, rhs),
                .less => try self.lessValues(lhs, rhs),
                .more => try self.moreValues(lhs, rhs),
                .equal => try self.equalValues(lhs, rhs),
                else => return error.Unsupported,
            });
        }
        return try self.makeArrayFromValues(out.items);
    }

    fn applyHostArrayMonad(self: *Session, op: BuiltinId, array: *const HostArray) KError!Value {
        return switch (op) {
            .add => self.shareValue(hostArraySourceValue(array)),
            .sub => switch (array.storage) {
                .bit, .int8, .int16, .int32, .int64 => blk: {
                    const items = hostIntArrayView(array).?;
                    const input_kind = hostIntArrayViewKind(items);
                    const len = hostIntArrayViewLen(items);
                    if (hostIntNegRange(hostArrayCachedIntRange(array) orelse hostIntArrayViewEndpointRange(items, array.flags) orelse hostIntArrayViewRange(items))) |result_range| {
                        const result_kind = hostIntStorageKindForRange(result_range.min, result_range.max);
                        var plan = try self.planHostIntUnaryOutput(hostArraySourceValue(array), input_kind, result_kind, len, true, true);
                        try fillIntNegArrayResult(&plan.output, items, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intNegResultFlags(array.flags));
                    }
                    var attempt_kind = hostNegInitialResultKind(input_kind);
                    while (true) {
                        var plan = try self.planHostIntUnaryOutput(
                            hostArraySourceValue(array),
                            input_kind,
                            attempt_kind,
                            len,
                            false,
                            hostNegUncheckedSafeForOutput(input_kind, attempt_kind),
                        );
                        fillIntNegArrayResult(&plan.output, items, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intNegResultFlags(array.flags));
                    }
                },
                .float64 => |items| blk: {
                    var plan = try self.planHostFloatUnaryOutput(hostArraySourceValue(array), items.len, true);
                    for (items, 0..) |item, idx| plan.output.items[idx] = -item;
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .boxed => error.Type,
            },
            .mul => self.shareValue(hostArraySourceValue(array)),
            .div, .exp, .log, .tanh, .sigmoid => switch (array.storage) {
                .bit => |words| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostArraySourceValue(array), array.logical_len, false);
                    fillFloatUnaryBitArray(plan.output.items, op, .{ .words = words, .len = array.logical_len });
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int8 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostArraySourceValue(array), items.len, false);
                    fillFloatUnaryArray(i8, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int16 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostArraySourceValue(array), items.len, false);
                    fillFloatUnaryArray(i16, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int32 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostArraySourceValue(array), items.len, false);
                    fillFloatUnaryArray(i32, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int64 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostArraySourceValue(array), items.len, false);
                    fillFloatUnaryArray(i64, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float64 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostArraySourceValue(array), items.len, true);
                    fillFloatUnaryArray(f64, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .boxed => error.Type,
            },
            else => error.Type,
        };
    }

fn applyHostArrayDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
    const mode = arrayResultMode(op, left, right) orelse {
        self.noteHostDenseDyadMiss(.mode);
        return error.Type;
    };
    const len = try arrayResultLen(left, right);
    if (rowwiseMatrixVectorDyad(left, right)) |rowwise| {
        self.noteHostDenseDyadHost();
        return switch (mode) {
            .int => try self.applyHostArrayDyadRowwiseInt(op, left, right, rowwise, len),
            .float => try self.applyHostArrayDyadRowwiseFloat(op, left, right, rowwise, len),
        };
    }
    const left_view = hostDenseView(self, left) catch |err| {
        self.noteHostDenseDyadMiss(.view);
        return err;
        };
        const right_view = hostDenseView(self, right) catch |err| {
            self.noteHostDenseDyadMiss(.view);
            return err;
        };
    self.noteHostDenseDyadHost();
    return switch (mode) {
        .int => try self.applyHostArrayDyadInt(op, left, right, left_view, right_view, len),
        .float => try self.applyHostArrayDyadFloat(op, left, right, left_view, right_view, len),
    };
}

fn applyHostArrayDyadRowwiseInt(self: *Session, op: BuiltinId, left: Value, right: Value, rowwise: RowwiseMatrixVectorDyad, len: usize) KError!Value {
    var profile_scope = self.beginSamplingProfileScope(.dense_host);
    defer profile_scope.end();

    var out = std.ArrayList(i64).empty;
    defer out.deinit(self.allocator);
    try out.ensureTotalCapacity(self.allocator, len);
    for (0..len) |idx| {
        const lhs = try numericIntAt(left, rowwise.operandIndex(true, idx));
        const rhs = try numericIntAt(right, rowwise.operandIndex(false, idx));
        try out.append(self.allocator, switch (op) {
            .add => try checkedIntOp(.add, lhs, rhs),
            .sub => try checkedIntOp(.sub, lhs, rhs),
            .mul => try checkedIntOp(.mul, lhs, rhs),
            .minimum => @min(lhs, rhs),
            .maximum => @max(lhs, rhs),
            else => return error.Type,
        });
    }
    const result = try self.createManagedHostIntArray(out.items);
    return try applyNonVectorNumericShapeToValue(self, result, numericShapeSnapshotMatrix(rowwise.rows, rowwise.cols));
}

fn applyHostArrayDyadRowwiseFloat(self: *Session, op: BuiltinId, left: Value, right: Value, rowwise: RowwiseMatrixVectorDyad, len: usize) KError!Value {
    var profile_scope = self.beginSamplingProfileScope(.dense_host);
    defer profile_scope.end();

    var out = std.ArrayList(f64).empty;
    defer out.deinit(self.allocator);
    try out.ensureTotalCapacity(self.allocator, len);
    for (0..len) |idx| {
        const lhs = try numericFloatAt(left, rowwise.operandIndex(true, idx));
        const rhs = try numericFloatAt(right, rowwise.operandIndex(false, idx));
        try out.append(self.allocator, switch (op) {
            .add => lhs + rhs,
            .sub => lhs - rhs,
            .mul => lhs * rhs,
            .div => lhs / rhs,
            .minimum => @min(lhs, rhs),
            .maximum => @max(lhs, rhs),
            else => return error.Type,
        });
    }
    const result = try self.createManagedHostFloatArray(out.items);
    return try applyNonVectorNumericShapeToValue(self, result, numericShapeSnapshotMatrix(rowwise.rows, rowwise.cols));
}

    fn applyHostArrayDyadInt(self: *Session, op: BuiltinId, left_value: Value, right_value: Value, left: HostDenseView, right: HostDenseView, len: usize) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.dense_host);
        defer profile_scope.end();
        return switch (left) {
            .scalar_int => |li| switch (right) {
                .scalar_int => |ri| blk: {
                    const result = try checkedIntOp(op, li, ri);
                    break :blk try self.intValue(result);
                },
                .int_array => |items| blk: {
                    const left_kind = hostIntStorageKindForValue(li);
                    const right_kind = hostIntDenseViewKind(items);
                    const left_range = hostIntRangeForValue(li);
                    const right_range = hostIntDenseValueRange(right_value, items);
                    const right_flags = hostIntDenseValueFlags(right_value, items);
                    if (hostIntDyadRange(op, left_range, right_range)) |result_range| {
                        const result_kind = hostIntDyadResultKindForRange(op, left_kind, right_kind, result_range);
                        var plan = try self.planHostIntDyadOutput(left_value, right_value, left_kind, right_kind, result_kind, len, true, true);
                        try fillIntScalarDenseResult(&plan.output, op, li, items, true, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intArrayScalarResultFlags(op, right_flags, li, true));
                    }
                    var attempt_kind = hostIntInitialResultKind(op, left_kind, right_kind);
                    while (true) {
                        var plan = try self.planHostIntDyadOutput(
                            left_value,
                            right_value,
                            left_kind,
                            right_kind,
                            attempt_kind,
                            len,
                            false,
                            hostIntUncheckedSafeForOutput(left_kind, right_kind, attempt_kind),
                        );
                        fillIntScalarDenseResult(&plan.output, op, li, items, true, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intArrayScalarResultFlags(op, right_flags, li, true));
                    }
                },
                else => error.Type,
            },
            .int_array => |items| switch (right) {
                .scalar_int => |ri| blk: {
                    const left_kind = hostIntDenseViewKind(items);
                    const right_kind = hostIntStorageKindForValue(ri);
                    const left_range = hostIntDenseValueRange(left_value, items);
                    const left_flags = hostIntDenseValueFlags(left_value, items);
                    const right_range = hostIntRangeForValue(ri);
                    if (hostIntDyadRange(op, left_range, right_range)) |result_range| {
                        const result_kind = hostIntDyadResultKindForRange(op, left_kind, right_kind, result_range);
                        var plan = try self.planHostIntDyadOutput(left_value, right_value, left_kind, right_kind, result_kind, len, true, true);
                        try fillIntScalarDenseResult(&plan.output, op, ri, items, false, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intArrayScalarResultFlags(op, left_flags, ri, false));
                    }
                    var attempt_kind = hostIntInitialResultKind(op, left_kind, right_kind);
                    while (true) {
                        var plan = try self.planHostIntDyadOutput(
                            left_value,
                            right_value,
                            left_kind,
                            right_kind,
                            attempt_kind,
                            len,
                            false,
                            hostIntUncheckedSafeForOutput(left_kind, right_kind, attempt_kind),
                        );
                        fillIntScalarDenseResult(&plan.output, op, ri, items, false, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intArrayScalarResultFlags(op, left_flags, ri, false));
                    }
                },
                .int_array => |right_items| blk: {
                    const left_kind = hostIntDenseViewKind(items);
                    const right_kind = hostIntDenseViewKind(right_items);
                    const left_range = hostIntDenseValueRange(left_value, items);
                    const right_range = hostIntDenseValueRange(right_value, right_items);
                    const left_flags = hostIntDenseValueFlags(left_value, items);
                    const right_flags = hostIntDenseValueFlags(right_value, right_items);
                    if (hostIntDyadRange(op, left_range, right_range)) |result_range| {
                        const result_kind = hostIntDyadResultKindForRange(op, left_kind, right_kind, result_range);
                        var plan = try self.planHostIntDyadOutput(left_value, right_value, left_kind, right_kind, result_kind, len, true, true);
                        try fillIntDenseDenseResult(&plan.output, op, items, right_items, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intArrayArrayResultFlags(op, left_flags, right_flags));
                    }
                    var attempt_kind = hostIntInitialResultKind(op, left_kind, right_kind);
                    while (true) {
                        var plan = try self.planHostIntDyadOutput(
                            left_value,
                            right_value,
                            left_kind,
                            right_kind,
                            attempt_kind,
                            len,
                            false,
                            hostIntUncheckedSafeForOutput(left_kind, right_kind, attempt_kind),
                        );
                        fillIntDenseDenseResult(&plan.output, op, items, right_items, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intArrayArrayResultFlags(op, left_flags, right_flags));
                    }
                },
                else => error.Type,
            },
            else => error.Type,
        };
    }

    fn applyHostArrayDyadFloat(self: *Session, op: BuiltinId, left_value: Value, right_value: Value, left: HostDenseView, right: HostDenseView, len: usize) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.dense_host);
        defer profile_scope.end();
        return switch (left) {
            .scalar_int => |li| switch (right) {
                .scalar_int => |ri| blk: {
                    const result = applyFloatOp(op, @floatFromInt(li), @floatFromInt(ri));
                    break :blk try self.floatValue(result);
                },
                .scalar_float => |rf| blk: {
                    const result = applyFloatOp(op, @floatFromInt(li), rf);
                    break :blk try self.floatValue(result);
                },
                .int_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatScalarIntDenseView(plan.output.items, op, @floatFromInt(li), right_items, true);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatScalarDenseView(plan.output.items, op, @floatFromInt(li), right_items, true);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
            .scalar_float => |lf| switch (right) {
                .scalar_int => |ri| blk: {
                    const result = applyFloatOp(op, lf, @floatFromInt(ri));
                    break :blk try self.floatValue(result);
                },
                .scalar_float => |rf| blk: {
                    const result = applyFloatOp(op, lf, rf);
                    break :blk try self.floatValue(result);
                },
                .int_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatScalarIntDenseView(plan.output.items, op, lf, right_items, true);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatScalarDenseView(plan.output.items, op, lf, right_items, true);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
            .int_array => |items| switch (right) {
                .scalar_int => |ri| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatScalarIntDenseView(plan.output.items, op, @floatFromInt(ri), items, false);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .scalar_float => |rf| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatScalarIntDenseView(plan.output.items, op, rf, items, false);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatIntDenseViewIntDenseView(plan.output.items, op, items, right_items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatIntDenseViewDenseView(plan.output.items, op, items, right_items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
            .float_array => |items| switch (right) {
                .scalar_int => |ri| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatScalarDenseView(plan.output.items, op, @floatFromInt(ri), items, false);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .scalar_float => |rf| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatScalarDenseView(plan.output.items, op, rf, items, false);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatDenseViewIntDenseView(plan.output.items, op, items, right_items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatDenseViewDenseView(plan.output.items, op, items, right_items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
        };
    }

    fn applyMlxArrayMonad(self: *Session, op: BuiltinId, value: Value) KError!Value {
        var input = try self.materializeMlxArray(value);
        errdefer input.deinit();
        if (op == .add) return try self.wrapManagedMlxArray(input);
        defer input.deinit();
        const out = switch (op) {
            .add => unreachable,
            .sub => blk: {
                try castMlxBoolArrayTo(self, &input, c.MLX_INT32);
                const ctx = try self.mlxContext();
                break :blk mlx.Array.negate(ctx.*, input) catch |err| return mapMlxError(err);
            },
            .div => blk: {
                try castMlxBoolArrayTo(self, &input, c.MLX_FLOAT32);
                const ctx = try self.mlxContext();
                break :blk mlx.Array.sqrt(ctx.*, input) catch |err| return mapMlxError(err);
            },
            .mul => return error.Unsupported,
            .exp => blk: {
                try castMlxBoolArrayTo(self, &input, c.MLX_FLOAT32);
                const ctx = try self.mlxContext();
                break :blk mlx.Array.exp(ctx.*, input) catch |err| return mapMlxError(err);
            },
            .log => blk: {
                try castMlxBoolArrayTo(self, &input, c.MLX_FLOAT32);
                const ctx = try self.mlxContext();
                break :blk mlx.Array.log(ctx.*, input) catch |err| return mapMlxError(err);
            },
            .tanh => blk: {
                try castMlxBoolArrayTo(self, &input, c.MLX_FLOAT32);
                const ctx = try self.mlxContext();
                break :blk mlx.Array.tanh(ctx.*, input) catch |err| return mapMlxError(err);
            },
            .sigmoid => blk: {
                try castMlxBoolArrayTo(self, &input, c.MLX_FLOAT32);
                const ctx = try self.mlxContext();
                break :blk mlx.Array.sigmoid(ctx.*, input) catch |err| return mapMlxError(err);
            },
            else => return error.Unsupported,
        };
        return try self.wrapManagedMlxArray(out);
    }

fn applyMlxArrayDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
    var profile_scope = self.beginSamplingProfileScope(.dense_mlx);
    defer profile_scope.end();
    var left_arr = try self.materializeMlxArray(left);
        defer left_arr.deinit();
        var right_arr = try self.materializeMlxArray(right);
        defer right_arr.deinit();

    const use_float = op == .div or mlxDtypeIsFloat(left_arr.dtype()) or mlxDtypeIsFloat(right_arr.dtype());
    try castMlxBoolArrayTo(self, &left_arr, if (use_float) c.MLX_FLOAT32 else c.MLX_INT32);
    try castMlxBoolArrayTo(self, &right_arr, if (use_float) c.MLX_FLOAT32 else c.MLX_INT32);

    const ctx = try self.mlxContext();
    if (rowwiseMatrixVectorDyad(left, right)) |rowwise| {
        if (rowwise.matrix_on_left) {
            const reshaped = mlx.Array.reshape(ctx.*, right_arr, &[_]i32{ @intCast(rowwise.rows), 1 }) catch |err| return mapMlxError(err);
            right_arr.deinit();
            right_arr = reshaped;
        } else {
            const reshaped = mlx.Array.reshape(ctx.*, left_arr, &[_]i32{ @intCast(rowwise.rows), 1 }) catch |err| return mapMlxError(err);
            left_arr.deinit();
            left_arr = reshaped;
        }
    }
    const out = switch (op) {
        .add => mlx.Array.add(ctx.*, left_arr, right_arr) catch |err| return mapMlxError(err),
        .sub => mlx.Array.sub(ctx.*, left_arr, right_arr) catch |err| return mapMlxError(err),
            .mul => mlx.Array.mul(ctx.*, left_arr, right_arr) catch |err| return mapMlxError(err),
            .div => mlx.Array.div(ctx.*, left_arr, right_arr) catch |err| return mapMlxError(err),
            .less => mlx.Array.less(ctx.*, left_arr, right_arr) catch |err| return mapMlxError(err),
            .more => mlx.Array.greater(ctx.*, left_arr, right_arr) catch |err| return mapMlxError(err),
            .equal => mlx.Array.equal(ctx.*, left_arr, right_arr) catch |err| return mapMlxError(err),
            else => return error.Unsupported,
        };
        return try self.wrapManagedMlxArray(out);
    }

    fn materializeMlxArrayFromHandle(self: *Session, handle: *NumericArray) KError!mlx.Array {
        var profile_scope = self.beginSamplingProfileScope(.mlx_realization);
        defer profile_scope.end();
        if (try tryEnsureManagedMlxRealizationForHandle(self, handle)) |owned| {
            return owned.array.clone() catch |err| return mapMlxError(err);
        }
        if (numericArrayIsRangeIota(handle)) return try createMlxArrayFromRangeIota(self, handle);
        if (numericArrayIsFlatSlice(handle)) return try createMlxArrayFromFlatSlice(self, handle);
        if (numericArrayIsFlatConcat(handle)) return try createMlxArrayFromFlatConcat(self, handle);
        if (numericArrayIsFlatSegments(handle)) return try createMlxArrayFromFlatSegments(self, handle);
        if (numericArrayIsFirstAxisSlice(handle)) return try createMlxArrayFromFirstAxisSlice(self, handle);
        if (numericArrayIsFirstAxisIndex(handle)) return try createMlxArrayFromFirstAxisIndex(self, handle);
        if (numericArrayIsFirstAxisConcat(handle)) return try createMlxArrayFromFirstAxisConcat(self, handle);
        if (numericArrayIsReshapeView(handle)) return try createMlxArrayFromReshapeView(self, handle);
        if (numericArrayIsTransposeView(handle)) return try createMlxArrayFromTransposeView(self, handle);
        return try createMlxArrayFromHostArray(self, try hostStructuralArrayForHandle(self, handle));
    }

    fn materializeMlxArray(self: *Session, value: Value) KError!mlx.Array {
        return switch (value.tag()) {
            .int => mlx.Array.fromInt(@intCast(value.asInt())),
            .float => mlx.Array.fromFloat(@floatCast(value.asFloat())),
            .bool => mlx.Array.fromInt(@intFromBool(value.asBool())),
            .array => blk: {
                if (mutableNumericHandle(value)) |handle| {
                    if (try tryEnsureManagedMlxRealizationForHandle(self, handle)) |owned| {
                        break :blk owned.array.clone() catch |err| return mapMlxError(err);
                    }
                }
                break :blk switch (value.arraySubkind()) {
                    .host_array => try createMlxArrayFromHostArray(self, value.asHostArray()),
                    .mlx_array => value.asMlxArray().array.clone() catch |err| return mapMlxError(err),
                    .numeric_array => try self.materializeMlxArrayFromHandle(@constCast(value.asNumericArray())),
                    else => error.Internal,
                };
            },
            else => error.Type,
        };
    }

    fn dotTensor(self: *Session, value: Value) KError!mlx.Array {
        var arr = try self.materializeMlxArray(value);
        errdefer arr.deinit();
        if (arr.ndim() == 0) return error.Type;
        if (arr.dtype() != c.MLX_FLOAT32 and arr.dtype() != c.MLX_FLOAT64) {
            const ctx = try self.mlxContext();
            const casted = mlx.Array.cast(ctx.*, arr, c.MLX_FLOAT32) catch |err| return mapMlxError(err);
            arr.deinit();
            arr = casted;
        }
        return arr;
    }

    fn negateIntValue(self: *Session, value: i64) KError!Value {
        const result = @subWithOverflow(@as(i64, 0), value);
        if (result[1] != 0) return error.Unsupported;
        return try self.intValue(result[0]);
    }

    fn addIntValue(self: *Session, left: i64, right: i64) KError!Value {
        const result = @addWithOverflow(left, right);
        if (result[1] != 0) return error.Unsupported;
        return try self.intValue(result[0]);
    }

    fn subIntValue(self: *Session, left: i64, right: i64) KError!Value {
        const result = @subWithOverflow(left, right);
        if (result[1] != 0) return error.Unsupported;
        return try self.intValue(result[0]);
    }

    fn mulIntValue(self: *Session, left: i64, right: i64) KError!Value {
        const result = @mulWithOverflow(left, right);
        if (result[1] != 0) return error.Unsupported;
        return try self.intValue(result[0]);
    }

    fn internGlobalSlot(self: *Session, name: []const u8) !u16 {
        if (self.global_slots.get(name)) |slot| return slot;

        const slot = std.math.cast(u16, self.global_values.items.len) orelse return error.Unsupported;
        const owned_name = try self.arena.allocator().dupe(u8, name);
        try self.global_values.append(self.allocator, Value.fromBool(false));
        try self.global_initialized.append(self.allocator, false);
        try self.global_names.append(self.allocator, owned_name);
        try self.global_slots.put(owned_name, slot);
        return slot;
    }

    fn storeGlobalSlot(self: *Session, slot: u16, value: Value) !void {
        if (slot >= self.global_values.items.len or slot >= self.global_initialized.items.len) return error.Internal;
        if (self.global_initialized.items[slot]) {
            self.releaseValue(self.global_values.items[slot]);
        }
        self.global_values.items[slot] = try self.retainGlobalStoredValue(value);
        self.global_initialized.items[slot] = true;
    }

    pub fn debugGlobalIsFrozenClosure(self: *Session, name: []const u8) !bool {
        const slot = self.global_slots.get(name) orelse return error.Name;
        const value = try self.loadGlobalSlot(slot);
        return value.tag() == .closure and value.asClosure().header.owner == .frozen;
    }

    pub fn debugGlobalValue(self: *Session, name: []const u8) !Value {
        const slot = self.global_slots.get(name) orelse return error.Name;
        return try self.loadGlobalSlot(slot);
    }

    pub fn debugEnsureNumericHandleValue(self: *Session, value: Value) !Value {
        return Value.array(try ensureNumericArrayHandle(self, value));
    }

    pub fn debugMakeBareManagedHostIntVector(self: *Session, data: []const i64) !Value {
        var min_value: i64 = 0;
        var max_value: i64 = 0;
        if (data.len != 0) {
            min_value = data[0];
            max_value = data[0];
            for (data[1..]) |item| {
                min_value = @min(min_value, item);
                max_value = @max(max_value, item);
            }
        }
        var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(min_value, max_value), data.len);
        for (data, 0..) |item, idx| try out.set(idx, item);
        return Value.array(out.arrayPtr());
    }

    pub fn debugMaterializeMlxArrayValue(self: *Session, value: Value) !void {
        var array = try self.materializeMlxArray(value);
        array.deinit();
    }

    pub fn debugEnsureHostRealizationValue(self: *Session, value: Value) !void {
        _ = try tryEnsureHostRealization(self, value) orelse return error.Unsupported;
    }

    fn loadGlobalSlot(self: *Session, slot: u16) KError!Value {
        if (slot >= self.global_values.items.len or slot >= self.global_initialized.items.len) return error.Internal;
        if (!self.global_initialized.items[slot]) return error.Name;
        return self.global_values.items[slot];
    }

    inline fn pop(self: *Session) Value {
        self.stack_len -= 1;
        return self.stack[self.stack_len];
    }

    inline fn peek(self: *Session) Value {
        return self.stack[self.stack_len - 1];
    }

    inline fn push(self: *Session, value: Value) KError!void {
        if (self.stack_len >= self.stack.len) return error.Unsupported;
        self.stack[self.stack_len] = value;
        self.stack_len += 1;
    }

    inline fn pushFrame(self: *Session, frame: CallFrame) KError!void {
        if (self.frame_len >= self.frames.len) return error.Unsupported;
        self.frames[self.frame_len] = frame;
        self.frame_len += 1;
    }

    fn createManagedHostIntArray(self: *Session, items: []const i64) !Value {
        const analysis = analyzeIntSlice(items);
        var out = try self.allocManagedHostIntResult(analysis.kind, items.len);
        for (items, 0..) |item, idx| try out.set(idx, item);
        const value = try out.value(self);
        hostArraySetFlags(@constCast(value.asHostArray()), analysis.flags);
        hostArraySetCachedIntRange(@constCast(value.asHostArray()), analysis.range);
        return value;
    }

    fn createManagedHostBitArray(self: *Session, items: []const bool) !Value {
        var asc = true;
        var dsc = true;
        var saw_zero = items.len == 0;
        var saw_one = false;
        if (items.len != 0) {
            if (items[0]) saw_one = true else saw_zero = true;
            var prev = items[0];
            for (items[1..]) |item| {
                if (item) saw_one = true else saw_zero = true;
                if (@intFromBool(prev) > @intFromBool(item)) asc = false;
                if (@intFromBool(prev) < @intFromBool(item)) dsc = false;
                prev = item;
            }
        }

        var out = try self.allocManagedHostIntResult(.bit, items.len);
        for (items, 0..) |item, idx| try out.set(idx, @intFromBool(item));
        const value = try out.value(self);
        hostArraySetFlags(@constCast(value.asHostArray()), host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        hostArraySetCachedIntRange(@constCast(value.asHostArray()), .{
            .min = if (saw_zero) 0 else 1,
            .max = if (saw_one) 1 else 0,
        });
        return value;
    }

    fn createManagedHostFloatArray(self: *Session, items: []const f64) !Value {
        const analysis = analyzeFloatSlice(items);
        const out = try self.allocManagedHostFloatResult(items.len);
        @memcpy(out.items, items);
        const value = try out.value(self);
        hostArraySetFlags(@constCast(value.asHostArray()), analysis.flags);
        return value;
    }

    fn createManagedHostIntArrayFromValues(self: *Session, values: []const Value) !Value {
        if (values.len == 0) {
            var out = try self.allocManagedHostIntResult(.bit, 0);
            const value = try out.value(self);
            hostArraySetFlags(@constCast(value.asHostArray()), host_array_flag_normalized | host_array_flag_asc | host_array_flag_dsc);
            hostArraySetCachedIntRange(@constCast(value.asHostArray()), .{ .min = 0, .max = 0 });
            return value;
        }
        var all_bool = true;
        for (values) |value| {
            if (value.tag() != .bool) {
                all_bool = false;
                break;
            }
        }
        if (all_bool) {
            var bools = try self.allocator.alloc(bool, values.len);
            defer self.allocator.free(bools);
            for (values, 0..) |value, idx| bools[idx] = value.asBool();
            return try self.createManagedHostBitArray(bools);
        }
        var min_value = switch (values[0].tag()) {
            .int => values[0].asInt(),
            .bool => @intFromBool(values[0].asBool()),
            else => unreachable,
        };
        var max_value = min_value;
        var asc = true;
        var dsc = true;
        var prev = min_value;
        for (values[1..]) |value| {
            const int_value = switch (value.tag()) {
                .int => value.asInt(),
                .bool => @intFromBool(value.asBool()),
                else => unreachable,
            };
            min_value = @min(min_value, int_value);
            max_value = @max(max_value, int_value);
            if (prev > int_value) asc = false;
            if (prev < int_value) dsc = false;
            prev = int_value;
        }
        var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(min_value, max_value), values.len);
        for (values, 0..) |value, idx| {
            try out.set(idx, switch (value.tag()) {
                .int => value.asInt(),
                .bool => @intFromBool(value.asBool()),
                else => unreachable,
            });
        }
        const result = try out.value(self);
        hostArraySetFlags(@constCast(result.asHostArray()), host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        hostArraySetCachedIntRange(@constCast(result.asHostArray()), .{ .min = min_value, .max = max_value });
        return result;
    }

    fn createManagedHostFloatArrayFromValues(self: *Session, values: []const Value) !Value {
        if (values.len == 0) {
            const out = try self.allocManagedHostFloatResult(0);
            const value = try out.value(self);
            hostArraySetFlags(@constCast(value.asHostArray()), host_array_flag_normalized | host_array_flag_asc | host_array_flag_dsc);
            return value;
        }

        var asc = true;
        var dsc = true;
        var prev = switch (values[0].tag()) {
            .int => @as(f64, @floatFromInt(values[0].asInt())),
            .bool => @as(f64, @floatFromInt(@intFromBool(values[0].asBool()))),
            .float => values[0].asFloat(),
            else => unreachable,
        };
        var all_int = true;
        var min_value: i64 = 0;
        var max_value: i64 = 0;
        for (values, 0..) |value, idx| {
            const float_value = switch (value.tag()) {
                .int => @as(f64, @floatFromInt(value.asInt())),
                .bool => @as(f64, @floatFromInt(@intFromBool(value.asBool()))),
                .float => value.asFloat(),
                else => unreachable,
            };
            if (idx != 0) {
                if (prev > float_value) asc = false;
                if (prev < float_value) dsc = false;
                prev = float_value;
            }
            if (all_int) {
                const int_value = switch (value.tag()) {
                    .int => value.asInt(),
                    .bool => @intFromBool(value.asBool()),
                    .float => exactIntFromFloat(value.asFloat()) orelse {
                        all_int = false;
                        continue;
                    },
                    else => unreachable,
                };
                if (idx == 0) {
                    min_value = int_value;
                    max_value = int_value;
                } else {
                    min_value = @min(min_value, int_value);
                    max_value = @max(max_value, int_value);
                }
            }
        }

        if (all_int) {
            var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(min_value, max_value), values.len);
            for (values, 0..) |value, idx| {
                try out.set(idx, switch (value.tag()) {
                    .int => value.asInt(),
                    .bool => @intFromBool(value.asBool()),
                    .float => exactIntFromFloat(value.asFloat()).?,
                    else => unreachable,
                });
            }
            const result = try out.value(self);
            hostArraySetFlags(@constCast(result.asHostArray()), host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
            hostArraySetCachedIntRange(@constCast(result.asHostArray()), .{ .min = min_value, .max = max_value });
            return result;
        }

        const out = try self.allocManagedHostFloatResult(values.len);
        for (values, 0..) |value, idx| {
            out.items[idx] = switch (value.tag()) {
                .int => @as(f64, @floatFromInt(value.asInt())),
                .bool => @as(f64, @floatFromInt(@intFromBool(value.asBool()))),
                .float => value.asFloat(),
                else => unreachable,
            };
        }
        const result = try out.value(self);
        hostArraySetFlags(@constCast(result.asHostArray()), host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        return result;
    }

    fn createManagedHostBoxedArray(self: *Session, values: []const Value) !Value {
        const array = try self.allocator.create(HostArray);
        errdefer self.allocator.destroy(array);
        const items = try self.allocator.alloc(Value, values.len);
        errdefer self.allocator.free(items);
        for (values, 0..) |value, idx| {
            items[idx] = try self.retainEscapedValue(value);
        }
        array.* = .{
            .header = HeapHeader.init(.host_array, .managed),
            .logical_handle = null,
            .logical_len = values.len,
            .flags = 0,
            .storage = .{ .boxed = items },
        };
        return Value.array(array);
    }

    fn createManagedHostStringList(self: *Session, values: []const Value) !Value {
        const buf = try hostStringListAllocSlice(self.allocator, values.len);
        errdefer self.allocator.free(buf);
        const list = hostStringListFromAlloc(buf);
        const items = hostStringListItemsFromAlloc(buf, values.len);
        var bytes_len: usize = 0;

        for (values) |value| {
            const piece = stringBytes(value) orelse return error.Type;
            bytes_len = std.math.add(usize, bytes_len, piece.len) catch return error.Unsupported;
        }

        const base: ?*HostText = if (values.len == 0) null else blk: {
            const base_buf = try hostTextAllocSlice(self.allocator, bytes_len);
            errdefer self.allocator.free(base_buf);
            const text = hostTextFromAlloc(base_buf);
            const payload = hostTextBytesFromAlloc(base_buf, bytes_len);
            var offset: usize = 0;
            for (values, 0..) |value, idx| {
                const piece = stringBytes(value) orelse return error.Type;
                @memcpy(payload[offset .. offset + piece.len], piece);
                items[idx] = .{ .view = .{
                    .start = offset,
                    .len = piece.len,
                } };
                offset += piece.len;
            }
            std.debug.assert(offset == bytes_len);
            text.* = .{
                .header = HeapHeader.init(.host_string, .managed),
                .len = bytes_len,
            };
            break :blk text;
        };
        list.* = .{
            .header = HeapHeader.init(.host_string_list, .managed),
            .len = values.len,
            .bytes_len = bytes_len,
            .base = base,
            .storage = .{ .eager = items },
        };
        return Value.array(list);
    }

    fn createManagedHostStringListPieces(self: *Session, base: ?*HostText, pieces: []const HostStringPiece) !Value {
        const buf = try hostStringListAllocSlice(self.allocator, pieces.len);
        errdefer self.allocator.free(buf);
        const list = hostStringListFromAlloc(buf);
        const items = hostStringListItemsFromAlloc(buf, pieces.len);
        var bytes_len: usize = 0;

        if (base) |shared| _ = self.retainValue(Value.array(shared));
        errdefer if (base) |shared| self.releaseValue(Value.array(shared));

        var initialized: usize = 0;
        errdefer {
            for (items[0..initialized]) |item| self.releaseHostStringPiece(item);
        }
        for (pieces, 0..) |piece, idx| {
            items[idx] = piece;
            self.retainHostStringPiece(piece);
            bytes_len = std.math.add(usize, bytes_len, hostStringPieceBytes(base, piece).len) catch return error.Unsupported;
            initialized += 1;
        }
        list.* = .{
            .header = HeapHeader.init(.host_string_list, .managed),
            .len = pieces.len,
            .bytes_len = bytes_len,
            .base = base,
            .storage = .{ .eager = items },
        };
        return Value.array(list);
    }

    fn createManagedHostStringListLazyScalar(self: *Session, base: *HostText, sep: u8, count: usize) !Value {
        const list = try self.allocator.create(HostStringList);
        errdefer self.allocator.destroy(list);
        _ = self.retainValue(Value.array(base));
        errdefer self.releaseValue(Value.array(base));
        list.* = .{
            .header = HeapHeader.init(.host_string_list, .managed),
            .len = count,
            .bytes_len = base.len -| (count -| 1),
            .base = base,
            .storage = .{ .split_scalar = .{ .sep = sep } },
        };
        return Value.array(list);
    }

    fn createManagedHostStringListFromSlices(self: *Session, items: []const []const u8) !Value {
        const buf = try hostStringListAllocSlice(self.allocator, items.len);
        errdefer self.allocator.free(buf);
        const list = hostStringListFromAlloc(buf);
        const pieces = hostStringListItemsFromAlloc(buf, items.len);

        var bytes_len: usize = 0;
        for (items) |item| {
            bytes_len = std.math.add(usize, bytes_len, item.len) catch return error.Unsupported;
        }

        const base: ?*HostText = if (items.len == 0) null else blk: {
            const base_buf = try hostTextAllocSlice(self.allocator, bytes_len);
            errdefer self.allocator.free(base_buf);
            const text = hostTextFromAlloc(base_buf);
            const payload = hostTextBytesFromAlloc(base_buf, bytes_len);
            var offset: usize = 0;
            for (items, 0..) |item, idx| {
                @memcpy(payload[offset .. offset + item.len], item);
                pieces[idx] = .{ .view = .{
                    .start = offset,
                    .len = item.len,
                } };
                offset += item.len;
            }
            std.debug.assert(offset == bytes_len);
            text.* = .{
                .header = HeapHeader.init(.host_string, .managed),
                .len = bytes_len,
            };
            break :blk text;
        };

        list.* = .{
            .header = HeapHeader.init(.host_string_list, .managed),
            .len = items.len,
            .bytes_len = bytes_len,
            .base = base,
            .storage = .{ .eager = pieces },
        };
        return Value.array(list);
    }

    fn retainHostStringPiece(self: *Session, piece: HostStringPiece) void {
        switch (piece) {
            .owned => |text| _ = self.retainValue(Value.array(text)),
            .view => {},
        }
    }

    fn releaseHostStringPiece(self: *Session, piece: HostStringPiece) void {
        switch (piece) {
            .owned => |text| self.releaseValue(Value.array(text)),
            .view => {},
        }
    }
};

const CompiledSource = struct {
    source: []const u8,
    code: *const Code,
};

const HostIntArrayView = union(HostIntStorageKind) {
    bit: HostBitSlice,
    int8: []const i8,
    int16: []const i16,
    int32: []const i32,
    int64: []const i64,
};

const HostIntResult = union(HostIntStorageKind) {
    bit: HostBitAlloc,
    int8: HostArrayAlloc(i8),
    int16: HostArrayAlloc(i16),
    int32: HostArrayAlloc(i32),
    int64: HostArrayAlloc(i64),

    fn set(self: *HostIntResult, idx: usize, item_value: i64) KError!void {
        switch (self.*) {
            .bit => |*out| switch (item_value) {
                0 => bitSet(out.words, idx, false),
                1 => bitSet(out.words, idx, true),
                else => return error.Unsupported,
            },
            .int8 => |*out| out.items[idx] = std.math.cast(i8, item_value) orelse return error.Unsupported,
            .int16 => |*out| out.items[idx] = std.math.cast(i16, item_value) orelse return error.Unsupported,
            .int32 => |*out| out.items[idx] = std.math.cast(i32, item_value) orelse return error.Unsupported,
            .int64 => |*out| out.items[idx] = item_value,
        }
    }

    fn value(self: *const HostIntResult, session: *Session) !Value {
        return try wrapOwnedHostArrayValue(session, self.arrayPtr());
    }

    fn arrayPtr(self: *const HostIntResult) *HostArray {
        return switch (self.*) {
            .bit => |out| out.array,
            .int8 => |out| out.array,
            .int16 => |out| out.array,
            .int32 => |out| out.array,
            .int64 => |out| out.array,
        };
    }
};

const HostFloatResult = struct {
    array: *HostArray,
    items: []f64,

    fn value(self: HostFloatResult, session: *Session) !Value {
        return try wrapOwnedHostArrayValue(session, self.array);
    }
};

const HostIntOutputPlan = struct {
    output: HostIntResult,
    kind: HostIntStorageKind,
    reused: bool,
    unchecked_safe: bool,
    shape: ?NumericShapeSnapshot = null,
};

const HostFloatOutputPlan = struct {
    output: HostFloatResult,
    reused: bool,
    shape: ?NumericShapeSnapshot = null,
};

const HostArrayNormalizationPlan = union(enum) {
    int: struct {
        view: HostIntArrayView,
        kind: HostIntStorageKind,
        flags: u8,
    },
    float: struct {
        items: []const f64,
        flags: u8,
    },
    float_to_int: struct {
        items: []const f64,
        kind: HostIntStorageKind,
        flags: u8,
    },
};

fn copyHostIntViewToResult(out: *HostIntResult, view: HostIntArrayView) KError!void {
    switch (view) {
        .bit => |items| for (0..items.len) |idx| try out.set(idx, @intFromBool(bitGet(items.words, idx))),
        .int8 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
        .int16 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
        .int32 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
        .int64 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
    }
}

fn copyExactFloatSliceToIntResult(out: *HostIntResult, items: []const f64) KError!void {
    for (items, 0..) |item, idx| try out.set(idx, exactIntFromFloat(item).?);
}

fn hostIntArrayView(array: *const HostArray) ?HostIntArrayView {
    return switch (array.storage) {
        .bit => |words| .{ .bit = .{ .words = words, .len = array.logical_len } },
        .int8 => |items| .{ .int8 = items },
        .int16 => |items| .{ .int16 = items },
        .int32 => |items| .{ .int32 = items },
        .int64 => |items| .{ .int64 = items },
        .float64 => null,
        .boxed => null,
    };
}

fn hostIntArrayViewKind(view: HostIntArrayView) HostIntStorageKind {
    return std.meta.activeTag(view);
}

fn hostIntArrayViewLen(view: HostIntArrayView) usize {
    return switch (view) {
        .bit => |items| items.len,
        .int8 => |items| items.len,
        .int16 => |items| items.len,
        .int32 => |items| items.len,
        .int64 => |items| items.len,
    };
}

fn hostIntArrayViewRange(view: HostIntArrayView) HostIntRange {
    return switch (view) {
        .bit => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var saw_zero = false;
            var saw_one = false;
            if (items.words.len != 0) {
                for (items.words, 0..) |word, idx| {
                    const masked = if (idx + 1 == items.words.len) word & bitTailMask(items.len) else word;
                    if (masked != 0) saw_one = true;
                    const valid_mask = if (idx + 1 == items.words.len) bitTailMask(items.len) else std.math.maxInt(u64);
                    if (masked != valid_mask) saw_zero = true;
                    if (saw_zero and saw_one) break;
                }
            }
            break :blk .{
                .min = if (saw_zero) 0 else 1,
                .max = if (saw_one) 1 else 0,
            };
        },
        .int8 => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value: i64 = items[0];
            var max_value: i64 = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, @as(i64, item));
                max_value = @max(max_value, @as(i64, item));
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .int16 => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value: i64 = items[0];
            var max_value: i64 = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, @as(i64, item));
                max_value = @max(max_value, @as(i64, item));
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .int32 => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value: i64 = items[0];
            var max_value: i64 = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, @as(i64, item));
                max_value = @max(max_value, @as(i64, item));
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .int64 => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = items[0];
            var max_value = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, item);
                max_value = @max(max_value, item);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
    };
}

fn hostIntArrayViewEndpointRange(view: HostIntArrayView, flags: u8) ?HostIntRange {
    const mono = monotonicFlags(flags);
    if (mono == 0) return null;
    if (hostIntArrayViewLen(view) == 0) return .{ .min = 0, .max = 0 };
    const first = hostIntViewItem(view, 0);
    const last = hostIntViewItem(view, hostIntArrayViewLen(view) - 1);
    if ((mono & host_array_flag_asc) != 0) return .{ .min = first, .max = last };
    if ((mono & host_array_flag_dsc) != 0) return .{ .min = last, .max = first };
    return null;
}

fn hostIntViewItem(view: HostIntArrayView, idx: usize) i64 {
    return switch (view) {
        .bit => |items| @intFromBool(bitGet(items.words, idx)),
        .int8 => |items| items[idx],
        .int16 => |items| items[idx],
        .int32 => |items| items[idx],
        .int64 => |items| items[idx],
    };
}

fn hostRangeIotaViewLen(view: HostRangeIotaView) usize {
    return numericArrayRangeLen(view.handle);
}

fn hostRangeIotaViewBounds(view: HostRangeIotaView) HostIntRange {
    return numericArrayRangeIotaBounds(view.handle);
}

fn hostRangeIotaViewFlags(view: HostRangeIotaView) u8 {
    const len = hostRangeIotaViewLen(view);
    const mono = if (len <= 1)
        host_array_flag_asc | host_array_flag_dsc
    else
        orderFlagsFromMonotonic(view.handle.range_iota.step >= 0, view.handle.range_iota.step <= 0);
    return host_array_flag_normalized | mono;
}

fn hostRangeIotaViewItem(view: HostRangeIotaView, idx: usize) KError!i64 {
    return numericArrayRangeIotaValueAt(view.handle, idx);
}

fn hostIntDenseViewKind(view: HostIntDenseView) HostIntStorageKind {
    return switch (view) {
        .dense => |items| hostIntArrayViewKind(items),
        .range_iota => |items| blk: {
            const bounds = hostRangeIotaViewBounds(items);
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .flat_slice => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .flat_slice = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .flat_stride => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .flat_stride = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .flat_concat => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .flat_concat = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .flat_segments => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .flat_segments = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .first_axis_slice => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .first_axis_slice = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .first_axis_index => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .first_axis_index = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .first_axis_concat => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .first_axis_concat = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .transpose => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .transpose = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
    };
}

fn hostIntDenseViewLen(view: HostIntDenseView) usize {
    return switch (view) {
        .dense => |items| hostIntArrayViewLen(items),
        .range_iota => |items| hostRangeIotaViewLen(items),
        .flat_slice => |items| items.len,
        .flat_stride => |items| items.len,
        .flat_concat => |items| items.len,
        .flat_segments => |items| items.len,
        .first_axis_slice => |items| items.len,
        .first_axis_index => |items| items.len,
        .first_axis_concat => |items| items.len,
        .transpose => |items| hostTransposeViewLen(items),
    };
}

fn hostIntDenseViewRange(view: HostIntDenseView) HostIntRange {
    return switch (view) {
        .dense => |items| hostIntArrayViewRange(items),
        .range_iota => |items| hostRangeIotaViewBounds(items),
        .flat_slice => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .flat_slice = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .flat_slice = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .flat_stride => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .flat_stride = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .flat_stride = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .flat_concat => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .flat_concat = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .flat_concat = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .flat_segments => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .flat_segments = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .flat_segments = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .first_axis_slice => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .first_axis_slice = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .first_axis_slice = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .first_axis_index => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .first_axis_index = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .first_axis_index = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .first_axis_concat => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .first_axis_concat = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .first_axis_concat = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .transpose => |items| blk: {
            const len = hostTransposeViewLen(items);
            if (len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .transpose = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..len) |idx| {
                const value = hostIntDenseViewItem(.{ .transpose = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
    };
}

fn hostFirstAxisSliceFlatIndex(view: HostFirstAxisSliceView, idx: usize) KError!usize {
    if (idx >= view.len) return error.Internal;
    if (view.row_width == 0) return error.Internal;
    if (view.row_step == 1) return view.start_row * view.row_width + idx;

    const row_idx = idx / view.row_width;
    const col_idx = idx % view.row_width;
    const source_row_i64 = @as(i64, @intCast(view.start_row)) + @as(i64, @intCast(row_idx)) * @as(i64, view.row_step);
    if (source_row_i64 < 0) return error.Internal;
    return @as(usize, @intCast(source_row_i64)) * view.row_width + col_idx;
}

fn hostFirstAxisSliceIntItem(view: HostFirstAxisSliceView, idx: usize) KError!i64 {
    const flat_idx = try hostFirstAxisSliceFlatIndex(view, idx);
    if (view.source_host) |array| return try hostArrayIntAt(array, flat_idx);
    return try numericIntAt(view.source_value, flat_idx);
}

fn hostFirstAxisSliceFloatItem(view: HostFirstAxisSliceView, idx: usize) KError!f64 {
    const flat_idx = try hostFirstAxisSliceFlatIndex(view, idx);
    if (view.source_host) |array| return try hostArrayFloatAt(array, flat_idx);
    return try numericFloatAt(view.source_value, flat_idx);
}

fn hostFirstAxisIndexSourceRow(view: HostFirstAxisIndexView, row_pos: usize) KError!usize {
    if (view.row_width == 0) return error.Internal;
    if (row_pos >= view.len / view.row_width) return error.Internal;
    const source_row_i64 = try numericIntAt(view.row_indices, row_pos);
    if (source_row_i64 < 0) return error.Internal;
    return @as(usize, @intCast(source_row_i64));
}

fn hostFirstAxisIndexSourceIntAt(view: HostFirstAxisIndexView, flat_idx: usize) KError!i64 {
    if (view.source_host) |array| return try hostArrayIntAt(array, flat_idx);
    return try numericIntAt(view.source_value, flat_idx);
}

fn hostFirstAxisIndexSourceFloatAt(view: HostFirstAxisIndexView, flat_idx: usize) KError!f64 {
    if (view.source_host) |array| return try hostArrayFloatAt(array, flat_idx);
    return try numericFloatAt(view.source_value, flat_idx);
}

fn hostFirstAxisIndexFlatIndex(view: HostFirstAxisIndexView, idx: usize) KError!usize {
    if (idx >= view.len) return error.Internal;
    if (view.row_width == 0) return error.Internal;
    const row_pos = idx / view.row_width;
    const col_idx = idx % view.row_width;
    const source_row = try hostFirstAxisIndexSourceRow(view, row_pos);
    return source_row * view.row_width + col_idx;
}

fn hostFirstAxisIndexIntItem(view: HostFirstAxisIndexView, idx: usize) KError!i64 {
    const flat_idx = try hostFirstAxisIndexFlatIndex(view, idx);
    if (view.source_host) |array| return try hostArrayIntAt(array, flat_idx);
    return try numericIntAt(view.source_value, flat_idx);
}

fn hostFirstAxisIndexFloatItem(view: HostFirstAxisIndexView, idx: usize) KError!f64 {
