fn hostIntDenseViewItem(view: HostIntDenseView, idx: usize) KError!i64 {
    return switch (view) {
        .dense => |items| hostIntViewItem(items, idx),
        .range_iota => |items| try hostRangeIotaViewItem(items, idx),
        .flat_slice => |items| try hostFlatSliceIntItem(items, idx),
        .flat_stride => |items| try hostFlatStrideIntItem(items, idx),
        .flat_concat => |items| try hostFirstAxisConcatIntItem(items, idx),
        .flat_segments => |items| try hostFlatSegmentsIntItem(items, idx),
        .first_axis_slice => |items| try hostFirstAxisSliceIntItem(items, idx),
        .first_axis_index => |items| try hostFirstAxisIndexIntItem(items, idx),
        .first_axis_concat => |items| try hostFirstAxisConcatIntItem(items, idx),
        .transpose => |items| try hostTransposeIntItem(items, idx),
    };
}

fn hostIntDenseValueFlags(value: Value, view: HostIntDenseView) u8 {
    return switch (view) {
        .dense => switch (value.arrayKind()) {
            .host_array => value.asHostArray().flags,
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.host) |array| break :blk array.flags;
                if (numericArrayIsRangeIota(handle)) break :blk hostRangeIotaViewFlags(.{ .handle = handle });
                break :blk 0;
            },
            .mlx_array => blk: {
                const handle = valueNumericHandle(value) orelse break :blk 0;
                if (handle.host) |array| break :blk array.flags;
                break :blk 0;
            },
            else => 0,
        },
        .range_iota => |items| hostRangeIotaViewFlags(items),
        .flat_slice => |items| hostFlatSliceIntFlags(items),
        .flat_stride => |items| hostFlatStrideIntFlags(items),
        .flat_concat => |items| hostFirstAxisConcatIntFlags(items),
        .flat_segments => |items| hostFlatSegmentsIntFlags(items),
        .first_axis_slice => |items| hostFirstAxisSliceIntFlags(items),
        .first_axis_index => |items| hostFirstAxisIndexIntFlags(items),
        .first_axis_concat => |items| hostFirstAxisConcatIntFlags(items),
        .transpose => |items| hostTransposeIntFlags(items),
    };
}

fn hostIntDenseValueRange(value: Value, view: HostIntDenseView) HostIntRange {
    return switch (view) {
        .dense => |items| switch (value.arrayKind()) {
            .host_array => hostArrayCachedIntRange(value.asHostArray()) orelse
                hostIntArrayViewEndpointRange(items, value.asHostArray().flags) orelse
                hostIntArrayViewRange(items),
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.host) |array| {
                    break :blk hostArrayCachedIntRange(array) orelse
                        hostIntArrayViewEndpointRange(items, array.flags) orelse
                        hostIntArrayViewRange(items);
                }
                if (numericArrayIsRangeIota(handle)) break :blk numericArrayRangeIotaBounds(handle);
                break :blk hostIntArrayViewRange(items);
            },
            .mlx_array => blk: {
                const handle = valueNumericHandle(value) orelse break :blk hostIntArrayViewRange(items);
                if (handle.host) |array| {
                    break :blk hostArrayCachedIntRange(array) orelse
                        hostIntArrayViewEndpointRange(items, array.flags) orelse
                        hostIntArrayViewRange(items);
                }
                break :blk hostIntArrayViewRange(items);
            },
            else => hostIntArrayViewRange(items),
        },
        .range_iota => |items| hostRangeIotaViewBounds(items),
        .flat_slice => |_| hostIntDenseViewRange(view),
        .flat_stride => |_| hostIntDenseViewRange(view),
        .flat_concat => |_| hostIntDenseViewRange(view),
        .flat_segments => |_| hostIntDenseViewRange(view),
        .first_axis_slice => |_| hostIntDenseViewRange(view),
        .first_axis_index => |_| hostIntDenseViewRange(view),
        .first_axis_concat => |_| hostIntDenseViewRange(view),
        .transpose => |_| hostIntDenseViewRange(view),
    };
}

fn hostBitSliceContiguousTrueRun(mask: HostBitSlice) ?ContiguousIndexSlice {
    var start: ?usize = null;
    var run_len: usize = 0;
    var saw_gap_after_run = false;
    for (0..mask.len) |idx| {
        const bit = bitGet(mask.words, idx);
        if (bit) {
            if (saw_gap_after_run) return null;
            if (start == null) start = idx;
            run_len += 1;
        } else if (start != null and run_len != 0) {
            saw_gap_after_run = true;
        }
    }
    return .{
        .start = start orelse 0,
        .len = run_len,
    };
}

fn hostIntDenseViewArithmeticSlice(view: HostIntDenseView, len: usize) KError!?ArithmeticIndexSlice {
    return switch (view) {
        .dense => |items| switch (items) {
            .bit => |bits| blk: {
                if (bits.len != len) break :blk null;
                const run = hostBitSliceContiguousTrueRun(bits) orelse break :blk null;
                break :blk .{ .start = run.start, .len = run.len, .step = 1 };
            },
            else => blk: {
                const slice_len = hostIntArrayViewLen(items);
                if (slice_len == 0) break :blk .{ .start = 0, .len = 0, .step = 1 };
                const start = try normalizeIndex(hostIntViewItem(items, 0), len);
                if (slice_len == 1) break :blk .{ .start = start, .len = 1, .step = 1 };
                const second = try normalizeIndex(hostIntViewItem(items, 1), len);
                const step_i64 = @as(i64, @intCast(second)) - @as(i64, @intCast(start));
                if (step_i64 == 0) break :blk null;
                const step = std.math.cast(i32, step_i64) orelse break :blk null;
                for (1..slice_len) |idx| {
                    const expected_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(idx)) * @as(i64, step);
                    if (expected_i64 < 0 or expected_i64 >= len) break :blk null;
                    if (try normalizeIndex(hostIntViewItem(items, idx), len) != @as(usize, @intCast(expected_i64))) break :blk null;
                }
                break :blk .{ .start = start, .len = slice_len, .step = step };
            },
        },
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => blk: {
            const slice_len = hostIntDenseViewLen(view);
            if (slice_len == 0) break :blk .{ .start = 0, .len = 0, .step = 1 };
            const start = try normalizeIndex(try hostIntDenseViewItem(view, 0), len);
            if (slice_len == 1) break :blk .{ .start = start, .len = 1, .step = 1 };
            const second = try normalizeIndex(try hostIntDenseViewItem(view, 1), len);
            const step_i64 = @as(i64, @intCast(second)) - @as(i64, @intCast(start));
            if (step_i64 == 0) break :blk null;
            const step = std.math.cast(i32, step_i64) orelse break :blk null;
            for (1..slice_len) |idx| {
                const expected_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(idx)) * @as(i64, step);
                if (expected_i64 < 0 or expected_i64 >= len) break :blk null;
                if (try normalizeIndex(try hostIntDenseViewItem(view, idx), len) != @as(usize, @intCast(expected_i64))) break :blk null;
            }
            break :blk .{ .start = start, .len = slice_len, .step = step };
        },
    };
}

fn hostIntDenseViewContiguousSlice(view: HostIntDenseView, len: usize) KError!?ContiguousIndexSlice {
    if (try hostIntDenseViewArithmeticSlice(view, len)) |slice| {
        if (slice.step == 1) return .{ .start = slice.start, .len = slice.len };
    }
    return null;
}

fn valueHostIntStructuralView(value: Value) ?HostIntDenseView {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .host_array => if (hostIntArrayView(value.asHostArray())) |view|
            .{ .dense = view }
        else
            null,
        .numeric_array => blk: {
            const handle = value.asNumericArray();
            if (numericArrayIsRangeIota(handle)) break :blk .{ .range_iota = .{ .handle = handle } };
            if (numericArrayIsFlatSlice(handle)) {
                const source = numericArrayFlatSliceSource(handle) orelse break :blk null;
                const source_host = if (hostArrayIfPresent(source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(source) != .int) break :blk null;
                break :blk .{ .flat_slice = .{
                    .source_value = source,
                    .source_host = source_host,
                    .start = numericArrayFlatSliceStart(handle) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFlatConcat(handle)) {
                const left = numericArrayFlatConcatLeft(handle) orelse break :blk null;
                const right = numericArrayFlatConcatRight(handle) orelse break :blk null;
                const left_host = if (hostArrayIfPresent(left)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(left))
                    null
                else
                    break :blk null;
                const right_host = if (hostArrayIfPresent(right)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(right))
                    null
                else
                    break :blk null;
                if (valueNumericMode(value) != .int) break :blk null;
                break :blk .{ .flat_concat = .{
                    .left_value = left,
                    .left_host = left_host,
                    .right_value = right,
                    .right_host = right_host,
                    .left_len = numericVectorLen(left) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFlatSegments(handle)) {
                if (valueNumericMode(value) != .int) break :blk null;
                break :blk .{ .flat_segments = .{
                    .values = numericArrayFlatSegmentsValues(handle) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFirstAxisSlice(handle)) {
                const slice = handle.first_axis_slice orelse break :blk null;
                if (slice.step != 1) break :blk null;
                const source_handle = shapedNumericHandle(slice.source) orelse break :blk null;
                const source_host = if (hostArrayIfPresent(slice.source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(slice.source))
                    null
                else
                    break :blk null;
                break :blk .{ .first_axis_slice = .{
                    .source_value = slice.source,
                    .source_host = source_host,
                    .start_row = slice.start,
                    .len = numericFlatLen(value) orelse break :blk null,
                    .row_width = numericShapeInnerBlockLen(source_handle),
                    .row_step = 1,
                } };
            }
            if (numericArrayIsFirstAxisIndex(handle)) {
                const index = handle.first_axis_index orelse break :blk null;
                const source_handle = shapedNumericHandle(index.source) orelse break :blk null;
                const source_host = if (hostArrayIfPresent(index.source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(index.source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(index.source) != .int) break :blk null;
                break :blk .{ .first_axis_index = .{
                    .source_value = index.source,
                    .source_host = source_host,
                    .row_indices = index.row_indices,
                    .len = numericFlatLen(value) orelse break :blk null,
                    .row_width = numericShapeInnerBlockLen(source_handle),
                } };
            }
            if (numericArrayIsTransposeView(handle)) {
                const source = numericArrayTransposeSource(handle) orelse break :blk null;
                const source_shape = valueNumericMatrixShape(source) orelse break :blk null;
                const source_host = if (hostArrayIfPresent(source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(source) != .int) break :blk null;
                break :blk .{ .transpose = .{
                    .source_value = source,
                    .source_host = source_host,
                    .source_rows = source_shape.rows,
                    .source_cols = source_shape.cols,
                } };
            }
            if (numericArrayIsReshapeView(handle)) {
                const source = numericArrayReshapeSource(handle) orelse break :blk null;
                break :blk valueHostIntStructuralView(source);
            }
            if (handle.host) |array| {
                if (hostIntArrayView(array)) |view| break :blk .{ .dense = view };
            }
            break :blk null;
        },
        .mlx_array => blk: {
            const handle = valueNumericHandle(value) orelse break :blk null;
            if (numericArrayIsRangeIota(handle)) break :blk .{ .range_iota = .{ .handle = handle } };
            if (numericArrayIsFlatSlice(handle)) {
                const source = numericArrayFlatSliceSource(handle) orelse break :blk null;
                const source_host = if (hostArrayIfPresent(source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(source) != .int) break :blk null;
                break :blk .{ .flat_slice = .{
                    .source_value = source,
                    .source_host = source_host,
                    .start = numericArrayFlatSliceStart(handle) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFlatConcat(handle)) {
                const left = numericArrayFlatConcatLeft(handle) orelse break :blk null;
                const right = numericArrayFlatConcatRight(handle) orelse break :blk null;
                const left_host = if (hostArrayIfPresent(left)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(left))
                    null
                else
                    break :blk null;
                const right_host = if (hostArrayIfPresent(right)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(right))
                    null
                else
                    break :blk null;
                if (valueNumericMode(value) != .int) break :blk null;
                break :blk .{ .flat_concat = .{
                    .left_value = left,
                    .left_host = left_host,
                    .right_value = right,
                    .right_host = right_host,
                    .left_len = numericVectorLen(left) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFlatSegments(handle)) {
                if (valueNumericMode(value) != .int) break :blk null;
                break :blk .{ .flat_segments = .{
                    .values = numericArrayFlatSegmentsValues(handle) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFirstAxisSlice(handle)) {
                const slice = handle.first_axis_slice orelse break :blk null;
                if (slice.step != 1) break :blk null;
                const source_handle = shapedNumericHandle(slice.source) orelse break :blk null;
                const source_host = if (hostArrayIfPresent(slice.source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(slice.source))
                    null
                else
                    break :blk null;
                break :blk .{ .first_axis_slice = .{
                    .source_value = slice.source,
                    .source_host = source_host,
                    .start_row = slice.start,
                    .len = numericFlatLen(value) orelse break :blk null,
                    .row_width = numericShapeInnerBlockLen(source_handle),
                    .row_step = 1,
                } };
            }
            if (numericArrayIsFirstAxisIndex(handle)) {
                const index = handle.first_axis_index orelse break :blk null;
                const source_handle = shapedNumericHandle(index.source) orelse break :blk null;
                const source_host = if (hostArrayIfPresent(index.source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(index.source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(index.source) != .int) break :blk null;
                break :blk .{ .first_axis_index = .{
                    .source_value = index.source,
                    .source_host = source_host,
                    .row_indices = index.row_indices,
                    .len = numericFlatLen(value) orelse break :blk null,
                    .row_width = numericShapeInnerBlockLen(source_handle),
                } };
            }
            if (numericArrayIsTransposeView(handle)) {
                const source = numericArrayTransposeSource(handle) orelse break :blk null;
                const source_shape = valueNumericMatrixShape(source) orelse break :blk null;
                const source_host = if (hostArrayIfPresent(source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(source) != .int) break :blk null;
                break :blk .{ .transpose = .{
                    .source_value = source,
                    .source_host = source_host,
                    .source_rows = source_shape.rows,
                    .source_cols = source_shape.cols,
                } };
            }
            if (numericArrayIsReshapeView(handle)) {
                const source = numericArrayReshapeSource(handle) orelse break :blk null;
                break :blk valueHostIntStructuralView(source);
            }
            if (handle.host) |array| {
                if (hostIntArrayView(array)) |view| break :blk .{ .dense = view };
            }
            break :blk null;
        },
        else => null,
    };
}

fn normalizeIndex(raw_index: i64, len: usize) KError!usize {
    if (len == 0) return error.Type;
    var index = raw_index;
    if (index < 0) index += @as(i64, @intCast(len));
    if (index < 0 or index >= @as(i64, @intCast(len))) return error.Type;
    return @intCast(index);
}

fn hostStorageCopyIntSlice(array: *const HostArray) []const i64 {
    return switch (array.storage) {
        .int64 => |items| items,
        .bit, .int8, .int16, .int32, .float64 => unreachable,
        else => unreachable,
    };
}

fn destroyManagedHostArrayNoPool(allocator: std.mem.Allocator, array: *HostArray) void {
    array.logical_handle = null;
    switch (array.storage) {
        .bit => |words| allocator.free(words),
        .int8 => |items| allocator.free(items),
        .int16 => |items| allocator.free(items),
        .int32 => |items| allocator.free(items),
        .int64 => |items| allocator.free(items),
        .float64 => |items| allocator.free(items),
        .boxed => |items| {
            for (items) |item| releaseHeapValue(allocator, item);
            allocator.free(items);
        },
    }
    allocator.destroy(array);
}

fn destroyManagedMlxArrayNoPool(allocator: std.mem.Allocator, array: *MlxArray) void {
    array.logical_handle = null;
    array.array.deinit();
    allocator.destroy(array);
}

fn isManagedValue(value: Value) bool {
    return switch (value.raw & Value.tag_mask) {
        Value.boxed_float_tag => value.asBoxedFloat().header.owner == .managed,
        Value.boxed_int_tag => value.asBoxedInt().header.owner == .managed,
        Value.closure_tag => value.asClosure().header.owner == .managed,
        Value.array_tag => value.arrayOwner() == .managed,
        else => false,
    };
}

fn releaseManagedNumericHandleNoPool(allocator: std.mem.Allocator, handle: *NumericArray) void {
    std.debug.assert(handle.header.owner == .managed);
    std.debug.assert(handle.header.ref_count != 0);
    handle.header.ref_count -= 1;
    syncNumericArrayChildren(handle);
    if (handle.header.ref_count == 0) {
        if (handle.flat_slice) |slice| releaseHeapValue(allocator, slice.source);
        if (handle.flat_concat) |concat| {
            releaseHeapValue(allocator, concat.left);
            releaseHeapValue(allocator, concat.right);
        }
        if (handle.flat_segments) |segments| {
            for (segments.values) |item| releaseHeapValue(allocator, item);
            allocator.free(segments.values);
        }
        if (handle.first_axis_slice) |slice| releaseHeapValue(allocator, slice.source);
        if (handle.first_axis_index) |index| {
            releaseHeapValue(allocator, index.source);
            releaseHeapValue(allocator, index.row_indices);
        }
        if (handle.first_axis_concat) |concat| {
            releaseHeapValue(allocator, concat.left);
            releaseHeapValue(allocator, concat.right);
        }
        if (handle.reshape_view) |reshape| releaseHeapValue(allocator, reshape.source);
        if (handle.transpose_view) |transpose| releaseHeapValue(allocator, transpose.source);
        if (handle.host) |array| destroyManagedHostArrayNoPool(allocator, array);
        if (handle.mlx) |array| destroyManagedMlxArrayNoPool(allocator, array);
        allocator.destroy(handle);
    }
}

fn retainHeapValue(value: Value) void {
    switch (value.raw & Value.tag_mask) {
        Value.boxed_float_tag => {
            const box = @constCast(value.asBoxedFloat());
            if (box.header.owner == .managed) box.header.ref_count += 1;
        },
        Value.boxed_int_tag => {
            const box = @constCast(value.asBoxedInt());
            if (box.header.owner == .managed) box.header.ref_count += 1;
        },
        Value.closure_tag => {
            const closure = @constCast(value.asClosure());
            if (closure.header.owner == .managed) closure.header.ref_count += 1;
        },
        Value.array_tag => {
            switch (value.arraySubkind()) {
                .numeric_array => {
                    const handle = @constCast(value.asNumericArray());
                    if (handle.header.owner == .managed) {
                        handle.header.ref_count += 1;
                        syncNumericArrayChildren(handle);
                    }
                },
                .host_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner == .managed) {
                            handle.header.ref_count += 1;
                            syncNumericArrayChildren(handle);
                        }
                    } else {
                        const array = @constCast(value.asHostArray());
                        if (array.header.owner == .managed) array.header.ref_count += 1;
                    }
                },
                .host_string => {
                    const text = @constCast(value.asHostString());
                    if (text.header.owner == .managed) text.header.ref_count += 1;
                },
                .host_symbol => {
                    const text = @constCast(value.asHostSymbol());
                    if (text.header.owner == .managed) text.header.ref_count += 1;
                },
                .host_string_view => {
                    const view = @constCast(value.asHostStringView());
                    if (view.header.owner == .managed) view.header.ref_count += 1;
                },
                .host_string_list => {
                    const list = @constCast(value.asHostStringList());
                    if (list.header.owner == .managed) list.header.ref_count += 1;
                },
                .mlx_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner == .managed) {
                            handle.header.ref_count += 1;
                            syncNumericArrayChildren(handle);
                        }
                    } else {
                        const array = @constCast(value.asMlxArray());
                        if (array.header.owner == .managed) array.header.ref_count += 1;
                    }
                },
            }
        },
        else => {},
    }
}

fn releaseHeapValue(allocator: std.mem.Allocator, value: Value) void {
    switch (value.raw & Value.tag_mask) {
        Value.boxed_float_tag => {
            const box = @constCast(value.asBoxedFloat());
            if (box.header.owner != .managed) return;
            std.debug.assert(box.header.ref_count != 0);
            box.header.ref_count -= 1;
            if (box.header.ref_count == 0) allocator.destroy(box);
        },
        Value.boxed_int_tag => {
            const box = @constCast(value.asBoxedInt());
            if (box.header.owner != .managed) return;
            std.debug.assert(box.header.ref_count != 0);
            box.header.ref_count -= 1;
            if (box.header.ref_count == 0) allocator.destroy(box);
        },
        Value.closure_tag => {
            const closure = @constCast(value.asClosure());
            if (closure.header.owner != .managed) return;
            std.debug.assert(closure.header.ref_count != 0);
            closure.header.ref_count -= 1;
            if (closure.header.ref_count == 0) {
                for (closure.captures) |capture| releaseHeapValue(allocator, capture);
                allocator.free(closure.captures);
                allocator.destroy(closure);
            }
        },
        Value.array_tag => {
            switch (value.arraySubkind()) {
                .numeric_array => {
                    const handle = @constCast(value.asNumericArray());
                    if (handle.header.owner != .managed) return;
                    releaseManagedNumericHandleNoPool(allocator, handle);
                },
                .host_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner != .managed) return;
                        releaseManagedNumericHandleNoPool(allocator, handle);
                    } else {
                        const array = @constCast(value.asHostArray());
                        if (array.header.owner != .managed) return;
                        std.debug.assert(array.header.ref_count != 0);
                        array.header.ref_count -= 1;
                        if (array.header.ref_count == 0) {
                            destroyManagedHostArrayNoPool(allocator, array);
                        }
                    }
                },
                .host_string, .host_symbol => {
                    const text = switch (value.arrayKind()) {
                        .host_string => @constCast(value.asHostString()),
                        .host_symbol => @constCast(value.asHostSymbol()),
                        else => unreachable,
                    };
                    if (text.header.owner != .managed) return;
                    std.debug.assert(text.header.ref_count != 0);
                    text.header.ref_count -= 1;
                    if (text.header.ref_count == 0) freeHostTextAlloc(allocator, text);
                },
                .host_string_view => {
                    const view = @constCast(value.asHostStringView());
                    if (view.header.owner != .managed) return;
                    std.debug.assert(view.header.ref_count != 0);
                    view.header.ref_count -= 1;
                    if (view.header.ref_count == 0) {
                        releaseHeapValue(allocator, Value.array(view.base));
                        allocator.destroy(view);
                    }
                },
                .host_string_list => {
                    const list = @constCast(value.asHostStringList());
                    if (list.header.owner != .managed) return;
                    std.debug.assert(list.header.ref_count != 0);
                    list.header.ref_count -= 1;
                    if (list.header.ref_count == 0) {
                        if (list.base) |base| releaseHeapValue(allocator, Value.array(base));
                        switch (list.storage) {
                            .eager => |items| {
                                for (items) |item| switch (item) {
                                    .owned => |text| releaseHeapValue(allocator, Value.array(text)),
                                    .view => {},
                                };
                                freeHostStringListAlloc(allocator, list);
                            },
                            .split_scalar => allocator.destroy(list),
                        }
                    }
                },
                .mlx_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner != .managed) return;
                        releaseManagedNumericHandleNoPool(allocator, handle);
                    } else {
                        const array = @constCast(value.asMlxArray());
                        if (array.header.owner != .managed) return;
                        std.debug.assert(array.header.ref_count != 0);
                        array.header.ref_count -= 1;
                        if (array.header.ref_count == 0) {
                            destroyManagedMlxArrayNoPool(allocator, array);
                        }
                    }
                },
            }
        },
        else => {},
    }
}

fn allocBoxedFloat(allocator: std.mem.Allocator, owner: HeapOwner, value: f64) !Value {
    const box = try allocator.create(BoxedFloat);
    box.* = .{
        .header = HeapHeader.init(.boxed_float, owner),
        .value = value,
    };
    return Value.boxedFloat(box);
}

fn allocBoxedInt(allocator: std.mem.Allocator, owner: HeapOwner, value: i64) !Value {
    const box = try allocator.create(BoxedInt);
    box.* = .{
        .header = HeapHeader.init(.boxed_int, owner),
        .value = value,
    };
    return Value.boxedInt(box);
}

fn allocHostText(allocator: std.mem.Allocator, kind: HeapKind, owner: HeapOwner, bytes: []const u8) !Value {
    std.debug.assert(kind == .host_string or kind == .host_symbol);
    const buf = try hostTextAllocSlice(allocator, bytes.len);
    errdefer allocator.free(buf);
    const text = hostTextFromAlloc(buf);
    const payload = hostTextBytesFromAlloc(buf, bytes.len);
    @memcpy(payload, bytes);
    text.* = .{
        .header = HeapHeader.init(kind, owner),
        .len = bytes.len,
    };
    return Value.array(text);
}

fn allocNumericArrayHandle(self: *Session, owner: HeapOwner) !*NumericArray {
    const allocator = switch (owner) {
        .managed => self.allocator,
        .scratch => self.scratch_arena.allocator(),
        .frozen => self.arena.allocator(),
    };
    if (owner == .managed and self.free_numeric_array_len != 0) {
        self.free_numeric_array_len -= 1;
        return self.free_numeric_arrays[self.free_numeric_array_len].?;
    }
    return try allocator.create(NumericArray);
}

fn syncNumericArrayChildren(handle: *NumericArray) void {
    if (handle.host) |host| {
        host.logical_handle = handle;
        host.header.owner = handle.header.owner;
        host.header.ref_count = if (handle.header.owner == .managed) handle.header.ref_count else 0;
    }
    if (handle.mlx) |array| {
        array.logical_handle = handle;
        array.header.owner = handle.header.owner;
        array.header.ref_count = if (handle.header.owner == .managed) handle.header.ref_count else 0;
    }
}

fn newNumericArrayValue(
    self: *Session,
    owner: HeapOwner,
    preferred: NumericArrayPreferred,
    host: ?*HostArray,
    mlx_array: ?*MlxArray,
) !Value {
    const handle = try allocNumericArrayHandle(self, owner);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, owner),
        .preferred = preferred,
        .host = host,
        .mlx = mlx_array,
    };
    if (host) |array| {
        numericArraySetVectorShape(handle, array.len());
    } else if (mlx_array) |array| {
        numericArraySetShapeFromMlx(handle, array.array);
    }
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    return Value.array(handle);
}

fn newRangeIotaValue(self: *Session, owner: HeapOwner, len: usize) !Value {
    const handle = try allocNumericArrayHandle(self, owner);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, owner),
        .preferred = .host,
    };
    numericArraySetRangeIota(handle, len);
    self.registerManagedNumericHandle(handle);
    return Value.array(handle);
}

fn newRangeIotaValueWithParams(self: *Session, owner: HeapOwner, len: usize, start: i64, step: i64) !Value {
    const value = try newRangeIotaValue(self, owner, len);
    const handle = @constCast(value.asNumericArray());
    handle.range_iota = .{ .start = start, .step = step };
    return value;
}

fn newRangeIotaValueWithShape(
    self: *Session,
    owner: HeapOwner,
    len: usize,
    start: i64,
    step: i64,
    shape: ?NumericShapeSnapshot,
) !Value {
    const value = try newRangeIotaValueWithParams(self, owner, len, start, step);
    return try applyNonVectorNumericShapeToValue(self, value, shape);
}

fn newFlatSliceValue(self: *Session, source: Value, start: usize, len: usize) KError!Value {
    const source_len = numericFlatLen(source) orelse return error.Type;
    if (start > source_len or start + len > source_len) return error.Type;

    const retained_source = try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);

    const source_handle = valueNumericHandle(source);
    const preferred: NumericArrayPreferred = if (source_handle) |handle|
        handle.preferred
    else if (source.tag() == .array and source.arrayKind() == .mlx_array)
        .mlx
    else
        .host;

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .flat_slice,
        .rank = 1,
        .shape = [_]i32{ @intCast(len), 0, 0, 0 },
        .flat_slice = .{ .source = retained_source, .start = start },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.flat_slice);
    return Value.array(handle);
}

fn newFlatConcatPairValue(self: *Session, left: Value, right: Value) KError!Value {
    if (valueNumericMode(left) == null or valueNumericMode(right) == null) return error.Type;
    const left_len = numericVectorLen(left) orelse return error.Type;
    const right_len = numericVectorLen(right) orelse return error.Type;

    const retained_left = try self.retainEscapedValue(left);
    errdefer self.releaseValue(retained_left);
    const retained_right = try self.retainEscapedValue(right);
    errdefer self.releaseValue(retained_right);

    const left_handle = valueNumericHandle(left);
    const right_handle = valueNumericHandle(right);
    const preferred: NumericArrayPreferred = if ((left_handle != null and left_handle.?.preferred == .mlx) or
        (right_handle != null and right_handle.?.preferred == .mlx))
        .mlx
    else
        .host;

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .flat_concat,
        .rank = 1,
        .shape = [_]i32{ @intCast(left_len + right_len), 0, 0, 0 },
        .flat_concat = .{ .left = retained_left, .right = retained_right },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.flat_concat);
    return Value.array(handle);
}

fn newFlatSegmentsValue(self: *Session, segments: []const FlatNumericSegment) KError!Value {
    if (segments.len < 3) return error.Type;

    const retained = try self.allocator.alloc(Value, segments.len);
    errdefer self.allocator.free(retained);

    var total_len: usize = 0;
    var preferred: NumericArrayPreferred = .host;
    var retained_len: usize = 0;
    errdefer {
        for (retained[0..retained_len]) |value| self.releaseValue(value);
    }
    for (segments, 0..) |segment, idx| {
        retained[idx] = try self.retainEscapedValue(segment.value);
        retained_len += 1;
        total_len += segment.len;
        if (valueNumericHandle(segment.value)) |handle| {
            if (handle.preferred == .mlx) preferred = .mlx;
        } else if (segment.value.tag() == .array and segment.value.arrayKind() == .mlx_array) {
            preferred = .mlx;
        }
    }

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .flat_segments,
        .rank = 1,
        .shape = [_]i32{ @intCast(total_len), 0, 0, 0 },
        .flat_segments = .{ .values = retained },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.flat_segments);
    return Value.array(handle);
}

fn newFlatConcatValue(self: *Session, left: Value, right: Value) KError!Value {
    var segments = std.ArrayList(FlatNumericSegment).empty;
    defer segments.deinit(self.allocator);
    try collectFlatNumericSegments(self.allocator, left, &segments);
    try collectFlatNumericSegments(self.allocator, right, &segments);
    return try buildFlatNumericComposition(self, segments.items);
}

fn newFirstAxisSliceValueWithStep(self: *Session, source: Value, start: usize, len: usize, step: i32) KError!Value {
    const source_handle = shapedNumericHandle(source) orelse return error.Type;
    const rows: usize = @intCast(source_handle.shape[0]);
    if (step == 0) return error.Type;
    if (len == 0) {
        if (start > rows) return error.Type;
    } else {
        const start_i64 = @as(i64, @intCast(start));
        const last_i64 = start_i64 + @as(i64, @intCast(len - 1)) * @as(i64, step);
        if (start_i64 < 0 or start_i64 >= rows) return error.Type;
        if (last_i64 < 0 or last_i64 >= rows) return error.Type;
    }

    const retained_source = try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = source_handle.preferred,
        .structural = .first_axis_slice,
        .rank = source_handle.rank,
        .shape = source_handle.shape,
        .first_axis_slice = .{ .source = retained_source, .start = start, .step = step },
        .host = null,
        .mlx = null,
    };
    handle.shape[0] = @intCast(len);
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.first_axis_slice);
    return Value.array(handle);
}

fn newFirstAxisSliceValue(self: *Session, source: Value, start: usize, len: usize) KError!Value {
    return try newFirstAxisSliceValueWithStep(self, source, start, len, 1);
}

fn newFirstAxisIndexValue(self: *Session, source: Value, row_indices: Value) KError!Value {
    const source_handle = shapedNumericHandle(source) orelse return error.Type;
    const rows_view = valueHostIntStructuralView(row_indices) orelse return error.Type;
    const row_count = hostIntDenseViewLen(rows_view);
    for (0..row_count) |idx| {
        const row_i64 = try hostIntDenseViewItem(rows_view, idx);
        if (row_i64 < 0 or row_i64 >= @as(i64, @intCast(source_handle.shape[0]))) return error.Type;
    }

    const retained_source = try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);
    const retained_rows = try self.retainEscapedValue(row_indices);
    errdefer self.releaseValue(retained_rows);

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = source_handle.preferred,
        .structural = .first_axis_index,
        .rank = source_handle.rank,
        .shape = source_handle.shape,
        .first_axis_index = .{ .source = retained_source, .row_indices = retained_rows },
        .host = null,
        .mlx = null,
    };
    handle.shape[0] = @intCast(row_count);
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.first_axis_index);
    return Value.array(handle);
}

fn newFirstAxisConcatValue(self: *Session, left: Value, right: Value, shape: NumericMatrixShape) KError!Value {
    if (valueNumericMode(left) == null or valueNumericMode(right) == null) return error.Type;

    const retained_left = try self.retainEscapedValue(left);
    errdefer self.releaseValue(retained_left);
    const retained_right = try self.retainEscapedValue(right);
    errdefer self.releaseValue(retained_right);

    const left_handle = valueNumericHandle(left);
    const right_handle = valueNumericHandle(right);
    const preferred: NumericArrayPreferred = if ((left_handle != null and left_handle.?.preferred == .mlx) or
        (right_handle != null and right_handle.?.preferred == .mlx))
        .mlx
    else
        .host;

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .first_axis_concat,
        .rank = 2,
        .shape = numericShapeSnapshotMatrix(shape.rows, shape.cols).shape,
        .first_axis_concat = .{ .left = retained_left, .right = retained_right },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.first_axis_concat);
    return Value.array(handle);
}

fn newReshapeViewValue(self: *Session, source: Value, shape: NumericShapeSnapshot) KError!Value {
    if (shape.rank == 0) return error.Type;

    const source_handle = valueNumericHandle(source);
    if (source_handle == null and valueNumericMode(source) == null) return error.Type;
    const retained_source = if (source_handle) |handle|
        if (numericArrayReshapeSource(handle)) |base_source|
            try self.retainEscapedValue(base_source)
        else
            try self.retainEscapedValue(source)
    else
        try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);

    const preferred: NumericArrayPreferred = if (source_handle) |handle|
        handle.preferred
    else switch (source.arrayKind()) {
        .mlx_array => .mlx,
        .host_array => .host,
        else => return error.Type,
    };

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .reshape_view,
        .rank = shape.rank,
        .shape = shape.shape,
        .reshape_view = .{ .source = retained_source },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.reshape_view);
    return Value.array(handle);
}

fn newTransposeViewValue(self: *Session, source: Value) KError!Value {
    const source_handle = shapedNumericHandle(source) orelse return error.Type;
    if (source_handle.rank != 2) return error.Type;

    if (numericArrayIsTransposeView(source_handle)) {
        return self.shareValue(numericArrayTransposeSource(source_handle) orelse return error.Type);
    }

    const retained_source = try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = source_handle.preferred,
        .structural = .transpose_view,
        .rank = 2,
        .shape = numericShapeSnapshotMatrix(@intCast(source_handle.shape[1]), @intCast(source_handle.shape[0])).shape,
        .transpose_view = .{ .source = retained_source },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.transpose_view);
    return Value.array(handle);
}

fn wrapOwnedHostArrayValue(self: *Session, array: *HostArray) !Value {
    if (std.meta.activeTag(array.storage) == .boxed) return Value.array(array);
    if (array.logical_handle) |handle| return Value.array(handle);
    return try newNumericArrayValue(self, array.header.owner, .host, array, null);
}

fn wrapOwnedMlxArrayValue(self: *Session, array: *MlxArray) !Value {
    if (array.logical_handle) |handle| return Value.array(handle);
    return try newNumericArrayValue(self, array.header.owner, .mlx, null, array);
}

fn hostArraySourceValue(array: *const HostArray) Value {
    if (array.logical_handle) |handle| return Value.array(handle);
    return Value.array(@constCast(array));
}

const dense_mlx_min_len_dyad: usize = 500_000;
const dense_mlx_min_len_reduce: usize = 500_000;
const dense_mlx_min_len_autodiff: usize = 1024;
const dense_mlx_min_len_transpose: usize = 2_048;
const dense_mlx_min_len_matmul: usize = 65_536;
const dual_resident_numeric_budget: usize = 8;

const DenseRegionFacts = struct {
    elem_count: usize = 0,
    matrix_rows: usize = 0,
    matrix_cols: usize = 0,
    has_mlx_residency: bool = false,
    has_unmaterialized_range: bool = false,
    has_packed_bit_input: bool = false,
    prefer_host_kernel: bool = false,
    prefer_mlx_pipeline: bool = false,
    supports_mlx: bool = true,
    device_preference: device.DevicePreference = .cpu,
};

const DensePlanDecision = struct {
    backend: DenseExecBackend,
    reason: DensePlanReason,
};

fn ensureNumericArrayHandle(self: *Session, value: Value) !*NumericArray {
    std.debug.assert(value.tag() == .array);
    return switch (value.arraySubkind()) {
        .numeric_array => @constCast(value.asNumericArray()),
        .host_array => blk: {
            const array = @constCast(value.asHostArray());
            if (hostArrayNumericMode(array) == null) return error.Type;
            if (array.logical_handle) |handle| break :blk handle;
            const handle = try allocNumericArrayHandle(self, array.header.owner);
            handle.* = .{
                .header = .{
                    .kind = .numeric_array,
                    .owner = array.header.owner,
                    .ref_count = if (array.header.owner == .managed) array.header.ref_count else 0,
                },
                .preferred = .host,
                .host = array,
                .mlx = null,
            };
            numericArraySetVectorShape(handle, array.len());
            syncNumericArrayChildren(handle);
            self.registerManagedNumericHandle(handle);
            break :blk handle;
        },
        .mlx_array => blk: {
            const array = @constCast(value.asMlxArray());
            if (array.logical_handle) |handle| break :blk handle;
            const handle = try allocNumericArrayHandle(self, array.header.owner);
            handle.* = .{
                .header = .{
                    .kind = .numeric_array,
                    .owner = array.header.owner,
                    .ref_count = if (array.header.owner == .managed) array.header.ref_count else 0,
                },
                .preferred = .mlx,
                .host = null,
                .mlx = array,
            };
            numericArraySetShapeFromMlx(handle, array.array);
            syncNumericArrayChildren(handle);
            self.registerManagedNumericHandle(handle);
            break :blk handle;
        },
        else => error.Type,
    };
}

fn hasMlxRealization(value: Value) bool {
    if (value.tag() != .array) return false;
    return switch (value.arraySubkind()) {
        .numeric_array => blk: {
            const handle = value.asNumericArray();
            if (handle.mlx != null) break :blk true;
            if (numericArrayFlatSliceSource(handle)) |source| break :blk hasMlxRealization(source);
            if (numericArrayFlatConcatLeft(handle)) |left| {
                const right = numericArrayFlatConcatRight(handle) orelse break :blk hasMlxRealization(left);
                break :blk hasMlxRealization(left) or hasMlxRealization(right);
            }
            if (numericArrayFlatSegmentsValues(handle)) |segments| {
                for (segments) |segment| {
                    if (hasMlxRealization(segment)) break :blk true;
                }
            }
            if (numericArrayFirstAxisSliceSource(handle)) |source| break :blk hasMlxRealization(source);
            if (numericArrayFirstAxisIndexSource(handle)) |source| break :blk hasMlxRealization(source);
            if (numericArrayFirstAxisConcatLeft(handle)) |left| {
                const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk hasMlxRealization(left);
                break :blk hasMlxRealization(left) or hasMlxRealization(right);
            }
            if (numericArrayReshapeSource(handle)) |source| break :blk hasMlxRealization(source);
            if (numericArrayTransposeSource(handle)) |source| break :blk hasMlxRealization(source);
            break :blk false;
        },
        .host_array => if (hostArrayNumericMode(value.asHostArray()) != null and value.asHostArray().logical_handle != null)
            value.asHostArray().logical_handle.?.mlx != null
        else
            false,
        .mlx_array => true,
        else => false,
    };
}

fn numericVectorLen(value: Value) ?usize {
    return switch (value.tag()) {
        .array => switch (value.arrayKind()) {
            .host_array => blk: {
                if (valueNumericMode(value) == null) break :blk null;
                if (valueNumericHandle(value)) |handle| {
                    if (handle.rank > 1) break :blk null;
                }
                break :blk value.asHostArray().len();
            },
            .mlx_array => blk: {
                const array = value.asMlxArray().array;
                if (array.ndim() != 1) break :blk null;
                const shape = array.shape();
                if (shape.len != 1) break :blk null;
                break :blk @intCast(shape[0]);
            },
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.rank != 1) break :blk null;
                break :blk @intCast(handle.shape[0]);
            },
            else => null,
        },
        else => null,
    };
}

fn supportsMlxDyad(op: BuiltinId) bool {
    return switch (op) {
        .add, .sub, .mul, .div, .less, .more, .equal => true,
        else => false,
    };
}

fn supportsMlxMonad(op: BuiltinId) bool {
    return switch (op) {
        .add, .sub, .div, .exp, .log, .tanh, .sigmoid => true,
        else => false,
    };
}

fn mlxDtypeIsFloat(dtype: c.mlx_dtype) bool {
    return dtype == c.MLX_FLOAT32 or dtype == c.MLX_FLOAT64;
}

fn castMlxBoolArrayTo(self: *Session, array: *mlx.Array, target_dtype: c.mlx_dtype) KError!void {
    if (array.dtype() != c.MLX_BOOL) return;
    const ctx = try self.mlxContext();
    const casted = mlx.Array.cast(ctx.*, array.*, target_dtype) catch |err| return mapMlxError(err);
    array.deinit();
    array.* = casted;
}

fn createMlxArrayFromHostArray(self: *Session, array: *const HostArray) KError!mlx.Array {
    var dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
    const dims = hostArrayShapeDims(array, &dims_buf);
    return switch (array.storage) {
        .bit => |words| blk: {
            const converted = try self.allocator.alloc(bool, array.logical_len);
            defer self.allocator.free(converted);
            for (0..array.logical_len) |idx| converted[idx] = bitGet(words, idx);
            break :blk mlx.Array.fromBoolSliceChecked(converted, dims) catch |err| return mapMlxError(err);
        },
        .int8 => |items| blk: {
            const converted = try self.allocator.alloc(i32, items.len);
            defer self.allocator.free(converted);
            for (items, 0..) |item, idx| converted[idx] = item;
            break :blk mlx.Array.fromIntSlice(converted, dims);
        },
        .int16 => |items| blk: {
            const converted = try self.allocator.alloc(i32, items.len);
            defer self.allocator.free(converted);
            for (items, 0..) |item, idx| converted[idx] = item;
            break :blk mlx.Array.fromIntSlice(converted, dims);
        },
        .int32 => |items| blk: {
            break :blk mlx.Array.fromIntSlice(items, dims);
        },
        .int64 => |items| blk: {
            const converted = try self.allocator.alloc(i32, items.len);
            defer self.allocator.free(converted);
            for (items, 0..) |item, idx| {
                converted[idx] = std.math.cast(i32, item) orelse return error.Unsupported;
            }
            break :blk mlx.Array.fromIntSlice(converted, dims);
        },
        .float64 => |items| blk: {
            const converted = try self.allocator.alloc(f32, items.len);
            defer self.allocator.free(converted);
            for (items, 0..) |item, idx| converted[idx] = @floatCast(item);
            break :blk mlx.Array.fromFloatSlice(converted, dims);
        },
        .boxed => |items| blk: {
            if (!isRenderableMatrix(items)) return error.Type;
            const rows = items.len;
            const cols = items[0].asHostArray().len();
            const matrix_dims = [_]i32{ @intCast(rows), @intCast(cols) };
            const converted = try self.allocator.alloc(f32, rows * cols);
            defer self.allocator.free(converted);
            var out_idx: usize = 0;
            for (items) |row| {
                for (0..cols) |col| {
                    converted[out_idx] = @floatCast(try numericFloatAt(row, col));
                    out_idx += 1;
                }
            }
            break :blk mlx.Array.fromFloatSlice(converted, &matrix_dims);
        },
    };
}

fn mlxArrayElementCount(array: mlx.Array) usize {
    if (array.ndim() == 0) return 1;
    var total: usize = 1;
    for (array.shape()) |dim| total *= @as(usize, @intCast(dim));
    return total;
}

fn transposeTileLen(comptime T: type) usize {
    return if (@sizeOf(T) >= 8) 16 else 32;
}

fn transposeBlockedTyped(comptime T: type, out: []T, source: []const T, rows: usize, cols: usize) void {
    std.debug.assert(out.len == source.len);
    std.debug.assert(out.len == rows * cols);
    const tile = transposeTileLen(T);

    var row_base: usize = 0;
    while (row_base < rows) : (row_base += tile) {
        const row_end = @min(row_base + tile, rows);
        var col_base: usize = 0;
        while (col_base < cols) : (col_base += tile) {
            const col_end = @min(col_base + tile, cols);
            var row = row_base;
            while (row < row_end) : (row += 1) {
                const source_row_base = row * cols;
                var col = col_base;
                while (col < col_end) : (col += 1) {
                    out[col * rows + row] = source[source_row_base + col];
                }
            }
        }
    }
}

fn transposeBlockedIntResult(comptime T: type, out: *HostArrayAlloc(T), source: []const T, rows: usize, cols: usize) void {
    transposeBlockedTyped(T, out.items, source, rows, cols);
}

fn sourceHostIntRange(value: Value, array: *const HostArray) HostIntRange {
    return if (hostIntArrayView(array)) |view|
        hostIntDenseValueRange(value, .{ .dense = view })
    else
        .{ .min = 0, .max = 0 };
}

fn createHostArrayFromTransposeView(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsTransposeView(handle)) return error.Type;
    const value = Value.array(@constCast(handle));
    const source = numericArrayTransposeSource(handle) orelse return error.Type;
    const source_shape = valueNumericMatrixShape(source) orelse return error.Type;
    const rows = source_shape.rows;
    const cols = source_shape.cols;
    const total_len = rows * cols;
    noteTransposeMaterializationDecision(self, value, total_len, .host);
    const source_host = try ensureNumericHostAttachmentForDenseView(self, source);

    if (source_host) |array| {
        switch (array.storage) {
            .float64 => |items| {
                if (items.len == total_len) {
                    const out = try self.allocOwnedHostFloatResult(owner, total_len);
                    transposeBlockedTyped(f64, out.items, items, rows, cols);
                    const analysis = analyzeFloatSlice(out.items);
                    hostArraySetFlags(out.array, analysis.flags);
                    return out.array;
                }
            },
            .int8 => |items| {
                if (items.len == total_len) {
                    var out = try self.allocHostArrayTyped(i8, .int8, owner, total_len);
                    transposeBlockedIntResult(i8, &out, items, rows, cols);
                    const host = out.array;
                    hostArraySetFlags(host, host_array_flag_normalized);
                    hostArraySetCachedIntRange(host, sourceHostIntRange(source, array));
                    return host;
                }
            },
            .int16 => |items| {
                if (items.len == total_len) {
                    var out = try self.allocHostArrayTyped(i16, .int16, owner, total_len);
                    transposeBlockedIntResult(i16, &out, items, rows, cols);
                    const host = out.array;
                    hostArraySetFlags(host, host_array_flag_normalized);
                    hostArraySetCachedIntRange(host, sourceHostIntRange(source, array));
                    return host;
                }
            },
            .int32 => |items| {
                if (items.len == total_len) {
                    var out = try self.allocHostArrayTyped(i32, .int32, owner, total_len);
                    transposeBlockedIntResult(i32, &out, items, rows, cols);
                    const host = out.array;
                    hostArraySetFlags(host, host_array_flag_normalized);
                    hostArraySetCachedIntRange(host, sourceHostIntRange(source, array));
                    return host;
                }
            },
            .int64 => |items| {
                if (items.len == total_len) {
                    var out = try self.allocHostArrayTyped(i64, .int64, owner, total_len);
                    transposeBlockedIntResult(i64, &out, items, rows, cols);
                    const host = out.array;
                    hostArraySetFlags(host, host_array_flag_normalized);
                    hostArraySetCachedIntRange(host, sourceHostIntRange(source, array));
                    return host;
                }
            },
            else => {},
        }
    }

    return switch (valueNumericMode(source) orelse return error.Type) {
        .float => blk: {
            const out = try self.allocOwnedHostFloatResult(owner, total_len);
            const transpose_view: HostTransposeView = .{
                .source_value = source,
                .source_host = source_host,
                .source_rows = rows,
                .source_cols = cols,
            };
            for (0..total_len) |idx| out.items[idx] = try hostFloatDenseViewItem(.{ .transpose = .{
                .source_value = transpose_view.source_value,
                .source_host = transpose_view.source_host,
                .source_rows = transpose_view.source_rows,
                .source_cols = transpose_view.source_cols,
            } }, idx);
            const analysis = analyzeFloatSlice(out.items);
            hostArraySetFlags(out.array, analysis.flags);
            break :blk out.array;
        },
        .int => blk: {
            const source_view = valueHostIntStructuralView(source) orelse return error.Type;
            const analysis = .{
                .kind = hostIntDenseViewKind(source_view),
                .range = hostIntDenseValueRange(source, source_view),
            };
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
            const transpose_view: HostTransposeView = .{
                .source_value = source,
                .source_host = source_host,
                .source_rows = rows,
                .source_cols = cols,
            };
            for (0..total_len) |idx| try out.set(idx, try hostTransposeIntItem(transpose_view, idx));
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, hostTransposeIntFlags(transpose_view));
            hostArraySetCachedIntRange(host, analysis.range);
            break :blk host;
        },
    };
}

fn createMlxArrayFromTransposeView(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsTransposeView(handle)) return error.Type;
    const value = Value.array(@constCast(handle));
    const source = numericArrayTransposeSource(handle) orelse return error.Type;
    noteTransposeMaterializationDecision(self, value, numericArrayElementCount(handle), .mlx);
    var source_array = try self.materializeMlxArray(source);
    defer source_array.deinit();
    const ctx = try self.mlxContext();
    return mlx.Array.transpose(ctx.*, source_array) catch |err| return mapMlxError(err);
}

fn createHostArrayFromRangeIota(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsRangeIota(handle)) return error.Type;
    const len = numericArrayRangeLen(handle);
    const bounds = numericArrayRangeIotaBounds(handle);
    const kind = hostIntStorageKindForRange(bounds.min, bounds.max);
    var out = try self.allocOwnedHostIntResult(owner, kind, len);
    for (0..len) |idx| try out.set(idx, try numericArrayRangeIotaValueAt(handle, idx));
    const host = out.arrayPtr();
    if (kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
    hostArraySetFlags(
        host,
        host_array_flag_normalized |
            orderFlagsFromMonotonic(handle.range_iota.step >= 0, handle.range_iota.step <= 0),
    );
    hostArraySetCachedIntRange(host, bounds);
    return host;
}

fn createMlxArrayFromRangeIota(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsRangeIota(handle)) return error.Type;
    const len = numericArrayRangeLen(handle);
    const converted = try self.allocator.alloc(i32, len);
    defer self.allocator.free(converted);

    for (0..len) |idx| {
        converted[idx] = std.math.cast(i32, try numericArrayRangeIotaValueAt(handle, idx)) orelse return error.Unsupported;
    }
    return mlx.Array.fromIntSlice(converted, handle.shapeSlice());
}

fn createHostArrayFromFlatSlice(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsFlatSlice(handle)) return error.Type;
    const source = numericArrayFlatSliceSource(handle) orelse return error.Type;
    const start = numericArrayFlatSliceStart(handle) orelse return error.Type;
    const len = numericVectorLen(Value.array(@constCast(handle))) orelse return error.Type;
    const collapsed = try tryCollapseHostFlatSlice(self, source, start, len);
    if (valueNumericHandle(source)) |source_handle| {
        if (source_handle.host == null and source_handle.mlx != null and
            !numericArrayIsRangeIota(source_handle) and
            !numericArrayIsFlatSlice(source_handle) and
            !numericArrayIsFlatConcat(source_handle) and
            !numericArrayIsFlatSegments(source_handle) and
            !numericArrayIsFirstAxisSlice(source_handle) and
            !numericArrayIsFirstAxisIndex(source_handle) and
            !numericArrayIsFirstAxisConcat(source_handle) and
            !numericArrayIsTransposeView(source_handle) and
            !numericArrayIsReshapeView(source_handle))
        {
            _ = try tryEnsureHostRealizationForHandle(self, @constCast(source_handle)) orelse return error.Type;
        }
    }

    return switch (valueNumericMode(source) orelse return error.Type) {
        .float => blk: {
            if (collapsed) |view| switch (view) {
                .flat_slice => |items| {
                    if (items.source_host) |array| switch (array.storage) {
                        .float64 => |values| {
                            const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
                            @memcpy(out.items, values[items.start .. items.start + len]);
                            const analysis = analyzeFloatSlice(out.items);
                            hostArraySetFlags(out.array, analysis.flags);
                            break :blk out.array;
                        },
                        else => {},
                    };
                    const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
                    for (0..len) |idx| out.items[idx] = try hostFlatSliceFloatItem(items, idx);
                    const analysis = analyzeFloatSlice(out.items);
                    hostArraySetFlags(out.array, analysis.flags);
                    break :blk out.array;
                },
                .flat_stride => |items| {
                    const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
                    for (0..len) |idx| out.items[idx] = try hostFlatStrideFloatItem(items, idx);
                    const analysis = analyzeFloatSlice(out.items);
                    hostArraySetFlags(out.array, analysis.flags);
                    break :blk out.array;
                },
            };
            if (hostArrayIfPresent(source)) |array| switch (array.storage) {
                .float64 => |items| {
                    const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
                    @memcpy(out.items, items[start .. start + len]);
                    const analysis = analyzeFloatSlice(out.items);
                    hostArraySetFlags(out.array, analysis.flags);
                    break :blk out.array;
                },
                else => {},
            };
            const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
            for (0..len) |idx| out.items[idx] = try numericFloatAt(source, start + idx);
            const analysis = analyzeFloatSlice(out.items);
            hostArraySetFlags(out.array, analysis.flags);
            break :blk out.array;
        },
        .int => blk: {
            if (collapsed) |view| switch (view) {
                .flat_slice => |items| {
                    var values = try self.allocator.alloc(i64, len);
                    defer self.allocator.free(values);
                    for (0..len) |idx| values[idx] = try hostFlatSliceIntItem(items, idx);
                    const analysis = analyzeIntSlice(values);
                    var out = try self.allocOwnedHostIntResult(owner, analysis.kind, len);
                    for (values, 0..) |item, idx| try out.set(idx, item);
                    const host = out.arrayPtr();
                    if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
                    hostArraySetFlags(host, analysis.flags);
                    hostArraySetCachedIntRange(host, analysis.range);
                    break :blk host;
                },
                .flat_stride => |items| {
                    var values = try self.allocator.alloc(i64, len);
                    defer self.allocator.free(values);
                    for (0..len) |idx| values[idx] = try hostFlatStrideIntItem(items, idx);
                    const analysis = analyzeIntSlice(values);
                    var out = try self.allocOwnedHostIntResult(owner, analysis.kind, len);
                    for (values, 0..) |item, idx| try out.set(idx, item);
                    const host = out.arrayPtr();
                    if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
                    hostArraySetFlags(host, analysis.flags);
                    hostArraySetCachedIntRange(host, analysis.range);
                    break :blk host;
                },
            };
            var values = try self.allocator.alloc(i64, len);
            defer self.allocator.free(values);
            for (0..len) |idx| values[idx] = try numericIntAt(source, start + idx);
            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, analysis.flags);
            hostArraySetCachedIntRange(host, analysis.range);
            break :blk host;
        },
    };
}

fn createMlxArrayFromFlatSlice(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFlatSlice(handle)) return error.Type;
    const source = numericArrayFlatSliceSource(handle) orelse return error.Type;
    const source_len = numericFlatLen(source) orelse return error.Type;
    const start = numericArrayFlatSliceStart(handle) orelse return error.Type;
    const len = numericVectorLen(Value.array(@constCast(handle))) orelse return error.Type;

    var source_array = try self.materializeMlxArray(source);
    defer source_array.deinit();
    if (source_array.ndim() != 1) {
        const dims = [_]i32{std.math.cast(i32, source_len) orelse return error.Unsupported};
        const reshaped = mlx.Array.reshape((try self.mlxContext()).*, source_array, &dims) catch |err| return mapMlxError(err);
        source_array.deinit();
        source_array = reshaped;
    }
    const ctx = try self.mlxContext();
    const start_buf = [_]i32{std.math.cast(i32, start) orelse return error.Unsupported};
    const stop_buf = [_]i32{std.math.cast(i32, start + len) orelse return error.Unsupported};
    const stride_buf = [_]i32{1};
    return mlx.Array.slice(ctx.*, source_array, &start_buf, &stop_buf, &stride_buf) catch |err| return mapMlxError(err);
}

fn createHostArrayFromFlatValues(self: *Session, owner: HeapOwner, segments: []const Value) KError!*HostArray {
    if (segments.len == 0) return error.Type;
    const mode = valueNumericMode(segments[0]) orelse return error.Type;
    var total_len: usize = 0;
    var all_int = mode == .int;
    for (segments) |segment| {
        const segment_mode = valueNumericMode(segment) orelse return error.Type;
        if (segment_mode == .float) all_int = false;
        total_len += numericVectorLen(segment) orelse return error.Type;
    }

    if (all_int) {
        var all_bits = true;
        for (segments) |segment| {
            if (valueNumericBitSlice(segment) == null) {
                all_bits = false;
                break;
            }
        }
        if (all_bits) {
            var out_bits = std.ArrayList(bool).empty;
            defer out_bits.deinit(self.allocator);
            try out_bits.ensureTotalCapacity(self.allocator, total_len);
            for (segments) |segment| {
                const bits = valueNumericBitSlice(segment) orelse return error.Type;
                for (0..bits.len) |idx| try out_bits.append(self.allocator, bitGet(bits.words, idx));
            }
            var asc = true;
            var dsc = true;
            var saw_zero = out_bits.items.len == 0;
            var saw_one = false;
            if (out_bits.items.len != 0) {
                if (out_bits.items[0]) saw_one = true else saw_zero = true;
                var prev = out_bits.items[0];
                for (out_bits.items[1..]) |item| {
                    if (item) saw_one = true else saw_zero = true;
                    if (@intFromBool(prev) > @intFromBool(item)) asc = false;
                    if (@intFromBool(prev) < @intFromBool(item)) dsc = false;
                    prev = item;
                }
            }
            var out = try self.allocOwnedHostIntResult(owner, .bit, total_len);
            for (out_bits.items, 0..) |item, idx| try out.set(idx, @intFromBool(item));
            const host = out.arrayPtr();
            bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
            hostArraySetCachedIntRange(host, .{
                .min = if (saw_zero) 0 else 1,
                .max = if (saw_one) 1 else 0,
            });
            return host;
        }

        var values = try self.allocator.alloc(i64, total_len);
        defer self.allocator.free(values);
        var out_idx: usize = 0;
        for (segments) |segment| {
            const len = numericVectorLen(segment) orelse return error.Type;
            for (0..len) |idx| {
                values[out_idx] = try numericIntAt(segment, idx);
                out_idx += 1;
            }
        }
        const analysis = analyzeIntSlice(values);
        var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
        for (values, 0..) |item, idx| try out.set(idx, item);
        const host = out.arrayPtr();
        if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
        hostArraySetFlags(host, analysis.flags);
        hostArraySetCachedIntRange(host, analysis.range);
        return host;
    }

    const out = try self.allocOwnedHostFloatResult(owner, total_len);
    var out_idx: usize = 0;
    for (segments) |segment| {
        const len = numericVectorLen(segment) orelse return error.Type;
        for (0..len) |idx| {
            out.items[out_idx] = try numericFloatAt(segment, idx);
            out_idx += 1;
        }
    }
    const analysis = analyzeFloatSlice(out.items);
    hostArraySetFlags(out.array, analysis.flags);
    return out.array;
}

fn createMlxArrayFromFlatValues(self: *Session, segments: []const Value) KError!mlx.Array {
    if (segments.len == 0) return error.Type;
    var arrays = try self.allocator.alloc(mlx.Array, segments.len);
    defer self.allocator.free(arrays);
    defer for (arrays[0..segments.len]) |*item| item.deinit();

    for (segments, 0..) |segment, idx| {
        arrays[idx] = try self.materializeMlxArray(segment);
    }
    return try mlxConcatAxis0((try self.mlxContext()).*, arrays[0..segments.len]);
}

fn createHostArrayFromFlatConcat(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsFlatConcat(handle)) return error.Type;
    const left = numericArrayFlatConcatLeft(handle) orelse return error.Type;
    const right = numericArrayFlatConcatRight(handle) orelse return error.Type;
    return try createHostArrayFromFlatValues(self, owner, &[_]Value{ left, right });
}

fn createMlxArrayFromFlatConcat(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFlatConcat(handle)) return error.Type;
    const left = numericArrayFlatConcatLeft(handle) orelse return error.Type;
    const right = numericArrayFlatConcatRight(handle) orelse return error.Type;
    return try createMlxArrayFromFlatValues(self, &[_]Value{ left, right });
}

fn createHostArrayFromFlatSegments(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsFlatSegments(handle)) return error.Type;
    const segments = numericArrayFlatSegmentsValues(handle) orelse return error.Type;
    return try createHostArrayFromFlatValues(self, owner, segments);
}

fn createMlxArrayFromFlatSegments(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFlatSegments(handle)) return error.Type;
    const segments = numericArrayFlatSegmentsValues(handle) orelse return error.Type;
    return try createMlxArrayFromFlatValues(self, segments);
}

fn createHostArrayFromFirstAxisSlice(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsFirstAxisSlice(handle)) return error.Type;
    const slice = handle.first_axis_slice orelse return error.Type;
    const source_handle = shapedNumericHandle(slice.source) orelse return error.Type;
    const row_width = numericShapeInnerBlockLen(source_handle);
    const row_count: usize = @intCast(handle.shape[0]);
    const start = slice.start * row_width;
    const total_len = row_count * row_width;

    if (valueRangeIotaHandle(slice.source)) |range_handle| {
        var values = try self.allocator.alloc(i64, total_len);
        defer self.allocator.free(values);
        var out_idx: usize = 0;
        for (0..row_count) |row| {
            const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
            if (source_row_i64 < 0) return error.Type;
            const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
            for (0..row_width) |col| {
                values[out_idx] = try numericArrayRangeIotaValueAt(range_handle, base_idx + col);
                out_idx += 1;
            }
        }
        const analysis = analyzeIntSlice(values);
        var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
        for (values, 0..) |item, idx| try out.set(idx, item);
        const host = out.arrayPtr();
        if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
        hostArraySetFlags(host, analysis.flags);
        hostArraySetCachedIntRange(host, analysis.range);
        return host;
    }

    const source_array = try hostStructuralArrayForHandle(self, try numericHandleRequired(slice.source));
    if (slice.step == 1) switch (source_array.storage) {
        .bit => {
            var out = try self.allocOwnedHostIntResult(owner, .bit, total_len);
            for (0..total_len) |idx| try out.set(idx, @intFromBool(bitGet(source_array.storage.bit, start + idx)));
            const host = out.arrayPtr();
            bitClearUnusedTail(host.storage.bit, host.logical_len);
            host.flags = source_array.flags;
            host.int_range_known = source_array.int_range_known;
            host.int_range_min = source_array.int_range_min;
            host.int_range_max = source_array.int_range_max;
            return host;
        },
        .float64 => |items| {
            const out = try self.allocHostArrayTyped(f64, .float64, owner, total_len);
            @memcpy(out.items, items[start .. start + total_len]);
            const host = out.array;
            host.flags = source_array.flags;
            return host;
        },
        .boxed => return error.Type,
        else => {
            const kind = hostIntArrayViewKind(hostIntArrayView(source_array).?);
            var out = try self.allocOwnedHostIntResult(owner, kind, total_len);
            for (0..total_len) |idx| try out.set(idx, try hostArrayIntAt(source_array, start + idx));
            const host = out.arrayPtr();
            host.flags = source_array.flags;
            host.int_range_known = source_array.int_range_known;
            host.int_range_min = source_array.int_range_min;
            host.int_range_max = source_array.int_range_max;
            return host;
        },
    };

    switch (hostArrayNumericMode(source_array) orelse return error.Type) {
        .float => {
            const out = try self.allocHostArrayTyped(f64, .float64, owner, total_len);
            var out_idx: usize = 0;
            for (0..row_count) |row| {
                const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
                if (source_row_i64 < 0) return error.Type;
                const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                for (0..row_width) |col| {
                    out.items[out_idx] = try hostArrayFloatAt(source_array, base_idx + col);
                    out_idx += 1;
                }
            }
            const analysis = analyzeFloatSlice(out.items);
            hostArraySetFlags(out.array, analysis.flags);
            return out.array;
        },
        .int => {
            var values = try self.allocator.alloc(i64, total_len);
            defer self.allocator.free(values);
            var out_idx: usize = 0;
            for (0..row_count) |row| {
                const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
                if (source_row_i64 < 0) return error.Type;
                const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                for (0..row_width) |col| {
                    values[out_idx] = try hostArrayIntAt(source_array, base_idx + col);
                    out_idx += 1;
                }
            }
            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, analysis.flags);
            hostArraySetCachedIntRange(host, analysis.range);
            return host;
        },
    }
}

fn createMlxArrayFromFirstAxisSlice(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFirstAxisSlice(handle)) return error.Type;
    const slice = handle.first_axis_slice orelse return error.Type;
    const source_handle = shapedNumericHandle(slice.source) orelse return error.Type;
    if (source_handle.rank != handle.rank) return error.Type;

    var source_array = try self.materializeMlxArray(slice.source);
    defer source_array.deinit();

    var start_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
    var stop_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
    var stride_buf: [numeric_array_max_rank]i32 = [_]i32{1} ** numeric_array_max_rank;
    for (0..source_handle.rank) |idx| {
        stop_buf[idx] = source_handle.shape[idx];
    }

    const row_count: usize = @intCast(handle.shape[0]);
    const ctx = try self.mlxContext();
    if (slice.step == 1) {
        start_buf[0] = std.math.cast(i32, slice.start) orelse return error.Unsupported;
        stop_buf[0] = std.math.cast(i32, slice.start + row_count) orelse return error.Unsupported;
        return mlx.Array.slice(
            ctx.*,
            source_array,
            start_buf[0..source_handle.rank],
            stop_buf[0..source_handle.rank],
            stride_buf[0..source_handle.rank],
        ) catch |err| return mapMlxError(err);
    }

    const idx_dims = [_]i32{std.math.cast(i32, row_count) orelse return error.Unsupported};
    const indices_buf = try self.allocator.alloc(i32, row_count);
    defer self.allocator.free(indices_buf);
    for (0..row_count) |row| {
        const row_idx_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
        if (row_idx_i64 < 0) return error.Type;
        indices_buf[row] = std.math.cast(i32, row_idx_i64) orelse return error.Unsupported;
    }
    var indices = mlx.Array.fromIntSlice(indices_buf, &idx_dims);
    defer indices.deinit();
    return mlx.Array.takeAxis(ctx.*, source_array, indices, 0) catch |err| return mapMlxError(err);
}

fn createHostArrayFromFirstAxisIndex(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsFirstAxisIndex(handle)) return error.Type;
    const index = handle.first_axis_index orelse return error.Type;
    const source_handle = shapedNumericHandle(index.source) orelse return error.Type;
    const row_width = numericShapeInnerBlockLen(source_handle);
    const row_count: usize = @intCast(handle.shape[0]);
    const total_len = row_count * row_width;

    return switch (valueNumericMode(index.source) orelse return error.Type) {
        .float => blk: {
            const out = try self.allocHostArrayTyped(f64, .float64, owner, total_len);
            var out_idx: usize = 0;
            for (0..row_count) |row| {
                const source_row_i64 = try numericIntAt(index.row_indices, row);
                if (source_row_i64 < 0) return error.Type;
                const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                for (0..row_width) |col| {
                    out.items[out_idx] = try numericFloatAt(index.source, base_idx + col);
                    out_idx += 1;
                }
            }
            const analysis = analyzeFloatSlice(out.items);
            hostArraySetFlags(out.array, analysis.flags);
            break :blk out.array;
        },
        .int => blk: {
            var values = try self.allocator.alloc(i64, total_len);
            defer self.allocator.free(values);
            var out_idx: usize = 0;
            for (0..row_count) |row| {
                const source_row_i64 = try numericIntAt(index.row_indices, row);
                if (source_row_i64 < 0) return error.Type;
                const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                for (0..row_width) |col| {
                    values[out_idx] = try numericIntAt(index.source, base_idx + col);
                    out_idx += 1;
                }
            }
            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, analysis.flags);
            hostArraySetCachedIntRange(host, analysis.range);
            break :blk host;
        },
    };
}

fn createMlxArrayFromFirstAxisIndex(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFirstAxisIndex(handle)) return error.Type;
    const index = handle.first_axis_index orelse return error.Type;
    const row_count: usize = @intCast(handle.shape[0]);
    const idx_dims = [_]i32{std.math.cast(i32, row_count) orelse return error.Unsupported};
    const indices_buf = try self.allocator.alloc(i32, row_count);
    defer self.allocator.free(indices_buf);
    for (0..row_count) |row| {
        const row_i64 = try numericIntAt(index.row_indices, row);
        if (row_i64 < 0) return error.Type;
        indices_buf[row] = std.math.cast(i32, row_i64) orelse return error.Unsupported;
    }

    var source_array = try self.materializeMlxArray(index.source);
    defer source_array.deinit();
    var indices = mlx.Array.fromIntSlice(indices_buf, &idx_dims);
    defer indices.deinit();
    const ctx = try self.mlxContext();
    return mlx.Array.takeAxis(ctx.*, source_array, indices, 0) catch |err| return mapMlxError(err);
}

fn createHostArrayFromFirstAxisConcat(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsFirstAxisConcat(handle)) return error.Type;
    const cols: usize = @intCast(handle.shape[1]);
    var segments = std.ArrayList(FirstAxisMatrixSegment).empty;
    defer segments.deinit(self.allocator);
    try collectFirstAxisMatrixSegments(self.allocator, Value.array(@constCast(handle)), cols, &segments);
    if (segments.items.len == 0) return error.Type;

    const left = segments.items[0].value;
    const left_mode = valueNumericMode(left) orelse return error.Type;
    var right_mode: HostArrayElem = left_mode;
    var total_len: usize = 0;
    for (segments.items) |segment| {
        const mode = valueNumericMode(segment.value) orelse return error.Type;
        if (mode == .float) right_mode = .float;
        total_len += numericFlatLen(segment.value) orelse return error.Type;
    }

    if (left_mode == .int and right_mode == .int) {
        var all_bits = true;
        for (segments.items) |segment| {
            if (valueNumericBitSlice(segment.value) == null) {
                all_bits = false;
                break;
            }
        }
        if (all_bits) {
            var out_bits = std.ArrayList(bool).empty;
            defer out_bits.deinit(self.allocator);
            try out_bits.ensureTotalCapacity(self.allocator, total_len);
            for (segments.items) |segment| {
                const bits = valueNumericBitSlice(segment.value) orelse return error.Type;
                for (0..bits.len) |idx| try out_bits.append(self.allocator, bitGet(bits.words, idx));
            }
            var asc = true;
            var dsc = true;
            var saw_zero = out_bits.items.len == 0;
            var saw_one = false;
            if (out_bits.items.len != 0) {
                if (out_bits.items[0]) saw_one = true else saw_zero = true;
                var prev = out_bits.items[0];
                for (out_bits.items[1..]) |item| {
                    if (item) saw_one = true else saw_zero = true;
                    if (@intFromBool(prev) > @intFromBool(item)) asc = false;
                    if (@intFromBool(prev) < @intFromBool(item)) dsc = false;
                    prev = item;
                }
            }
            var out = try self.allocOwnedHostIntResult(owner, .bit, total_len);
            for (out_bits.items, 0..) |item, idx| try out.set(idx, @intFromBool(item));
            const host = out.arrayPtr();
            bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
            hostArraySetCachedIntRange(host, .{
                .min = if (saw_zero) 0 else 1,
                .max = if (saw_one) 1 else 0,
            });
            return host;
        }

        var values = try self.allocator.alloc(i64, total_len);
        defer self.allocator.free(values);
        var out_idx: usize = 0;
        for (segments.items) |segment| {
            const len = numericFlatLen(segment.value) orelse return error.Type;
            for (0..len) |idx| {
                values[out_idx] = try numericIntAt(segment.value, idx);
                out_idx += 1;
            }
        }
        const analysis = analyzeIntSlice(values);
        var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
        for (values, 0..) |item, idx| try out.set(idx, item);
        const host = out.arrayPtr();
        if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
        hostArraySetFlags(host, analysis.flags);
        hostArraySetCachedIntRange(host, analysis.range);
        return host;
    }

    const out = try self.allocOwnedHostFloatResult(owner, total_len);
    var out_idx: usize = 0;
    for (segments.items) |segment| {
        const len = numericFlatLen(segment.value) orelse return error.Type;
        for (0..len) |idx| {
            out.items[out_idx] = try numericFloatAt(segment.value, idx);
            out_idx += 1;
        }
    }
    const analysis = analyzeFloatSlice(out.items);
    hostArraySetFlags(out.array, analysis.flags);
    return out.array;
}

fn createMlxConcatOperand(self: *Session, value: Value, cols: usize) KError!mlx.Array {
    var array = try self.materializeMlxArray(value);
    errdefer array.deinit();
    if (valueNumericMatrixShape(value) != null) return array;

    const dims = [_]i32{
        1,
        std.math.cast(i32, cols) orelse return error.Unsupported,
    };
    const ctx = try self.mlxContext();
    const reshaped = mlx.Array.reshape(ctx.*, array, &dims) catch |err| return mapMlxError(err);
    array.deinit();
    return reshaped;
}

fn mlxConcatAxis0(ctx: mlx.Context, arrays: []const mlx.Array) KError!mlx.Array {
    if (comptime !runtime_has_mlx) return error.Unsupported;
    if (comptime mlx.backend_kind == .wasm_bridge) {
        return mlx.Array.concat(ctx, arrays) catch |err| return mapMlxError(err);
    }
    const vec = c.mlx_vector_array_new();
    defer _ = c.mlx_vector_array_free(vec);
    for (arrays) |item| {
        mlx.check(c.mlx_vector_array_append_value(vec, item.handle)) catch |err| return mapMlxError(err);
    }
    var out = c.mlx_array_new();
    mlx.check(c.mlx_concatenate_axis(&out, vec, 0, ctx.stream)) catch |err| return mapMlxError(err);
    return .{ .handle = out };
}

fn createMlxArrayFromFirstAxisConcat(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFirstAxisConcat(handle)) return error.Type;
    if (handle.rank != 2) return error.Type;
    const cols: usize = @intCast(handle.shape[1]);
    var segments = std.ArrayList(FirstAxisMatrixSegment).empty;
    defer segments.deinit(self.allocator);
    try collectFirstAxisMatrixSegments(self.allocator, Value.array(@constCast(handle)), cols, &segments);
    if (segments.items.len == 0) return error.Type;

    var arrays = try self.allocator.alloc(mlx.Array, segments.items.len);
    defer self.allocator.free(arrays);
    defer for (arrays[0..segments.items.len]) |*item| item.deinit();

    for (segments.items, 0..) |segment, idx| {
        arrays[idx] = try createMlxConcatOperand(self, segment.value, cols);
    }

    return try mlxConcatAxis0((try self.mlxContext()).*, arrays[0..segments.items.len]);
}

fn createHostArrayFromReshapeView(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostArray {
    if (!numericArrayIsReshapeView(handle)) return error.Type;
    const source = numericArrayReshapeSource(handle) orelse return error.Type;
    const source_array = try hostStructuralArrayForHandle(self, try numericHandleRequired(source));
    const total_len = numericArrayElementCount(handle);

    return switch (hostArrayNumericMode(source_array) orelse return error.Type) {
        .float => switch (source_array.storage) {
            .float64 => |items| blk: {
                if (items.len != total_len) return error.Type;
                const out = try self.allocHostArrayTyped(f64, .float64, owner, total_len);
                @memcpy(out.items, items);
                const analysis = analyzeFloatSlice(out.items);
                hostArraySetFlags(out.array, analysis.flags);
                break :blk out.array;
            },
            else => error.Type,
        },
        .int => blk: {
            const view = hostIntArrayView(source_array) orelse return error.Type;
            if (hostIntArrayViewLen(view) != total_len) return error.Type;
            var values = try self.allocator.alloc(i64, total_len);
            defer self.allocator.free(values);
            for (0..total_len) |idx| values[idx] = hostIntViewItem(view, idx);
            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, analysis.flags);
            hostArraySetCachedIntRange(host, analysis.range);
            break :blk host;
        },
    };
}

fn createMlxArrayFromReshapeView(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsReshapeView(handle)) return error.Type;
    const source = numericArrayReshapeSource(handle) orelse return error.Type;
    var source_array = try self.materializeMlxArray(source);
    defer source_array.deinit();
    const ctx = try self.mlxContext();
    return mlx.Array.reshape(ctx.*, source_array, handle.shapeSlice()) catch |err| return mapMlxError(err);
}

fn createHostArrayFromMlxArray(self: *Session, owner: HeapOwner, array: mlx.Array) KError!*HostArray {
    var owned = array.clone() catch |err| return mapMlxError(err);
    defer owned.deinit();
    owned.eval() catch |err| return mapMlxError(err);

    const len = mlxArrayElementCount(owned);
    return switch (owned.dtype()) {
        c.MLX_BOOL => blk: {
            const items = owned.readBools(self.allocator) catch |err| return mapMlxError(err);
            defer self.allocator.free(items);

            var asc = true;
            var dsc = true;
            var saw_zero = items.len == 0;
            var saw_one = false;
            if (items.len != 0) {
                if (items[0]) saw_one = true else saw_zero = true;
                var prev = items[0];
                for (items[1..]) |item| {
                    if (item) saw_one = true else saw_zero = true;
                    if (@intFromBool(prev) > @intFromBool(item)) asc = false;
                    if (@intFromBool(prev) < @intFromBool(item)) dsc = false;
                    prev = item;
                }
            }

            var out = try self.allocOwnedHostIntResult(owner, .bit, len);
            for (items, 0..) |item, idx| try out.set(idx, @intFromBool(item));
            const host = out.arrayPtr();
            bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
            hostArraySetCachedIntRange(host, .{
                .min = if (saw_zero) 0 else 1,
                .max = if (saw_one) 1 else 0,
            });
            break :blk host;
        },
        c.MLX_INT32, c.MLX_INT64, c.MLX_UINT32 => blk: {
            const items = owned.readInts(self.allocator) catch |err| return mapMlxError(err);
            defer self.allocator.free(items);

            var values = try self.allocator.alloc(i64, items.len);
            defer self.allocator.free(values);
            for (items, 0..) |item, idx| values[idx] = item;

            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostArraySetFlags(host, analysis.flags);
            hostArraySetCachedIntRange(host, analysis.range);
            break :blk host;
        },
        c.MLX_FLOAT32, c.MLX_FLOAT64 => blk: {
            const items = owned.readFloats(self.allocator) catch |err| return mapMlxError(err);
            defer self.allocator.free(items);

            const out = try self.allocOwnedHostFloatResult(owner, len);
            for (items, 0..) |item, idx| out.items[idx] = @floatCast(item);
            const analysis = analyzeFloatSlice(out.items);
            hostArraySetFlags(out.array, analysis.flags);
            break :blk out.array;
        },
        else => error.Type,
    };
}

fn tryEnsureManagedMlxRealizationForHandle(self: *Session, handle: *NumericArray) KError!?*MlxArray {
    if (handle.mlx) |array| {
        if (comptime enable_probe_instrumentation) self.debug_mlx_realization_reuse_count += 1;
        self.touchMlxAttachment(handle);
        return array;
    }
    if (handle.header.owner != .managed) return null;
    const had_host_attachment = handle.host != null;
    var materialized = if (numericArrayIsRangeIota(handle))
        try createMlxArrayFromRangeIota(self, handle)
    else if (numericArrayIsFlatSlice(handle))
        try createMlxArrayFromFlatSlice(self, handle)
    else if (numericArrayIsFlatConcat(handle))
        try createMlxArrayFromFlatConcat(self, handle)
    else if (numericArrayIsFlatSegments(handle))
        try createMlxArrayFromFlatSegments(self, handle)
    else if (numericArrayIsFirstAxisSlice(handle))
        try createMlxArrayFromFirstAxisSlice(self, handle)
    else if (numericArrayIsFirstAxisIndex(handle))
        try createMlxArrayFromFirstAxisIndex(self, handle)
    else if (numericArrayIsFirstAxisConcat(handle))
        try createMlxArrayFromFirstAxisConcat(self, handle)
    else if (numericArrayIsReshapeView(handle))
        try createMlxArrayFromReshapeView(self, handle)
    else if (numericArrayIsTransposeView(handle))
        try createMlxArrayFromTransposeView(self, handle)
    else blk: {
        const host = if (handle.host) |array|
            array
        else
            (try tryEnsureHostRealizationForHandle(self, handle) orelse return null);
        if (hostArrayNumericMode(host) == null) return null;
        break :blk try createMlxArrayFromHostArray(self, host);
    };
    errdefer materialized.deinit();
    const owned = try self.allocManagedMlxPayload(materialized);
    materialized = mlx.Array.empty();
    if (comptime enable_probe_instrumentation) {
        self.debug_mlx_realization_count += 1;
        if (handle.structural != .materialized) self.debug_structural_mlx_realization_count += 1;
        if (had_host_attachment) self.debug_mlx_promotion_count += 1;
    }
    handle.mlx = owned;
    syncNumericArrayChildren(handle);
    self.touchMlxAttachment(handle);
    if (handle.host != null) self.enforceDualResidentBudget(handle);
    return owned;
}

fn tryEnsureManagedMlxRealization(self: *Session, value: Value) KError!?*MlxArray {
    const handle = mutableNumericHandle(value) orelse return null;
    return try tryEnsureManagedMlxRealizationForHandle(self, handle);
}

fn tryEnsureHostRealizationForHandle(self: *Session, handle: *NumericArray) KError!?*HostArray {
    var profile_scope = self.beginSamplingProfileScope(.host_realization);
    defer profile_scope.end();
    if (handle.host) |array| {
        if (comptime enable_probe_instrumentation) self.debug_host_realization_reuse_count += 1;
        self.touchHostAttachment(handle);
        return array;
    }
    if (handle.header.owner == .frozen) return error.Unsupported;
    const had_mlx_attachment = handle.mlx != null;

    const host = if (numericArrayIsRangeIota(handle))
        try createHostArrayFromRangeIota(self, handle.header.owner, handle)
    else if (numericArrayIsFlatSlice(handle))
        try createHostArrayFromFlatSlice(self, handle.header.owner, handle)
    else if (numericArrayIsFlatConcat(handle))
        try createHostArrayFromFlatConcat(self, handle.header.owner, handle)
    else if (numericArrayIsFlatSegments(handle))
        try createHostArrayFromFlatSegments(self, handle.header.owner, handle)
    else if (numericArrayIsFirstAxisSlice(handle))
        try createHostArrayFromFirstAxisSlice(self, handle.header.owner, handle)
    else if (numericArrayIsFirstAxisIndex(handle))
        try createHostArrayFromFirstAxisIndex(self, handle.header.owner, handle)
    else if (numericArrayIsFirstAxisConcat(handle))
        try createHostArrayFromFirstAxisConcat(self, handle.header.owner, handle)
    else if (numericArrayIsReshapeView(handle))
        try createHostArrayFromReshapeView(self, handle.header.owner, handle)
    else if (numericArrayIsTransposeView(handle))
        try createHostArrayFromTransposeView(self, handle.header.owner, handle)
    else blk: {
        const mlx_array = handle.mlx orelse return null;
        if (handle.rank == 0) numericArraySetShapeFromMlx(handle, mlx_array.array);
        break :blk try createHostArrayFromMlxArray(self, handle.header.owner, mlx_array.array);
    };
    if (comptime enable_probe_instrumentation) {
        self.debug_host_realization_count += 1;
        if (handle.structural != .materialized) self.debug_structural_host_realization_count += 1;
        if (had_mlx_attachment) self.debug_host_readback_count += 1;
    }
    handle.host = host;
    syncNumericArrayChildren(handle);
    self.touchHostAttachment(handle);
    if (handle.mlx != null) self.enforceDualResidentBudget(handle);
    return host;
}

fn tryEnsureHostRealization(self: *Session, value: Value) KError!?*HostArray {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .host_array => @constCast(value.asHostArray()),
        .numeric_array => try tryEnsureHostRealizationForHandle(self, @constCast(value.asNumericArray())),
        .mlx_array => if (value.asMlxArray().logical_handle) |handle|
            try tryEnsureHostRealizationForHandle(self, handle)
        else
            null,
        else => null,
    };
}

fn hostStructuralArrayForHandle(self: *Session, handle: *NumericArray) KError!*const HostArray {
    return try tryEnsureHostRealizationForHandle(self, handle) orelse return error.Unsupported;
}

// Generic array compatibility wrapper. Numeric execution should prefer
// handle-native helpers; this remains for boxed-array and boundary code.
fn hostStructuralArrayValue(self: *Session, value: Value) KError!*const HostArray {
    if (value.tag() != .array) return error.Type;
    return switch (value.arraySubkind()) {
        .host_array => value.asHostArray(),
        .numeric_array => try hostStructuralArrayForHandle(self, @constCast(value.asNumericArray())),
        .mlx_array => if (value.asMlxArray().logical_handle) |handle|
            try hostStructuralArrayForHandle(self, handle)
        else
            error.Unsupported,
        else => error.Type,
    };
}

fn actualDenseBackend(self: *Session, supports_mlx: bool, planned: DenseExecBackend) DenseExecBackend {
    return switch (self.dense_backend_override) {
        .auto => planned,
        .host => .host,
        .mlx => if (supports_mlx) .mlx else planned,
    };
}

fn noteDensePlanDecision(self: *Session, kind: DenseRegionKind, planned_backend: DenseExecBackend, actual_backend: DenseExecBackend, reason: DensePlanReason) void {
    if (comptime !enable_probe_instrumentation) {
        return;
    }
    self.debug_dense_plan_counts[@intFromEnum(kind)][@intFromEnum(planned_backend)] += 1;
    self.debug_dense_exec_counts[@intFromEnum(kind)][@intFromEnum(actual_backend)] += 1;
    self.last_dense_plan_region = kind;
    self.last_dense_plan_backend = planned_backend;
    self.last_dense_exec_backend = actual_backend;
    self.last_dense_plan_reason = reason;
    self.last_dense_plan_overridden = planned_backend != actual_backend;
}

fn countDensePlanDecision(self: *Session, kind: DenseRegionKind, planned_backend: DenseExecBackend, actual_backend: DenseExecBackend) void {
    if (comptime !enable_probe_instrumentation) {
        return;
    }
    self.debug_dense_plan_counts[@intFromEnum(kind)][@intFromEnum(planned_backend)] += 1;
    self.debug_dense_exec_counts[@intFromEnum(kind)][@intFromEnum(actual_backend)] += 1;
}

fn planDenseRegionDecision(kind: DenseRegionKind, facts: DenseRegionFacts) DensePlanDecision {
    return switch (kind) {
        .numeric_dyad => if (!facts.supports_mlx)
            .{ .backend = .host, .reason = .no_mlx_support }
        else if (facts.has_unmaterialized_range and !facts.has_mlx_residency)
            .{ .backend = .host, .reason = .unmaterialized_range_host }
        else if (facts.prefer_mlx_pipeline)
            .{ .backend = .mlx, .reason = .large_problem }
        else if (facts.prefer_host_kernel and facts.elem_count < dense_mlx_min_len_dyad)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.has_mlx_residency)
            .{ .backend = .mlx, .reason = .already_mlx_resident }
        else if (facts.elem_count < dense_mlx_min_len_dyad)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
        .compare_mask => if (!facts.supports_mlx)
            .{ .backend = .host, .reason = .no_mlx_support }
        else if (facts.has_unmaterialized_range and !facts.has_mlx_residency)
            .{ .backend = .host, .reason = .unmaterialized_range_host }
        else if (facts.has_packed_bit_input and !facts.has_mlx_residency)
            .{ .backend = .host, .reason = .packed_mask_host }
        else if (facts.has_mlx_residency)
            .{ .backend = .mlx, .reason = .already_mlx_resident }
        else
            .{ .backend = .host, .reason = .compare_host_default },
        .reduce, .scan => if (!facts.supports_mlx)
            .{ .backend = .host, .reason = .no_mlx_support }
        else if (facts.has_unmaterialized_range)
            .{ .backend = .host, .reason = .unmaterialized_range_host }
        else if (facts.has_packed_bit_input and !facts.has_mlx_residency)
            .{ .backend = .host, .reason = .packed_mask_host }
        else if (facts.prefer_host_kernel and facts.elem_count < dense_mlx_min_len_reduce)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if ((!runtime_has_mlx or mlx.backend_kind == .wasm_bridge) and facts.elem_count < dense_mlx_min_len_reduce)
            .{ .backend = .host, .reason = .small_problem }
        else if (facts.has_mlx_residency)
            .{ .backend = .mlx, .reason = .already_mlx_resident }
        else if (facts.elem_count < dense_mlx_min_len_reduce)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
        .matmul => if (!facts.supports_mlx)
            .{ .backend = .host, .reason = .no_mlx_support }
        else if (facts.prefer_host_kernel and facts.elem_count <= dense_mlx_min_len_matmul)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.has_mlx_residency)
            .{ .backend = .mlx, .reason = .already_mlx_resident }
        else if (facts.elem_count < dense_mlx_min_len_matmul)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
        .transpose => if (!facts.supports_mlx)
            .{ .backend = .host, .reason = .no_mlx_support }
        else if (facts.device_preference == .gpu and
            facts.matrix_rows != 0 and facts.matrix_cols != 0 and
            (!facts.has_mlx_residency or facts.prefer_host_kernel) and
            facts.elem_count <= 16_384 and
            @max(facts.matrix_rows, facts.matrix_cols) <= 128)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.device_preference == .gpu and
            facts.matrix_rows != 0 and facts.matrix_cols != 0 and
            (!facts.has_mlx_residency or facts.prefer_host_kernel) and
            facts.elem_count <= 16_384 and
            @min(facts.matrix_rows, facts.matrix_cols) <= 32)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.matrix_rows != 0 and facts.matrix_cols != 0 and facts.prefer_host_kernel and facts.elem_count <= 4_096)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.matrix_rows != 0 and facts.matrix_cols != 0 and
            facts.prefer_host_kernel and
            @min(facts.matrix_rows, facts.matrix_cols) <= 16 and
            facts.elem_count <= 16_384)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.matrix_rows != 0 and facts.matrix_cols != 0 and
            @min(facts.matrix_rows, facts.matrix_cols) <= 8 and
            facts.elem_count <= 32_768)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.has_mlx_residency)
            .{ .backend = .mlx, .reason = .already_mlx_resident }
        else if (facts.elem_count < dense_mlx_min_len_transpose)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
        .dense_autodiff => if (!facts.supports_mlx)
            .{ .backend = .host, .reason = .no_mlx_support }
        else if (facts.has_unmaterialized_range)
            .{ .backend = .host, .reason = .unmaterialized_range_host }
        else if (facts.has_mlx_residency)
            .{ .backend = .mlx, .reason = .already_mlx_resident }
        else if (facts.elem_count < dense_mlx_min_len_autodiff)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
    };
}

fn chooseDenseRegionBackend(self: *Session, kind: DenseRegionKind, facts: DenseRegionFacts) DenseExecBackend {
    const decision = planDenseRegionDecision(kind, facts);
    const actual_backend = actualDenseBackend(self, facts.supports_mlx, decision.backend);
    noteDensePlanDecision(self, kind, decision.backend, actual_backend, decision.reason);
    return actual_backend;
}

fn planDenseNumericDyadBackend(self: *Session, op: BuiltinId, left: Value, right: Value) DenseExecBackend {
    const has_mlx_residency = isMlxBackedArray(left) or isMlxBackedArray(right) or hasMlxRealization(left) or hasMlxRealization(right);
    const preserve_mlx_pipeline = has_mlx_residency and
        (valueNonVectorNumericShape(left) != null or valueNonVectorNumericShape(right) != null);
    return chooseDenseRegionBackend(self, .numeric_dyad, .{
        .elem_count = arrayResultLen(left, right) catch 0,
        .has_mlx_residency = has_mlx_residency,
        .has_unmaterialized_range = isUnmaterializedRangeIotaValue(left) or isUnmaterializedRangeIotaValue(right),
        .prefer_host_kernel = !preserve_mlx_pipeline and
            has_mlx_residency and
            valueSupportsHostDensePlanning(left) and valueSupportsHostDensePlanning(right),
        .prefer_mlx_pipeline = transposePipelinePrefersMlx(self, left) or transposePipelinePrefersMlx(self, right),
        .supports_mlx = supportsMlxDyad(op),
    });
}

fn planCompareMaskBackend(self: *Session, op: BuiltinId, left: Value, right: Value) DenseExecBackend {
    return chooseDenseRegionBackend(self, .compare_mask, .{
        .elem_count = arrayResultLen(left, right) catch 0,
        .has_mlx_residency = isMlxBackedArray(left) or isMlxBackedArray(right) or hasMlxRealization(left) or hasMlxRealization(right),
        .has_unmaterialized_range = isUnmaterializedRangeIotaValue(left) or isUnmaterializedRangeIotaValue(right),
        .has_packed_bit_input = valueNumericBitSlice(left) != null or valueNumericBitSlice(right) != null,
        .supports_mlx = op == .equal or op == .less or op == .more,
    });
}

fn planDenseReduceScanBackend(self: *Session, collect: bool, value: Value) DenseExecBackend {
    return chooseDenseRegionBackend(self, if (collect) .scan else .reduce, denseReduceScanFacts(value));
}

fn denseReduceScanFacts(value: Value) DenseRegionFacts {
    return .{
        .elem_count = numericVectorLen(value) orelse 0,
        .has_mlx_residency = isMlxBackedArray(value) or hasMlxRealization(value),
        .has_unmaterialized_range = isUnmaterializedRangeIotaValue(value),
        .has_packed_bit_input = valueNumericBitSlice(value) != null,
        .prefer_host_kernel = (isMlxBackedArray(value) or hasMlxRealization(value)) and
            valueSupportsHostDensePlanning(value),
    };
}

fn valueSupportsHostDensePlanning(value: Value) bool {
    const source_supported = struct {
        fn check(source: Value) bool {
            return switch (source.tag()) {
                .int, .bool, .float => true,
                .array => switch (source.arraySubkind()) {
                    .host_array => hostArrayNumericMode(source.asHostArray()) != null,
                    .numeric_array => true,
                    .mlx_array => source.asMlxArray().logical_handle != null,
                    else => false,
                },
                else => false,
            };
        }
    }.check;

    return switch (value.tag()) {
        .int, .bool, .float => true,
        .array => switch (value.arraySubkind()) {
            .host_array => hostArrayNumericMode(value.asHostArray()) != null,
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.host != null or numericArrayIsRangeIota(handle)) break :blk true;
                if (numericArrayIsFlatSlice(handle)) {
                    const source = numericArrayFlatSliceSource(handle) orelse break :blk false;
                    break :blk source_supported(source);
                }
                if (numericArrayIsFlatConcat(handle)) {
                    const left = numericArrayFlatConcatLeft(handle) orelse break :blk false;
                    const right = numericArrayFlatConcatRight(handle) orelse break :blk false;
                    break :blk source_supported(left) and source_supported(right);
                }
                if (numericArrayIsFlatSegments(handle)) {
                    const segments = numericArrayFlatSegmentsValues(handle) orelse break :blk false;
                    for (segments) |segment| {
                        if (!source_supported(segment)) break :blk false;
                    }
                    break :blk true;
                }
                if (numericArrayIsFirstAxisSlice(handle)) {
                    const source = numericArrayFirstAxisSliceSource(handle) orelse break :blk false;
                    break :blk source_supported(source);
                }
                if (numericArrayIsFirstAxisIndex(handle)) {
                    const source = numericArrayFirstAxisIndexSource(handle) orelse break :blk false;
                    const row_indices = numericArrayFirstAxisIndexRows(handle) orelse break :blk false;
                    break :blk source_supported(source) and source_supported(row_indices);
                }
                if (numericArrayIsFirstAxisConcat(handle)) {
                    const left = numericArrayFirstAxisConcatLeft(handle) orelse break :blk false;
                    const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk false;
                    break :blk source_supported(left) and source_supported(right);
                }
                if (numericArrayIsReshapeView(handle)) {
                    const source = numericArrayReshapeSource(handle) orelse break :blk false;
                    break :blk source_supported(source);
                }
                if (numericArrayIsTransposeView(handle)) {
                    const source = numericArrayTransposeSource(handle) orelse break :blk false;
                    break :blk source_supported(source);
                }
                break :blk false;
            },
            .mlx_array => blk: {
                const handle = value.asMlxArray().logical_handle orelse break :blk false;
                if (handle.host != null) break :blk true;
                if (!numericArrayIsTransposeView(handle)) break :blk false;
                const source = numericArrayTransposeSource(handle) orelse break :blk false;
                break :blk source_supported(source);
            },
            else => false,
        },
        else => false,
    };
}

fn matmulPrefersHostKernel(left: Value, right: Value, result_rank: usize) bool {
    if (result_rank != 0) return false;
    return valueSupportsHostDensePlanning(left) and valueSupportsHostDensePlanning(right);
}

fn planMatmulBackend(self: *Session, left: Value, right: Value) DenseExecBackend {
    const shape = Session.matmulShapeForValues(left, right) catch null;
    const has_mlx_residency = isMlxBackedArray(left) or isMlxBackedArray(right) or hasMlxRealization(left) or hasMlxRealization(right);
    return chooseDenseRegionBackend(self, .matmul, .{
        .elem_count = if (shape) |info| info.result_rows * info.left_cols * info.result_cols else 0,
        .matrix_rows = if (shape) |info| info.result_rows else 0,
        .matrix_cols = if (shape) |info| info.result_cols else 0,
        .has_mlx_residency = has_mlx_residency,
        .prefer_host_kernel = if (shape) |info| matmulPrefersHostKernel(left, right, info.result_rank) else false,
    });
}

fn planDenseAutodiffBackend(self: *Session, value: Value) DenseExecBackend {
    return chooseDenseRegionBackend(self, .dense_autodiff, .{
        .elem_count = numericVectorLen(value) orelse 0,
        .has_mlx_residency = isMlxBackedArray(value) or hasMlxRealization(value),
        .has_unmaterialized_range = isUnmaterializedRangeIotaValue(value),
    });
}

fn transposeSourceValue(value: Value) Value {
    if (value.tag() != .array) return value;
    const handle = valueNumericHandle(value) orelse return value;
    return numericArrayTransposeSource(handle) orelse value;
}

fn transposeHasFastHostKernel(value: Value) bool {
    const source = transposeSourceValue(value);
    const array = hostArrayIfPresent(source) orelse return false;
    return switch (array.storage) {
        .float64, .int8, .int16, .int32, .int64 => true,
        else => false,
    };
}

fn transposeRegionFacts(self: *Session, value: Value, elem_count: usize) DenseRegionFacts {
    const source = transposeSourceValue(value);
    const shape = valueNumericMatrixShape(value) orelse valueNumericMatrixShape(source);
    const has_mlx_residency = isMlxBackedArray(source) or hasMlxRealization(source);
    const preserve_mlx_pipeline = has_mlx_residency and shape != null;
    return .{
        .elem_count = elem_count,
        .matrix_rows = if (shape) |matrix| matrix.rows else 0,
        .matrix_cols = if (shape) |matrix| matrix.cols else 0,
        .has_mlx_residency = has_mlx_residency,
        .prefer_host_kernel = !preserve_mlx_pipeline and transposeHasFastHostKernel(value),
        .device_preference = self.device_preference,
    };
}

fn transposePipelinePrefersMlx(self: *Session, value: Value) bool {
    const handle = valueNumericHandle(value) orelse return false;
    if (!numericArrayIsTransposeView(handle)) return false;
    const decision = planDenseRegionDecision(.transpose, transposeRegionFacts(self, value, numericArrayElementCount(handle)));
    return decision.backend == .mlx;
}

fn planTransposeBackend(self: *Session, value: Value, elem_count: usize) DenseExecBackend {
    return chooseDenseRegionBackend(self, .transpose, transposeRegionFacts(self, value, elem_count));
}

fn noteTransposeMaterializationDecision(self: *Session, value: Value, elem_count: usize, actual_backend: DenseExecBackend) void {
    const facts = transposeRegionFacts(self, value, elem_count);
    const decision = planDenseRegionDecision(.transpose, facts);
    noteDensePlanDecision(self, .transpose, decision.backend, actual_backend, decision.reason);
}

fn countTransposeStructuralHostUse(self: *Session, value: Value) void {
    const handle = valueNumericHandle(value) orelse return;
    if (!numericArrayIsTransposeView(handle)) return;
    const decision = planDenseRegionDecision(.transpose, transposeRegionFacts(self, value, numericArrayElementCount(handle)));
    countDensePlanDecision(self, .transpose, decision.backend, .host);
}

fn valueNumericMode(value: Value) ?HostArrayElem {
    return switch (value.tag()) {
        .int, .bool => .int,
        .float => .float,
        .array => switch (value.arrayKind()) {
            .host_array => hostArrayNumericMode(value.asHostArray()),
            .mlx_array => .float,
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.host) |array| break :blk hostArrayNumericMode(array);
                if (handle.mlx != null) break :blk .float;
                if (numericArrayIsRangeIota(handle)) break :blk .int;
                if (numericArrayFlatSliceSource(handle)) |source| break :blk valueNumericMode(source);
                if (numericArrayFlatConcatLeft(handle)) |left| {
                    const right = numericArrayFlatConcatRight(handle) orelse break :blk valueNumericMode(left);
                    const left_mode = valueNumericMode(left) orelse break :blk null;
                    const right_mode = valueNumericMode(right) orelse break :blk null;
                    break :blk if (left_mode == .float or right_mode == .float) .float else .int;
                }
                if (numericArrayFlatSegmentsValues(handle)) |segments| {
                    var saw_float = false;
                    for (segments) |segment| {
                        const segment_mode = valueNumericMode(segment) orelse break :blk null;
                        if (segment_mode == .float) saw_float = true;
                    }
                    break :blk if (saw_float) .float else .int;
                }
                if (numericArrayFirstAxisSliceSource(handle)) |source| break :blk valueNumericMode(source);
                if (numericArrayFirstAxisIndexSource(handle)) |source| break :blk valueNumericMode(source);
                if (numericArrayFirstAxisConcatLeft(handle)) |left| {
                    const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk valueNumericMode(left);
                    const left_mode = valueNumericMode(left) orelse break :blk null;
                    const right_mode = valueNumericMode(right) orelse break :blk null;
                    break :blk if (left_mode == .float or right_mode == .float) .float else .int;
                }
                if (numericArrayReshapeSource(handle)) |source| break :blk valueNumericMode(source);
                if (numericArrayTransposeSource(handle)) |source| break :blk valueNumericMode(source);
                break :blk null;
            },
            else => null,
        },
        else => null,
    };
}

fn isMlxBackedArray(value: Value) bool {
    return value.tag() == .array and value.arrayKind() == .mlx_array;
}

fn arrayResultMode(op: BuiltinId, left: Value, right: Value) ?HostArrayElem {
    const left_mode = valueNumericMode(left) orelse return null;
    const right_mode = valueNumericMode(right) orelse return null;
    if (op == .div or left_mode == .float or right_mode == .float) return .float;
    return .int;
}

fn denseResultMode(op: BuiltinId, left_mode: HostArrayElem, right_mode: HostArrayElem) HostArrayElem {
    if (op == .div or left_mode == .float or right_mode == .float) return .float;
    return .int;
}

fn numericFlatLen(value: Value) ?usize {
    if (value.tag() != .array) return null;
    return switch (value.arrayKind()) {
        .host_array => value.asHostArray().len(),
        .mlx_array => blk: {
            if (valueNumericHandle(value)) |handle| {
                if (handle.host) |array| break :blk array.len();
                if (handle.rank != 0) {
                    var total: usize = 1;
                    for (handle.shapeSlice()) |dim| total *= @as(usize, @intCast(dim));
                    break :blk total;
                }
            }
            break :blk mlxArrayElementCount(value.asMlxArray().array);
        },
        .numeric_array => blk: {
            const handle = value.asNumericArray();
            if (handle.rank == 0) break :blk null;
            var total: usize = 1;
            for (handle.shapeSlice()) |dim| total *= @as(usize, @intCast(dim));
            break :blk total;
        },
        else => null,
    };
}

fn arrayResultLen(left: Value, right: Value) KError!usize {
    if (rowwiseMatrixVectorDyad(left, right)) |shape| return shape.rows * shape.cols;
    const left_len = switch (left.tag()) {
        .array => switch (left.arrayKind()) {
            .host_array, .mlx_array, .numeric_array => numericFlatLen(left) orelse return error.Type,
            else => return error.Internal,
        },
        .int, .float, .bool => null,
        else => return error.Type,
    };
    const right_len = switch (right.tag()) {
        .array => switch (right.arrayKind()) {
            .host_array, .mlx_array, .numeric_array => numericFlatLen(right) orelse return error.Type,
            else => return error.Internal,
        },
        .int, .float, .bool => null,
        else => return error.Type,
    };

    if (left_len) |llen| {
        if (right_len) |rlen| {
            _ = try nonVectorNumericShapeForDyad(left, right);
            if (llen != rlen) return error.Type;
            return llen;
        }
        return llen;
    }
    return right_len orelse return error.Type;
}

fn isBoxedHostArrayValue(value: Value) bool {
    return value.tag() == .array and
        value.arrayKind() == .host_array and
        std.meta.activeTag(value.asHostArray().storage) == .boxed;
}

fn isGenericArrayValue(value: Value) bool {
    return isBoxedHostArrayValue(value);
}

fn shouldUseGenericArrayDyad(left: Value, right: Value) bool {
    if (isMlxBackedArray(left) or isMlxBackedArray(right)) return false;
    if ((valueIsRenderableMatrixLike(left) and valueNumericMode(right) != null) or
        (valueIsRenderableMatrixLike(right) and valueNumericMode(left) != null))
    {
        return false;
    }
    return (left.tag() == .array or right.tag() == .array) and
        (valueNumericMode(left) == null or valueNumericMode(right) == null);
}

const HostRangeIotaView = struct {
    handle: *const NumericArray,
};

const HostFlatSliceView = struct {
    source_value: Value,
    source_host: ?*const HostArray = null,
    start: usize,
    len: usize,
};

const HostFlatStrideView = struct {
    source_value: Value,
    source_host: ?*const HostArray = null,
    start: usize,
    len: usize,
    step: usize = 1,
};

const HostFlatSegmentsView = struct {
    values: []const Value,
    len: usize,
};

const HostFirstAxisSliceView = struct {
    source_value: Value,
    source_host: ?*const HostArray = null,
    start_row: usize,
    len: usize,
    row_width: usize = 1,
    row_step: i32 = 1,
};

const HostFirstAxisIndexView = struct {
    source_value: Value,
    source_host: ?*const HostArray = null,
    row_indices: Value,
    len: usize,
    row_width: usize = 1,
};

const HostFirstAxisConcatView = struct {
    left_value: Value,
    left_host: ?*const HostArray = null,
    right_value: Value,
    right_host: ?*const HostArray = null,
    left_len: usize,
    len: usize,
};

const HostTransposeView = struct {
    source_value: Value,
    source_host: ?*const HostArray = null,
    source_rows: usize,
    source_cols: usize,
};

const HostIntDenseView = union(enum) {
    dense: HostIntArrayView,
    range_iota: HostRangeIotaView,
    flat_slice: HostFlatSliceView,
    flat_stride: HostFlatStrideView,
    flat_concat: HostFirstAxisConcatView,
    flat_segments: HostFlatSegmentsView,
    first_axis_slice: HostFirstAxisSliceView,
    first_axis_index: HostFirstAxisIndexView,
    first_axis_concat: HostFirstAxisConcatView,
    transpose: HostTransposeView,
};

const HostFloatDenseView = union(enum) {
    dense: []const f64,
    flat_slice: HostFlatSliceView,
    flat_stride: HostFlatStrideView,
    flat_concat: HostFirstAxisConcatView,
    flat_segments: HostFlatSegmentsView,
    first_axis_slice: HostFirstAxisSliceView,
    first_axis_index: HostFirstAxisIndexView,
    first_axis_concat: HostFirstAxisConcatView,
    transpose: HostTransposeView,
};

const HostDenseView = union(enum) {
    scalar_int: i64,
    scalar_float: f64,
    int_array: HostIntDenseView,
    float_array: HostFloatDenseView,
};

const HostCollapsedFlatSlice = union(enum) {
    flat_slice: HostFlatSliceView,
    flat_stride: HostFlatStrideView,
};

fn hostDenseView(self: *Session, value: Value) KError!HostDenseView {
    return switch (value.tag()) {
        .int => .{ .scalar_int = value.asInt() },
        .bool => .{ .scalar_int = @intFromBool(value.asBool()) },
        .float => .{ .scalar_float = value.asFloat() },
        .array => switch (value.arrayKind()) {
            .host_array => switch (value.asHostArray().storage) {
                .bit => |words| .{ .int_array = .{ .dense = .{ .bit = .{ .words = words, .len = value.asHostArray().logical_len } } } },
                .int8 => |items| .{ .int_array = .{ .dense = .{ .int8 = items } } },
                .int16 => |items| .{ .int_array = .{ .dense = .{ .int16 = items } } },
                .int32 => |items| .{ .int_array = .{ .dense = .{ .int32 = items } } },
                .int64 => |items| .{ .int_array = .{ .dense = .{ .int64 = items } } },
                .float64 => |items| .{ .float_array = .{ .dense = items } },
                .boxed => error.Type,
            },
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.host) |array| {
                    break :blk try hostDenseView(self, Value.array(array));
                }
                if (numericArrayIsRangeIota(handle)) {
                    break :blk .{ .int_array = .{ .range_iota = .{ .handle = handle } } };
                }
                if (numericArrayIsFlatSlice(handle)) {
                    const source = numericArrayFlatSliceSource(handle) orelse return error.Type;
                    const flat_len = numericFlatLen(value) orelse return error.Type;
                    const start = numericArrayFlatSliceStart(handle) orelse return error.Type;
                    if (try tryCollapseHostFlatSlice(self, source, start, flat_len)) |collapsed| {
                        break :blk switch (valueNumericMode(source) orelse return error.Type) {
                            .float => switch (collapsed) {
                                .flat_slice => |items| .{ .float_array = .{ .flat_slice = items } },
                                .flat_stride => |items| .{ .float_array = .{ .flat_stride = items } },
                            },
                            .int => switch (collapsed) {
                                .flat_slice => |items| .{ .int_array = .{ .flat_slice = items } },
                                .flat_stride => |items| .{ .int_array = .{ .flat_stride = items } },
                            },
                        };
                    }
                    const source_host = try ensureNumericHostAttachmentForDenseView(self, source);
                    break :blk switch (valueNumericMode(source) orelse return error.Type) {
                        .float => .{ .float_array = .{ .flat_slice = .{
                            .source_value = source,
                            .source_host = source_host,
                            .start = start,
                            .len = flat_len,
                        } } },
                        .int => .{ .int_array = .{ .flat_slice = .{
                            .source_value = source,
                            .source_host = source_host,
                            .start = start,
                            .len = flat_len,
                        } } },
                    };
                }
                if (numericArrayIsFlatConcat(handle)) {
                    const left = numericArrayFlatConcatLeft(handle) orelse return error.Type;
                    const right = numericArrayFlatConcatRight(handle) orelse return error.Type;
                    const left_len = numericVectorLen(left) orelse return error.Type;
                    const right_len = numericVectorLen(right) orelse return error.Type;
                    const left_host = try ensureNumericHostAttachmentForDenseView(self, left);
                    const right_host = try ensureNumericHostAttachmentForDenseView(self, right);
                    if (comptime enable_probe_instrumentation) self.debug_flat_concat_dense_view_count += 1;
                    break :blk switch (valueNumericMode(value) orelse return error.Type) {
                        .float => .{ .float_array = .{ .flat_concat = .{
                            .left_value = left,
                            .left_host = left_host,
                            .right_value = right,
                            .right_host = right_host,
                            .left_len = left_len,
                            .len = left_len + right_len,
                        } } },
                        .int => .{ .int_array = .{ .flat_concat = .{
                            .left_value = left,
                            .left_host = left_host,
                            .right_value = right,
                            .right_host = right_host,
                            .left_len = left_len,
                            .len = left_len + right_len,
                        } } },
                    };
                }
                if (numericArrayIsFlatSegments(handle)) {
                    const segments = numericArrayFlatSegmentsValues(handle) orelse return error.Type;
                    const flat_len = numericFlatLen(value) orelse return error.Type;
                    break :blk switch (valueNumericMode(value) orelse return error.Type) {
                        .float => .{ .float_array = .{ .flat_segments = .{
                            .values = segments,
                            .len = flat_len,
                        } } },
                        .int => .{ .int_array = .{ .flat_segments = .{
                            .values = segments,
                            .len = flat_len,
                        } } },
                    };
                }
                if (numericArrayIsFirstAxisSlice(handle)) {
                    const slice = handle.first_axis_slice orelse return error.Type;
                    const source_handle = shapedNumericHandle(slice.source) orelse return error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_count: usize = @intCast(handle.shape[0]);
                    const flat_len = numericFlatLen(value) orelse return error.Type;
                    const source_host = try ensureNumericHostAttachmentForDenseView(self, slice.source);
                    if (slice.step == 1 and row_count == 1) {
                        const start = slice.start * row_width;
                        break :blk switch (valueNumericMode(slice.source) orelse return error.Type) {
                            .float => .{ .float_array = .{ .flat_slice = .{
                                .source_value = slice.source,
                                .source_host = source_host,
                                .start = start,
                                .len = flat_len,
                            } } },
                            .int => .{ .int_array = .{ .flat_slice = .{
                                .source_value = slice.source,
                                .source_host = source_host,
                                .start = start,
                                .len = flat_len,
                            } } },
                        };
                    }
                    if (comptime enable_probe_instrumentation) self.debug_first_axis_slice_dense_view_count += 1;
                    break :blk switch (valueNumericMode(slice.source) orelse return error.Type) {
                        .float => .{ .float_array = .{ .first_axis_slice = .{
                            .source_value = slice.source,
                            .source_host = source_host,
                            .start_row = slice.start,
                            .len = flat_len,
                            .row_width = row_width,
                            .row_step = slice.step,
                        } } },
                        .int => .{ .int_array = .{ .first_axis_slice = .{
                            .source_value = slice.source,
                            .source_host = source_host,
                            .start_row = slice.start,
                            .len = flat_len,
                            .row_width = row_width,
                            .row_step = slice.step,
                        } } },
                    };
                }
                if (numericArrayIsFirstAxisIndex(handle)) {
                    const index = handle.first_axis_index orelse return error.Type;
                    const source_handle = shapedNumericHandle(index.source) orelse return error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const flat_len = numericFlatLen(value) orelse return error.Type;
                    const source_host = try ensureNumericHostAttachmentForDenseView(self, index.source);
                    if (comptime enable_probe_instrumentation) self.debug_first_axis_index_dense_view_count += 1;
                    break :blk switch (valueNumericMode(index.source) orelse return error.Type) {
                        .float => .{ .float_array = .{ .first_axis_index = .{
                            .source_value = index.source,
                            .source_host = source_host,
                            .row_indices = index.row_indices,
                            .len = flat_len,
                            .row_width = row_width,
                        } } },
                        .int => .{ .int_array = .{ .first_axis_index = .{
                            .source_value = index.source,
                            .source_host = source_host,
                            .row_indices = index.row_indices,
                            .len = flat_len,
                            .row_width = row_width,
                        } } },
                    };
                }
                if (numericArrayIsFirstAxisConcat(handle)) {
                    const left = numericArrayFirstAxisConcatLeft(handle) orelse return error.Type;
                    const right = numericArrayFirstAxisConcatRight(handle) orelse return error.Type;
                    const left_len = numericFlatLen(left) orelse return error.Type;
                    const right_len = numericFlatLen(right) orelse return error.Type;
                    const left_host = try ensureNumericHostAttachmentForDenseView(self, left);
                    const right_host = try ensureNumericHostAttachmentForDenseView(self, right);
                    if (comptime enable_probe_instrumentation) self.debug_first_axis_concat_dense_view_count += 1;
                    break :blk switch (valueNumericMode(value) orelse return error.Type) {
                        .float => .{ .float_array = .{ .first_axis_concat = .{
                            .left_value = left,
                            .left_host = left_host,
                            .right_value = right,
                            .right_host = right_host,
                            .left_len = left_len,
                            .len = left_len + right_len,
                        } } },
                        .int => .{ .int_array = .{ .first_axis_concat = .{
                            .left_value = left,
                            .left_host = left_host,
                            .right_value = right,
                            .right_host = right_host,
                            .left_len = left_len,
                            .len = left_len + right_len,
                        } } },
                    };
                }
                if (numericArrayIsTransposeView(handle)) {
                    countTransposeStructuralHostUse(self, value);
                    const source = numericArrayTransposeSource(handle) orelse return error.Type;
                    const source_shape = valueNumericMatrixShape(source) orelse return error.Type;
                    const source_host = try ensureNumericHostAttachmentForDenseView(self, source);
                    break :blk switch (valueNumericMode(source) orelse return error.Type) {
                        .float => .{ .float_array = .{ .transpose = .{
                            .source_value = source,
                            .source_host = source_host,
                            .source_rows = source_shape.rows,
                            .source_cols = source_shape.cols,
                        } } },
                        .int => .{ .int_array = .{ .transpose = .{
                            .source_value = source,
                            .source_host = source_host,
                            .source_rows = source_shape.rows,
                            .source_cols = source_shape.cols,
                        } } },
                    };
                }
                if (numericArrayIsReshapeView(handle)) {
                    const source = numericArrayReshapeSource(handle) orelse return error.Type;
                    if (valueNumericHandle(source)) |source_handle| {
                        if (source_handle.host == null and source_handle.mlx != null and
                            !numericArrayIsRangeIota(source_handle) and
                            !numericArrayIsFlatSlice(source_handle) and
                            !numericArrayIsFlatConcat(source_handle) and
                            !numericArrayIsFlatSegments(source_handle) and
                            !numericArrayIsFirstAxisSlice(source_handle) and
                            !numericArrayIsFirstAxisIndex(source_handle) and
                            !numericArrayIsFirstAxisConcat(source_handle) and
                            !numericArrayIsTransposeView(source_handle))
                        {
                            _ = try tryEnsureHostRealizationForHandle(self, @constCast(source_handle)) orelse return error.Type;
                        }
                    }
                    break :blk try hostDenseView(self, source);
                }
                if (handle.mlx != null) {
                    _ = try tryEnsureHostRealizationForHandle(self, @constCast(handle)) orelse return error.Type;
                    break :blk try hostDenseView(self, value);
                }
                return error.Type;
            },
            .mlx_array => blk: {
                const handle = valueNumericHandle(value) orelse return error.Type;
                if (handle.host) |array| break :blk try hostDenseView(self, Value.array(array));
                if (numericArrayIsTransposeView(handle)) {
                    countTransposeStructuralHostUse(self, value);
                    const source = numericArrayTransposeSource(handle) orelse return error.Type;
                    const source_shape = valueNumericMatrixShape(source) orelse return error.Type;
                    const source_host = try ensureNumericHostAttachmentForDenseView(self, source);
                    break :blk switch (valueNumericMode(source) orelse return error.Type) {
                        .float => .{ .float_array = .{ .transpose = .{
                            .source_value = source,
                            .source_host = source_host,
                            .source_rows = source_shape.rows,
                            .source_cols = source_shape.cols,
                        } } },
                        .int => .{ .int_array = .{ .transpose = .{
                            .source_value = source,
                            .source_host = source_host,
                            .source_rows = source_shape.rows,
                            .source_cols = source_shape.cols,
                        } } },
                    };
                }
                if (handle.mlx != null) {
                    _ = try tryEnsureHostRealizationForHandle(self, @constCast(handle)) orelse return error.Type;
                    break :blk try hostDenseView(self, value);
                }
                return error.Type;
            },
            else => error.Internal,
        },
        else => error.Type,
    };
}

fn hostDenseIntKind(view: HostDenseView) ?HostIntStorageKind {
    return switch (view) {
        .scalar_int => |value| hostIntStorageKindForValue(value),
        .int_array => |items| hostIntDenseViewKind(items),
        else => null,
    };
}

fn hostFloatDenseViewLen(view: HostFloatDenseView) usize {
    return switch (view) {
        .dense => |items| items.len,
        .flat_slice => |items| items.len,
        .flat_stride => |items| items.len,
        .flat_concat => |items| items.len,
        .flat_segments => |items| items.len,
        .first_axis_slice => |items| items.len,
        .first_axis_index => |items| items.len,
        .first_axis_concat => |items| items.len,
        .transpose => |items| hostTransposeViewLen(items),
    };
}

fn hostFloatDenseViewItem(view: HostFloatDenseView, idx: usize) KError!f64 {
    return switch (view) {
        .dense => |items| items[idx],
        .flat_slice => |items| try hostFlatSliceFloatItem(items, idx),
        .flat_stride => |items| try hostFlatStrideFloatItem(items, idx),
        .flat_concat => |items| try hostFirstAxisConcatFloatItem(items, idx),
        .flat_segments => |items| try hostFlatSegmentsFloatItem(items, idx),
        .first_axis_slice => |items| try hostFirstAxisSliceFloatItem(items, idx),
        .first_axis_index => |items| try hostFirstAxisIndexFloatItem(items, idx),
        .first_axis_concat => |items| try hostFirstAxisConcatFloatItem(items, idx),
        .transpose => |items| try hostTransposeFloatItem(items, idx),
    };
}

fn hostArrayIntAt(array: *const HostArray, idx: usize) KError!i64 {
    return switch (array.storage) {
        .bit => |words| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk @intFromBool(bitGet(words, idx));
        },
        .int8 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk items[idx];
        },
        .int16 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk items[idx];
        },
        .int32 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk items[idx];
        },
        .int64 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk items[idx];
        },
        .float64 => error.Type,
        .boxed => error.Type,
    };
}

fn hostArrayFloatAt(array: *const HostArray, idx: usize) KError!f64 {
    return switch (array.storage) {
        .bit => |words| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk if (bitGet(words, idx)) 1.0 else 0.0;
        },
        .int8 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk @floatFromInt(items[idx]);
        },
        .int16 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk @floatFromInt(items[idx]);
        },
        .int32 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk @floatFromInt(items[idx]);
        },
        .int64 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk @as(f64, @floatFromInt(items[idx]));
        },
        .float64 => |items| blk: {
            if (idx >= items.len) return error.Internal;
            break :blk items[idx];
        },
        .boxed => error.Type,
    };
}

fn numericIntAt(value: Value, idx: usize) KError!i64 {
    return switch (value.tag()) {
        .int => value.asInt(),
        .bool => @intFromBool(value.asBool()),
        .array => switch (value.arrayKind()) {
            .host_array => hostArrayIntAt(value.asHostArray(), idx),
            .mlx_array => if (valueNumericHandle(value)) |handle|
                if (handle.host) |array|
                    hostArrayIntAt(array, idx)
                else
                    error.Type
            else
                error.Type,
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.host) |array| break :blk hostArrayIntAt(array, idx);
                if (numericArrayIsRangeIota(handle)) break :blk try numericArrayRangeIotaValueAt(handle, idx);
                if (numericArrayIsFlatSlice(handle)) {
                    const source = numericArrayFlatSliceSource(handle) orelse break :blk error.Type;
                    const start = numericArrayFlatSliceStart(handle) orelse break :blk error.Type;
                    break :blk try numericIntAt(source, start + idx);
                }
                if (numericArrayIsFlatConcat(handle)) {
                    const left = numericArrayFlatConcatLeft(handle) orelse break :blk error.Type;
                    const right = numericArrayFlatConcatRight(handle) orelse break :blk error.Type;
                    const left_len = numericVectorLen(left) orelse break :blk error.Type;
                    if (idx < left_len) break :blk try numericIntAt(left, idx);
                    break :blk try numericIntAt(right, idx - left_len);
                }
                if (numericArrayIsFlatSegments(handle)) {
                    const segments = numericArrayFlatSegmentsValues(handle) orelse break :blk error.Type;
                    var offset: usize = 0;
                    for (segments) |segment| {
                        const len = numericVectorLen(segment) orelse break :blk error.Type;
                        if (idx < offset + len) break :blk try numericIntAt(segment, idx - offset);
                        offset += len;
                    }
                    break :blk error.Type;
                }
                if (numericArrayIsFirstAxisSlice(handle)) {
                    const source = numericArrayFirstAxisSliceSource(handle) orelse break :blk error.Type;
                    const start = numericArrayFirstAxisSliceRowStart(handle) orelse break :blk error.Type;
                    const row_step = numericArrayFirstAxisSliceRowStep(handle) orelse break :blk error.Type;
                    const source_handle = shapedNumericHandle(source) orelse break :blk error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_idx = idx / row_width;
                    const col_idx = idx % row_width;
                    const source_row_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(row_idx)) * @as(i64, row_step);
                    if (source_row_i64 < 0) break :blk error.Type;
                    break :blk try numericIntAt(source, @as(usize, @intCast(source_row_i64)) * row_width + col_idx);
                }
                if (numericArrayIsFirstAxisIndex(handle)) {
                    const source = numericArrayFirstAxisIndexSource(handle) orelse break :blk error.Type;
                    const row_indices = numericArrayFirstAxisIndexRows(handle) orelse break :blk error.Type;
                    const source_handle = shapedNumericHandle(source) orelse break :blk error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_idx = idx / row_width;
                    const col_idx = idx % row_width;
                    const source_row_i64 = try numericIntAt(row_indices, row_idx);
                    if (source_row_i64 < 0) break :blk error.Type;
                    break :blk try numericIntAt(source, @as(usize, @intCast(source_row_i64)) * row_width + col_idx);
                }
                if (numericArrayIsFirstAxisConcat(handle)) {
                    const left = numericArrayFirstAxisConcatLeft(handle) orelse break :blk error.Type;
                    const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk error.Type;
                    const left_len = numericFlatLen(left) orelse break :blk error.Type;
                    if (idx < left_len) break :blk try numericIntAt(left, idx);
                    break :blk try numericIntAt(right, idx - left_len);
                }
                if (numericArrayIsTransposeView(handle)) {
                    const source = numericArrayTransposeSource(handle) orelse break :blk error.Type;
                    const source_shape = valueNumericMatrixShape(source) orelse break :blk error.Type;
                    const out_row = idx / source_shape.rows;
                    const out_col = idx % source_shape.rows;
                    break :blk try numericIntAt(source, out_col * source_shape.cols + out_row);
                }
                if (numericArrayIsReshapeView(handle)) {
                    const source = numericArrayReshapeSource(handle) orelse break :blk error.Type;
                    break :blk try numericIntAt(source, idx);
                }
                break :blk error.Type;
            },
            else => error.Internal,
        },
        else => error.Type,
    };
}

fn numericFloatAt(value: Value, idx: usize) KError!f64 {
    return switch (value.tag()) {
        .int => @as(f64, @floatFromInt(value.asInt())),
        .bool => @as(f64, @floatFromInt(@intFromBool(value.asBool()))),
        .float => value.asFloat(),
        .array => switch (value.arrayKind()) {
            .host_array => hostArrayFloatAt(value.asHostArray(), idx),
            .mlx_array => if (valueNumericHandle(value)) |handle|
                if (handle.host) |array|
                    hostArrayFloatAt(array, idx)
                else
                    error.Type
            else
                error.Type,
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.host) |array| break :blk hostArrayFloatAt(array, idx);
                if (numericArrayIsRangeIota(handle)) break :blk @floatFromInt(try numericArrayRangeIotaValueAt(handle, idx));
                if (numericArrayIsFlatSlice(handle)) {
                    const source = numericArrayFlatSliceSource(handle) orelse break :blk error.Type;
                    const start = numericArrayFlatSliceStart(handle) orelse break :blk error.Type;
                    break :blk try numericFloatAt(source, start + idx);
                }
                if (numericArrayIsFlatConcat(handle)) {
                    const left = numericArrayFlatConcatLeft(handle) orelse break :blk error.Type;
                    const right = numericArrayFlatConcatRight(handle) orelse break :blk error.Type;
                    const left_len = numericVectorLen(left) orelse break :blk error.Type;
                    if (idx < left_len) break :blk try numericFloatAt(left, idx);
                    break :blk try numericFloatAt(right, idx - left_len);
                }
                if (numericArrayIsFlatSegments(handle)) {
                    const segments = numericArrayFlatSegmentsValues(handle) orelse break :blk error.Type;
                    var offset: usize = 0;
                    for (segments) |segment| {
                        const len = numericVectorLen(segment) orelse break :blk error.Type;
                        if (idx < offset + len) break :blk try numericFloatAt(segment, idx - offset);
                        offset += len;
                    }
                    break :blk error.Type;
                }
                if (numericArrayIsFirstAxisSlice(handle)) {
                    const source = numericArrayFirstAxisSliceSource(handle) orelse break :blk error.Type;
                    const start = numericArrayFirstAxisSliceRowStart(handle) orelse break :blk error.Type;
                    const row_step = numericArrayFirstAxisSliceRowStep(handle) orelse break :blk error.Type;
                    const source_handle = shapedNumericHandle(source) orelse break :blk error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_idx = idx / row_width;
                    const col_idx = idx % row_width;
                    const source_row_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(row_idx)) * @as(i64, row_step);
                    if (source_row_i64 < 0) break :blk error.Type;
                    break :blk try numericFloatAt(source, @as(usize, @intCast(source_row_i64)) * row_width + col_idx);
                }
                if (numericArrayIsFirstAxisIndex(handle)) {
                    const source = numericArrayFirstAxisIndexSource(handle) orelse break :blk error.Type;
                    const row_indices = numericArrayFirstAxisIndexRows(handle) orelse break :blk error.Type;
                    const source_handle = shapedNumericHandle(source) orelse break :blk error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_idx = idx / row_width;
                    const col_idx = idx % row_width;
                    const source_row_i64 = try numericIntAt(row_indices, row_idx);
                    if (source_row_i64 < 0) break :blk error.Type;
                    break :blk try numericFloatAt(source, @as(usize, @intCast(source_row_i64)) * row_width + col_idx);
                }
                if (numericArrayIsFirstAxisConcat(handle)) {
                    const left = numericArrayFirstAxisConcatLeft(handle) orelse break :blk error.Type;
                    const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk error.Type;
                    const left_len = numericFlatLen(left) orelse break :blk error.Type;
                    if (idx < left_len) break :blk try numericFloatAt(left, idx);
                    break :blk try numericFloatAt(right, idx - left_len);
                }
                if (numericArrayIsTransposeView(handle)) {
                    const source = numericArrayTransposeSource(handle) orelse break :blk error.Type;
                    const source_shape = valueNumericMatrixShape(source) orelse break :blk error.Type;
                    const out_row = idx / source_shape.rows;
                    const out_col = idx % source_shape.rows;
                    break :blk try numericFloatAt(source, out_col * source_shape.cols + out_row);
                }
                if (numericArrayIsReshapeView(handle)) {
                    const source = numericArrayReshapeSource(handle) orelse break :blk error.Type;
                    break :blk try numericFloatAt(source, idx);
                }
                break :blk error.Type;
            },
            else => error.Internal,
        },
        else => error.Type,
    };
}

fn checkedIntOp(op: BuiltinId, left: i64, right: i64) KError!i64 {
    return switch (op) {
        .add => blk: {
            const result = @addWithOverflow(left, right);
            if (result[1] != 0) return error.Unsupported;
            break :blk result[0];
        },
        .sub => blk: {
            const result = @subWithOverflow(left, right);
            if (result[1] != 0) return error.Unsupported;
            break :blk result[0];
        },
        .minimum => @min(left, right),
        .maximum => @max(left, right),
        .mul => blk: {
            const result = @mulWithOverflow(left, right);
            if (result[1] != 0) return error.Unsupported;
            break :blk result[0];
        },
        .div => unreachable,
        else => unreachable,
    };
}

fn applyFloatOp(op: BuiltinId, left: f64, right: f64) f64 {
    return switch (op) {
        .add => left + right,
        .sub => left - right,
        .minimum => @min(left, right),
        .maximum => @max(left, right),
        .mul => left * right,
        .div => left / right,
        else => unreachable,
    };
}

fn applyFloatMonadOp(op: BuiltinId, value: f64) f64 {
    return switch (op) {
        .div => std.math.sqrt(value),
        .exp => std.math.exp(value),
        .log => std.math.log(f64, std.math.e, value),
        .tanh => std.math.tanh(value),
        .sigmoid => 1.0 / (1.0 + std.math.exp(-value)),
        else => unreachable,
    };
}

fn applyIntOpUnchecked(op: BuiltinId, left: i64, right: i64) i64 {
    return switch (op) {
        .add => left + right,
        .sub => left - right,
        .minimum => @min(left, right),
        .maximum => @max(left, right),
        .mul => left * right,
        .div => unreachable,
        else => unreachable,
    };
}

fn checkedAddAcc(acc: *i64, value: i64) KError!void {
    acc.* = try checkedIntOp(.add, acc.*, value);
}

fn addScanIntFlags(item_range: HostIntRange) u8 {
    return host_array_flag_normalized | orderFlagsFromMonotonic(item_range.min >= 0, item_range.max <= 0);
}

fn addScanFloatFlags(items: []const f64) u8 {
    var asc = true;
    var dsc = true;
    for (items) |item| {
        if (!std.math.isFinite(item)) {
            asc = false;
            dsc = false;
            break;
        }
        if (item < 0) asc = false;
        if (item > 0) dsc = false;
    }
    return host_array_flag_normalized | orderFlagsFromMonotonic(asc, dsc);
}

fn foldAddIntBitSlice(items: HostBitSlice, seed: ?i64) KError!i64 {
    // Packed bool folds can count whole words instead of scalarizing each element.
    var total = seed orelse 0;
    var saw_value = seed != null;
    for (items.words, 0..) |_, word_idx| {
        const masked = bitWordMasked(items.words, items.len, word_idx);
        const count: i64 = @intCast(@popCount(masked));
        if (!saw_value) {
            total = count;
            saw_value = true;
        } else {
            try checkedAddAcc(&total, count);
        }
    }
    return total;
}

fn foldAddIntSlice(comptime T: type, items: []const T, seed: ?i64) KError!i64 {
    var total = seed orelse @as(i64, items[0]);
    const start_idx: usize = if (seed == null) 1 else 0;
    for (items[start_idx..]) |item| try checkedAddAcc(&total, @intCast(item));
    return total;
}

fn foldAddIntSliceUnchecked(comptime T: type, items: []const T, seed: ?i64) i64 {
    var total = seed orelse @as(i64, items[0]);
    const start_idx: usize = if (seed == null) 1 else 0;
    for (items[start_idx..]) |item| total += @intCast(item);
    return total;
}

fn foldAddIntBitSliceUnchecked(items: HostBitSlice, seed: ?i64) i64 {
    var total = seed orelse 0;
    var saw_value = seed != null;
    for (items.words, 0..) |_, word_idx| {
        const count: i64 = @intCast(@popCount(bitWordMasked(items.words, items.len, word_idx)));
        if (!saw_value) {
            total = count;
            saw_value = true;
        } else {
            total += count;
        }
    }
    return total;
}

fn foldAddRangeFitsI64(item_range: HostIntRange, len: usize, seed: ?i64) bool {
    const len_i128: i128 = @intCast(len);
    const seed_i128: i128 = if (seed) |value| value else 0;
    const min_total = @as(i128, item_range.min) * len_i128 + seed_i128;
    const max_total = @as(i128, item_range.max) * len_i128 + seed_i128;
    return min_total >= std.math.minInt(i64) and max_total <= std.math.maxInt(i64);
}

fn foldAddIntView(view: HostIntArrayView, seed: ?i64) KError!i64 {
    return switch (view) {
        .bit => |items| try foldAddIntBitSlice(items, seed),
        .int8 => |items| try foldAddIntSlice(i8, items, seed),
        .int16 => |items| try foldAddIntSlice(i16, items, seed),
        .int32 => |items| try foldAddIntSlice(i32, items, seed),
        .int64 => |items| try foldAddIntSlice(i64, items, seed),
    };
}

fn foldAddIntViewUnchecked(view: HostIntArrayView, seed: ?i64) i64 {
    return switch (view) {
        .bit => |items| foldAddIntBitSliceUnchecked(items, seed),
        .int8 => |items| foldAddIntSliceUnchecked(i8, items, seed),
        .int16 => |items| foldAddIntSliceUnchecked(i16, items, seed),
        .int32 => |items| foldAddIntSliceUnchecked(i32, items, seed),
        .int64 => |items| foldAddIntSliceUnchecked(i64, items, seed),
    };
}

fn foldAddIntViewMaybeUnchecked(view: HostIntArrayView, known_range: ?HostIntRange, seed: ?i64) KError!i64 {
    if (known_range) |item_range| {
        if (foldAddRangeFitsI64(item_range, hostIntArrayViewLen(view), seed)) return foldAddIntViewUnchecked(view, seed);
    }
    return try foldAddIntView(view, seed);
}

fn foldAddFloatSlice(items: []const f64, seed: ?f64) f64 {
    var total = seed orelse items[0];
    const start_idx: usize = if (seed == null) 1 else 0;
    for (items[start_idx..]) |item| total += item;
    return total;
}

fn foldAddFloatIntView(view: HostIntArrayView, seed: f64) f64 {
    var total = seed;
    switch (view) {
        .bit => |items| {
            for (items.words, 0..) |_, word_idx| total += @floatFromInt(@popCount(bitWordMasked(items.words, items.len, word_idx)));
        },
        .int8 => |items| for (items) |item| {
            total += @floatFromInt(item);
        },
        .int16 => |items| for (items) |item| {
            total += @floatFromInt(item);
        },
        .int32 => |items| for (items) |item| {
            total += @floatFromInt(item);
        },
        .int64 => |items| for (items) |item| {
            total += @floatFromInt(item);
        },
    }
    return total;
}

const HostFloatBounds = struct {
    min: f64,
    max: f64,
};

fn hostFloatDenseViewBounds(view: HostFloatDenseView) KError!HostFloatBounds {
    return switch (view) {
        .dense => |items| blk: {
            var min_value = items[0];
            var max_value = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, item);
                max_value = @max(max_value, item);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        else => blk: {
            const len = hostFloatDenseViewLen(view);
            var min_value = try hostFloatDenseViewItem(view, 0);
            var max_value = min_value;
            for (1..len) |idx| {
                const item = try hostFloatDenseViewItem(view, idx);
                min_value = @min(min_value, item);
                max_value = @max(max_value, item);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
    };
}

fn analyzeAddScanIntView(view: HostIntArrayView, seed: ?i64) KError!HostAddScanIntAnalysis {
    const len = hostIntArrayViewLen(view);
    std.debug.assert(len > 1);

    var acc = if (seed) |seed_value|
        try checkedIntOp(.add, seed_value, hostIntViewItem(view, 0))
    else
        hostIntViewItem(view, 0);
    var min_value = acc;
    var max_value = acc;

    for (1..len) |idx| {
        try checkedAddAcc(&acc, hostIntViewItem(view, idx));
        min_value = @min(min_value, acc);
        max_value = @max(max_value, acc);
    }

    return .{
        .range = .{ .min = min_value, .max = max_value },
        .kind = hostIntStorageKindForRange(min_value, max_value),
        .flags = addScanIntFlags(hostIntArrayViewRange(view)),
    };
}

fn fillAddScanBitTo(comptime OutT: type, out: []OutT, items: HostBitSlice, seed: ?i64) void {
    var acc = seed orelse 0;
    var saw_value = seed != null;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const item: i64 = @intCast(bits & 1);
            if (!saw_value) {
                acc = item;
                saw_value = true;
            } else {
                acc += item;
            }
            out[out_idx] = @intCast(acc);
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillAddScanIntTo(comptime OutT: type, comptime InT: type, out: []OutT, items: []const InT, seed: ?i64) void {
    var acc = seed orelse @as(i64, items[0]);
    const start_idx: usize = if (seed == null) 1 else 0;
    if (seed == null) {
        out[0] = @intCast(acc);
    }
    for (items[start_idx..], start_idx..) |item, idx| {
        if (seed != null or idx != 0) acc += @intCast(item);
        out[idx] = @intCast(acc);
    }
}

fn fillAddScanIntResult(out: *HostIntResult, view: HostIntArrayView, seed: ?i64) void {
    switch (out.*) {
        .bit => unreachable,
        .int8 => |*dest| switch (view) {
            .bit => |items| fillAddScanBitTo(i8, dest.items, items, seed),
            .int8 => |items| fillAddScanIntTo(i8, i8, dest.items, items, seed),
            .int16 => |items| fillAddScanIntTo(i8, i16, dest.items, items, seed),
            .int32 => |items| fillAddScanIntTo(i8, i32, dest.items, items, seed),
            .int64 => |items| fillAddScanIntTo(i8, i64, dest.items, items, seed),
        },
        .int16 => |*dest| switch (view) {
            .bit => |items| fillAddScanBitTo(i16, dest.items, items, seed),
            .int8 => |items| fillAddScanIntTo(i16, i8, dest.items, items, seed),
            .int16 => |items| fillAddScanIntTo(i16, i16, dest.items, items, seed),
            .int32 => |items| fillAddScanIntTo(i16, i32, dest.items, items, seed),
            .int64 => |items| fillAddScanIntTo(i16, i64, dest.items, items, seed),
        },
        .int32 => |*dest| switch (view) {
            .bit => |items| fillAddScanBitTo(i32, dest.items, items, seed),
            .int8 => |items| fillAddScanIntTo(i32, i8, dest.items, items, seed),
            .int16 => |items| fillAddScanIntTo(i32, i16, dest.items, items, seed),
            .int32 => |items| fillAddScanIntTo(i32, i32, dest.items, items, seed),
            .int64 => |items| fillAddScanIntTo(i32, i64, dest.items, items, seed),
        },
        .int64 => |*dest| switch (view) {
            .bit => |items| fillAddScanBitTo(i64, dest.items, items, seed),
            .int8 => |items| fillAddScanIntTo(i64, i8, dest.items, items, seed),
            .int16 => |items| fillAddScanIntTo(i64, i16, dest.items, items, seed),
            .int32 => |items| fillAddScanIntTo(i64, i32, dest.items, items, seed),
            .int64 => |items| fillAddScanIntTo(i64, i64, dest.items, items, seed),
        },
    }
}

fn fillAddScanFloatSlice(out: []f64, items: []const f64, seed: ?f64) void {
    var acc = seed orelse items[0];
    const start_idx: usize = if (seed == null) 1 else 0;
    if (seed == null) out[0] = acc;
    for (items[start_idx..], start_idx..) |item, idx| {
        if (seed != null or idx != 0) acc += item;
        out[idx] = acc;
    }
}

fn fillAddScanFloatBitView(out: []f64, items: HostBitSlice, seed: f64) void {
    var acc = seed;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            acc += @floatFromInt(bits & 1);
            out[out_idx] = acc;
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillAddScanFloatIntTo(comptime InT: type, out: []f64, items: []const InT, seed: f64) void {
    var acc = seed;
    for (items, 0..) |item, idx| {
        acc += @floatFromInt(item);
        out[idx] = acc;
    }
}

fn fillAddScanFloatIntView(out: []f64, view: HostIntArrayView, seed: f64) void {
    switch (view) {
        .bit => |items| fillAddScanFloatBitView(out, items, seed),
        .int8 => |items| fillAddScanFloatIntTo(i8, out, items, seed),
        .int16 => |items| fillAddScanFloatIntTo(i16, out, items, seed),
        .int32 => |items| fillAddScanFloatIntTo(i32, out, items, seed),
        .int64 => |items| fillAddScanFloatIntTo(i64, out, items, seed),
    }
}

fn castDenseInt(comptime T: type, value: anytype) T {
    return @as(T, @intCast(value));
}

fn castCheckedDenseInt(comptime T: type, value: i64) KError!T {
    return std.math.cast(T, value) orelse return error.Unsupported;
}

fn applyIntOpUncheckedTyped(comptime T: type, op: BuiltinId, left: anytype, right: anytype) T {
    const lhs: T = castDenseInt(T, left);
    const rhs: T = castDenseInt(T, right);
    return switch (op) {
        .add => lhs + rhs,
        .sub => lhs - rhs,
        .mul => lhs * rhs,
        .div => unreachable,
        else => unreachable,
    };
}

fn WiderDenseInt(comptime T: type) type {
    return switch (T) {
        i8 => i16,
        i16 => i32,
        i32 => i64,
        i64 => i64,
        else => @compileError("unsupported dense int type"),
    };
}

fn applyIntOpCheckedNarrow(comptime OutT: type, op: BuiltinId, left: anytype, right: anytype) KError!OutT {
    if (OutT == i64) {
        return castDenseInt(OutT, try checkedIntOp(op, @as(i64, @intCast(left)), @as(i64, @intCast(right))));
    }

    const WideT = WiderDenseInt(OutT);
    const lhs: WideT = castDenseInt(WideT, left);
    const rhs: WideT = castDenseInt(WideT, right);
    const result: WideT = switch (op) {
        .add => lhs + rhs,
        .sub => lhs - rhs,
        .mul => lhs * rhs,
        .div => unreachable,
        else => unreachable,
    };
    return std.math.cast(OutT, result) orelse error.Unsupported;
}

fn negateCheckedNarrow(comptime OutT: type, value: anytype) KError!OutT {
    if (OutT == i64) {
        return castDenseInt(OutT, try checkedIntOp(.sub, 0, @as(i64, @intCast(value))));
    }

    const WideT = WiderDenseInt(OutT);
    const result: WideT = -castDenseInt(WideT, value);
    return std.math.cast(OutT, result) orelse error.Unsupported;
}

fn toDenseFloat(value: anytype) f64 {
    return switch (@typeInfo(@TypeOf(value))) {
        .float, .comptime_float => value,
        .int, .comptime_int => @floatFromInt(value),
        else => @compileError("unsupported dense numeric type"),
    };
}

fn fillBitScalarArrayResultGeneric(out: *HostBitAlloc, op: BuiltinId, scalar: i64, items: HostIntArrayView, scalar_left: bool, unchecked_safe: bool) KError!void {
    if (op == .mul and scalar >= 0 and scalar <= 1 and std.meta.activeTag(items) == .bit) {
        const bit_items = items.bit;
        if (scalar == 0) {
            bitFill(out.words, out.len, false);
            return;
        }
        if (out.words.ptr != bit_items.words.ptr) @memcpy(out.words, bit_items.words);
        bitClearUnusedTail(out.words, out.len);
        return;
    }

    var generic_out = HostIntResult{ .bit = out.* };
    for (0..hostIntArrayViewLen(items)) |idx| {
        const item = hostIntViewItem(items, idx);
        const result = if (unchecked_safe)
            if (scalar_left) applyIntOpUnchecked(op, scalar, item) else applyIntOpUnchecked(op, item, scalar)
        else
            try checkedIntOp(op, if (scalar_left) scalar else item, if (scalar_left) item else scalar);
        try generic_out.set(idx, result);
    }
}

fn fillBitArrayArrayResultGeneric(out: *HostBitAlloc, op: BuiltinId, left_items: HostIntArrayView, right_items: HostIntArrayView, unchecked_safe: bool) KError!void {
    if (op == .mul and std.meta.activeTag(left_items) == .bit and std.meta.activeTag(right_items) == .bit) {
        const left_bits = left_items.bit;
        const right_bits = right_items.bit;
        for (0..out.words.len) |idx| out.words[idx] = left_bits.words[idx] & right_bits.words[idx];
        bitClearUnusedTail(out.words, out.len);
        return;
    }

    var generic_out = HostIntResult{ .bit = out.* };
    for (0..hostIntArrayViewLen(left_items)) |idx| {
        const left = hostIntViewItem(left_items, idx);
        const right = hostIntViewItem(right_items, idx);
        const result = if (unchecked_safe)
            applyIntOpUnchecked(op, left, right)
        else
            try checkedIntOp(op, left, right);
        try generic_out.set(idx, result);
    }
}

fn fillIntScalarArrayResultGeneric(out: *HostIntResult, op: BuiltinId, scalar: i64, items: HostIntArrayView, scalar_left: bool, unchecked_safe: bool) KError!void {
    for (0..hostIntArrayViewLen(items)) |idx| {
        const item = hostIntViewItem(items, idx);
        const result = if (unchecked_safe)
            if (scalar_left) applyIntOpUnchecked(op, scalar, item) else applyIntOpUnchecked(op, item, scalar)
        else
            try checkedIntOp(op, if (scalar_left) scalar else item, if (scalar_left) item else scalar);
        try out.set(idx, result);
    }
}

fn fillIntArrayArrayResultGeneric(out: *HostIntResult, op: BuiltinId, left_items: HostIntArrayView, right_items: HostIntArrayView, unchecked_safe: bool) KError!void {
    for (0..hostIntArrayViewLen(left_items)) |idx| {
        const left = hostIntViewItem(left_items, idx);
        const right = hostIntViewItem(right_items, idx);
        const result = if (unchecked_safe)
            applyIntOpUnchecked(op, left, right)
        else
            try checkedIntOp(op, left, right);
        try out.set(idx, result);
    }
}

fn fillIntNegArrayResultGeneric(out: *HostIntResult, items: HostIntArrayView, unchecked_safe: bool) KError!void {
    for (0..hostIntArrayViewLen(items)) |idx| {
        const item = hostIntViewItem(items, idx);
        const result = if (unchecked_safe) -item else try checkedIntOp(.sub, 0, item);
        try out.set(idx, result);
    }
}

fn fillIntScalarBitArrayTo(comptime OutT: type, out: []OutT, op: BuiltinId, scalar: i64, items: HostBitSlice, scalar_left: bool, unchecked_safe: bool) KError!void {
    if (items.len == 0) return;
    const scalar_value: OutT = if (unchecked_safe) castDenseInt(OutT, scalar) else undefined;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const item_value: OutT = @intCast(bits & 1);
            out[out_idx] = if (unchecked_safe)
                if (scalar_left) applyIntOpUncheckedTyped(OutT, op, scalar_value, item_value) else applyIntOpUncheckedTyped(OutT, op, item_value, scalar_value)
            else
                try applyIntOpCheckedNarrow(OutT, op, if (scalar_left) scalar else @as(i64, @intCast(item_value)), if (scalar_left) @as(i64, @intCast(item_value)) else scalar);
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillIntBitArrayArrayTo(comptime OutT: type, out: []OutT, op: BuiltinId, left_items: HostBitSlice, right_items: HostBitSlice, unchecked_safe: bool) KError!void {
    if (left_items.len == 0) return;
    var out_idx: usize = 0;
    for (left_items.words, 0..) |_, word_idx| {
        var left_bits = bitWordMasked(left_items.words, left_items.len, word_idx);
        var right_bits = bitWordMasked(right_items.words, right_items.len, word_idx);
        const active = bitWordActiveLen(left_items.len, word_idx, left_items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const left_value: OutT = @intCast(left_bits & 1);
            const right_value: OutT = @intCast(right_bits & 1);
            out[out_idx] = if (unchecked_safe)
                applyIntOpUncheckedTyped(OutT, op, left_value, right_value)
            else
                try applyIntOpCheckedNarrow(OutT, op, @as(i64, @intCast(left_value)), @as(i64, @intCast(right_value)));
            left_bits >>= 1;
            right_bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillIntBitArrayMixedTo(
    comptime OutT: type,
    comptime OtherT: type,
    out: []OutT,
    op: BuiltinId,
    bit_items: HostBitSlice,
    other_items: []const OtherT,
    bit_left: bool,
    unchecked_safe: bool,
) KError!void {
    if (bit_items.len == 0) return;
    var out_idx: usize = 0;
    for (bit_items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(bit_items.words, bit_items.len, word_idx);
        const active = bitWordActiveLen(bit_items.len, word_idx, bit_items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const bit_value: OutT = @intCast(bits & 1);
            const other_value: OutT = castDenseInt(OutT, other_items[out_idx]);
            out[out_idx] = if (unchecked_safe)
                if (bit_left) applyIntOpUncheckedTyped(OutT, op, bit_value, other_value) else applyIntOpUncheckedTyped(OutT, op, other_value, bit_value)
            else
                try applyIntOpCheckedNarrow(OutT, op, if (bit_left) @as(i64, @intCast(bit_value)) else @as(i64, @intCast(other_items[out_idx])), if (bit_left) @as(i64, @intCast(other_items[out_idx])) else @as(i64, @intCast(bit_value)));
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillIntNegBitArrayTo(comptime OutT: type, out: []OutT, items: HostBitSlice) void {
    if (items.len == 0) return;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            out[out_idx] = -@as(OutT, @intCast(bits & 1));
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillIntScalarArrayTo(comptime OutT: type, comptime InT: type, out: []OutT, op: BuiltinId, scalar: i64, items: []const InT, scalar_left: bool, unchecked_safe: bool) KError!void {
    if (unchecked_safe) {
        const scalar_value: OutT = castDenseInt(OutT, scalar);
        for (items, 0..) |item, idx| {
            const item_value: OutT = castDenseInt(OutT, item);
            out[idx] = if (scalar_left)
                applyIntOpUncheckedTyped(OutT, op, scalar_value, item_value)
            else
                applyIntOpUncheckedTyped(OutT, op, item_value, scalar_value);
        }
        return;
    }

    for (items, 0..) |item, idx| {
        const lhs = if (scalar_left) scalar else @as(i64, @intCast(item));
        const rhs = if (scalar_left) @as(i64, @intCast(item)) else scalar;
        out[idx] = try applyIntOpCheckedNarrow(OutT, op, lhs, rhs);
    }
}

fn fillIntArrayArrayTo(comptime OutT: type, comptime LT: type, comptime RT: type, out: []OutT, op: BuiltinId, left_items: []const LT, right_items: []const RT, unchecked_safe: bool) KError!void {
    if (unchecked_safe) {
        for (left_items, 0..) |left_item, idx| {
            out[idx] = applyIntOpUncheckedTyped(OutT, op, left_item, right_items[idx]);
        }
        return;
    }

    for (left_items, 0..) |left_item, idx| {
        out[idx] = try applyIntOpCheckedNarrow(OutT, op, left_item, right_items[idx]);
    }
}

fn fillIntNegArrayTo(comptime OutT: type, comptime InT: type, out: []OutT, items: []const InT, unchecked_safe: bool) KError!void {
    if (unchecked_safe or @bitSizeOf(OutT) > @bitSizeOf(InT)) {
        for (items, 0..) |item, idx| out[idx] = -castDenseInt(OutT, item);
        return;
    }

    for (items, 0..) |item, idx| {
        out[idx] = try negateCheckedNarrow(OutT, item);
    }
}

fn fillIntScalarDenseResult(out: *HostIntResult, op: BuiltinId, scalar: i64, items: HostIntDenseView, scalar_left: bool, unchecked_safe: bool) KError!void {
    switch (items) {
        .dense => |view| try fillIntScalarArrayResult(out, op, scalar, view, scalar_left, unchecked_safe),
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(items)) |idx| {
                const item = try hostIntDenseViewItem(items, idx);
                const lhs = if (scalar_left) scalar else item;
                const rhs = if (scalar_left) item else scalar;
                try out.set(idx, if (unchecked_safe) applyIntOpUnchecked(op, lhs, rhs) else try checkedIntOp(op, lhs, rhs));
            }
        },
    }
}

fn fillIntDenseDenseResult(out: *HostIntResult, op: BuiltinId, left_items: HostIntDenseView, right_items: HostIntDenseView, unchecked_safe: bool) KError!void {
    switch (left_items) {
        .dense => |left_view| switch (right_items) {
            .dense => |right_view| try fillIntArrayArrayResult(out, op, left_view, right_view, unchecked_safe),
            .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
                for (0..hostIntDenseViewLen(left_items)) |idx| {
                    const left_value = try hostIntDenseViewItem(left_items, idx);
                    const right_value = try hostIntDenseViewItem(right_items, idx);
                    try out.set(idx, if (unchecked_safe) applyIntOpUnchecked(op, left_value, right_value) else try checkedIntOp(op, left_value, right_value));
                }
            },
        },
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(left_items)) |idx| {
                const left_value = try hostIntDenseViewItem(left_items, idx);
                const right_value = try hostIntDenseViewItem(right_items, idx);
                try out.set(idx, if (unchecked_safe) applyIntOpUnchecked(op, left_value, right_value) else try checkedIntOp(op, left_value, right_value));
            }
        },
    }
}

fn fillIntScalarArrayResult(out: *HostIntResult, op: BuiltinId, scalar: i64, items: HostIntArrayView, scalar_left: bool, unchecked_safe: bool) KError!void {
    if (std.meta.activeTag(out.*) == .bit) {
        return fillBitScalarArrayResultGeneric(&out.bit, op, scalar, items, scalar_left, unchecked_safe);
    }
    if (std.meta.activeTag(items) == .bit) {
        return switch (out.*) {
            .bit => unreachable,
            .int8 => |*dest| fillIntScalarBitArrayTo(i8, dest.items, op, scalar, items.bit, scalar_left, unchecked_safe),
            .int16 => |*dest| fillIntScalarBitArrayTo(i16, dest.items, op, scalar, items.bit, scalar_left, unchecked_safe),
