            .int64 => |*dest| fillIntScalarBitArrayTo(i64, dest.items, op, scalar, items.bit, scalar_left, unchecked_safe),
        };
    }
    switch (out.*) {
        .bit => |*dest| try fillBitScalarArrayResultGeneric(dest, op, scalar, items, scalar_left, unchecked_safe),
        .int8 => |*dest| switch (items) {
            .int8 => |slice| try fillIntScalarArrayTo(i8, i8, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int16 => |slice| try fillIntScalarArrayTo(i8, i16, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
